  // ============ 安全工具函数 ============

  /**
   * invoke 安全包装器：
   * 为每次调用预先附加 rejection 处理器，避免 fire-and-forget 触发 unhandled rejection。
   * 同时返回原始 Promise，保持 await/try-catch 的原有语义。
   */
  function invoke<T>(
    cmd: string,
    args?: Record<string, unknown>,
  ): Promise<T> {
    const promise =
      args !== undefined ? tauriInvoke<T>(cmd, args) : tauriInvoke<T>(cmd);
    promise.catch(() => {});
    return promise;
  }

  // 一次性定时器管理（组件卸载时自动清理）
  const pendingTimeouts = new Set<number>();

  /**
   * 安全的 setTimeout 包装器，自动在组件卸载时清理
   * @param callback 回调函数
   * @param delay 延迟时间（毫秒）
   * @returns 定时器 ID
   */
  function safeTimeout(callback: () => void, delay: number): number {
    const id = window.setTimeout(() => {
      pendingTimeouts.delete(id);
      callback();
    }, delay);
    pendingTimeouts.add(id);
    return id;
  }

  /**
   * 清理所有待处理的一次性定时器
   */
  function clearAllPendingTimeouts(): void {
    pendingTimeouts.forEach((id) => window.clearTimeout(id));
    pendingTimeouts.clear();
  }

  /**
   * 带超时保护的 invoke 调用，防止后端卡死导致 UI 无响应
   */
  function invokeWithTimeout<T>(
    cmd: string,
    args: Record<string, unknown> | undefined,
    timeoutMs: number,
    fallback: T,
  ): Promise<T> {
    let timer: ReturnType<typeof setTimeout>;
    return Promise.race([
      (args !== undefined ? invoke<T>(cmd, args) : invoke<T>(cmd)).finally(() => clearTimeout(timer)),
      new Promise<T>((resolve) =>
        timer = setTimeout(() => {
          console.warn(`[Timeout] invoke("${cmd}") 超时 (${timeoutMs}ms)，使用回退值`);
          resolve(fallback);
        }, timeoutMs),
      ),
    ]);
  }

  /**
   * 防抖的 save_settings（用于高频率滑块操作，避免请求风暴）
   */
  let saveSettingsTimer: number | null = null;
  function debouncedSaveSettings(settings: Record<string, unknown>, delay = 300) {
    if (saveSettingsTimer !== null) clearTimeout(saveSettingsTimer);
    saveSettingsTimer = window.setTimeout(() => {
      saveSettingsTimer = null;
      invoke("save_settings", { settings }).catch((e: any) =>
        console.error("save_settings failed:", e),
      );
    }, delay);
  }

