      }
      // 进阶设置（展开/折叠）
      items.push({ id: "advanced_settings_toggle", type: "toggle" });
      if (advancedSettingsExpanded) {
        items.push({ id: "epp", type: "slider" });
        items.push({ id: "active_cores", type: "stepper" });
        // 仅混合架构 CPU 显示大小核切换
        if (coreTopology?.has_hybrid_cores) {
          items.push({ id: "core_mode", type: "stepper" });
        }
        items.push({ id: "cpu_freq_toggle", type: "toggle" });
        if (cpuFreqLimitEnabled) {
          items.push({ id: "cpu_freq", type: "slider" });
        }
        // 首选高性能处理器（仅混合架构 CPU 显示）
        if (coreTopology?.has_hybrid_cores) {
