        }
        // 核心调度策略（仅 Intel 混合架构显示）
        if (coreTopology?.has_hybrid_cores) {
          items.push({ id: "core_scheduling", type: "stepper" });
        }
        // Intel CPU/GPU 偏好（功耗分配）
        if (isIntelDevice) {
