      items.push({ id: "kbm_right_stick_mode", type: "stepper" });

      // 添加 button_mapping_toggle 项
      items.push(staticItems[buttonMappingIdx]);

      // 按键映射展开时插入详细选项（已复用 KBM 引擎）
