      // 陀螺仪：允许在启用前选择设备/映射模式
      // 仅当检测到可用设备时显示这些选项，避免出现空选项
      if (gyroAvailableDevices.length > 0) {
        items.push({ id: "gyro_device", type: "stepper" });

        // 灵敏度/死区等仅在启用后显示（避免误以为已生效）
        if (gyroEnabled) {
          items.push({ id: "gyro_sensitivity", type: "slider" });
          items.push({ id: "gyro_deadzone", type: "slider" });
