        items.push({ id: "gyro_mapping", type: "stepper" });

        // ViGEm 驱动安装：仅在需要虚拟手柄（右摇杆模式）且未安装时显示
        if (gyroMappingMode === "RightStick" && !vigemDriverInstalled) {
          items.push({ id: "vigem_install", type: "action" });
        }

        if (gyroEnabled) {
          items.push({ id: "gyro_invert_x", type: "toggle" });
          items.push({ id: "gyro_invert_y", type: "toggle" });
          items.push({ id: "gyro_filtering", type: "toggle" });
          items.push({ id: "gyro_test", type: "special" });
        }
      }

      // ROG Ally 控制器配置（仅在 ROG Ally 设备上显示）
      if (rogAllyControllerAvailable) {
        items.push({ id: "rog_ally_toggle", type: "toggle" });
        if (rogAllyExpanded) {
          items.push({ id: "rog_ally_mode", type: "stepper" });
          items.push({ id: "rog_ally_ls_min", type: "slider" });
          items.push({ id: "rog_ally_ls_max", type: "slider" });
          items.push({ id: "rog_ally_rs_min", type: "slider" });
          items.push({ id: "rog_ally_rs_max", type: "slider" });
          items.push({ id: "rog_ally_lt_min", type: "slider" });
          items.push({ id: "rog_ally_lt_max", type: "slider" });
          items.push({ id: "rog_ally_rt_min", type: "slider" });
          items.push({ id: "rog_ally_rt_max", type: "slider" });
          items.push({ id: "rog_ally_vibration", type: "slider" });
          items.push({ id: "rog_ally_apply", type: "action" });
        }
      }

      // Legion Go 控制器配置（仅在 Legion Go 设备上显示）
      if (legionControllerAvailable) {
        items.push({ id: "legion_toggle", type: "toggle" });
        if (legionExpanded) {
          items.push({ id: "legion_touchpad", type: "toggle" });
          items.push({ id: "legion_touchpad_vibration", type: "stepper" });
          items.push({ id: "legion_vibration", type: "stepper" });
          items.push({ id: "legion_nintendo_layout", type: "toggle" });
          items.push({ id: "legion_rgb", type: "toggle" });
          items.push({ id: "legion_stick_light_left", type: "toggle" });
          items.push({ id: "legion_stick_light_right", type: "toggle" });
          items.push({ id: "legion_apply", type: "action" });
        }
      }

      // 添加 gyro_enable 之后的静态项（shortcut_toggle 等）
      for (let i = gyroEnableIdx + 1; i < staticItems.length; i++) {
        items.push(staticItems[i]);
      }

      // 添加快捷键（需要展开才显示）
      if (shortcutExpanded) {
        SHORTCUTS.forEach((_, i) => {
          items.push({ id: `shortcut_${i}`, type: "action" });
        });
      }
      return items;
    }

    if (tabId === "hotkey") {
      // 热键页：所有快捷键绑定
      return TAB_ITEMS_STATIC.hotkey || [];
    }

    return TAB_ITEMS_STATIC[tabId] || [];
  }

  // 获取当前焦点项
  function getCurrentItem(): TabItem | null {
    return currentTabItems[focusIndex] || null;
  }

  // 获取指定 id 在当前 Tab 中的索引（用于 UI 模板）
  function getItemIndex(itemId: string): number {
    return currentTabItemIndexMap.get(itemId) ?? -1;
  }

  // 检查当前焦点是否在指定项目上
  function isFocused(itemId: string): boolean {
    return getCurrentItem()?.id === itemId;
  }

