    quick: true, // 快捷
    guide: true, // 使用说明（默认显示）
    display: true, // 视听
    performance: true, // 性能
    monitor: true, // 监控
    library: true, // 游戏库
    trainers: false, // 修改器（默认关闭）
    gamepad: true, // 输入
    hotkey: true, // 热键
  });
  // 分页排序：记录分页开启的顺序，新开启的分页会添加到数组末尾
  // 快捷和设置不在此数组中，因为它们有固定位置
  let tabOrder: string[] = $state([
    "guide",
    "display",
    "performance",
    "monitor",
    "library",
    "gamepad",
    "hotkey",
  ]);
