  // 动态显示的 Tab 列表（根据 tabVisibility 过滤，并按 tabOrder 排序）
  let visibleTabs = $derived.by(() => {
    const result: typeof TABS_ALL = [];

    // 1. 快捷分页（如果启用）在最前
    if (tabVisibility.quick !== false) {
      const quickTab = TABS_ALL.find((t) => t.id === "quick");
      if (quickTab) result.push(quickTab);
    }

    // 2. 按照 tabOrder 的顺序添加可见的分页（排除 quick 和 settings，它们有固定位置）
    for (const tabId of tabOrder) {
      if (tabId === "quick" || tabId === "settings") continue;
      if (tabVisibility[tabId] !== false) {
        const tab = TABS_ALL.find((t) => t.id === tabId);
        if (tab) result.push(tab);
      }
    }

    // 3. 设置分页始终在最后
    const settingsTab = TABS_ALL.find((t) => t.id === "settings");
    if (settingsTab) result.push(settingsTab);

    return result;
  });
