  let isInSwapMode = $derived(swapSourceIndex !== null); // 是否处于交换模式

  // 当前 Tab 的可见项目（缓存派生值，只在依赖变化时重算）
  let currentTabItems = $derived.by(() => getTabItems(currentTabId));

  // 当前 Tab 项目索引表：id -> index（避免模板热路径里反复 findIndex）
  let currentTabItemIndexMap = $derived.by(() => {
    const map = new Map<string, number>();
    for (let i = 0; i < currentTabItems.length; i++) {
      map.set(currentTabItems[i].id, i);
    }
    return map;
  });

  // ====== 计算属性 ======
  // 最近游戏：只要玩过（有 lastPlayedAt）就显示，按时间倒序
  let recentGames = $derived.by(() => {
    return games
      .filter((g) => g.lastPlayedAt)
      .sort((a, b) => (b.lastPlayedAt || 0) - (a.lastPlayedAt || 0));
  });

  // 其他游戏：从未玩过的游戏
  let otherGames = $derived.by(() => {
    return games.filter((g) => !g.lastPlayedAt);
