  let displayGames = $derived([...recentGames, ...otherGames]);

  // ====== 辅助函数 ======

  // 格式化 TDP 值（处理 "unlimited" 的翻译）
  function formatTdpValue(value: number | string): string {
    if (value === "unlimited") {
      return t("unlimited");
    }
    return `${value}W`;
  }

  function getTabItemCount(tabId: string): number {
    // 当前 Tab 使用缓存派生值，避免在滚动/导航热路径里反复构建数组
    if (tabId === currentTabId) return currentTabItems.length;
    return getTabItems(tabId).length;
  }

  // 缓存封面 URL（convertFileSrc 开销较高，避免在模板热路径里重复计算）
  // 使用 LRU 策略限制缓存大小，防止内存泄漏
  const COVER_URL_CACHE_MAX_SIZE = 200;
  const coverUrlCache = new Map<string, string>();

  function getGameCoverUrl(game: Game): string | null {
    const coverPath = game.cover || gameCovers[game.id];
    if (!coverPath) return null;

    const cached = coverUrlCache.get(coverPath);
    if (cached !== undefined) {
      // LRU: 访问时移到末尾（最近使用）
      coverUrlCache.delete(coverPath);
      coverUrlCache.set(coverPath, cached);
      return cached;
    }

    // 使用 Tauri 的 convertFileSrc 转换本地路径
    const url = coverPath.match(/^[A-Z]:/i)
      ? convertFileSrc(coverPath)
      : coverPath;

    // 缓存满时删除最旧的条目（Map 迭代顺序是插入顺序）
    if (coverUrlCache.size >= COVER_URL_CACHE_MAX_SIZE) {
      const oldestKey = coverUrlCache.keys().next().value;
      if (oldestKey) coverUrlCache.delete(oldestKey);
    }

    coverUrlCache.set(coverPath, url);
    return url;
  }

  function formatLastPlayed(timestamp: number | undefined): string {
    if (!timestamp) return "";
    const now = Date.now();
    const diff = now - timestamp;
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 1) return t("just_now");
    if (minutes < 60) return t("minutes_ago").replace("{n}", String(minutes));
    if (hours < 24) return t("hours_ago").replace("{n}", String(hours));
    return t("days_ago").replace("{n}", String(days));
  }

  function getXboxButtonName(index: number): string {
    const buttonMap: Record<number, string> = {
      0: "A",
      1: "B",
      2: "X",
      3: "Y",
      4: "LB",
      5: "RB",
      6: "LT",
      7: "RT",
      8: "Back",
      9: "Start",
      10: "LS",
      11: "RS",
      12: "Up",
      13: "Down",
      14: "Left",
      15: "Right",
      16: "Guide",
    };
    return buttonMap[index] || `按钮${index}`;
  }

  // 将键盘 accelerator 转换为友好显示名称
  // GPD Win5 等设备的背键在固件层映射为 F13/F14/F15，显示时用友好名称
  function friendlyKeyLabel(accelerator: string): string {
    // 对整个 accelerator 字符串中的各个键名做替换
    const keyMap: Record<string, string> = {
      "F13": "GPD",
      "F14": "L4",
      "F15": "R4",
      "F16": "L5",
      "F17": "R5",
    };
    return accelerator
      .split("+")
      .map((k) => keyMap[k.trim()] || k.trim())
      .join("+");
  }

  function getSummonBindingLabel(): string {
    if (isListeningSummon) {
      if (tempBinding?.type === "gamepadButton") {
        const parts: string[] = [];
        if (tempBinding.buttons?.length) {
          parts.push(...tempBinding.buttons.map((b) => getXboxButtonName(b)));
        }
        if (tempBinding.custom_keys) {
          parts.push(customKeysToLabel(tempBinding.custom_keys));
        }
        if (parts.length > 0) return parts.join("+");
      }
      if (pressedKeys.length > 0) {
        return friendlyKeyLabel(pressedKeys.join("+"));
      }
      return t("hotkey_waiting");
    }
    if (summonBinding) {
      const lpTag = summonBinding.long_press ? ` [${t("long_press_tag")}]` : "";
      if (summonBinding.type === "gamepadButton") {
        const parts: string[] = [];
        if (summonBinding.buttons?.length) {
          parts.push(...summonBinding.buttons.map((b) => getXboxButtonName(b)));
        }
        if (summonBinding.custom_keys) {
          parts.push(customKeysToLabel(summonBinding.custom_keys));
        }
        if (parts.length > 0) return parts.join("+") + lpTag;
      }
      if (summonBinding.type === "keyboard" && summonBinding.accelerator) {
        return friendlyKeyLabel(summonBinding.accelerator) + lpTag;
      }
    }
    return "LT+RT";
  }

  function getSummonBinding2Label(): string {
    if (isListeningSummon2) {
      if (tempBinding?.type === "gamepadButton") {
        const parts: string[] = [];
        if (tempBinding.buttons?.length) {
          parts.push(...tempBinding.buttons.map((b) => getXboxButtonName(b)));
        }
        if (tempBinding.custom_keys) {
          parts.push(customKeysToLabel(tempBinding.custom_keys));
        }
        if (parts.length > 0) return parts.join("+");
      }
      if (pressedKeys.length > 0) {
        return friendlyKeyLabel(pressedKeys.join("+"));
      }
      return t("hotkey_waiting");
    }
    if (summonBinding2) {
      const lpTag = summonBinding2.long_press ? ` [${t("long_press_tag")}]` : "";
      if (summonBinding2.type === "gamepadButton") {
        const parts: string[] = [];
        if (summonBinding2.buttons?.length) {
          parts.push(
            ...summonBinding2.buttons.map((b) => getXboxButtonName(b)),
          );
        }
        if (summonBinding2.custom_keys) {
          parts.push(customKeysToLabel(summonBinding2.custom_keys));
        }
        if (parts.length > 0) return parts.join("+") + lpTag;
      }
      if (summonBinding2.type === "keyboard" && summonBinding2.accelerator) {
        return friendlyKeyLabel(summonBinding2.accelerator) + lpTag;
      }
    }
    return t("not_set");
  }

  function getHotkeyBindingLabel(type: string): string {
    const bindingMap: Record<string, SummonBinding | null> = {
      osd_toggle: osdToggleBinding,
      tdp_up: tdpUpBinding,
      tdp_down: tdpDownBinding,
      show_desktop: showDesktopBinding,
      desktop_mode: desktopModeBinding,
      mouse_sim_toggle: mouseSimToggleBinding,
      screenshot: screenshotBinding,
      record_toggle: recordToggleBinding,
      bigscreen_mode: bigscreenModeBinding,
      steam_bigpicture: steamBigpictureBinding,
      hibernate: hibernateBinding,
      sleep: sleepBinding,
      shutdown: shutdownBinding,
      task_manager: taskManagerBinding,
      gyro_toggle: gyroToggleBinding,
      gyro_hold: gyroHoldBinding,
      gyro_hold_2: gyroHoldBinding2,
      gyro_hold_3: gyroHoldBinding3,
      alt_tab: altTabBinding,
    };
    const binding = bindingMap[type] || null;
    const longPressTag = binding?.long_press ? ` [${t("long_press_tag")}]` : "";

    if (listeningHotkeyType === type) {
      if (tempBinding?.type === "gamepadButton") {
        const parts: string[] = [];
        if (tempBinding.buttons?.length) {
          parts.push(...tempBinding.buttons.map((b) => getXboxButtonName(b)));
        }
        if (tempBinding.custom_keys) {
          parts.push(customKeysToLabel(tempBinding.custom_keys));
        }
        if (parts.length > 0) return parts.join("+");
      }
      if (pressedKeys.length > 0) {
        return friendlyKeyLabel(pressedKeys.join("+"));
      }
      return t("hotkey_waiting");
    }
    if (binding) {
      if (binding.type === "gamepadButton") {
        const parts: string[] = [];
        if (binding.buttons?.length) {
          parts.push(...binding.buttons.map((b) => getXboxButtonName(b)));
        }
        if (binding.custom_keys) {
          parts.push(customKeysToLabel(binding.custom_keys));
        }
        if (parts.length > 0) return parts.join("+") + longPressTag;
      }
      if (binding.type === "keyboard" && binding.accelerator) {
        return friendlyKeyLabel(binding.accelerator) + longPressTag;
      }
    }
    return t("not_set");
  }

  function startHotkeyListening(type: string) {
    listeningHotkeyType = type;
    triggerKey = "a";
    triggerButtonIndex = 0;
    tempBinding = null;
    pressedKeys = [];
    heldKeys.clear();
    gamepadButtons.clear();

    // 聚焦窗口以确保能捕获所有按键
    invoke("focus_panel_window").catch((e) => console.warn("focus_panel_window failed:", e));

    listeningCountdown = 5;
  }

  async function confirmHotkeyBinding() {
    if (!listeningHotkeyType) return;

    const type = listeningHotkeyType;
    let finalBinding: SummonBinding | null = null;

    // HID 特殊按键优先级最高：如果检测到了 HID 按键（tempBinding 为 gamepadButton 且有 custom_keys），
    // 直接使用它，忽略同时捕获的键盘键（那些是 HID 映射后的，如 M1→F13）
    if (tempBinding?.type === "gamepadButton" && tempBinding.custom_keys) {
      finalBinding = tempBinding;
    } else if (gamepadButtons.size > 0) {
      const buttons = Array.from(gamepadButtons).sort((a, b) => a - b);
      finalBinding = {
        type: "gamepadButton",
        buttons,
        ...(tempBinding?.custom_keys ? { custom_keys: tempBinding.custom_keys } : {}),
      };
    } else if (tempBinding) {
      finalBinding = tempBinding;
    } else if (pressedKeys.length > 0) {
      finalBinding = { type: "keyboard", accelerator: pressedKeys.join("+") };
    }

    // 保留旧绑定的 long_press 设置（重新绑定按键不应丢失长按模式）
    if (finalBinding) {
      const oldBinding = getHotkeyBinding(type);
      if (oldBinding?.long_press) {
        finalBinding.long_press = true;
      }
    }

    // 更新本地状态
    if (type === "osd_toggle") osdToggleBinding = finalBinding;
    else if (type === "tdp_up") tdpUpBinding = finalBinding;
    else if (type === "tdp_down") tdpDownBinding = finalBinding;
    else if (type === "show_desktop") showDesktopBinding = finalBinding;
    else if (type === "desktop_mode") desktopModeBinding = finalBinding;
    else if (type === "mouse_sim_toggle") mouseSimToggleBinding = finalBinding;
    else if (type === "screenshot") screenshotBinding = finalBinding;
    else if (type === "record_toggle") recordToggleBinding = finalBinding;
    else if (type === "bigscreen_mode") bigscreenModeBinding = finalBinding;
    else if (type === "steam_bigpicture") steamBigpictureBinding = finalBinding;
    else if (type === "hibernate") hibernateBinding = finalBinding;
    else if (type === "sleep") sleepBinding = finalBinding;
    else if (type === "shutdown") shutdownBinding = finalBinding;
    else if (type === "task_manager") taskManagerBinding = finalBinding;
    else if (type === "gyro_toggle") gyroToggleBinding = finalBinding;
    else if (type === "gyro_hold") gyroHoldBinding = finalBinding;
    else if (type === "gyro_hold_2") gyroHoldBinding2 = finalBinding;
    else if (type === "gyro_hold_3") gyroHoldBinding3 = finalBinding;
    else if (type === "alt_tab") altTabBinding = finalBinding;

    // 先重置 UI 状态，防止后续 invoke 卡住导致面板不消失
    listeningHotkeyType = null;
    listeningCountdown = 0;
    tempBinding = null;
    pressedKeys = [];
    heldKeys.clear();
    gamepadButtons.clear();

    // 保存到后端
    if (finalBinding) {
      try {
        await invoke("set_hotkey_binding", {
          action: type,
          binding: finalBinding,
        });
      } catch (e) {
        console.error("保存快捷键失败:", e);
      }
    } else {
      // 没有输入任何内容，清除绑定
      try {
        await invoke("set_hotkey_binding", {
          action: type,
          binding: { type: "none" },
        });
      } catch (e) {
        console.error("清除快捷键失败:", e);
      }
    }
  }

  async function clearHotkeyBinding(type: string) {
    if (type === "summon") {
      summonBinding = null;
      try {
        await invoke("set_summon_binding", { binding: { type: "none" } });
        showToast(t("toast_hotkey_cleared"), "success");
      } catch (e) {
        console.error("清除呼出键失败:", e);
      }
      return;
    }
    if (type === "summon2") {
      summonBinding2 = null;
      try {
        await invoke("set_summon_binding_2", { binding: { type: "none" } });
        showToast(t("toast_hotkey_cleared"), "success");
      } catch (e) {
        console.error("清除呼出键2失败:", e);
      }
      return;
    }

    if (type === "osd_toggle") osdToggleBinding = null;
    else if (type === "tdp_up") tdpUpBinding = null;
    else if (type === "tdp_down") tdpDownBinding = null;
    else if (type === "show_desktop") showDesktopBinding = null;
    else if (type === "desktop_mode") desktopModeBinding = null;
    else if (type === "mouse_sim_toggle") mouseSimToggleBinding = null;
    else if (type === "screenshot") screenshotBinding = null;
    else if (type === "record_toggle") recordToggleBinding = null;
    else if (type === "bigscreen_mode") bigscreenModeBinding = null;
    else if (type === "steam_bigpicture") steamBigpictureBinding = null;
    else if (type === "hibernate") hibernateBinding = null;
    else if (type === "sleep") sleepBinding = null;
    else if (type === "shutdown") shutdownBinding = null;
    else if (type === "task_manager") taskManagerBinding = null;
    else if (type === "gyro_toggle") gyroToggleBinding = null;
    else if (type === "gyro_hold") gyroHoldBinding = null;
    else if (type === "gyro_hold_2") gyroHoldBinding2 = null;
    else if (type === "gyro_hold_3") gyroHoldBinding3 = null;
    else if (type === "alt_tab") altTabBinding = null;

    try {
      // 使用特殊的 binding_type="none" 表示解绑，避免 null 值无法正确保存
      await invoke("set_hotkey_binding", {
        action: type,
        binding: { type: "none" },
      });
      showToast(t("toast_hotkey_cleared"), "success");
    } catch (e) {
      console.error("清除快捷键失败:", e);
    }
  }

  function startHotkeyHold(type: string) {
    // 如果已有绑定才能长按清除
    const bindingMap: Record<string, SummonBinding | null> = {
      osd_toggle: osdToggleBinding,
      tdp_up: tdpUpBinding,
      tdp_down: tdpDownBinding,
      show_desktop: showDesktopBinding,
      desktop_mode: desktopModeBinding,
      mouse_sim_toggle: mouseSimToggleBinding,
      screenshot: screenshotBinding,
      record_toggle: recordToggleBinding,
      bigscreen_mode: bigscreenModeBinding,
      steam_bigpicture: steamBigpictureBinding,
      hibernate: hibernateBinding,
      sleep: sleepBinding,
      shutdown: shutdownBinding,
      task_manager: taskManagerBinding,
      gyro_toggle: gyroToggleBinding,
      gyro_hold: gyroHoldBinding,
      gyro_hold_2: gyroHoldBinding2,
      gyro_hold_3: gyroHoldBinding3,
      alt_tab: altTabBinding,
    };
    const binding = bindingMap[type] || null;
    if (!binding) return;

    hotkeyHoldType = type;
    hotkeyHoldProgress = 0;

    const startTime = Date.now();
    const updateProgress = () => {
      const elapsed = Date.now() - startTime;
      hotkeyHoldProgress = Math.min(elapsed / HOTKEY_HOLD_DURATION, 1);

      if (elapsed >= HOTKEY_HOLD_DURATION) {
        // 长按完成，清除绑定
        clearHotkeyBinding(type);
        cancelHotkeyHold();
      } else if (hotkeyHoldType === type) {
        hotkeyHoldTimer = setTimeout(updateProgress, 50);
      }
    };
    hotkeyHoldTimer = setTimeout(updateProgress, 50);
  }

  function cancelHotkeyHold() {
    if (hotkeyHoldTimer) {
      clearTimeout(hotkeyHoldTimer);
      hotkeyHoldTimer = null;
    }
    hotkeyHoldType = null;
    hotkeyHoldProgress = 0;
  }

  // 获取当前聚焦的快捷键类型（用于 X 键长按清除）
  function getFocusedHotkeyType(): string | null {
    const hotkeyMap: Record<string, string> = {
      summon_binding: "summon",
      summon_binding_2: "summon2",
      osd_toggle_hotkey: "osd_toggle",
      tdp_up_hotkey: "tdp_up",
      tdp_down_hotkey: "tdp_down",
      show_desktop_hotkey: "show_desktop",
      desktop_mode_hotkey: "desktop_mode",
      bigscreen_mode_hotkey: "bigscreen_mode",
      steam_bigpicture_hotkey: "steam_bigpicture",
      hotkey_hibernate: "hibernate",
      hotkey_sleep: "sleep",
      hotkey_shutdown: "shutdown",
      hotkey_task_manager: "task_manager",
      mouse_sim_toggle_hotkey: "mouse_sim_toggle",
      screenshot_hotkey: "screenshot",
      record_toggle_hotkey: "record_toggle",
      gyro_toggle_hotkey: "gyro_toggle",
      gyro_hold_hotkey: "gyro_hold",
      gyro_hold_2_hotkey: "gyro_hold_2",
      gyro_hold_3_hotkey: "gyro_hold_3",
      alt_tab_hotkey: "alt_tab",
    };
    const item = getCurrentItem();
    if (item && hotkeyMap[item.id]) {
      return hotkeyMap[item.id];
    }
    return null;
  }

  // 获取快捷键绑定（用于检查是否有绑定可清除）
  function getHotkeyBinding(type: string): SummonBinding | null {
    const bindingMap: Record<string, SummonBinding | null> = {
      summon: summonBinding,
      summon2: summonBinding2,
      osd_toggle: osdToggleBinding,
      tdp_up: tdpUpBinding,
      tdp_down: tdpDownBinding,
      show_desktop: showDesktopBinding,
      desktop_mode: desktopModeBinding,
      bigscreen_mode: bigscreenModeBinding,
      steam_bigpicture: steamBigpictureBinding,
      hibernate: hibernateBinding,
      sleep: sleepBinding,
      shutdown: shutdownBinding,
      task_manager: taskManagerBinding,
      mouse_sim_toggle: mouseSimToggleBinding,
      screenshot: screenshotBinding,
      record_toggle: recordToggleBinding,
      gyro_toggle: gyroToggleBinding,
      gyro_hold: gyroHoldBinding,
      gyro_hold_2: gyroHoldBinding2,
      gyro_hold_3: gyroHoldBinding3,
      alt_tab: altTabBinding,
    };
    return bindingMap[type] || null;
  }

  // 切换热键的长按模式（Y 键短按触发）
  async function toggleHotkeyLongPress(hotkeyType: string) {
    const binding = getHotkeyBinding(hotkeyType);
    if (!binding || binding.type === "none") return; // 没有绑定时不操作

    const newLongPress = !binding.long_press;
    binding.long_press = newLongPress;

    // 更新本地状态引用（binding 是引用，直接修改即可）
    // 保存到后端（重新发送完整绑定）
    try {
      if (hotkeyType === "summon") {
        await invoke("set_summon_binding", { binding });
      } else if (hotkeyType === "summon2") {
        await invoke("set_summon_binding_2", { binding });
      } else {
        await invoke("set_hotkey_binding", { action: hotkeyType, binding });
      }
      playSound("click", soundEnabled);
      showToast(
        newLongPress ? t("hotkey_long_press_on") : t("hotkey_long_press_off"),
        "info",
      );
    } catch (e) {
      console.error("切换长按模式失败:", e);
    }
  }

  function handleHotkeyClick(type: string) {
    // 如果正在长按，取消
    if (hotkeyHoldType === type) {
      cancelHotkeyHold();
      return;
    }
    // 如果已经是当前监听的热键，不做任何处理（点击确认由其他逻辑处理）
    if (listeningHotkeyType === type) {
      return;
    }
    // 如果有其他热键正在监听，先取消
    if (listeningHotkeyType !== null) {
      listeningHotkeyType = null;
      listeningCountdown = 0;
      tempBinding = null;
      pressedKeys = [];
      heldKeys.clear();
      gamepadButtons.clear();
    }
    // 如果呼出键正在监听，也取消
    if (isListeningSummon) {
      isListeningSummon = false;
      listeningCountdown = 0;
      tempBinding = null;
      pressedKeys = [];
      heldKeys.clear();
      maxKeys.clear();
      gamepadButtons.clear();
    }
    // 开始监听新的热键
    startHotkeyListening(type);
  }

  // ====== 快捷分页功能 ======
