        float_gpu_toggle: "float_gpu",
        auto_fan_toggle: "auto_fan",
        auto_fan_temp_min: "auto_fan_temp_min",
        auto_fan_temp_max: "auto_fan_temp_max",
        epp: "epp",
        cpu_freq_toggle: "cpu_freq",
        cpu_freq: "cpu_max_freq",
        prefer_perf_cores: "prefer_perf_cores",
        core_scheduling: "core_scheduling",
        intel_gpu_power: "cpu_gpu_power_share",
