      },
      monitor: {
        rtss_toggle: "osd_toggle",
        rtss_fps_limit_toggle: "fps_limit",
        rtss_fps_limit_value: "fps_limit_value",
        osd_font_size: "osd_font_size",
      },
      gamepad: {
        vibration: "vibration",
        disable_builtin: "disable_builtin",
