        font_size: "font_size",
        gesture_toggle: "gesture_toggle",
        sound_toggle: "sound_toggle",
        autostart: "autostart",
        tablet_mode: "tablet_mode",
        optical_mouse: "optical_mouse",
        touchscreen_toggle: "touchscreen",
        wifi_toggle: "wifi",
        bluetooth_toggle: "bluetooth",
        hotspot_toggle: "hotspot",
        no_focus_mode: "window_behavior",
        blur_hide_toggle: "window_behavior",
        focus_return_toggle: "window_behavior",
        fullscreen_mode: "fullscreen_mode",
