      },
    };
    // 检查静态标签
    if (labelKeys[tabId]?.[itemId]) {
      return t(labelKeys[tabId][itemId] as TranslationKey);
    }
    // 动态处理系统快捷键标签
    if (tabId === "gamepad" && itemId.startsWith("shortcut_")) {
      const idx = parseInt(itemId.split("_")[1]);
      if (!isNaN(idx) && idx >= 0 && idx < SHORTCUTS.length) {
        return t(SHORTCUTS[idx].label as TranslationKey);
      }
    }
    // 游戏库项目标签（通过稳定 game ID 查找）
    if (tabId === "library" && itemId.startsWith("game_id:")) {
      const gameId = itemId.slice(8);
      const game = games.find((g) => g.id === gameId);
      if (game) return game.name;
    }
    return itemId;
  }

  // 检查项目是否可以添加到快捷分页（允许 slider/stepper/toggle 和特定的 action）
  // 允许添加的 action 类型项目白名单
  const ALLOWED_QUICK_ACTIONS: Record<string, string[]> = {
    display: ["kill_top_process", "suspend_top_process"], // 一键关闭/冻结游戏（其他 display toggle/slider 默认允许）
    gamepad: ["desktop_mode", "bigscreen_mode"], // 桌面模式、大屏幕模式
    settings: ["fan_curve_save", "fan_curve_reset"], // 风扇曲线保存和重置
  };

  // 视听页进程列表起始索引：等于静态项目数量
  const DISPLAY_PROCESS_BASE_INDEX = TAB_ITEMS_STATIC.display.length;

  function canAddToQuick(
    itemType: string,
    tabId?: string,
    itemId?: string,
  ): boolean {
    // display 类型（性能监控）可以添加到快捷页
    if (itemType === "display") {
      return true;
    }
    if (["slider", "stepper", "toggle"].includes(itemType)) {
      return true;
    }
    // 检查是否为允许的 action 类型
    if (itemType === "action" && tabId && itemId) {
      // 检查静态白名单
      if (ALLOWED_QUICK_ACTIONS[tabId]?.includes(itemId)) {
        return true;
      }
      // 允许所有系统快捷键 (shortcut_0, shortcut_1, ...)
      if (tabId === "gamepad" && itemId.startsWith("shortcut_")) {
        const idx = parseInt(itemId.split("_")[1]);
        return !isNaN(idx) && idx >= 0 && idx < SHORTCUTS.length;
      }
      // 允许游戏库中的游戏（不包括导入/清空等操作按钮）
      if (tabId === "library" && itemId.startsWith("game_")) {
        const idx = parseInt(itemId.split("_")[1]);
        return !isNaN(idx) && idx >= 0 && idx < games.length;
      }
    }
    return false;
  }

  // 检查项目是否已在快捷分页中
  function isInQuickItems(tabId: string, itemId: string): boolean {
    return quickItems.some(
      (item) => item.tab_id === tabId && item.item_id === itemId,
    );
  }

  // 添加项目到快捷分页
  async function addToQuickItems(
    tabId: string,
    itemId: string,
    itemType: string,
  ) {
    if (isInQuickItems(tabId, itemId)) {
      showToast(t("toast_item_already_in_quick"), "warning");
      return;
    }

    const label = getItemLabel(tabId, itemId);
    const newItem: QuickItem = {
      tab_id: tabId,
      item_id: itemId,
      item_type: itemType,
      label: label,
    };

    quickItems = [...quickItems, newItem];

    // 保存到后端
    try {
      await invoke("save_settings", { settings: { quick_items: quickItems } });
      showToast(
        t("toast_added_to_quick").replace("{label}", label),
        "success",
      );
      playSound("success", soundEnabled);
    } catch (e) {
      console.error("保存快捷项失败:", e);
      showToast(t("toast_save_failed"), "error");
    }
  }

  // 从快捷分页移除项目
  async function removeFromQuickItems(index: number) {
    if (index < 0 || index >= quickItems.length) return;

    const removed = quickItems[index];
    quickItems = quickItems.filter((_, i) => i !== index);

    // 保存到后端
    try {
      await invoke("save_settings", { settings: { quick_items: quickItems } });
      showToast(
        t("toast_removed_from_quick").replace("{label}", removed.label),
        "success",
      );
    } catch (e) {
      console.error("保存快捷项失败:", e);
    }

    // 调整焦点
    if (focusIndex >= quickItems.length) {
      focusIndex = Math.max(0, quickItems.length - 1);
    }
  }

  // 退出交换模式
  function exitSwapMode() {
    if (swapSourceIndex !== null) {
      swapSourceIndex = null;
    }
  }

  // 交换快捷分页中两个选项的位置
  async function swapQuickItems(indexA: number, indexB: number) {
    if (indexA === indexB) return;
    if (indexA < 0 || indexA >= quickItems.length) return;
    if (indexB < 0 || indexB >= quickItems.length) return;

    // 交换位置
    const newItems = [...quickItems];
    [newItems[indexA], newItems[indexB]] = [newItems[indexB], newItems[indexA]];
    quickItems = newItems;

    // 保存到后端
    try {
      await invoke("save_settings", { settings: { quick_items: quickItems } });
      showToast(t("toast_swapped"), "success");
      playSound("success", soundEnabled);
    } catch (e) {
      console.error("保存快捷项失败:", e);
      showToast(t("toast_save_failed"), "error");
    }
  }

  // 处理快捷分页中的Y键交换操作
  function handleQuickItemSwap() {
    if (quickItems.length < 2) {
      showToast(t("toast_need_two_items"), "warning");
      return;
    }

    if (swapSourceIndex === null) {
      // 进入交换模式：记录源选项索引
      swapSourceIndex = focusIndex;
      showToast(t("toast_select_target"), "info");
    } else {
      // 已在交换模式：执行交换
      if (swapSourceIndex === focusIndex) {
        // 选中同一项，取消交换
        exitSwapMode();
        showToast(t("toast_swap_cancelled"), "info");
      } else {
        // 执行交换
        swapQuickItems(swapSourceIndex, focusIndex);
        exitSwapMode();
      }
    }
  }

  // 处理长按 Y 键添加到快捷分页
  function handleYButtonHold() {
    // 只在非快捷分页中生效
    if (currentTabId === "quick") return;

    const item = getCurrentItem();
    if (!item) return;

    // 只允许特定类型的项目
    if (!canAddToQuick(item.type, currentTabId, item.id)) {
      showToast(t("toast_cannot_add_to_quick"), "warning");
      return;
    }

    // 游戏库项目：使用稳定的游戏 ID 而非索引（displayGames 顺序会变化）
    let stableItemId = item.id;
    if (currentTabId === "library" && item.id.startsWith("game_")) {
      const idx = parseInt(item.id.split("_")[1]);
      if (!isNaN(idx) && idx >= 0 && idx < displayGames.length) {
        stableItemId = `game_id:${displayGames[idx].id}`;
      }
    }

    // 检查是否已存在
    if (isInQuickItems(currentTabId, stableItemId)) {
      showToast(t("toast_item_already_in_quick"), "warning");
      return;
    }

    addToQuickItems(currentTabId, stableItemId, item.type);
  }

  // 判断 stepper 是否为横向列表类型（而非箭头选择器）
  function isHorizontalListStepper(itemId: string): boolean {
    const horizontalListSteppers = [
      "tdp_preset",
      "fan_mode",
      "theme_select",
      "fan_curve_mode",
    ];
    return horizontalListSteppers.includes(itemId);
  }

  // 获取横向列表 stepper 的选项
  function getStepperOptions(
    itemId: string,
  ): { label: string; value: number | string }[] {
    const optionsMap: Record<
      string,
      () => { label: string; value: number | string }[]
    > = {
      tdp_preset: () =>
        tdpPresetLevels.map((level, i) => ({
          label: typeof level === "number" ? `${level}W` : t("unlimited"),
          value: i,
        })),
      fan_mode: () =>
        FAN_MODES.map((mode, i) => ({ label: t(mode as TranslationKey), value: i })),
      theme_select: () =>
        COLOR_THEMES.map((t) => ({ label: t.name, value: t.id })),
      fan_curve_mode: () => [
        { label: t("fan_curve_follow_tdp"), value: "tdp" },
        { label: t("fan_curve_fixed"), value: "fixed" },
      ],
    };
    return optionsMap[itemId]?.() || [];
  }

