  // 当分辨率改变时，更新可用刷新率列表
  async function updateRefreshRatesForResolution() {
    if (availableResolutions.length === 0) return;
    const res = availableResolutions[resolutionIndex];
    if (!res) return;
    try {
      const rates = await invoke<number[]>("get_available_refresh_rates", {
        width: res.width,
        height: res.height,
      });
      availableRefreshRates = rates;
      // 如果当前选择的刷新率不在新列表中，选择第一个
      if (!rates.includes(refreshRateOptions[refreshRateIndex])) {
        refreshRateIndex = 0;
      }
    } catch (e) {
      console.error("获取刷新率失败:", e);
    }
  }

  async function applyDisplaySettings() {
    if (availableResolutions.length === 0 || availableRefreshRates.length === 0)
      return;
    const res = availableResolutions[resolutionIndex];
    const rate = availableRefreshRates[refreshRateIndex];
    if (!res || !rate) return;

    try {
      const result = await invoke<{
        success: boolean;
        message?: string;
        error?: string;
      }>("set_display", {
        width: res.width,
        height: res.height,
        rate,
      });

      if (!result || result.success === false) {
        const msg =
          result?.error || result?.message || t("toast_set_failed");
        console.error("应用显示设置失败:", msg);
        showToast(msg, "error", 6000);
        return;
      }

      appliedSettings.resolutionIndex = resolutionIndex;
      appliedSettings.refreshRateIndex = refreshRateIndex;
      // 持久化分辨率和刷新率设置
      await invoke("save_settings", {
        settings: {
          display_resolution_width: res.width,
          display_resolution_height: res.height,
          display_refresh_rate: rate,
        },
      });
      // 刷新显示信息（使用 safeTimeout 确保组件卸载时清理）
      safeTimeout(loadDisplayInfo, 1000);
    } catch (e) {
      console.error("应用显示设置失败:", e);
      showToast(t("toast_set_failed"), "error", 6000);
    }
  }

  // 进程暂停功能
  async function loadWindowProcesses() {
    processListLoading = true;
    try {
      const processes = await invoke<WindowProcess[]>("get_window_processes");
      windowProcesses = processes;
      // 焦点边界修正：如果在 display 页面且焦点在进程区域，确保不越界
      // 进程列表从 DISPLAY_PROCESS_BASE_INDEX (TAB_ITEMS_STATIC.display.length) 开始追加
      if (currentTabId === "display") {
        const processStartIndex = DISPLAY_PROCESS_BASE_INDEX;
        const maxValidIndex = processStartIndex + processes.length - 1;
        if (focusIndex >= processStartIndex && focusIndex > maxValidIndex) {
          // 焦点越界，钳制到最后一个有效项
          focusIndex = Math.max(
            0,
            maxValidIndex >= processStartIndex
              ? maxValidIndex
              : processStartIndex - 1,
          );
        }
      }
    } catch (e) {
      console.error("获取进程列表失败:", e);
      windowProcesses = [];
      // 出错时如果在 display 页且焦点在进程区域，回到一键冻结项
      if (
        currentTabId === "display" &&
        focusIndex >= DISPLAY_PROCESS_BASE_INDEX
      ) {
        focusIndex = DISPLAY_PROCESS_BASE_INDEX - 1;
      }
    } finally {
      processListLoading = false;
    }
  }

