  // 一键冻结/恢复内存占用最高的活跃图形化应用
  let suspendingTopProcess = $state(false);
  let topProcessSuspended = $state(false);
  async function suspendTopMemoryProcess() {
    suspendingTopProcess = true;
    try {
      const result = await invoke<{
        success: boolean;
        message?: string;
        error?: string;
        suspended?: boolean;
        process_name?: string;
      }>("suspend_top_memory_process");
      if (result.success) {
        topProcessSuspended = result.suspended ?? false;
        const name = result.process_name ?? "";
        if (result.suspended) {
          showToast(
            t("toast_process_suspended").replace("{name}", name),
            "success",
          );
        } else {
          showToast(
            t("toast_process_resumed").replace("{name}", name),
            "success",
          );
        }
        console.log("进程状态:", result.message);
      } else {
        console.error("操作失败:", result.error);
        showToast(result.error ?? t("no_game_process"), "error");
      }
      // 刷新进程列表
      await loadWindowProcesses();
    } catch (e) {
      console.error("一键冻结失败:", e);
    } finally {
      suspendingTopProcess = false;
    }
  }

  // ====== ADLX 管理函数
  async function checkAdlxAvailable() {
    try {
      const status = await invoke<AdlxStatus>("adlx_check_available");
      adlxAvailable = status.available;
      adlxMessage = status.message;
      console.log("ADLX 状态:", status);
      if (status.available) {
        // 只有在真正有 AMD GPU 时才加载设置
        await loadAdlxSettings();
      }
    } catch (e) {
      console.error("检查 ADLX 可用性失败:", e);
      adlxAvailable = false;
      adlxMessage = t("adlx_check_failed");
    }
  }

  async function retryAdlx() {
    if (adlxRetrying) return;
    adlxRetrying = true;
    try {
      const status = await invoke<AdlxStatus>("adlx_retry_initialize");
      adlxAvailable = status.available;
      adlxMessage = status.message;
      if (status.available) {
        showToast("ADLX 初始化成功", "success");
        await loadAdlxSettings();
      } else {
        showToast(status.message || "ADLX 初始化失败", "error");
      }
    } catch (e) {
      console.error("ADLX 重试失败:", e);
      showToast("ADLX 重试失败", "error");
    } finally {
      adlxRetrying = false;
    }
  }

  async function loadAdlxSettings() {
    if (!adlxAvailable || adlxLoading) return;
    adlxLoading = true;
    try {
      // 并行加载所有 ADLX 设置
      const [
        rsrResult,
        displayResult,
        antiLagResult,
        chillResult,
        boostResult,
        fpsLimitResult,
        risResult,
        afmfResult,
      ] = await Promise.allSettled([
        invoke<RsrSettings>("adlx_get_rsr_settings"),
        invoke<DisplaySettings>("adlx_get_display_settings"),
        invoke<boolean>("adlx_get_antilag", { gpuIndex: 0 }),
        invoke<[boolean, number, number]>("adlx_get_chill", { gpuIndex: 0 }),
        invoke<[boolean, number]>("adlx_get_boost", { gpuIndex: 0 }),
        invoke<[boolean, number]>("adlx_get_fps_limit", { gpuIndex: 0 }),
        invoke<[boolean, boolean, number]>("adlx_get_image_sharpening", {
          gpuIndex: 0,
        }),
        invoke<[boolean, boolean]>("adlx_get_afmf"),
      ]);

      // 应用 RSR 设置
      if (rsrResult.status === "fulfilled") {
        const rsrSettings = rsrResult.value;
        console.log("RSR 设置:", rsrSettings);
        rsrEnabled = rsrSettings.enabled;
        rsrSharpness = rsrSettings.sharpness;
      }

      // 应用显示设置
      if (displayResult.status === "fulfilled") {
        console.log("显示设置:", displayResult.value);
        adlxDisplaySettings = displayResult.value;
      }

      // 应用 3D 设置
      if (antiLagResult.status === "fulfilled")
        antiLagEnabled = antiLagResult.value;
      if (chillResult.status === "fulfilled") {
        const [chillOn, chillMin, chillMax] = chillResult.value;
        chillEnabled = chillOn;
        chillMinFps = chillMin;
        chillMaxFps = chillMax;
      }
      if (boostResult.status === "fulfilled") {
        const [boostOn, boostRes] = boostResult.value;
        boostEnabled = boostOn;
        boostResolution = boostRes;
      }
      if (fpsLimitResult.status === "fulfilled") {
        const [limitOn, limitFps] = fpsLimitResult.value;
        fpsLimitEnabled = limitOn;
        // 驱动里可能有非常规值（比如 25），这里保留原始值
        if (typeof limitFps === "number" && limitFps > 0) {
          fpsLimitValue = limitFps;
        }
      }
      if (risResult.status === "fulfilled") {
        const [risSupported, risOn, risLevel] = risResult.value;
        imageSharpeningSupported = risSupported;
        imageSharpeningEnabled = risOn;
        imageSharpeningLevel = risLevel;
      }
      if (afmfResult.status === "fulfilled") {
        const [afmfSup, afmfOn] = afmfResult.value;
        afmfSupported = afmfSup;
        afmfEnabled = afmfOn;
      }

      // 加载颜色设置（使用 -1 让后端自动查找支持颜色设置的显示器）
      try {
        const colorResult = await invoke<typeof customColorSettings>(
          "adlx_get_custom_color_settings",
          { displayIndex: -1 },
        );
        customColorSettings = colorResult;
        console.log("颜色设置:", colorResult);
      } catch (e) {
        console.error("加载颜色设置失败:", e);
      }

      console.log(
        "3D 设置: AntiLag=",
        antiLagEnabled,
        "Chill=",
        chillEnabled,
        chillMinFps,
        "-",
        chillMaxFps,
        "Boost=",
        boostEnabled,
        boostResolution,
        "RIS=",
        imageSharpeningEnabled,
        "AFMF=",
        afmfEnabled,
      );
    } catch (e) {
      console.error("加载 ADLX 设置失败:", e);
    } finally {
      adlxLoading = false;
    }
  }

  async function toggleRsr() {
    if (!adlxAvailable || adlxLoading) return;

    const newState = !rsrEnabled;
    adlxLoading = true;

    try {
      // RSR 需要先启用 GPU 缩放
      if (newState && !adlxDisplaySettings.gpu_scaling_enabled) {
        const gpuScaleResult = await invoke<AdlxResult>(
          "adlx_set_gpu_scaling",
          { display: 1, enabled: true },
        );
        if (gpuScaleResult.success) {
          adlxDisplaySettings.gpu_scaling_enabled = true;
          console.log("已自动启用 GPU 缩放（RSR 依赖）");
        } else {
          console.error("启用 GPU 缩放失败:", gpuScaleResult.error);
        }
      }

      const result = await invoke<AdlxResult>("adlx_set_rsr", {
        enabled: newState,
      });
      if (result.success) {
        rsrEnabled = newState;
      } else {
        console.error("RSR 设置失败:", result.error);
        if (newState) {
          alert(t("alert_rsr_failed"));
        }
      }
    } catch (e) {
      console.error("RSR 设置失败:", e);
      if (newState) {
        alert(t("alert_rsr_failed"));
      }
    } finally {
      adlxLoading = false;
    }
  }

