  async function toggleAntiLag() {
    if (!adlxAvailable || adlxLoading) return;
    adlxLoading = true;
    try {
      const newState = !antiLagEnabled;
      const result = await invoke<AdlxResult>("adlx_set_antilag", {
        gpuIndex: 0,
        enabled: newState,
      });
      if (result.success) {
        antiLagEnabled = newState;
      } else if (newState) {
        alert(t("alert_antilag_failed"));
      }
    } catch (e) {
      console.error("Anti-Lag 设置失败:", e);
    } finally {
      adlxLoading = false;
    }
  }

