  /** 重置显示颜色设置为默认值 */
  async function resetCustomColorSettings() {
    if (!adlxAvailable) return;
    try {
      // 色调、饱和度、亮度、对比度设为中间值
      if (customColorSettings.hue_supported) {
        const defaultHue = Math.round(
          (customColorSettings.hue_min + customColorSettings.hue_max) / 2,
        );
        await setCustomColorHue(defaultHue);
      }
      if (customColorSettings.saturation_supported) {
        const defaultSat = Math.round(
          (customColorSettings.saturation_min +
            customColorSettings.saturation_max) /
            2,
        );
        await setCustomColorSaturation(defaultSat);
      }
      if (customColorSettings.brightness_supported) {
        const defaultBright = Math.round(
          (customColorSettings.brightness_min +
            customColorSettings.brightness_max) /
            2,
        );
        await setCustomColorBrightness(defaultBright);
      }
      if (customColorSettings.contrast_supported) {
        const defaultContrast = Math.round(
          (customColorSettings.contrast_min +
            customColorSettings.contrast_max) /
            2,
        );
        await setCustomColorContrast(defaultContrast);
      }
      // 色温默认为 6500K（标准白色）
      if (customColorSettings.temperature_supported) {
        const defaultTemp = 6500;
        // 确保在范围内
        const clampedTemp = Math.max(
          customColorSettings.temperature_min,
          Math.min(customColorSettings.temperature_max, defaultTemp),
        );
        await setCustomColorTemperature(clampedTemp);
      }
      showToast(t("toast_color_reset_success"), "success");
    } catch (e) {
      console.error("重置颜色设置失败:", e);
      showToast(t("toast_color_reset_failed"), "error");
    }
  }

  // ====== RTSS 功能 ======
  // 参考 MotionAssistant：面板启动时就启动 RTSS 和 LHM，开关只控制 OSD 显示
  let rtssOsdEnabled = $state(false); // OSD 是否启用（与进程无关）
  let rtssToggleCooldown = $state(false); // 开关冷却中（防止快速切换）
  let osdTypeSwitching = $state(false); // OSD 类型切换中（防止快速切换导致卡死）
  let osdScale = $state(100); // OSD 缩放比例 (100 = 正常, 200 = 2倍)
  let osdCompactMode = $state(false); // OSD 精简模式（兼容旧设置）
  let rtssOsdMode = $state<"minimal" | "compact" | "detailed">("detailed"); // RTSS OSD 显示模式
  let rtssOsdTransparentBg = $state(false); // RTSS OSD 背景透明（去掉黑底）
  let osdType = $state<"rtss" | "builtin">("builtin"); // OSD 类型：rtss=RTSS注入, builtin=内置窗口
  let osdVisualStyle = $state<"transparent" | "solid" | "bar" | "bar-trans">(
    "solid",
  ); // OSD 视觉样式：透明/实体/横条/透明横条
  // 内置 OSD 新增设置项
  let osdDisplayMode = $state<"minimal" | "compact" | "detailed" | "custom">(
    "compact",
  ); // 显示模式：极简/灵动/详细/自定义
  let osdTheme = $state<
    "neon" | "sunset" | "frost" | "crimson" | "gold" | "lavender"
  >("neon"); // 配色主题
  let osdPosition = $state<
    "top-left" | "top-right" | "bottom-left" | "bottom-right"
  >("top-left"); // 显示位置
  let osdDesktopMode = $state(false); // 常驻桌面模式（忽略窗口位置限制，全屏常显）
  // 自定义 OSD 显示项目
  const ALL_OSD_ITEMS: OsdItemKey[] = [
    "fps",
    "frametime",
    "cpu_temp",
    "gpu_temp",
    "cpu_power",
    "gpu_power",
    "battery",
    "battery_power",
    "remaining",
    "fan",
    "ram",
    "vram",
    "time",
  ];
  let customOsdItems = $state<OsdItemKey[]>([
    "fps",
    "cpu_temp",
    "gpu_temp",
    "cpu_power",
    "battery",
    "time",
  ]); // 默认启用的自定义项

  // RTSS 帧率限制
  let rtssFpsLimitEnabled = $state(false); // 帧率限制是否启用
  let rtssFpsLimitValue = $state(60); // 帧率限制值
  // FPS 限制滑条上下限（用户可自定义范围）
  let fpsLimitMin = $state(DEFAULT_FPS_LIMIT_MIN); // 滑条最小值
  let fpsLimitMax = $state(DEFAULT_FPS_LIMIT_MAX); // 滑条最大值
  let fpsSettingsExpanded = $state(false); // FPS 上下限设置折叠状态

  async function loadRtssStatus() {
    try {
      // 并行获取 RTSS 状态和设置
      const [statusResult, settingsResult] = await Promise.allSettled([
        invoke<RtssStatus>("rtss_get_status"),
        invoke<any>("load_settings"),
      ]);

      if (statusResult.status !== "fulfilled") {
        console.error("获取 RTSS 状态失败");
        return;
      }
      rtssStatus = statusResult.value;
      const settings =
        settingsResult.status === "fulfilled" ? settingsResult.value : {};

      // 恢复 OSD 字体大小（立即应用，不需要等待 RTSS）
      if (typeof settings.osd_font_size === "number") {
        osdScale = Math.max(50, Math.min(200, settings.osd_font_size));
        console.log(`[OSD] 加载字体大小: ${osdScale}%`);
      }
      // 恢复帧率限制状态
      if (typeof settings.rtss_fps_limit_enabled === "boolean") {
        rtssFpsLimitEnabled = settings.rtss_fps_limit_enabled;
      }
      if (typeof settings.rtss_fps_limit_value === "number") {
        rtssFpsLimitValue = settings.rtss_fps_limit_value;
      }
      // 恢复 FPS 限制滑条上下限
      if (typeof settings.fps_limit_min === "number") {
        fpsLimitMin = Math.max(FPS_LIMIT_ABSOLUTE_MIN, Math.min(FPS_LIMIT_ABSOLUTE_MAX, settings.fps_limit_min));
      }
      if (typeof settings.fps_limit_max === "number") {
        fpsLimitMax = Math.max(FPS_LIMIT_ABSOLUTE_MIN, Math.min(FPS_LIMIT_ABSOLUTE_MAX, settings.fps_limit_max));
      }
      // 确保 min <= max
      if (fpsLimitMin > fpsLimitMax) {
        fpsLimitMin = fpsLimitMax;
      }
      // 恢复 OSD 精简模式（兼容旧设置）
      if (typeof settings.osd_compact_mode === "boolean") {
        osdCompactMode = settings.osd_compact_mode;
      }
      // 恢复 RTSS OSD 显示模式
      if (
        settings.rtss_osd_mode === "minimal" ||
        settings.rtss_osd_mode === "compact" ||
        settings.rtss_osd_mode === "detailed"
      ) {
        rtssOsdMode = settings.rtss_osd_mode;
      } else if (osdCompactMode) {
        // 兼容旧设置：如果旧的 osdCompactMode 为 true，则使用 compact 模式
        rtssOsdMode = "compact";
      }
      // 恢复 RTSS OSD 背景透明（去黑底）
      if (typeof settings.rtss_osd_transparent === "boolean") {
        rtssOsdTransparentBg = settings.rtss_osd_transparent;
      }
      // 恢复 OSD 缩放
      if (typeof settings.osd_scale === "number") {
        osdScale = Math.max(50, Math.min(200, settings.osd_scale));
      }
      // 恢复 OSD 视觉样式
      if (
        settings.osd_visual_style === "transparent" ||
        settings.osd_visual_style === "solid" ||
        settings.osd_visual_style === "bar" ||
        settings.osd_visual_style === "bar-trans"
      ) {
        osdVisualStyle = settings.osd_visual_style;
      } else if (typeof settings.osd_transparent === "boolean") {
        // 兼容旧设置
        osdVisualStyle = settings.osd_transparent ? "transparent" : "solid";
      }
      // 恢复 OSD 类型
      if (settings.osd_type === "rtss" || settings.osd_type === "builtin") {
        osdType = settings.osd_type;
      }

      // 恢复内置 OSD 显示模式
      if (
        settings.osd_display_mode === "minimal" ||
        settings.osd_display_mode === "compact" ||
        settings.osd_display_mode === "detailed" ||
        settings.osd_display_mode === "custom"
      ) {
        osdDisplayMode = settings.osd_display_mode;
      }
      // 恢复自定义 OSD 项目
      if (
        Array.isArray(settings.osd_custom_items) &&
        settings.osd_custom_items.length > 0
      ) {
        customOsdItems = settings.osd_custom_items.filter((item: string) =>
          ALL_OSD_ITEMS.includes(item as OsdItemKey),
        );
      }
      // 恢复内置 OSD 配色主题
      if (
        ["neon", "sunset", "frost", "crimson", "gold", "lavender"].includes(
          settings.osd_theme,
        )
      ) {
        osdTheme = settings.osd_theme;
      }
      // 恢复内置 OSD 位置
      if (
        settings.osd_position === "top-left" ||
        settings.osd_position === "top-right" ||
        settings.osd_position === "bottom-left" ||
        settings.osd_position === "bottom-right"
      ) {
        osdPosition = settings.osd_position;
      }
      // 恢复内置 OSD 常驻桌面模式
      if (typeof settings.osd_desktop_mode === "boolean") {
        osdDesktopMode = settings.osd_desktop_mode;
      }

      if (!rtssStatus.installed) return;

      // RTSS 未运行时尝试手动启动（使用已检测到的安装路径）
      if (!rtssStatus.running) {
        console.log("[RTSS] 面板启动，自动启动 RTSS...");
        try {
          const result = await invoke<RtssResult>("rtss_manual_launch");
          if (result.success) rtssStatus.running = true;
        } catch (e) {
          console.error("自动启动 RTSS 失败:", e);
        }
      }

      // RTSS 启动完成后再启动 LHM，收集系统数据（供 OSD 使用）
      // 单次调用即可触发 LHM 启动并获取数据（原先双重调用是多余的）
      console.log("[LHM] 面板启动，预启动 LHM...");
      try {
        performanceMetrics = await invoke<SystemMetrics>("get_system_metrics");
        console.log("[OSD] 系统数据已预加载");
      } catch (e) {
        console.warn("get_system_metrics failed:", e);
      }

      // RTSS 运行后恢复 OSD 状态
      if (
        rtssStatus.running &&
        settings.osd_enabled === true &&
        !rtssOsdEnabled
      ) {
        console.log("[OSD] 恢复上次开启状态, 模式:", osdType);
        if (osdType === "builtin") {
          // 内置 OSD 模式：设置样式并启用
          try {
            await Promise.all([
              invoke("set_osd_mode", { mode: osdDisplayMode }),
              invoke("set_osd_theme", { theme: osdTheme }),
              invoke("set_osd_position_corner", { position: osdPosition }),
              invoke("set_osd_scale", { scale: osdScale }),
              invoke("set_osd_visual_style", { style: osdVisualStyle }),
              invoke("set_osd_language", { language: currentLanguage }),
              invoke("set_osd_desktop_mode", { enabled: osdDesktopMode }),
              ...(osdDisplayMode === "custom"
                ? [invoke("set_osd_custom_items", { items: customOsdItems })]
                : []),
            ]);
            await invoke("enable_osd");
          } catch (e) {
            console.error("恢复内置 OSD 失败:", e);
          }
        } else {
          // RTSS 模式：配置 RTSS（EnableOSD=1, EnableStat=0 等）
          try {
            await invoke<RtssResult>("rtss_configure", {
              rtssOsdTransparent: rtssOsdTransparentBg,
            });
          } catch (e) {
            console.warn("[RTSS] 启动恢复时配置 RTSS 失败:", e);
          }
        }
        rtssOsdEnabled = true;
        startRtssPolling();
      } else if (rtssStatus.running && settings.osd_enabled !== true) {
        // OSD 已关闭，确保清除 RTSS OSD（防止残留）
        console.log("[OSD] 实时监控已关闭，清除 RTSS OSD");
        try {
          await invoke<RtssResult>("rtss_clear_osd");
        } catch (e) {}
      }

      // 加载当前 RTSS 帧率限制
      if (rtssStatus.running) {
        invoke<number | null>("rtss_get_framerate_limit")
          .then((limit) => {
            if (limit !== null && limit !== undefined) {
              rtssFpsLimitValue = limit;
              rtssFpsLimitEnabled = limit > 0;
              console.log(`[RTSS] 当前帧率限制: ${limit} FPS`);
            }
          })
          .catch((e) => console.warn("rtss_get_framerate_limit failed:", e));
      }
    } catch (e) {
      console.error("获取 RTSS 状态失败:", e);
    }
  }

  async function toggleRtss() {
    // 冷却时间检查（防止快速切换导致 OSD 残留）
    if (rtssToggleCooldown) return;

    rtssLoading = true;
    rtssToggleCooldown = true;

    try {
      if (rtssOsdEnabled) {
        // 关闭 OSD 显示
        // 先设置状态为 false，防止轮询继续更新 OSD
        rtssOsdEnabled = false;
        await stopRtssPolling();

        if (osdType === "builtin") {
          // 禁用内置 OSD 显示
          try {
            await invoke("disable_osd");
          } catch (e) {}
        } else {
          // 清除 RTSS OSD（多次确保清除）
          for (let i = 0; i < 5; i++) {
            try {
              await invoke<RtssResult>("rtss_clear_osd");
            } catch (e) {}
            if (i < 4) await new Promise((r) => setTimeout(r, 200));
          }
        }
      } else {
        // 开启 OSD 显示
        // RTSS 模式需要 RTSS 运行；内置模式可选（仅用于获取 FPS 数据）
        if (!rtssStatus.running) {
          if (!rtssStatus.installed) {
            // RTSS 未安装：RTSS 模式直接拒绝，内置模式允许继续（FPS 会显示 0）
            if (osdType === "rtss") {
              console.warn("[RTSS] 未安装，无法开启 RTSS 模式实时监控");
              rtssLoading = false;
              rtssToggleCooldown = false;
              return;
            }
            console.warn("[OSD] RTSS 未安装，内置 OSD 模式将无 FPS 数据");
          } else {
            // RTSS 已安装但未运行，尝试启动
            const result = await invoke<RtssResult>("rtss_manual_launch");
            if (result.success) {
              rtssStatus.running = true;
            } else {
              // RTSS 模式下，RTSS 必须运行才能使用
              if (osdType === "rtss") {
                console.warn("[RTSS] 启动失败，无法开启 RTSS 模式实时监控");
                rtssLoading = false;
                rtssToggleCooldown = false;
                return;
              }
              console.warn("[RTSS] 启动失败，FPS 数据可能不可用");
            }
          }
        }

        if (osdType === "builtin") {
          // 启用内置 OSD 显示
          try {
            // 先设置样式，再启用
            await Promise.all([
              invoke("set_osd_mode", { mode: osdDisplayMode }),
              invoke("set_osd_theme", { theme: osdTheme }),
              invoke("set_osd_position_corner", { position: osdPosition }),
              invoke("set_osd_scale", { scale: osdScale }),
              invoke("set_osd_visual_style", { style: osdVisualStyle }),
              invoke("set_osd_language", { language: currentLanguage }),
              // 如果是自定义模式，发送自定义项目
              ...(osdDisplayMode === "custom"
                ? [invoke("set_osd_custom_items", { items: customOsdItems })]
                : []),
            ]);
            await invoke("enable_osd");
          } catch (e) {
            console.error("启用内置 OSD 失败:", e);
            return;
          }
        } else {
          // RTSS 模式：配置 RTSS（EnableOSD=1, EnableStat=0 等）
          try {
            await invoke<RtssResult>("rtss_configure", {
              rtssOsdTransparent: rtssOsdTransparentBg,
            });
          } catch (e) {
            console.warn("[RTSS] 配置 RTSS 失败:", e);
          }
        }
        rtssOsdEnabled = true;
        startRtssPolling();
      }
    } catch (e) {
      console.error("切换 OSD 失败:", e);
    } finally {
      // 保存 OSD 开关状态到配置（无论成功失败都保存当前状态）
      try {
        await invoke("save_settings", {
          settings: { osd_enabled: rtssOsdEnabled },
        });
        console.log("[OSD] 状态已保存:", rtssOsdEnabled);
      } catch (e) {
        console.error("[OSD] 保存状态失败:", e);
      }
      rtssLoading = false;
      // 1 秒冷却时间（使用 safeTimeout 确保组件卸载时清理）
      safeTimeout(() => {
        rtssToggleCooldown = false;
      }, 1000);
    }
  }

  // 切换 OSD 类型（RTSS 注入 / 内置窗口）
  async function switchOsdType(newType: "rtss" | "builtin") {
    if (newType === osdType) return;
    if (osdTypeSwitching) return; // 防止快速切换导致卡死

    osdTypeSwitching = true;

    try {
      const wasEnabled = rtssOsdEnabled;
      const oldType = osdType;

      // 如果 OSD 正在运行，先彻底停止
      if (wasEnabled) {
        stopRtssPolling();
        rtssOsdEnabled = false;

        // 彻底清除前一个模式
        if (oldType === "builtin") {
          try {
            await invoke("disable_osd");
          } catch (e) {}
        } else {
          // RTSS 模式需要多次清除确保干净
          for (let i = 0; i < 3; i++) {
            try {
              await invoke<RtssResult>("rtss_clear_osd");
            } catch (e) {}
            if (i < 2) await new Promise((r) => setTimeout(r, 100));
          }
        }

        // 等待前者完全清除
        await new Promise((r) => setTimeout(r, 300));
      }

      osdType = newType;
      await invoke("save_settings", { settings: { osd_type: osdType } });

      // 如果之前是开启的，用新类型重新开启
      if (wasEnabled) {
        if (newType === "builtin") {
          try {
            await Promise.all([
              invoke("set_osd_mode", { mode: osdDisplayMode }),
              invoke("set_osd_theme", { theme: osdTheme }),
              invoke("set_osd_position_corner", { position: osdPosition }),
              invoke("set_osd_scale", { scale: osdScale }),
              invoke("set_osd_visual_style", { style: osdVisualStyle }),
              invoke("set_osd_language", { language: currentLanguage }),
              // 如果是自定义模式，发送自定义项目
              ...(osdDisplayMode === "custom"
                ? [invoke("set_osd_custom_items", { items: customOsdItems })]
                : []),
            ]);
            await invoke("enable_osd");
          } catch (e) {
            console.error("切换到内置 OSD 失败:", e);
          }
        } else {
          // 切换到 RTSS 模式：配置 RTSS
          try {
            await invoke<RtssResult>("rtss_configure", {
              rtssOsdTransparent: rtssOsdTransparentBg,
            });
          } catch (e) {
            console.warn("[RTSS] 配置 RTSS 失败:", e);
          }
        }
        rtssOsdEnabled = true;
        startRtssPolling();
      }
    } finally {
      // 切换完成后冷却 500ms（使用 safeTimeout 确保组件卸载时清理）
      safeTimeout(() => {
        osdTypeSwitching = false;
      }, 500);
    }
  }

  // 切换 OSD 常驻桌面模式
  async function toggleOsdDesktopMode() {
    osdDesktopMode = !osdDesktopMode;
    // 保存设置
    await invoke("save_settings", {
      settings: { osd_desktop_mode: osdDesktopMode },
    });
    // 通知 OSD 窗口
    if (osdType === "builtin" && rtssOsdEnabled) {
      await invoke("set_osd_desktop_mode", { enabled: osdDesktopMode });
    }
    console.log(`[OSD] 常驻桌面模式: ${osdDesktopMode ? "开启" : "关闭"}`);
  }

  // 切换自定义 OSD 项目
  function toggleCustomOsdItem(itemKey: OsdItemKey) {
    const idx = customOsdItems.indexOf(itemKey);
    if (idx >= 0) {
      // 已启用，移除
      customOsdItems = customOsdItems.filter((k) => k !== itemKey);
    } else {
      // 未启用，添加
      customOsdItems = [...customOsdItems, itemKey];
    }
    // 保存设置
    invoke("save_settings", { settings: { osd_custom_items: customOsdItems } });
    // 如果 OSD 开启且在自定义模式，通知后端
    if (
      rtssOsdEnabled &&
      osdDisplayMode === "custom" &&
      osdType === "builtin"
    ) {
      invoke("set_osd_custom_items", { items: customOsdItems });
    }
    console.log(`[OSD] 自定义项目已更新:`, customOsdItems);
  }

  // 切换 OSD 视觉样式（透明/实体/横条/透明横条）
  function cycleOsdVisualStyle(direction: number = 1) {
    const styles: Array<"transparent" | "solid" | "bar" | "bar-trans"> = [
      "solid",
      "transparent",
      "bar",
      "bar-trans",
    ];
    const currentIdx = styles.indexOf(osdVisualStyle);
    const nextIdx = (currentIdx + direction + styles.length) % styles.length;
    osdVisualStyle = styles[nextIdx];
    invoke("save_settings", { settings: { osd_visual_style: osdVisualStyle } });
    if (osdType === "builtin") {
      invoke("set_osd_visual_style", { style: osdVisualStyle });
    }
  }

  // 切换 RTSS OSD 显示模式（极简/灵动/详细）
  function cycleRtssOsdMode(direction: number = 1) {
    const modes: Array<"minimal" | "compact" | "detailed"> = [
      "minimal",
      "compact",
      "detailed",
    ];
    const currentIdx = modes.indexOf(rtssOsdMode);
    const nextIdx = (currentIdx + direction + modes.length) % modes.length;
    rtssOsdMode = modes[nextIdx];
    invoke("save_settings", { settings: { rtss_osd_mode: rtssOsdMode } });
  }

  // 切换 RTSS OSD 背景透明（去掉黑底）
  async function toggleRtssOsdTransparentBg() {
    rtssOsdTransparentBg = !rtssOsdTransparentBg;

    // 保存设置
    try {
      await invoke("save_settings", {
        settings: { rtss_osd_transparent: rtssOsdTransparentBg },
      });
    } catch (e) {
      console.error("[RTSS] 保存 OSD 背景设置失败:", e);
    }

    // RTSS 模式下实时更新 RTSS 配置
    if (osdType === "rtss" && rtssStatus.running) {
      try {
        await invoke<RtssResult>("rtss_configure", {
          rtssOsdTransparent: rtssOsdTransparentBg,
        });
      } catch (e) {
        console.warn("[RTSS] 更新 RTSS 背景配置失败:", e);
      }
    }
  }

  // RTSS 帧率限制功能
  async function toggleRtssFpsLimit() {
    if (!rtssStatus.running) {
      console.log("[RTSS] RTSS 未运行，无法设置帧率限制");
      return;
    }

    rtssLoading = true;
    try {
      const newEnabled = !rtssFpsLimitEnabled;
      const limit = newEnabled ? rtssFpsLimitValue : 0;

      const result = await invoke<RtssResult>("rtss_set_framerate_limit", {
        limit,
      });
      if (result.success) {
        rtssFpsLimitEnabled = newEnabled;
        // 保存状态
        await invoke("save_settings", {
          settings: {
            rtss_fps_limit_enabled: rtssFpsLimitEnabled,
            rtss_fps_limit_value: rtssFpsLimitValue,
          },
        });
        // 同步到绑定场景
        syncSettingsToBindingProfile({ 
          fps_limit_enabled: rtssFpsLimitEnabled, 
          fps_limit_value: rtssFpsLimitValue 
        });
        console.log(
          `[RTSS] 帧率限制 ${newEnabled ? "已开启: " + rtssFpsLimitValue + " FPS" : "已关闭"}`,
        );
      } else {
        console.error("[RTSS] 设置帧率限制失败:", result.message);
      }
    } catch (e) {
      console.error("切换帧率限制失败:", e);
    } finally {
      rtssLoading = false;
    }
  }

  async function setRtssFpsLimitValue(fps: number) {
    rtssFpsLimitValue = fps;

    // 如果帧率限制已启用，立即应用新值
    if (rtssFpsLimitEnabled && rtssStatus.running) {
      try {
        const result = await invoke<RtssResult>("rtss_set_framerate_limit", {
          limit: fps,
        });
        if (result.success) {
          console.log(`[RTSS] 帧率限制已更新为 ${fps} FPS`);
        }
      } catch (e) {
        console.error("设置帧率限制值失败:", e);
      }
    }

    // 保存设置
    try {
      await invoke("save_settings", {
        settings: { rtss_fps_limit_value: fps },
      });
      // 同步到绑定场景
      syncSettingsToBindingProfile({ fps_limit_value: fps });
    } catch (e) {}
  }

  // OSD 更新连续超时/错误计数（用于熔断器）
  let osdUpdateErrorCount = 0;
  const OSD_UPDATE_MAX_ERRORS = 5; // 连续错误超过此数自动暂停 OSD 更新一段时间
  let osdUpdatePaused = false; // OSD 更新是否暂停（熔断器）
  let osdUpdatePauseUntil = 0; // OSD 更新暂停截止时间

  /**
   * 带超时的 invoke 调用（用于 OSD 更新，防止后端卡死导致前端无响应）
   * 超时返回 null 而非抛出异常，避免错误累积
   */
  async function invokeWithOsdTimeout<T>(cmd: string, args?: Record<string, unknown>, timeoutMs = 2000): Promise<T | null> {
    try {
      let timer: ReturnType<typeof setTimeout>;
      const promise = args !== undefined ? invoke<T>(cmd, args) : invoke<T>(cmd);
      const result = await Promise.race([
        promise.finally(() => clearTimeout(timer)),
        new Promise<null>((resolve) => timer = setTimeout(() => resolve(null), timeoutMs)),
      ]);
      return result;
    } catch (e) {
      return null;
    }
  }

  let lastOsdTickTime = 0;
  async function updateRtssOsd() {
    if (!rtssOsdEnabled) return;
    // 防重入去重：Rust 后台定时器(eval) 和 setInterval 可能同时触发
    const now = Date.now();
    if (now - lastOsdTickTime < 800) return;
    lastOsdTickTime = now;
    // RTSS 模式需要 RTSS 运行，内置模式不需要
    if (osdType === "rtss" && !rtssStatus.running) return;

    // 熔断器检查：如果连续错误过多，暂停更新 30 秒
    if (osdUpdatePaused) {
      if (Date.now() < osdUpdatePauseUntil) {
        return; // 仍在暂停期
      }
      // 暂停期结束，重置状态
      osdUpdatePaused = false;
      osdUpdateErrorCount = 0;
      console.log("[OSD] 熔断器恢复，继续更新");
    }

    // 防止堆积：如果上一次还没完成，跳过本次
    if (rtssOsdInProgress) {
      osdUpdateErrorCount++;
      if (osdUpdateErrorCount >= OSD_UPDATE_MAX_ERRORS) {
        console.warn(`[OSD] 连续 ${osdUpdateErrorCount} 次更新未完成，触发熔断器暂停 30 秒`);
        osdUpdatePaused = true;
        osdUpdatePauseUntil = Date.now() + 30000;
        rtssOsdInProgress = false; // 重置标志，防止永久锁死
      }
      return;
    }
    rtssOsdInProgress = true;

    try {
      // 直接使用共享的 performanceMetrics（由统一的轮询更新）
      const sys = performanceMetrics;

      // 使用共享的 batteryStatus
      let battery = { ...batteryStatus };
      let chargeRate = 0; // 充放电功率 W

      // 获取电池详情（使用缓存，每 5 秒更新一次，不阻塞 OSD）
      const now = Date.now();
      if (now - batteryDetailsUpdateTime > 5000) {
        // 后台异步更新电池详情，不阻塞当前 OSD 更新
        invoke<BatteryDetails>("get_battery_details")
          .then((details) => {
            if (details) {
              cachedBatteryDetails = details;
              batteryDetailsUpdateTime = Date.now();
              // 只有获取到有效的满充容量时才更新缓存
              if (
                details.full_charge_capacity &&
                details.full_charge_capacity > 0
              ) {
                cachedBatteryCapacityWh = details.full_charge_capacity / 1000;
              }
            }
          })
          .catch(() => {
            /* 静默失败 */
          });
      }

      // 使用缓存的电池详情
      if (cachedBatteryDetails) {
        if (cachedBatteryDetails.charge_rate) {
          chargeRate = Math.abs(cachedBatteryDetails.charge_rate) / 1000;
        }
        // 如果常规方式获取不到电量，尝试从详情计算
        if (
          battery.battery_percent === 0 &&
          cachedBatteryDetails.current_capacity &&
          cachedBatteryDetails.full_charge_capacity
        ) {
          const p = Math.round(
            (cachedBatteryDetails.current_capacity /
              cachedBatteryDetails.full_charge_capacity) *
              100,
          );
          if (p > 0) {
            battery.battery_percent = p;
            battery.has_battery = true;
          }
        }
      }

      // 获取 FPS 数据（从 RTSS 共享内存，包含 Lossless Scaling 数据）
      // 使用带超时的调用，防止后端卡死导致前端无响应
      let gameFps = 0;
      let gameFrameTime = 0;
      let lsFps = 0;
      let lsRunning = false;
      const fpsData = await invokeWithOsdTimeout<LsFpsData>("rtss_get_foreground_fps_with_ls");
      if (fpsData) {
        gameFps = Math.round(fpsData.game_fps);
        gameFrameTime = fpsData.game_frametime;
        lsFps = Math.round(fpsData.ls_fps);
        lsRunning = fpsData.ls_running;
        osdUpdateErrorCount = 0; // FPS 数据获取成功，重置错误计数
      }

      // ========== 构建 OSD 文本 ==========
      const mainSize = osdScale; // 主字体大小
      const unitSize = Math.round(osdScale * 0.6); // 单位标签缩小
      let osd = "";

      // 设置主字体大小
      osd += `<S=${mainSize}>`;

      // 构建 FPS 显示字符串的辅助函数
      // 如果 LS 正在运行且有输出，显示 "游戏FPS→LS输出FPS" 格式
      const buildFpsDisplay = (showFrameTime: boolean = false) => {
        let fpsStr = "";
        if (gameFps > 0) {
          if (lsRunning && lsFps > 0) {
            // Lossless Scaling 模式：显示 "游戏FPS→LS输出FPS"
            // 游戏原始帧数用较暗的颜色，LS 输出用亮绿色
            fpsStr += `<C=70B030>${gameFps}<S=${unitSize}>→<S=${mainSize}><C>`;
            fpsStr += `<C=A0FF50>${lsFps}<S=${unitSize}>FPS<S=${mainSize}><C>`;
          } else {
            // 普通模式：只显示游戏 FPS
            fpsStr += `<C=A0FF50>${gameFps}<S=${unitSize}>FPS<S=${mainSize}><C>`;
          }
          if (showFrameTime && gameFrameTime > 0) {
            fpsStr += ` <C=FF8080>${gameFrameTime.toFixed(1)}<S=${unitSize}>MS<S=${mainSize}><C>`;
          }
        } else {
          // 使用 RTSS 原生标签
          fpsStr += `<C=A0FF50><FR><S=${unitSize}>FPS<S=${mainSize}><C>`;
          if (showFrameTime) {
            fpsStr += ` <C=FF8080><FT><S=${unitSize}>MS<S=${mainSize}><C>`;
          }
        }
        return fpsStr;
      };

      if (rtssOsdMode === "minimal") {
        // ========== 极简模式：只显示 FPS ==========
        osd += buildFpsDisplay(false);
      } else if (rtssOsdMode === "compact") {
        // ========== 灵动模式：帧数、帧时间、TDP、电量（插电无）、时间 ==========
        // FPS + 帧时间
        osd += buildFpsDisplay(true);
        // 帧时间图表（RTSS 原生标签）
        osd += ` <C=80FFFF><FTG><C>`;

        // 功耗：统一使用与内置 OSD 相同的逻辑
        // 1. 基础功耗：优先 SoC/APU 总功耗，否则回退到 CPU 核心功耗
        // 2. 总功耗 = 基础功耗 + 独显功耗（如果有）
        // 3. 放电时显示电池功率（更准确），否则显示总功耗
        const socPowerCompact = sys.soc_power || 0;
        const cpuPowerCompact = sys.cpu_power || 0;
        const gpuPowerCompact = sys.gpu_power || 0;
        const basePowerCompact = socPowerCompact > 0 ? socPowerCompact : cpuPowerCompact;
        const totalPowerCompact = basePowerCompact + gpuPowerCompact;
        const batteryPowerCompact = sys.battery_power || 0;
        const displayPowerCompact = (!battery.is_ac_connected && batteryPowerCompact > 0.5)
          ? batteryPowerCompact
          : totalPowerCompact;
        if (displayPowerCompact > 0) {
          osd += ` <C=F06060>${displayPowerCompact.toFixed(0)}<S=${unitSize}>W<S=${mainSize}><C>`;
        }

        // 电量（仅使用电池时显示，插电不显示）
        if (
          battery.has_battery &&
          !battery.is_ac_connected &&
          battery.battery_percent > 0
        ) {
          const batPercent = Math.round(battery.battery_percent);
          osd += ` <C=FFFF80>${batPercent}<S=${unitSize}>%<S=${mainSize}><C>`;
        }

        // 时间
        const now = new Date();
        const timeStr = `${now.getHours().toString().padStart(2, "0")}:${now.getMinutes().toString().padStart(2, "0")}:${now.getSeconds().toString().padStart(2, "0")}`;
        osd += ` <C=FFFFFF>${timeStr}<C>`;
      } else {
        // ========== 完整模式 ==========
        // 颜色方案: FPS绿色, CPU青色, GPU粉色, BAT黄色, MEM橙色, FAN蓝色, 功耗红色

        // 1. 应用名 + FPS + 帧时间
        osd += `<C=50B0FF><APP> <C>`;
        osd += buildFpsDisplay(true);

        // 2. CPU: 使用率 频率 温度 功耗
        const cpuUsage = Math.round(sys.cpu_usage);
        const cpuTemp = sys.cpu_temp.toFixed(1);
        const cpuPower = sys.cpu_power.toFixed(1);
        osd += `<C=FFFFFF> | <C>`;
        osd += `<C=80FFFF>CPU<C>`;
        osd += ` ${cpuUsage.toString().padStart(3)}<S=${unitSize}>%<S=${mainSize}>`;
        if (sys.cpu_temp > 0)
          osd += ` ${cpuTemp}<S=${unitSize}>C<S=${mainSize}>`;
        if (sys.cpu_power > 0)
          osd += `<C=F06060> ${cpuPower}<S=${unitSize}>W<S=${mainSize}><C>`;
        const socPower = sys.soc_power || 0;
        if (socPower > 0)
          osd += `<C=F06060> SOC${socPower.toFixed(1)}<S=${unitSize}>W<S=${mainSize}><C>`;

        // 3. GPU: 使用率 温度 显存(已用/总量) 功耗
        const gpuUsage = Math.round(sys.gpu_usage || 0);
        const gpuTemp = Math.round(sys.gpu_temp || 0);
        const gpuPower = Math.round(sys.gpu_power || 0);
        const vramUsedMB = sys.vram_used_mb || 0;
        const vramTotalMB = sys.vram_total_mb || 0;
        if (gpuUsage > 0 || gpuTemp > 0) {
          osd += `<C=FFFFFF> | <C>`;
          osd += `<C=FF90FF>GPU<C>`;
          osd += ` ${gpuUsage.toString().padStart(3)}<S=${unitSize}>%<S=${mainSize}>`;
          if (gpuTemp > 0) osd += ` ${gpuTemp}<S=${unitSize}>C<S=${mainSize}>`;
          if (vramUsedMB > 0 && vramTotalMB > 0) {
            const vramUsedGB = (vramUsedMB / 1024).toFixed(1);
            const vramTotalGB = Math.round(vramTotalMB / 1024);
            osd += ` ${vramUsedGB}/${vramTotalGB}<S=${unitSize}>GB<S=${mainSize}>`;
          } else if (vramUsedMB > 0) {
            const vramGB = (vramUsedMB / 1024).toFixed(1);
            osd += ` ${vramGB}<S=${unitSize}>GB<S=${mainSize}>`;
          }
          if (gpuPower > 0)
            osd += `<C=F06060> ${gpuPower}<S=${unitSize}>W<S=${mainSize}><C>`;
        }

        // 4. 电池: 电量 剩余时间 功耗
        if (battery.has_battery || battery.battery_percent > 0) {
          const batPercent = Math.round(battery.battery_percent);
          osd += `<C=FFFFFF> | <C>`;
          osd += `<C=FFFF80>BAT<C>`;
          osd += ` ${batPercent.toString().padStart(3)}<S=${unitSize}>%<S=${mainSize}>`;
          if (
            battery.battery_life_time &&
            battery.battery_life_time > 0 &&
            !battery.is_charging
          ) {
            const remainMin = battery.battery_life_time / 60;
            if (remainMin < 60) {
              osd += ` ${Math.round(remainMin)}<S=${unitSize}>min<S=${mainSize}>`;
            } else {
              osd += ` ${(remainMin / 60).toFixed(1)}<S=${unitSize}>h<S=${mainSize}>`;
            }
          }
          const battPower = sys.battery_power || 0;
          if (battPower > 0.5) {
            osd += `<C=F06060> -${battPower.toFixed(1)}<S=${unitSize}>W<S=${mainSize}><C>`;
          } else if (battPower < -0.5) {
            osd += `<C=50FF50> +${(-battPower).toFixed(1)}<S=${unitSize}>W<S=${mainSize}><C>`;
          } else if (chargeRate > 0.5) {
            osd += `<C=F06060> ${chargeRate.toFixed(1)}<S=${unitSize}>W<S=${mainSize}><C>`;
          }
        }

        // 5. 内存: 已用/总量 + 使用率
        const memUsedGB = Math.round(sys.ram_used_gb);
        const memTotalGB = Math.round(sys.ram_total_gb);
        const memLoad = Math.round(sys.ram_usage);
        if (memLoad > 0 || memUsedGB > 0) {
          osd += `<C=FFFFFF> | <C>`;
          osd += `<C=FFA050>MEM<C>`;
          if (memUsedGB > 0 && memTotalGB > 0) {
            osd += ` ${memUsedGB}/${memTotalGB}<S=${unitSize}>GB<S=${mainSize}>`;
          }
          osd += ` ${memLoad.toString().padStart(2)}<S=${unitSize}>%<S=${mainSize}>`;
        }

        // 6. 风扇: 转速
        if (sys.fan_speed && sys.fan_speed > 0) {
          osd += `<C=FFFFFF> | <C>`;
          osd += `<C=9090FF>FAN<C>`;
          osd += ` ${sys.fan_speed.toString().padStart(4)}<S=${unitSize}>RPM<S=${mainSize}>`;
        }
      }

      // 根据 OSD 类型发送数据（使用带超时的调用，防止后端卡死）
      if (osdType === "builtin") {
        // 内置 OSD：发送数据，fps=0 时 osd.html 会自动隐藏
        // 使用缓存的电池容量，避免偶尔获取不到时回退到假设值
        const batteryCapacityWh = cachedBatteryCapacityWh;

        const updateResult = await invokeWithOsdTimeout("update_osd_data", {
          data: {
            fps: gameFps, // 0 时 OSD 会隐藏
            frametime: gameFrameTime || 0,
            // Lossless Scaling 数据
            ls_fps: lsFps,
            ls_running: lsRunning,
            cpu_usage: sys.cpu_usage || 0,
            cpu_temp: sys.cpu_temp || 0,
            cpu_power: sys.cpu_power || 0,
            soc_power: sys.soc_power || 0,
            gpu_usage: sys.gpu_usage || 0,
            gpu_temp: sys.gpu_temp || 0,
            gpu_power: sys.gpu_power || 0,
            fan_speed: sys.fan_speed || 0,
            battery: battery.battery_percent || 0,
            battery_power: sys.battery_power || 0,
            is_ac_connected: battery.is_ac_connected || false,
            is_charging: battery.is_charging || false,
            show_battery_always: false,
            // 内存/显存
            ram_usage: sys.ram_used_gb || 0,
            ram_total: sys.ram_total_gb || 0,
            vram_usage: (sys.vram_used_mb || 0) / 1024, // MB -> GB
            vram_total: (sys.vram_total_mb || 0) / 1024, // MB -> GB
            // 硬件名称
            cpu_name: cpuName,
            gpu_name: gpuName,
            // 电池容量
            battery_capacity: batteryCapacityWh,
          },
        });
        if (updateResult !== null) {
          // 只在有游戏时跟随前台窗口
          if (gameFps > 0) {
            await invokeWithOsdTimeout("move_osd_to_foreground", undefined, 500);
          }
          rtssOsdErrorCount = 0;
        }
      } else if (osd) {
        // RTSS 模式：发送文本到 RTSS 共享内存
        const result = await invokeWithOsdTimeout<RtssResult>("rtss_update_osd", { text: osd });
        if (result && result.success) {
          rtssOsdErrorCount = 0;
        } else if (result) {
          rtssOsdErrorCount++;
          console.warn(
            `[OSD] 更新失败 (${rtssOsdErrorCount}/${RTSS_OSD_MAX_ERRORS}): ${result.message}`,
          );
          // 如果是 RTSS 未运行的错误，立即停止并关闭开关
          if (result.message && result.message.includes("未运行")) {
            console.warn("[OSD] RTSS 未运行，自动关闭实时监控");
            stopRtssPolling();
            rtssOsdEnabled = false;
            rtssStatus.running = false;
            rtssOsdErrorCount = 0;
            // 保存关闭状态
            invoke("save_settings", { settings: { osd_enabled: false } }).catch(() => {});
          }
        }
        // result 为 null 表示超时，不增加错误计数（熔断器会处理）
      }
    } catch (e) {
      rtssOsdErrorCount++;
      console.error(
        `[OSD] 异常 (${rtssOsdErrorCount}/${RTSS_OSD_MAX_ERRORS}):`,
        e,
      );

      // 连续错误过多，自动禁用 OSD 防止崩溃
      if (rtssOsdErrorCount >= RTSS_OSD_MAX_ERRORS) {
        console.error("[OSD] 连续错误过多，自动禁用 OSD");
        stopRtssPolling();
        rtssOsdEnabled = false;
        if (osdType === "builtin") {
          try {
            await invoke("disable_osd");
          } catch (e) {}
        }
        rtssOsdErrorCount = 0;
        // 保存关闭状态
        try {
          await invoke("save_settings", { settings: { osd_enabled: false } });
        } catch (e) {}
      }
    } finally {
      rtssOsdInProgress = false;
    }
  }

  async function startRtssPolling() {
    if (rtssPollingInterval) return;
    // 重置所有错误计数和熔断器状态
    rtssOsdErrorCount = 0;
    osdUpdateErrorCount = 0;
    osdUpdatePaused = false;
    osdUpdatePauseUntil = 0;
    lastOsdTickTime = 0;
    // 注册全局回调供 Rust 后台定时器通过 eval 调用
    // 当面板隐藏时 WebView2 会节流 setInterval，Rust 定时器通过 eval 绕过节流
    (window as any).__osdTick = () => { updateRtssOsd(); };
    // 启动 Rust 后台定时器（面板隐藏时仍能触发更新）
    invoke("start_osd_ticker").catch((e: any) =>
      console.warn("[OSD] 启动后台定时器失败:", e),
    );
    updateRtssOsd();
    // 保留 setInterval 作为面板可见时的主力更新源
    rtssPollingInterval = window.setInterval(updateRtssOsd, 1000);
  }

  async function stopRtssPolling() {
    if (rtssPollingInterval) {
      clearInterval(rtssPollingInterval);
      rtssPollingInterval = null;
    }
    // 停止 Rust 后台定时器
    invoke("stop_osd_ticker").catch(() => {});
    // 清理全局回调
    delete (window as any).__osdTick;
    // 停止时清除 OSD
    try {
      await invoke<RtssResult>("rtss_clear_osd");
    } catch (e) {}
  }

  // 风扇设置：对高频切换做“合并 + 串行化”，避免 IPC/后端任务堆积造成延迟/乱序
  let fanModeInvokeInFlight = false;
  let fanModeInvokePending: number | null = null;

  async function applyFanMode() {
    // 记录最新目标；如果正在执行中，只更新 pending，等当前调用完成后再应用最新值
    fanModeInvokePending = fanModeIndex;
    if (fanModeInvokeInFlight) return;

    fanModeInvokeInFlight = true;
    try {
      while (fanModeInvokePending !== null) {
        const targetMode = fanModeInvokePending;
        fanModeInvokePending = null;

        try {
          const result = await invoke<{
            success: boolean;
            message?: string;
            error?: string;
          }>("set_fan_mode", { modeIndex: targetMode });

          if (result?.success) {
            appliedFanModeIndex = targetMode;
            // 保存风扇模式到 settings.json（全局默认，不区分 AC/电池）
            await saveFanModeSetting(targetMode);
          } else {
            const msg =
              result?.error || result?.message || t("toast_unknown_error");
            console.error("风扇模式设置失败:", msg);
            showToast(msg, "error", 6000);
            // 仅当当前仍停留在失败目标值时才回滚，避免覆盖用户新的选择
            if (fanModeIndex === targetMode) {
              fanModeIndex = appliedFanModeIndex;
            }
          }
        } catch (e) {
          console.error("风扇模式设置异常:", e);
          showToast(t("toast_unknown_error"), "error", 6000);
          // 仅当当前仍停留在失败目标值时才回滚，避免覆盖用户新的选择
          if (fanModeIndex === targetMode) {
            fanModeIndex = appliedFanModeIndex;
          }
        }
      }
    } finally {
      fanModeInvokeInFlight = false;
    }
  }

  // 更新风扇曲线某个点的转速
  function updateFanCurvePoint(pointIdx: number, direction: number) {
    // 边界检查：确保模式和点索引有效
    if (fanCurveEditMode < 0 || fanCurveEditMode > 3) return;
    if (pointIdx < 0 || pointIdx > 5) return;
    const curve = fanCurves[fanCurveEditMode];
    if (!curve) return;
    let newSpeed = curve[pointIdx] + direction;
    newSpeed = Math.max(0, Math.min(100, newSpeed));
    // 确保曲线单调递增
    if (pointIdx > 0 && newSpeed < curve[pointIdx - 1]) {
      newSpeed = curve[pointIdx - 1];
    }
    if (pointIdx < 5 && newSpeed > curve[pointIdx + 1]) {
      newSpeed = curve[pointIdx + 1];
    }
    curve[pointIdx] = newSpeed;
    fanCurves[fanCurveEditMode] = [...curve];
    fanCurvesModified = true;
  }

  // 保存风扇曲线到后端
  async function saveFanCurves() {
    try {
      await invoke("save_fan_curves", { curves: fanCurves });
      fanCurvesModified = false;
      console.log("风扇曲线已保存");

      // 同步保存到 settings.json（全局默认）
      await saveFanCurvesSetting();
    } catch (e) {
      console.error("风扇曲线保存失败:", e);
    }
  }

  // 重置当前编辑模式的曲线为默认值
  function resetFanCurve() {
    fanCurves[fanCurveEditMode] = [...DEFAULT_FAN_CURVES[fanCurveEditMode]];
    fanCurvesModified = true;
  }

  // 加载已保存的风扇曲线（只读 settings.json 作为唯一来源）
  async function loadFanCurves() {
    try {
      const s = (await invoke<any>("load_settings").catch(() => null)) as any;
      const saved = (s && s.fan_curves) as Record<string, number[]> | null;

      // 将字符串键转换为数字键（若 settings 中不存在，则使用默认值）
      fanCurves = {
        0: saved?.["0"] || [...DEFAULT_FAN_CURVES[0]],
        1: saved?.["1"] || [...DEFAULT_FAN_CURVES[1]],
        2: saved?.["2"] || [...DEFAULT_FAN_CURVES[2]],
        3: saved?.["3"] || [...DEFAULT_FAN_CURVES[3]],
      };
      fanCurvesModified = false;
    } catch (e) {
      console.error("风扇曲线加载失败:", e);
    }
  }

  async function mediaControl(action: string) {
    try {
      await invoke("media_control", { action });
      // 媒体控制后立即刷新状态（使用 safeTimeout 确保组件卸载时清理）
      safeTimeout(fetchMediaInfo, 500);
    } catch (e) {
      console.error("媒体控制失败:", e);
    }
  }

  let mediaInfoInProgress = false; // 防止媒体信息轮询堆积

  async function fetchMediaInfo() {
    // 防止堆积：如果上一次还没完成，跳过本次
    if (mediaInfoInProgress) return;
    mediaInfoInProgress = true;

    try {
      const info = await invoke<MediaInfo>("get_media_info");
      if (info) {
        mediaInfo = info;
      }
    } catch (e) {
      console.error("获取媒体信息失败:", e);
    } finally {
      mediaInfoInProgress = false;
    }
  }

  // 管理媒体信息定期获取（仅在音频Tab且面板打开时）
  function startMediaInfoPolling() {
    if (mediaInfoInterval) return;
    fetchMediaInfo(); // 立即获取一次
    mediaInfoInterval = window.setInterval(fetchMediaInfo, 2000);
  }

  function stopMediaInfoPolling() {
    if (mediaInfoInterval) {
      clearInterval(mediaInfoInterval);
      mediaInfoInterval = null;
    }
