  async function simulateShortcut(command: string) {
    try {
      // 关机是破坏性操作：需要 2 秒内再次触发确认
      if (command === "system_shutdown") {
        const now = Date.now();
        if (shutdownConfirmUntil && now < shutdownConfirmUntil) {
          shutdownConfirmUntil = null;
          showToast(t("toast_shutting_down"), "info");
        } else {
          shutdownConfirmUntil = now + 2000;
          showToast(t("toast_shutdown_confirm"), "warning");
          return;
        }
      } else {
        // 任何其他快捷键会取消关机确认
        shutdownConfirmUntil = null;
      }

      if (command === "osk") {
        // 屏幕键盘：根据用户设置选择 TabTip 或 osk.exe
        await invoke("open_on_screen_keyboard", { useOsk: useOskKeyboard });
      } else {
        await invoke("simulate_shortcut", { shortcut: command });
      }
    } catch (e) {
      console.error("快捷键模拟失败:", e);
    }
  }

  async function loadGames() {
    try {
      const loadedGames = await invoke<Game[]>("get_games");
      games = loadedGames;
      // 自动加载封面
      if (loadedGames.length > 0) {
        loadGameCovers(loadedGames);
      }
    } catch (e) {
      console.error("加载游戏失败:", e);
    }
  }

  async function loadGameCovers(gameList?: Game[]) {
    const targetGames = (gameList || games).filter(
      (game) => !game.cover && !gameCovers[game.id],
    );
    if (targetGames.length === 0) return;

    // 并发加载封面（限制同时请求数，避免串行逐个加载导致前端卡住）
    const CONCURRENCY = 5;
    let cursor = 0;

    async function worker() {
      while (cursor < targetGames.length) {
        const game = targetGames[cursor++];
        try {
          const result = await invoke<{
            success: boolean;
            data: string | null;
          }>("fetch_game_cover", {
            gameId: game.id,
            steamAppId: game.steamAppId || null,
            gameName: game.name,
            gamePath: game.path || null,
            installLocation: game.installLocation || null,
            source: game.source || null,
          });
          if (result.success && result.data) {
            gameCovers[game.id] = result.data;
            gameCovers = { ...gameCovers };
          }
        } catch (e) {
          // 静默失败
        }
      }
    }

    const workers = Array.from(
      { length: Math.min(CONCURRENCY, targetGames.length) },
      () => worker(),
    );
    await Promise.allSettled(workers);
  }

  async function importSteamGames() {
    if (isImportingSteam) return;
    isImportingSteam = true;
    try {
      const newGames = await invoke<Game[]>("import_steam_games");
      if (newGames && newGames.length > 0) {
        // loadGames 内部已包含封面加载逻辑
        await loadGames();
        showToast(
          t("toast_imported_games")
            .replace("{count}", String(newGames.length))
            .replace("{platform}", "Steam"),
          "success",
        );
      } else {
        showToast(t("toast_no_new_steam"), "info");
      }
    } catch (e) {
      console.error("导入 Steam 游戏失败:", e);
      showToast(t("toast_steam_import_failed"), "error");
    }
    isImportingSteam = false;
  }

  async function importPlatformGames(
    platform: string,
    displayName: string,
    setLoading: (v: boolean) => void,
  ) {
    setLoading(true);
    try {
      const newGames = await invoke<Game[]>("import_platform_games", {
        platform,
      });
      if (newGames && newGames.length > 0) {
        await loadGames();
        showToast(
          t("toast_imported_platform_games")
            .replace("{count}", String(newGames.length))
            .replace("{platform}", displayName),
          "success",
        );
      } else {
        showToast(
          t("toast_no_new_games").replace("{platform}", displayName),
          "info",
        );
      }
    } catch (e) {
      console.error(`导入 ${displayName} 游戏失败:`, e);
      showToast(
        t("toast_import_failed").replace("{platform}", displayName),
        "error",
      );
    }
    setLoading(false);
  }

