  // ====== 全局性能配置 ======

  /**
   * 同步当前设置到绑定场景（双向绑定）
   * 
   * 当用户修改 TDP、风扇模式等设置时，自动更新当前电源状态绑定的场景
   * 
   * @param updates - 要同步的设置更新对象
   */
  async function syncSettingsToBindingProfile(updates: Partial<import("./lib/types").PerformanceProfile>) {
    // 获取当前电源状态对应的绑定场景 ID
    const isAc = getStablePowerProfileIsAcConnected();
    const bindingProfileId = isAc ? acProfileId : batteryProfileId;
    
    if (!bindingProfileId) {
      // 没有绑定场景，不需要同步
      return;
    }
    
    // 查找绑定场景
    const profile = performanceProfiles.find(p => p.id === bindingProfileId);
    if (!profile) {
      return;
    }
    
    // 合并更新
    const updatedProfile = { ...profile, ...updates };
    
    try {
      await invoke("update_performance_profile", { profile: updatedProfile });
      
      // 更新本地列表
      performanceProfiles = performanceProfiles.map(p => 
        p.id === updatedProfile.id ? updatedProfile : p
      );
      
      console.log(`[Settings] 已同步到绑定场景: ${profile.name} (${isAc ? "插电" : "电池"})`);
    } catch (e) {
      console.error("同步设置到绑定场景失败:", e);
    }
  }

  /** 保存 TDP 到设置文件（并同步到绑定场景） */
  async function saveTdpConfig() {
    const tdpValue = finalTdp !== null ? finalTdp : 0;
    try {
      await invoke("save_settings", { settings: { tdp: tdpValue, tdp_boost: tdpBoostWatts, tdp_fppt: tdpFpptWatts } });
      const tdpStr = tdpValue === 0 ? "无限制" : `${tdpValue}W`;
      console.log(`[Settings] 已保存 TDP: ${tdpStr}, Boost: ${tdpBoostWatts === 0 ? '自动' : tdpBoostWatts + 'W'}, FPPT: ${tdpFpptWatts === 0 ? '自动' : tdpFpptWatts + 'W'}`);
      
      // 同步到绑定场景
      syncSettingsToBindingProfile({ tdp: tdpValue || undefined, tdp_boost: tdpBoostWatts, tdp_fppt: tdpFpptWatts });
    } catch (e) {
      console.error("保存 TDP 配置失败:", e);
    }
  }

  /** 设置短时功耗 (SPPT) */
  async function applyTdpBoost(value: number) {
    tdpBoostWatts = value;
