  /** 保存风扇模式到 settings.json（并同步到绑定场景） */
  async function saveFanModeSetting(modeIndex: number) {
    if (!fanControlAvailable) return;
    try {
      await invoke("save_settings", {
        settings: { fan_mode: modeIndex },
      });
      const modes = ["静音", "平衡", "性能", "狂暴", "自动"];
      console.log(`[Settings] 已保存风扇模式: ${modes[modeIndex] || "未知"}`);
      
      // 同步到绑定场景
      syncSettingsToBindingProfile({ fan_mode: modeIndex });
