  async function toggleAutostart() {
    try {
      const newValue = !autostartEnabled;
      await invoke("set_autostart_enabled", { enabled: newValue });
      // 设置成功后，再次从系统验证状态
      const actualStatus = await invoke<boolean>("sync_autostart_status");
      autostartEnabled = actualStatus;

      if (actualStatus === newValue) {
        showToast(
          newValue
            ? t("toast_autostart_on")
            : t("toast_autostart_off"),
          "success",
        );
      } else {
        // 状态不一致，可能创建失败
        showToast(
          t("toast_autostart_set_failed") + ": 任务计划状态异常",
          "error",
          5000,
        );
      }
      // 独立保存 autostart
      await invoke("save_settings", {
        settings: { autostart: autostartEnabled },
      });
    } catch (e: any) {
      console.error("设置自动启动失败:", e);
      // 提取错误信息的第一行作为 toast 显示
      const errorStr = String(e);
      const firstLine = errorStr.split("\n")[0];
      showToast(firstLine, "error", 6000);
    }
  }

  // 同步开机自启状态（确保 UI 与系统任务计划一致）
  async function syncAutostartStatus() {
    try {
      const actualStatus = await invoke<boolean>("sync_autostart_status");
