  // 切换兼容性输入隔离
  async function toggleInputIsolation() {
    console.log("[HidHide] toggleInputIsolation 被调用", {
      inputIsolationEnabled,
      hidhideDriverInstalled,
      hidhideHasInstaller,
    });

    // 如果驱动未安装，先弹出安装程序
    if (!hidhideDriverInstalled) {
