        settings: { input_isolation_enabled: inputIsolationEnabled },
      });
      playSound("success", soundEnabled);
      if (inputIsolationEnabled) {
        showToast(t("toast_compat_isolation_on"), "success");
      } else {
        showToast(t("toast_compat_isolation_off"), "info");
      }
    } catch (e) {
      // 回滚状态
      inputIsolationEnabled = !inputIsolationEnabled;
      showToast(
        t("toast_isolation_error")
          .replace("{message}", t("toast_compat_isolation_failed"))
          .replace("{error}", String(e)),
        "error",
      );
    }
  }

