  // 切换按键映射展开状态（已复用 KBM 引擎）
  function toggleButtonMappingExpanded() {
    buttonMappingExpanded = !buttonMappingExpanded;
    if (buttonMappingExpanded) {
      loadKbmProfiles();
    }
  }

  // ==================== 按键映射（复用 KBM 引擎） ====================

  function sortKbmButtons(
    btns: import("./lib/api").KbmGamepadButton[],
  ): import("./lib/api").KbmGamepadButton[] {
    const order = new Map(
      KBM_GAMEPAD_BUTTONS_BY_INDEX.map((b, i) => [b, i] as const),
    );
    return Array.from(new Set(btns)).sort(
      (a, b) => (order.get(a) ?? 999) - (order.get(b) ?? 999),
    );
  }

  function normalizeKbmButtonSource(
    source: import("./lib/api").KbmButtonSource,
  ): import("./lib/api").KbmGamepadButton[] {
    const arr = Array.isArray(source) ? source : [source];
    return sortKbmButtons(arr);
  }

  function formatKbmButtonSource(source: import("./lib/api").KbmButtonSource): string {
    const arr = normalizeKbmButtonSource(source);
    return arr.map((b) => getKbmButtonLabel(b)).join(" + ");
  }

  function openButtonMappingDialog() {
    const profile = getSelectedKbmProfile();
    if (!profile) {
      showToast(t("mapping_no_profiles"), "info");
      return;
    }

    stopButtonMappingKeysCapture();
    buttonMappingGamepadCaptureCountdown = 0;

    buttonMappingDialog = {
      profile_id: profile.id,
      source_buttons: [],
      keys: "",
      action_type: "tap",
      turbo_rate_hz: 15,
      enabled: true,
    };

    // 尝试聚焦窗口（避免某些情况下输入未被捕获）
    invoke("focus_panel_window").catch((e) => console.warn("focus_panel_window failed:", e));
  }

  function cancelButtonMappingDialog() {
    stopButtonMappingKeysCapture();
    buttonMappingGamepadCaptureCountdown = 0;
    buttonMappingDialog = null;
  }

  function startButtonMappingGamepadCapture() {
    if (!buttonMappingDialog) return;

    // 避免与热键监听冲突

    if (isListeningSummon || isListeningSummon2 || listeningHotkeyType) {
      isListeningSummon = false;
      isListeningSummon2 = false;
      listeningHotkeyType = null;
      listeningCountdown = 0;
      tempBinding = null;
      pressedKeys = [];
      heldKeys.clear();
      maxKeys.clear();
      gamepadButtons.clear();
    }

    buttonMappingDialog.source_buttons = [];
    buttonMappingGamepadCaptureCountdown = BUTTON_MAPPING_GAMEPAD_CAPTURE_DURATION;

    invoke("focus_panel_window").catch((e) => console.warn("focus_panel_window failed:", e));
  }

  function stopButtonMappingGamepadCapture() {
    buttonMappingGamepadCaptureCountdown = 0;
  }

  function stopButtonMappingKeysCapture() {
    buttonMappingKeysCaptureActive = false;
    buttonMappingKeysCaptureHeld.clear();
    buttonMappingKeysCaptureMax.clear();
  }

  function startButtonMappingKeysCapture() {
    if (!buttonMappingDialog) return;

    buttonMappingKeysCaptureActive = true;
    buttonMappingKeysCaptureHeld.clear();
    buttonMappingKeysCaptureMax.clear();

    requestAnimationFrame(() => {
      buttonMappingKeysInputEl?.focus();
      buttonMappingKeysInputEl?.select();
    });
  }

  function handleButtonMappingKeysInputKeydown(e: KeyboardEvent) {
    if (!buttonMappingKeysCaptureActive) return;
    if (!e.isTrusted) return;

    e.preventDefault();
    e.stopPropagation();

    if (e.repeat) return;

    const token = kbmKeyEventToToken(e);
    if (!token) return;

    buttonMappingKeysCaptureHeld.add(token);
    buttonMappingKeysCaptureMax.add(token);

    if (buttonMappingDialog) {
      buttonMappingDialog.keys = formatCapturedKeys(buttonMappingKeysCaptureMax);
    }
  }

  function handleButtonMappingKeysInputKeyup(e: KeyboardEvent) {
    if (!buttonMappingKeysCaptureActive) return;
    if (!e.isTrusted) return;

    e.preventDefault();
    e.stopPropagation();

    const token = kbmKeyEventToToken(e);
    if (!token) return;

    buttonMappingKeysCaptureHeld.delete(token);

    // 松开所有键后结束捕获
    if (buttonMappingKeysCaptureHeld.size === 0 && buttonMappingKeysCaptureMax.size > 0) {
      if (buttonMappingDialog) {
        buttonMappingDialog.keys = formatCapturedKeys(buttonMappingKeysCaptureMax);
      }
      stopButtonMappingKeysCapture();
    }
  }

  async function confirmButtonMappingDialog() {
    if (!buttonMappingDialog) return;

    const profile = kbmProfiles.find((p) => p.id === buttonMappingDialog!.profile_id);
    if (!profile) {
      cancelButtonMappingDialog();
      return;
    }

    try {
      const { kbmValidateKeysString } = await import("./lib/api");

      const chord = sortKbmButtons(buttonMappingDialog.source_buttons);
      if (chord.length === 0) throw new Error("no gamepad buttons selected");

      const keys = buttonMappingDialog.keys.trim();
      if (keys.length === 0) throw new Error("no keys selected");

      await kbmValidateKeysString(keys);

      const action: import("./lib/api").KbmAction =
        buttonMappingDialog.action_type === "tap"
          ? { type: "tap", keys }
          : buttonMappingDialog.action_type === "hold"
            ? { type: "hold", keys }
            : {
                type: "turbo",
                keys,
                rate_hz: Math.max(1, Math.min(60, Math.round(buttonMappingDialog.turbo_rate_hz))),
              };

      const source: import("./lib/api").KbmButtonSource =
        chord.length === 1 ? chord[0] : chord;

      const newBinding: import("./lib/api").KbmButtonBinding = {
        source,
        normal: action,
        enabled: buttonMappingDialog.enabled,
      };

      const bindings = Array.isArray(profile.button_bindings) ? [...profile.button_bindings] : [];
      const newKey = normalizeKbmButtonSource(source).join(",");
      const idx = bindings.findIndex((b) => normalizeKbmButtonSource(b.source).join(",") === newKey);

      if (idx >= 0) {
        bindings[idx] = { ...bindings[idx], ...newBinding };
      } else {
        bindings.push(newBinding);
      }

      const updated: import("./lib/api").KbmProfile = { ...profile, button_bindings: bindings };
      updateKbmProfileInState(updated);
      await saveKbmProfile(updated, false);

      showToast(t("toast_mapping_saved"), "success");
      cancelButtonMappingDialog();
    } catch (e) {
      showToast(
        t("toast_mapping_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

  function toggleButtonMappingBindingEnabled(
    profile: import("./lib/api").KbmProfile,
    idx: number,
  ) {
    const bindings = Array.isArray(profile.button_bindings)
      ? [...profile.button_bindings]
      : [];
    if (idx < 0 || idx >= bindings.length) return;

    const cur = bindings[idx];
    const enabled = cur.enabled ?? true;
    bindings[idx] = { ...cur, enabled: !enabled };

    const updated: import("./lib/api").KbmProfile = { ...profile, button_bindings: bindings };
    updateKbmProfileInState(updated);
    void saveKbmProfile(updated);
  }

  function deleteButtonMappingBinding(profile: import("./lib/api").KbmProfile, idx: number) {
    const bindings = Array.isArray(profile.button_bindings)
      ? [...profile.button_bindings]
      : [];
    if (idx < 0 || idx >= bindings.length) return;

    bindings.splice(idx, 1);
    const updated: import("./lib/api").KbmProfile = { ...profile, button_bindings: bindings };
    updateKbmProfileInState(updated);
    void saveKbmProfile(updated);
  }

  // ==================== 手柄→键盘/鼠标映射 (KBM Mapper) ====================

  const KBM_STICK_MODES: import("./lib/api").KbmStickMode[] = ["off", "wasd", "arrows"];

  const KBM_STICK_MODE_LABEL_KEYS: Record<import("./lib/api").KbmStickMode, string> = {
    off: "kbm_stick_off",
    wasd: "kbm_stick_wasd",
    arrows: "kbm_stick_arrows",
  };

  const KBM_ACTION_LABEL_KEYS: Record<
    import("./lib/api").KbmAction["type"] | "none" | "inherit",
    string
  > = {
    none: "kbm_action_none",
    inherit: "kbm_action_inherit",
    tap: "kbm_action_tap",
    hold: "kbm_action_hold",
    turbo: "kbm_action_turbo",
    macro: "kbm_action_macro",
  };

  // 与后端 ui-gamepad-binding button index 保持一致（0..16）
  const KBM_GAMEPAD_BUTTONS_BY_INDEX: import("./lib/api").KbmGamepadButton[] = [
    "a",
    "b",
    "x",
    "y",
    "lb",
    "rb",
    "lt",
    "rt",
    "back",
    "start",
    "ls",
    "rs",
    "dpad_up",
    "dpad_down",
    "dpad_left",
    "dpad_right",
    "guide",
  ];

  function kbmButtonFromUiIndex(
    idx: number,
  ): import("./lib/api").KbmGamepadButton | null {
    if (idx < 0 || idx >= KBM_GAMEPAD_BUTTONS_BY_INDEX.length) return null;
    return KBM_GAMEPAD_BUTTONS_BY_INDEX[idx] || null;
  }

  function getKbmButtonLabel(btn: import("./lib/api").KbmGamepadButton): string {
    const found = kbmAvailableButtons.find(([id]) => id === btn);
    return found ? found[1] : btn;
  }

  function getSelectedKbmProfile(): import("./lib/api").KbmProfile | null {
    if (kbmProfiles.length === 0) return null;
    const idx = Math.max(0, Math.min(kbmProfiles.length - 1, selectedKbmProfileIndex));
    return kbmProfiles[idx] || null;
  }

  function sanitizeKbmStickMode(mode: unknown): import("./lib/api").KbmStickMode {
    return mode === "wasd" || mode === "arrows" || mode === "off" ? mode : "off";
  }

  function sanitizeKbmProfile(
    profile: import("./lib/api").KbmProfile,
  ): import("./lib/api").KbmProfile {
    const sticks = Array.isArray(profile.stick_bindings) ? profile.stick_bindings : [];
    const stick_bindings = sticks.map((b) => {
      const normal = sanitizeKbmStickMode((b as any).normal);
      const shiftedRaw = (b as any).shifted;
      const shifted = shiftedRaw === undefined ? undefined : sanitizeKbmStickMode(shiftedRaw);
      return shifted === undefined ? { ...b, normal } : { ...b, normal, shifted };
    });
    return { ...profile, stick_bindings };
  }

  const KBM_CAPTURE_MODIFIERS = ["Ctrl", "Shift", "Alt", "Win"];

  function formatCapturedKeys(keys: Iterable<string>): string {
    const arr = Array.from(keys);
    arr.sort((a, b) => {
      const aIsMod = KBM_CAPTURE_MODIFIERS.includes(a);
      const bIsMod = KBM_CAPTURE_MODIFIERS.includes(b);
      if (aIsMod && !bIsMod) return -1;
      if (!aIsMod && bIsMod) return 1;
      if (aIsMod && bIsMod) return KBM_CAPTURE_MODIFIERS.indexOf(a) - KBM_CAPTURE_MODIFIERS.indexOf(b);
      return a.localeCompare(b);
    });
    return arr.join("+");
  }

  function kbmKeyEventToToken(e: KeyboardEvent): string | null {
    const keyMap: Record<string, string> = {
      " ": "Space",
      ArrowUp: "Up",
      ArrowDown: "Down",
      ArrowLeft: "Left",
      ArrowRight: "Right",
      Control: "Ctrl",
      Shift: "Shift",
      Alt: "Alt",
      Meta: "Win",
      OS: "Win",
      Escape: "Esc",
      Enter: "Enter",
      Tab: "Tab",
      Backspace: "Backspace",
      Delete: "Delete",
      Insert: "Insert",
      Home: "Home",
      End: "End",
      PageUp: "PageUp",
      PageDown: "PageDown",
      Pause: "Pause",
      CapsLock: "CapsLock",
      NumLock: "NumLock",
      ScrollLock: "ScrollLock",
      PrintScreen: "PrintScreen",
      // Numpad
      Add: "plus",
    };

    // 优先映射表
    let token = keyMap[e.key];

    if (!token) {
      // Function keys
      if (/^F\d{1,2}$/.test(e.key)) {
        token = e.key;
      } else if (e.key.length === 1) {
        token = e.key.toUpperCase();
      } else {
        token = e.key;
      }
    }

    // '+' 作为分隔符，实际按键用 "plus" 代替
    if (token === "+") token = "plus";

    // 不接受无法识别的 key
    if (!token || token === "Unidentified" || token === "Dead") return null;

    return token;
  }

  function updateKbmProfileInState(updated: import("./lib/api").KbmProfile) {
    kbmProfiles = kbmProfiles.map((p) => (p.id === updated.id ? updated : p));
    if (activeKbmProfile?.id === updated.id) {
      activeKbmProfile = updated;
    }
  }

  async function saveKbmProfile(
    updated: import("./lib/api").KbmProfile,
    silent = true,
  ) {
    try {
      const { kbmUpdateProfile } = await import("./lib/api");
      await kbmUpdateProfile(updated);
    } catch (e) {
      console.error("保存映射配置失败:", e);
      if (!silent) {
        showToast(
          t("toast_mapping_failed").replace("{error}", String(e)),
          "error",
        );
      }
    }
  }

  async function loadKbmProfiles() {
    try {
      const {
        kbmGetProfiles,
        kbmGetActiveProfile,
        kbmIsEnabled,
        kbmGetAvailableGamepadButtons,
      } = await import("./lib/api");

      const profiles = await kbmGetProfiles();
      const active = await kbmGetActiveProfile();

      kbmProfiles = profiles.map(sanitizeKbmProfile);
      activeKbmProfile = active ? sanitizeKbmProfile(active) : null;
      kbmEnabled = await kbmIsEnabled();
      kbmAvailableButtons = await kbmGetAvailableGamepadButtons();

      if (activeKbmProfile) {
        const idx = kbmProfiles.findIndex((p) => p.id === activeKbmProfile!.id);
        if (idx >= 0) selectedKbmProfileIndex = idx;
      }
    } catch (e) {
      console.error("加载 KBM 映射配置失败:", e);
    }
  }

  async function createKbmProfile() {
    try {
      const { kbmCreateProfile } = await import("./lib/api");
      const name = `${t("mapping_profile")} ${kbmProfiles.length + 1}`;
      const profile = await kbmCreateProfile(name);
      kbmProfiles = [...kbmProfiles, profile];
      selectedKbmProfileIndex = kbmProfiles.length - 1;
      showToast(t("toast_mapping_created").replace("{name}", name), "success");
      playSound("success", soundEnabled);
    } catch (e) {
      showToast(
        t("toast_mapping_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

  async function deleteKbmProfile(profileId: string) {
    try {
      const { kbmDeleteProfile } = await import("./lib/api");
      const profile = kbmProfiles.find((p) => p.id === profileId);
      await kbmDeleteProfile(profileId);
      kbmProfiles = kbmProfiles.filter((p) => p.id !== profileId);
      if (selectedKbmProfileIndex >= kbmProfiles.length) {
        selectedKbmProfileIndex = Math.max(0, kbmProfiles.length - 1);
      }
      if (activeKbmProfile?.id === profileId) {
        activeKbmProfile = null;
        kbmEnabled = false;
      }
      showToast(
        t("toast_mapping_deleted").replace("{name}", profile?.name || ""),
        "info",
      );
      playSound("success", soundEnabled);
    } catch (e) {
      showToast(
        t("toast_mapping_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

  async function activateKbmProfile(profileId: string) {
    try {
      const { kbmActivateProfile } = await import("./lib/api");
      await kbmActivateProfile(profileId);
      activeKbmProfile = kbmProfiles.find((p) => p.id === profileId) || null;
      kbmEnabled = true;
      showToast(
        t("toast_mapping_activated").replace(
          "{name}",
          activeKbmProfile?.name || "",
        ),
        "success",
      );
      playSound("success", soundEnabled);
    } catch (e) {
      showToast(
        t("toast_mapping_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

  async function deactivateKbmProfile() {
    try {
      const { kbmDeactivate } = await import("./lib/api");
      await kbmDeactivate();
      activeKbmProfile = null;
      kbmEnabled = false;
      showToast(t("toast_mapping_deactivated"), "info");
      playSound("success", soundEnabled);
    } catch (e) {
      showToast(
        t("toast_mapping_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

  // 切换分页可见性
  async function toggleTabVisibility(tabId: string) {
    const currentTabIdBefore = visibleTabs[activeTab]?.id;
    const wasVisible = tabVisibility[tabId];
    tabVisibility[tabId] = !tabVisibility[tabId];

    // 快捷分页有固定位置（最左侧），不参与排序
    if (tabId !== "quick") {
      // 如果是开启分页，将其移动到 tabOrder 末尾（排在设置之前）
      if (!wasVisible) {
        // 从当前位置移除
        tabOrder = tabOrder.filter((id) => id !== tabId);
        // 添加到末尾
        tabOrder = [...tabOrder, tabId];
      }
      // 注意：关闭分页时不改变 tabOrder，保持其位置以便下次开启时恢复
    }

    // 切换后在新的 tabs 列表中找到相同 id 的索引（保持当前分页不变）
    // 在设置页面时抑制滚动，避免滚动条跳到顶部
    if (currentTabIdBefore === "settings") {
      suppressScrollOnTabUpdate = true;
    }
    tick().then(() => {
      const newIndex = visibleTabs.findIndex(
        (t) => t.id === currentTabIdBefore,
      );
      if (newIndex >= 0) activeTab = newIndex;
    });
    // 保存所有分页可见性设置和排序
    await invoke("save_setting", {
      key: "tab_visibility",
      value: JSON.stringify(tabVisibility),
    }).catch((e) => console.warn("save tab_visibility failed:", e));
    await invoke("save_setting", {
      key: "tab_order",
      value: JSON.stringify(tabOrder),
    }).catch((e) => console.warn("save tab_order failed:", e));
    playSound("click", soundEnabled);
  }

  // ====== 主题切换 ======

  async function setTheme(themeId: string) {
    currentTheme = themeId;
    // 清除之前的自定义主题内联样式
    clearCustomThemeStyles();
    if (themeId.startsWith("custom_")) {
      // 自定义主题：设置 data-theme 为 steam 作为基础，然后覆盖 CSS 变量
      const customId = themeId.replace("custom_", "");
      const theme = customThemes.find((t) => t.id === customId);
      if (theme?.variables) {
        document.documentElement.setAttribute("data-theme", "steam");
        applyCustomThemeVariables(theme.variables);
      } else {
        // 尝试从后端加载
        try {
          const data: any = await invoke("load_custom_theme", { id: customId });
          if (data?.variables) {
            document.documentElement.setAttribute("data-theme", "steam");
            applyCustomThemeVariables(data.variables);
          }
        } catch {
          document.documentElement.setAttribute("data-theme", "steam");
        }
      }
    } else {
      document.documentElement.setAttribute("data-theme", themeId);
    }
    // 独立保存 theme
    await invoke("save_settings", { settings: { theme: themeId } }).catch(
      () => {},
    );
  }

  function applyCustomThemeVariables(variables: Record<string, string>) {
    const style = document.documentElement.style;
    for (const [key, value] of Object.entries(variables)) {
      if (key.startsWith("--")) {
        style.setProperty(key, value);
      }
    }
  }

  function clearCustomThemeStyles() {
    const style = document.documentElement.style;
    // 移除所有以 -- 开头的内联样式属性
    const propsToRemove: string[] = [];
    for (let i = 0; i < style.length; i++) {
      const prop = style[i];
      if (prop.startsWith("--")) {
        propsToRemove.push(prop);
      }
    }
    for (const prop of propsToRemove) {
      style.removeProperty(prop);
    }
  }

  async function loadCustomThemes() {
    try {
      const list: any[] = await invoke("list_custom_themes");
      customThemes = list.map((t) => ({
        id: t.id || "",
        name: t.name || t.id || "",
        variables: t.variables || {},
      }));
    } catch {
      customThemes = [];
    }
  }

  async function importCustomTheme() {
    try {
      const { open } = await import("@tauri-apps/plugin-dialog");
      const selected = await open({
        filters: [{ name: "KoPanel 主题", extensions: ["json", "css"] }],
        title: "导入 KoPanel 主题",
      });
      if (!selected) return;
      const filePath = typeof selected === "string" ? selected : (selected as any).path;
      if (!filePath) return;
      const data: any = await invoke("import_custom_theme_file", { filePath });
      if (!data?.variables) {
        showToast("无法解析主题文件", "error");
        return;
      }
      // 生成唯一 ID
      const id = "user_" + Date.now().toString(36);
      const name = data.name || "导入的主题";
      await invoke("save_custom_theme", { id, name, variables: data.variables });
      await loadCustomThemes();
      setTheme("custom_" + id);
      showToast(`已导入主题: ${name}`, "success");
    } catch (e: any) {
      showToast(e?.toString() || "导入失败", "error");
    }
  }

  async function deleteCustomTheme(id: string) {
    try {
      await invoke("delete_custom_theme", { id });
      await loadCustomThemes();
      if (currentTheme === "custom_" + id) {
        setTheme("steam");
      }
      showToast("已删除自定义主题", "success");
    } catch (e: any) {
      showToast(e?.toString() || "删除失败", "error");
    }
  }

  function cycleTheme(direction: number) {
    const currentIndex = COLOR_THEMES.findIndex((t) => t.id === currentTheme);
    let newIndex = currentIndex + direction;
    if (newIndex < 0) newIndex = COLOR_THEMES.length - 1;
    if (newIndex >= COLOR_THEMES.length) newIndex = 0;
    setTheme(COLOR_THEMES[newIndex].id);
  }

  // ====== 语言切换 ======
  const LANGUAGES: Locale[] = ["zh", "en", "pt-BR", "ru", "de"];
  const LANGUAGE_LABELS: Record<Locale, string> = {
    zh: "简体中文",
    en: "English",
    "pt-BR": "Português",
    ru: "Русский",
    de: "Deutsch",
  };

  async function changeLanguage(locale: Locale) {
    currentLanguage = locale;
    setLocale(locale);
    // 保存语言设置
    try {
      await invoke("save_settings", {
        settings: { language: locale },
      });
      // 同步语言到 OSD 窗口
      if (osdType === "builtin") {
        await invoke("set_osd_language", { language: locale });
      }
    } catch (e) {
      console.error("保存语言设置失败:", e);
    }
  }

  function cycleLanguage(direction: number) {
    const currentIndex = LANGUAGES.indexOf(currentLanguage);
    let newIndex = currentIndex + direction;
    if (newIndex < 0) newIndex = LANGUAGES.length - 1;
    if (newIndex >= LANGUAGES.length) newIndex = 0;
    changeLanguage(LANGUAGES[newIndex]);
  }

  // 注意：所有设置现在都是独立保存的，每个设置只保存自己的字段，不会影响其他设置
  // - theme: 在 setTheme() 和主题选择器中保存
  // - language: 在 changeLanguage() 中保存
  // - sound_enabled: 在 toggleSound() 中保存
  // - autostart: 在 toggleAutostart() 和 syncAutostartStatus() 中保存
  // - start_minimized: 在 toggleStartMinimized() 中保存
  // - panel_width: 在滑块拖动结束后保存
  // - font_size: 在滑块拖动结束后保存
  // - 其他设置均在各自的 toggle/set 函数中独立保存

  /**
   * 使用 get_initial_settings 结果初始化 UI（主题、语言、TDP、面板宽度等），
   * 避免重复调用 load_settings 造成额外延迟。
   */
  function applyUiSettingsFromInitial(settings: any) {
    console.log(
      "[Theme] applyUiSettingsFromInitial 收到 theme =",
      settings.theme,
    );
    // 主题
    if (settings.theme && typeof settings.theme === "string" && settings.theme.startsWith("custom_")) {
      console.log("[Theme] 应用自定义主题:", settings.theme);
      currentTheme = settings.theme;
      document.documentElement.setAttribute("data-theme", "steam");
      // 异步加载自定义主题变量
      loadCustomThemes().then(() => setTheme(settings.theme));
    } else if (
      settings.theme &&
      COLOR_THEMES.some((t: any) => t.id === settings.theme)
    ) {
      console.log("[Theme] 应用主题:", settings.theme);
      currentTheme = settings.theme;
      document.documentElement.setAttribute("data-theme", settings.theme);
    } else {
      console.log("[Theme] 主题无效或未设置，使用默认 steam");
      currentTheme = "steam";
      document.documentElement.setAttribute("data-theme", "steam");
    }
    // 语言
    if (settings.language && LANGUAGES.includes(settings.language)) {
      currentLanguage = settings.language;
      setLocale(settings.language);
    }
    // 音效
    if (
      settings.sound_enabled !== undefined &&
      settings.sound_enabled !== null
    ) {
      soundEnabled = settings.sound_enabled;
    }
    // TDP 范围
    if (settings.tdp_min !== undefined && settings.tdp_min !== null) {
      tdpMin = settings.tdp_min;
    }
    if (settings.tdp_max !== undefined && settings.tdp_max !== null) {
      tdpMax = settings.tdp_max;
    }
    if (
      settings.tdp_presets &&
      Array.isArray(settings.tdp_presets) &&
      settings.tdp_presets.length > 0
    ) {
      customTdpPresets = settings.tdp_presets;
    }
    // TDP 值恢复（必须在 customTdpPresets 设置之后）
    if (settings.tdp !== undefined && settings.tdp !== null && settings.tdp > 0) {
      finalTdp = settings.tdp;
      tdpWatts = settings.tdp; // 同步滑块显示值
      // 直接计算预设列表（与 tdpPresetLevels 派生值逻辑一致）
      const sortedPresets = [...customTdpPresets].sort((a, b) => a - b);
      const presetIdx = sortedPresets.indexOf(settings.tdp);
      if (presetIdx >= 0) {
        tdpIndex = presetIdx;
      }
      console.log(`[Init] 恢复 TDP 设置: ${settings.tdp}W, index=${presetIdx >= 0 ? presetIdx : 'custom'}`);
    } else {
      // TDP 为 0 或 null 表示无限制
      finalTdp = null;
      tdpWatts = tdpMax; // 无限制时显示最大值
      // "unlimited" 选项在列表末尾
      const sortedPresets = [...customTdpPresets].sort((a, b) => a - b);
      tdpIndex = sortedPresets.length; // 指向 "unlimited"
      console.log(`[Init] TDP 未设置或无限制, index=${tdpIndex}`);
    }
    // 短时功耗 (SPPT) 恢复
    if (settings.tdp_boost != null && settings.tdp_boost > 0) {
      tdpBoostWatts = settings.tdp_boost;
      invoke("set_tdp_boost", { boostWatts: settings.tdp_boost }).catch(() => {});
      console.log(`[Init] 恢复短时功耗(SPPT): ${settings.tdp_boost}W`);
    }
    // 瞬时功耗 (FPPT) 恢复
    if (settings.tdp_fppt != null && settings.tdp_fppt > 0) {
      tdpFpptWatts = settings.tdp_fppt;
      invoke("set_tdp_fppt", { fpptWatts: settings.tdp_fppt }).catch(() => {});
      console.log(`[Init] 恢复瞬时功耗(FPPT): ${settings.tdp_fppt}W`);
    }
    // 面板宽度
    if (settings.panel_width !== undefined && settings.panel_width !== null) {
      console.log(
        "[PanelWidth] 收到 settings.panel_width =",
        settings.panel_width,
      );
      panelWidth = Math.max(20, Math.min(40, settings.panel_width));
      console.log("[PanelWidth] 应用后 panelWidth =", panelWidth);
      // 只需调用一次 set_panel_width，避免重复 RPC
      invoke("set_panel_width", { widthPercent: panelWidth }).catch((e) => console.warn("set_panel_width failed:", e));
    } else {
      console.log(
        "[PanelWidth] settings.panel_width 未设置，使用默认值 panelWidth =",
        panelWidth,
      );
    }
    // 字体大小
    if (settings.font_size !== undefined && settings.font_size !== null) {
      fontSize = Math.max(80, Math.min(200, settings.font_size));
      document.documentElement.style.setProperty(
        "--font-scale",
        String(fontSize / 100),
      );
    }
    // 手势 / 失焦相关
    if (settings.gesture_enabled !== undefined) {
      gestureEnabled = settings.gesture_enabled;
    }
    if (settings.blur_hide_enabled !== undefined) {
      blurHideEnabled = settings.blur_hide_enabled;
    }
    if (settings.no_focus_mode !== undefined) {
      noFocusMode = settings.no_focus_mode;
    }
    if (settings.focus_return_enabled !== undefined) {
      focusReturnEnabled = settings.focus_return_enabled;
    }
    if (settings.fullscreen_mode !== undefined) {
      fullscreenMode = settings.fullscreen_mode;
    }
    if (settings.safe_mode !== undefined) {
      safeMode = settings.safe_mode;
    }
    if (settings.suspend_on_sleep !== undefined) {
      suspendOnSleep = settings.suspend_on_sleep;
    }
    // 输入隔离
    if (
      settings.input_isolation_enabled !== undefined &&
      settings.input_isolation_enabled !== null
    ) {
      inputIsolationEnabled = settings.input_isolation_enabled;
      invoke("hidhide_set_enabled", { enabled: inputIsolationEnabled }).catch(
        (e) => console.error("应用 HidHide 失败:", e),
      );
    }
    if (
      settings.xinput_isolation_enabled !== undefined &&
      settings.xinput_isolation_enabled !== null
    ) {
      xinputIsolationEnabled = settings.xinput_isolation_enabled;
      invoke("xinput_set_enabled", { enabled: xinputIsolationEnabled }).catch(
        () => {},
      );
    }
    // gilrs 检测
    if (
      settings.gilrs_detection_enabled !== undefined &&
      settings.gilrs_detection_enabled !== null
    ) {
      gilrsDetectionEnabled = settings.gilrs_detection_enabled;
    }
    // 振动
    if (
      settings.vibration_intensity !== undefined &&
      settings.vibration_intensity !== null
    ) {
      vibrationIntensity = settings.vibration_intensity;
    }

    // 全局扳机死区（0-255）
    if (
      settings.trigger_deadzone_lt !== undefined &&
      settings.trigger_deadzone_lt !== null
    ) {
      triggerDeadzoneLt = Math.max(0, Math.min(255, settings.trigger_deadzone_lt));
    }
    if (
      settings.trigger_deadzone_rt !== undefined &&
      settings.trigger_deadzone_rt !== null
    ) {
      triggerDeadzoneRt = Math.max(0, Math.min(255, settings.trigger_deadzone_rt));
    }

    // 摇杆映射模式（关闭 / WASD / 方向键）
    if (settings.left_stick_mode !== undefined && settings.left_stick_mode !== null) {
      leftStickMode = sanitizeKbmStickMode(settings.left_stick_mode);
    }
    if (settings.right_stick_mode !== undefined && settings.right_stick_mode !== null) {
      rightStickMode = sanitizeKbmStickMode(settings.right_stick_mode);
    }

    if (
      settings.gamepad_vibration_intensity &&
      Array.isArray(settings.gamepad_vibration_intensity)
    ) {
      for (
        let i = 0;
        i < Math.min(settings.gamepad_vibration_intensity.length, 4);
        i++
      ) {
        gamepadVibrationIntensity[i] = settings.gamepad_vibration_intensity[i];
        invoke("set_gamepad_vibration", {
          gamepadIndex: i,
          intensity: gamepadVibrationIntensity[i],
        }).catch((e) => console.warn("set_gamepad_vibration failed:", e));
      }
    }
    // 触摸屏 / 光学鼠标
    if (settings.touchscreen_disabled !== undefined) {
      touchscreenEnabled = !settings.touchscreen_disabled;
    }
    if (settings.optical_mouse_disabled !== undefined) {
      opticalMouseEnabled = !settings.optical_mouse_disabled;
    }
    // 开机自启 / 最小化启动
    if (settings.autostart !== undefined) {
      autostartEnabled = settings.autostart;
    }
    if (settings.start_minimized !== undefined) {
      startMinimized = settings.start_minimized;
    }
    // 旋转屏幕和平板模式不保存设置，仅在切换时触发，启动时从后端读取实际状态
    loadScreenRotationAndTabletMode();
    // 布局控制
    if (settings.hide_tab_bar !== undefined) {
      hideTabBar = settings.hide_tab_bar;
    }
    if (settings.hide_status_bar !== undefined) {
      hideStatusBar = settings.hide_status_bar;
    }
    // 屏幕键盘类型
    if (settings.use_osk_keyboard !== undefined) {
      useOskKeyboard = settings.use_osk_keyboard;
    }
    invoke("set_osk_keyboard_mode", { useOsk: useOskKeyboard }).catch(
      () => {},
    );
    // 浮动 GPU 频率优化
    if (settings.float_gpu_enabled !== undefined) {
      floatGpuEnabled = settings.float_gpu_enabled;
    }
    // 核心调度策略
    if (settings.core_scheduling !== undefined && settings.core_scheduling !== null) {
      coreSchedulingMode = settings.core_scheduling;
    }
    // 快捷分页项目（过滤已移除的控件）
    if (settings.quick_items && Array.isArray(settings.quick_items)) {
      quickItems = settings.quick_items.filter(
        (it: QuickItem) =>
          !(
            (it?.tab_id === "display" &&
              it?.item_id === "adaptive_brightness") ||
            (it?.tab_id === "performance" &&
              (it?.item_id === "gpu_clock" || it?.item_id === "gpu_float"))
          ),
      );
    }
    // 额外快捷键绑定（type="none" 表示解绑）
    const bindingSetters: Record<string, (v: SummonBinding) => void> = {
      osd_toggle_binding: (v) => (osdToggleBinding = v),
      tdp_up_binding: (v) => (tdpUpBinding = v),
      tdp_down_binding: (v) => (tdpDownBinding = v),
      show_desktop_binding: (v) => (showDesktopBinding = v),
      desktop_mode_binding: (v) => (desktopModeBinding = v),
      bigscreen_mode_binding: (v) => (bigscreenModeBinding = v),
      steam_bigpicture_binding: (v) => (steamBigpictureBinding = v),
      hibernate_binding: (v) => (hibernateBinding = v),
      sleep_binding: (v) => (sleepBinding = v),
      shutdown_binding: (v) => (shutdownBinding = v),
      task_manager_binding: (v) => (taskManagerBinding = v),
      mouse_sim_toggle_binding: (v) => (mouseSimToggleBinding = v),
      screenshot_binding: (v) => (screenshotBinding = v),
      record_toggle_binding: (v) => (recordToggleBinding = v),
      gyro_toggle_binding: (v) => (gyroToggleBinding = v),
      gyro_hold_binding: (v) => (gyroHoldBinding = v),
      gyro_hold_binding_2: (v) => (gyroHoldBinding2 = v),
      gyro_hold_binding_3: (v) => (gyroHoldBinding3 = v),
      alt_tab_binding: (v) => (altTabBinding = v),
    };

    for (const [field, setter] of Object.entries(bindingSetters)) {
      const val = (settings as any)[field] as SummonBinding | null | undefined;
      if (val && val.type !== "none") {
        setter(val);
      }
    }
    // 检查 HidHide / XInput / 自启状态
    checkHidhideStatus();
    checkXinputHookStatus();
    syncAutostartStatus();
  }

  // ====== WiFi/蓝牙控制 ======
  async function loadRadioStatus() {
    try {
      const status = await invoke<{
        wifi_enabled: boolean;
        bluetooth_enabled: boolean;
      }>("get_radio_status");
      wifiEnabled = status.wifi_enabled;
      bluetoothEnabled = status.bluetooth_enabled;
    } catch (e) {
      console.error("获取WiFi/蓝牙状态失败:", e);
    }
  }

  async function toggleWifi() {
    try {
      radioLoading = true;
      const newValue = !wifiEnabled;
      await invoke("set_wifi_enabled", { enabled: newValue });
      wifiEnabled = newValue;
    } catch (e) {
      console.error("切换WiFi失败:", e);
    } finally {
      radioLoading = false;
    }
  }

  async function toggleBluetooth() {
    try {
      radioLoading = true;
      const newValue = !bluetoothEnabled;
      await invoke("set_bluetooth_enabled", { enabled: newValue });
      bluetoothEnabled = newValue;
    } catch (e) {
      console.error("切换蓝牙失败:", e);
    } finally {
      radioLoading = false;
    }
  }

  // ====== 便携热点控制 ======
  async function loadHotspotStatus() {
    try {
      const status = await invoke<{
        enabled: boolean;
        ssid: string;
        client_count: number;
      }>("get_hotspot_status");
      hotspotEnabled = status.enabled;
      hotspotSsid = status.ssid;
      hotspotClientCount = status.client_count;
    } catch (e) {
      console.error("获取热点状态失败:", e);
    }
  }

  async function toggleHotspot() {
    try {
      hotspotLoading = true;
      const newValue = !hotspotEnabled;
      await invoke("set_hotspot_enabled", { enabled: newValue });
      hotspotEnabled = newValue;
      if (newValue) {
        // 开启后刷新状态获取客户端数（使用 safeTimeout 确保组件卸载时清理）
        safeTimeout(loadHotspotStatus, 1000);
      }
    } catch (e) {
      console.error("切换热点失败:", e);
    } finally {
      hotspotLoading = false;
    }
  }

  async function saveHotspotConfig() {
    if (!hotspotNewSsid || hotspotNewPassword.length < 8) {
      return;
    }
    try {
      hotspotLoading = true;
      await invoke("configure_hotspot", {
        ssid: hotspotNewSsid,
        password: hotspotNewPassword,
      });
      hotspotSsid = hotspotNewSsid;
      hotspotConfigMode = false;
      hotspotNewPassword = "";
    } catch (e) {
      console.error("配置热点失败:", e);
    } finally {
      hotspotLoading = false;
    }
  }

