  async function handleResetSettings() {
    // 使用危险操作确认机制（按住5秒）
    if (dangerConfirmId === "reset_settings") {
      // 已在确认中，不重复触发
      return;
    }
    startDangerConfirm("reset_settings", async () => {
      try {
        const result = await invoke<{ success: boolean; message?: string; error?: string }>("reset_all_settings");
        if (result.success) {
          showToast(t("reset_settings_done"), "success", 3000);
          // 延迟后重启应用
          setTimeout(async () => {
            try {
              await invoke("exit_app");
            } catch {
              // 忽略退出错误
            }
          }, 1500);
        } else {
          showToast(result.error || t("toast_operation_failed"), "error");
        }
      } catch (e) {
        console.error("重置配置失败:", e);
        showToast(String(e), "error");
      }
    });
  }

