  // 应用核心模式（大小核切换）
  // p_only / e_only 模式需要二次确认，防止误触导致电脑卡死
  async function applyCoreMode() {
    if (!coreTopology?.has_hybrid_cores) return;

    const isDangerous = coreMode === "p_only" || coreMode === "e_only";
    if (isDangerous && coreModeConfirmPending !== coreMode) {
      // 第一次按 A：显示警告，进入待确认状态
      coreModeConfirmPending = coreMode;
      if (coreModeConfirmTimer) clearTimeout(coreModeConfirmTimer);
      coreModeConfirmTimer = setTimeout(() => {
        coreModeConfirmPending = null;
        coreModeConfirmTimer = null;
      }, 5000);
      const modeLabel = t(CORE_MODES.find((m) => m.id === coreMode)?.label as TranslationKey) || coreMode;
      showToast(
        t("toast_core_mode_confirm" as TranslationKey).replace("{mode}", modeLabel),
        "warning",
        5000,
      );
      return;
    }

    // 清除确认状态
    coreModeConfirmPending = null;
    if (coreModeConfirmTimer) { clearTimeout(coreModeConfirmTimer); coreModeConfirmTimer = null; }

    try {
      await invoke("set_core_mode", { mode: coreMode });
      // 保存到设置
      await invoke("save_settings", { settings: { core_mode: coreMode } });
      showToast(
        t("toast_core_mode_switched").replace(
          "{mode}",
          t(CORE_MODES.find((m) => m.id === coreMode)?.label as TranslationKey) ||
            coreMode,
        ),
        "success",
      );
    } catch (e: any) {
      showToast(
        t("toast_core_mode_failed").replace("{error}", String(e)),
        "error",
      );
    }
  }

