  // ====== 电池状态监控 ======

  function getPowerProfileSwitchDebounceMs(isAcConnected: boolean): number {
    return isAcConnected
      ? POWER_PROFILE_SWITCH_TO_AC_DEBOUNCE_MS
      : POWER_PROFILE_SWITCH_TO_BATTERY_DEBOUNCE_MS;
  }

  function getStablePowerProfileIsAcConnected(): boolean {
    return prevAcConnected ?? batteryStatus.is_ac_connected;
  }

  // 加载电池状态
  let batteryStatusInProgress = false;
  async function loadBatteryStatus() {
    if (batteryStatusInProgress) return;
    batteryStatusInProgress = true;
    try {
      const status = await invoke<BatteryStatus>("get_battery_status");

      // Win5 等设备在高负载 / PD 重新协商时可能短暂抖动 ACLineStatus。
      // 仅在状态稳定一段时间后才切换电源场景，避免误把 TDP 改成电池档。
      if (prevAcConnected === null) {
        prevAcConnected = status.is_ac_connected;
        pendingAcConnected = null;
        pendingAcConnectedSince = 0;
      } else if (status.is_ac_connected === prevAcConnected) {
        if (pendingAcConnected !== null) {
          console.log(
            `[Power] 电源状态恢复稳定，取消${pendingAcConnected ? "插电" : "电池"}场景切换`,
          );
          pendingAcConnected = null;
          pendingAcConnectedSince = 0;
        }
      } else {
        const now = Date.now();
        const requiredMs = getPowerProfileSwitchDebounceMs(
          status.is_ac_connected,
        );

        if (pendingAcConnected !== status.is_ac_connected) {
          pendingAcConnected = status.is_ac_connected;
          pendingAcConnectedSince = now;
          console.log(
            `[Power] 检测到候选电源状态切换: ${prevAcConnected ? "插电" : "电池"} -> ${status.is_ac_connected ? "插电" : "电池"}，开始稳定性确认 (${requiredMs}ms)`,
          );
        } else if (now - pendingAcConnectedSince >= requiredMs) {
          prevAcConnected = status.is_ac_connected;
          pendingAcConnected = null;
          pendingAcConnectedSince = 0;

          if (status.is_ac_connected) {
            showToast(t("toast_power_connected"), "info");
          } else {
            showToast(t("toast_battery_mode"), "warning");
          }

          // 通知后端应用对应电源状态的场景。
          // 后端的 WM_POWERBROADCAST 可能在某些设备上不可靠，这里作为带防抖的备用触发。
          void applyPowerProfile(status.is_ac_connected);
        }
      }

      batteryStatus = status;
    } catch (e) {
      console.error("获取电池状态失败:", e);
    } finally {
      batteryStatusInProgress = false;
    }
  }
  
  // 应用电源状态对应的场景
  async function applyPowerProfile(isAcConnected: boolean) {
    const profileId = isAcConnected ? acProfileId : batteryProfileId;
    if (!profileId) {
      console.log(`[Power] 未绑定${isAcConnected ? "插电" : "电池"}场景，跳过`);
      return;
    }
    
    // 如果插电和电池绑定了相同场景，跳过
    if (acProfileId && batteryProfileId && acProfileId === batteryProfileId) {
      console.log(`[Power] 插电和电池绑定相同场景，跳过`);
      return;
    }
    
    try {
      console.log(`[Power] 电源状态变化，应用${isAcConnected ? "插电" : "电池"}场景: ${profileId}`);
      await invoke("apply_performance_profile", { profileId });
      
      // 刷新设置以同步前端显示
      const settings = await invoke<any>("load_settings");
      if (settings.tdp != null && settings.tdp > 0) {
        finalTdp = settings.tdp;
        tdpWatts = settings.tdp;
        // 更新 TDP 预设索引（如果匹配）
        const presetIdx = tdpPresetLevels.findIndex((p) => p === settings.tdp);
        if (presetIdx >= 0) {
          tdpIndex = presetIdx;
        }
        console.log(`[Power] 已同步 TDP 显示: ${settings.tdp}W`);
      } else {
        finalTdp = null;
        tdpWatts = tdpMax;
        tdpIndex = tdpPresetLevels.length - 1; // "无限制"选项
      }
      if (settings.fan_mode != null) {
        fanModeIndex = settings.fan_mode;
        appliedFanModeIndex = settings.fan_mode;
      }
      // 同步 SPPT/FPPT 显示
      if (settings.tdp_boost != null) tdpBoostWatts = settings.tdp_boost;
      if (settings.tdp_fppt != null) tdpFpptWatts = settings.tdp_fppt;
      if (settings.turbo_boost != null) turboBoostEnabled = settings.turbo_boost;
      if (settings.auto_tdp_enabled != null) autoTdpEnabled = settings.auto_tdp_enabled;
      if (settings.auto_fan_enabled != null) autoFanEnabled = settings.auto_fan_enabled;
      // 更新帧率限制状态
      if (settings.rtss_fps_limit_enabled != null) rtssFpsLimitEnabled = settings.rtss_fps_limit_enabled;
      if (settings.rtss_fps_limit_value != null) rtssFpsLimitValue = settings.rtss_fps_limit_value;
      // 更新活跃核心数
      if (settings.active_cores != null) activeCores = settings.active_cores;
      // 更新 CPU 最大频率
      if (settings.cpu_max_freq != null) {
        cpuFreqLimitEnabled = settings.cpu_max_freq > 0;
        cpuFreqSlider = settings.cpu_max_freq > 0 ? settings.cpu_max_freq : 2500;
      }
    } catch (e) {
      console.error("应用电源场景失败:", e);
    }
  }

  // ========== 更新检查 (简单 GitHub Release 检查) ==========

  // 手动检查更新（显示所有状态提示）
  async function checkForUpdate() {
    if (isCheckingUpdate) return;
    isCheckingUpdate = true;
    try {
      const result = await invoke<{
        has_update: boolean;
        current_version: string;
        latest_version: string | null;
        notes: string | null;
        download_url: string | null;
        portable_url: string | null;
        error: string | null;
      }>("check_for_update");

      if (result.error) {
        showToast(
          t("toast_check_update_failed").replace(
            "{error}",
            result.error,
          ),
          "error",
        );
        return;
      }

      if (result.has_update && result.latest_version) {
        updateCheckResult = {
          has_update: true,
          current_version: result.current_version,
          latest_version: result.latest_version,
          update_info: {
            version: result.latest_version,
            notes: result.notes || t("version_update"),
            pub_date: new Date().toISOString(),
            download_url: result.download_url || "",
            portable_url: result.portable_url || "",
            file_size: 0,
          },
        };
        showToast(
          t("toast_new_version_found").replace(
            "{version}",
            result.latest_version,
          ),
          "info",
        );
      } else {
        updateCheckResult = {
          has_update: false,
          current_version: result.current_version,
        };
        showToast(t("toast_already_latest"), "success");
      }
    } catch (e) {
      showToast(
        t("toast_check_update_failed").replace("{error}", String(e)),
        "error",
      );
    } finally {
      isCheckingUpdate = false;
    }
  }

  // 静默检查更新（仅提示有新版本）
  async function silentCheckUpdate() {
    if (isCheckingUpdate) return;
    isCheckingUpdate = true;
    try {
      const result = await invoke<{
        has_update: boolean;
        current_version: string;
        latest_version: string | null;
        notes: string | null;
        download_url: string | null;
        portable_url: string | null;
