    } finally {
      isCheckingUpdate = false;
    }
  }

  // 下载并安装更新
  async function downloadAndInstallUpdate() {
    if (isDownloadingUpdate) return;

    const url =
      updateCheckResult?.update_info?.download_url ||
      "https://cdn.kobo07.cn/kopanel/KoPanel_latest_x64-setup.exe";
    if (!url) {
      showToast(t("toast_download_url_unavailable"), "error");
      return;
    }

    isDownloadingUpdate = true;
    updateDownloadProgress = 0;

    try {
      const expectedSha256 = updateCheckResult?.update_info?.sha256 || null;
      await invoke<string>("download_and_install_update", { url, expectedSha256 });
      showToast(t("toast_installer_started"), "success");

      // 延迟退出，让安装程序有时间启动
      setTimeout(async () => {
        const { exit } = await import("@tauri-apps/plugin-process");
        await exit(0);
      }, 1500);
    } catch (e) {
      showToast(
        t("toast_download_update_failed").replace("{error}", String(e)),
        "error",
      );
      isDownloadingUpdate = false;
    }
  }

