  // 优化结果类型
  interface OptimizationResult {
    success: boolean;
    message?: string;
    error?: string;
    fallback_settings_uri?: string;
    fallback_settings_name?: string;
    fallback_instruction?: string; // 操作指引
    auto_open_settings?: boolean; // 是否自动打开设置
  }

  async function runSystemOptimization(optimizationId: string) {
    if (optimizationRunning) return;
    optimizationRunning = optimizationId;
    try {
      const result = await invoke<OptimizationResult>(
        "run_system_optimization",
        { optimizationId },
      );

      // 如果需要自动打开设置
      if (result.auto_open_settings && result.fallback_settings_uri) {
        openWindowsSettings(result.fallback_settings_uri);
      }

      optimizationResults[optimizationId] = {
        success: result.success,
        message: result.success
          ? result.message || t("done")
          : result.fallback_instruction || result.error || t("failed"),
        fallbackUri: result.fallback_settings_uri,
        fallbackName: result.fallback_settings_name,
      };
      // 显示通知
      if (result.success) {
        showToast(t("toast_optimize_done"), "success");
      } else {
        showToast(result.error || t("optimize_failed"), "error");
      }
    } catch (e) {
      optimizationResults[optimizationId] = {
        success: false,
        message: String(e),
      };
      showToast(t("toast_optimize_failed"), "error");
    }
    optimizationRunning = null;
  }

  async function loadOptimizationStates() {
    try {
      const states = await invoke<Record<string, boolean>>(
        "get_optimization_states",
      );
      optimizationStates = states;
    } catch (e) {
      console.error("加载优化状态失败:", e);
    }
  }

  async function toggleOptimizationState(optimizationId: string) {
    if (optimizationRunning) return;
    optimizationRunning = optimizationId;
    const newState = !optimizationStates[optimizationId];
    try {
      const result = await invoke<OptimizationResult>(
        "set_optimization_state",
        {
          optimizationId,
          enabled: newState,
        },
      );
      if (result.success) {
        optimizationStates[optimizationId] = newState;
        // 清除之前的错误结果
        delete optimizationResults[optimizationId];
        showToast(
          newState
            ? t("toast_optimization_enabled")
            : t("toast_optimization_disabled"),
          "success",
        );
      } else {
        // 如果需要自动打开设置
        if (result.auto_open_settings && result.fallback_settings_uri) {
          openWindowsSettings(result.fallback_settings_uri);
        }
        // 保存结果和操作指引
        optimizationResults[optimizationId] = {
          success: false,
          message:
            result.fallback_instruction ||
            result.error ||
            t("toast_set_failed"),
          fallbackUri: result.fallback_settings_uri,
          fallbackName: result.fallback_settings_name,
        };
      }
    } catch (e) {
      console.error("切换优化状态失败:", e);
      optimizationResults[optimizationId] = {
        success: false,
        message: String(e),
      };
    }
    optimizationRunning = null;
  }

  async function openWindowsSettings(settingsUri: string) {
    try {
      await invoke("open_windows_settings", { settingsUri });
    } catch (e) {
