  // 开始危险操作确认（按住5秒）
  // onConfirm: 可选的自定义回调，不传时走默认的 runSystemOptimization
  function startDangerConfirm(optimizationId: string, onConfirm?: () => void) {
    if (dangerConfirmId === optimizationId) return;
    if (optimizationRunning) return;

    // 清理可能存在的旧 timer（防止不同 ID 连续调用时 interval 泄漏）
    cancelDangerConfirm();

    dangerConfirmId = optimizationId;
    dangerConfirmCountdown = 5;

    dangerConfirmTimer = setInterval(() => {
      dangerConfirmCountdown -= 1;
      if (dangerConfirmCountdown <= 0) {
        const optId = dangerConfirmId;
        cancelDangerConfirm();
        if (optId) {
          if (onConfirm) {
            onConfirm();
          } else {
            runSystemOptimization(optId);
          }
        }
      }
    }, 1000);
  }

  function cancelDangerConfirm() {
    if (dangerConfirmTimer) {
      clearInterval(dangerConfirmTimer);
      dangerConfirmTimer = null;
    }
    dangerConfirmId = null;
    dangerConfirmCountdown = 0;
  }

