  async function executeGameMenuItem(itemId: string) {
    if (!gameMenuTarget) return;
    const game = gameMenuTarget;
    closeGameMenu();

    switch (itemId) {
      case "edit_game_info":
        // 打开游戏信息编辑（名称和封面）
        editingGameInfo = {
          gameId: game.id,
          name: game.name,
          cover: game.cover || null,
        };
        break;
      case "find_trainer":
        // 查找修改器
        await findTrainerForGame(game);
        break;
      case "optiscaler_toggle":
        await toggleOptiScaler(game);
        break;
      case "ls_toggle":
        await toggleLsEnabled(game);
        break;
    }
