  // Lossless Scaling 自动启动开关
  async function toggleLsEnabled(game: Game) {
    if (lsLoading) return;
    lsLoading = true;
    try {
      // 未安装时，打开文件选择器让用户手动导入路径
      if (!lsInstalled) {
        showToast(t("ls_browse_hint"), "info");
        const selectedPath = await invoke("ls_browse_path") as string | null;
        if (selectedPath) {
          lsInstalled = true;
          showToast(t("ls_path_set"), "success");
        }
        return;
      }
      const newEnabled = !lsEnabled;
      await invoke("ls_set_game_enabled", { gameId: game.id, enabled: newEnabled });
      lsEnabled = newEnabled;
      // 同步本地状态
      games = games.map(g => g.id === game.id ? { ...g, lsEnabled: newEnabled } : g);
      showToast(
        newEnabled
          ? t("ls_enabled_toast")
          : t("ls_disabled_toast"),
        "success"
      );
    } catch (e: any) {
      showToast(String(e), "error");
    } finally {
      lsLoading = false;
    }
  }

  // OptiScaler 一键插帧
  async function toggleOptiScaler(game: Game) {
    if (!game.path || optiScalerLoading) return;
    optiScalerLoading = true;
    try {
      // 检查当前状态
      const status = await invoke("optiscaler_check_status", { gamePath: game.path }) as any;
      if (status.applied) {
        // 已应用 → 移除
        const result = await invoke("optiscaler_remove", { gamePath: game.path }) as any;
        optiScalerApplied = false;
        showToast(result.message, result.success ? "success" : "error");
      } else {
        // 未应用 → 检查缓存，没有则尝试下载
        const cached = await invoke("optiscaler_is_cached") as boolean;
        if (!cached) {
          showToast(t("optiscaler_downloading"), "info");
          try {
            await invoke("optiscaler_download");
          } catch {
            // 下载失败，提示手动导入
            showToast(t("optiscaler_download_failed"), "error");
            const imported = await invoke("optiscaler_import_dll") as boolean;
            if (!imported) {
              return;
            }
            showToast(t("optiscaler_import_success"), "success");
          }
        }
        const result = await invoke("optiscaler_apply", { gamePath: game.path }) as any;
        optiScalerApplied = result.success;
        showToast(result.message, result.success ? "success" : "error");
      }
    } catch (e: any) {
      showToast(String(e), "error");
    } finally {
      optiScalerLoading = false;
    }
  }

  // 打开游戏菜单时检查 OptiScaler 状态
  async function checkOptiScalerStatus(game: Game) {
    if (!game.path) {
      optiScalerApplied = false;
      return;
    }
    try {
      const status = await invoke("optiscaler_check_status", { gamePath: game.path }) as any;
      optiScalerApplied = status.applied;
    } catch {
      optiScalerApplied = false;
    }
  }

  // 打开游戏菜单时检查 Lossless Scaling 状态
  async function checkLsStatus(game: Game) {
    lsEnabled = game.lsEnabled || false;
    try {
      const status = await invoke("ls_check_status") as any;
      lsInstalled = status.installed;
    } catch {
      lsInstalled = false;
    }
  }

  // 处理游戏场景选择器的左右切换
  async function handleGameProfileChange(itemId: string, direction: number) {
    if (!gameMenuTarget) return;
    const game = gameMenuTarget;
    const options = [null, ...performanceProfiles.map(p => p.id)];
    
    if (itemId === "game_ac_profile") {
      const currentIdx = game.acProfileId ? options.indexOf(game.acProfileId) : 0;
      const newIdx = Math.max(0, Math.min(options.length - 1, currentIdx + direction));
      const newProfileId = options[newIdx];
      
      // 更新本地状态
      gameMenuTarget = { ...game, acProfileId: newProfileId || undefined };
      games = games.map(g => g.id === game.id ? { ...g, acProfileId: newProfileId || undefined } : g);
      
      // 保存到后端
      try {
        await invoke("set_game_profile_link", {
          gameId: game.id,
          acProfileId: newProfileId,
          batteryProfileId: game.batteryProfileId || null,
        });
      } catch (e) {
        console.error("保存游戏场景关联失败:", e);
      }
    } else if (itemId === "game_battery_profile") {
      const currentIdx = game.batteryProfileId ? options.indexOf(game.batteryProfileId) : 0;
      const newIdx = Math.max(0, Math.min(options.length - 1, currentIdx + direction));
      const newProfileId = options[newIdx];
      
      // 更新本地状态
      gameMenuTarget = { ...game, batteryProfileId: newProfileId || undefined };
      games = games.map(g => g.id === game.id ? { ...g, batteryProfileId: newProfileId || undefined } : g);
      
      // 保存到后端
      try {
        await invoke("set_game_profile_link", {
          gameId: game.id,
          acProfileId: game.acProfileId || null,
          batteryProfileId: newProfileId,
        });
      } catch (e) {
        console.error("保存游戏场景关联失败:", e);
      }
    }
  }

  async function findTrainerForGame(game: Game) {
    // 使用游戏名称搜索修改器
    const searchName = game.name;
    showToast(
      t("toast_searching_trainer").replace("{name}", searchName),
      "info",
    );

    try {
      const results = await invoke<any[]>("search_trainers", {
        keyword: searchName,
      });
      if (results && results.length > 0) {
        // 找到修改器，直接下载第一个
        const trainer = results[0];
        if (trainer.installed) {
          showToast(
            t("toast_trainer_installed").replace(
              "{name}",
              trainer.trainer_name || trainer.game_name,
            ),
            "success",
          );
          // 可选：直接启动
          if (trainer.local_path) {
            launchTrainer(trainer.local_path);
          }
        } else {
          showToast(
            t("toast_trainer_found_downloading").replace(
              "{name}",
              trainer.trainer_name || trainer.game_name,
            ),
            "info",
          );
          await downloadTrainer(trainer);
        }
      } else {
        showToast(t("toast_trainer_not_found"), "warning");
      }
    } catch (e: any) {
      showToast(
        t("toast_search_trainer_failed").replace(
          "{error}",
          e.toString(),
        ),
        "error",
      );
    }
  }

