  // 保存游戏信息
  async function saveGameInfo() {
    if (!editingGameInfo) return;
    try {
      await invoke("update_game_info", {
        gameId: editingGameInfo.gameId,
        newName: editingGameInfo.name,
        newCover: editingGameInfo.cover,
      });

      // 更新本地状态
      const game = games.find((g) => g.id === editingGameInfo!.gameId);
      if (game) {
        game.name = editingGameInfo.name;
        if (editingGameInfo.cover) {
          game.cover = editingGameInfo.cover;
          // 同步更新封面显示缓存，并清除旧的 URL 缓存
          gameCovers[editingGameInfo.gameId] = editingGameInfo.cover;
          gameCovers = { ...gameCovers };
          coverUrlCache.delete(editingGameInfo.cover);
        }
        games = [...games];
      }
      editingGameInfo = null;
    } catch (e) {
      console.error("保存游戏信息失败:", e);
    }
  }

