  async function refreshConnectedGamepads() {
    try {
      const result = await invoke<{
        gamepads: {
          index?: number;
          name?: string;
          connected?: boolean;
          isActive?: boolean;
          source?: string;
        }[];
        count: number;
      }>("get_connected_gamepads");
      connectedGamepads = result.gamepads
        .filter(
          (gamepad): gamepad is {
            index: number;
            name: string;
            connected?: boolean;
            isActive?: boolean;
            source?: string;
          } =>
            gamepad.source === "xinput" &&
            typeof gamepad.index === "number" &&
            Number.isInteger(gamepad.index) &&
            gamepad.index >= 0 &&
            gamepad.index < gamepadVibrationIntensity.length &&
            typeof gamepad.name === "string",
        )
        .map((gamepad) => ({
          index: gamepad.index,
          name: gamepad.name,
          connected: gamepad.connected ?? true,
          isActive: !!gamepad.isActive,
        }));
    } catch (e) {
      console.error("获取手柄列表失败:", e);
    }
  }

  async function toggleBuiltinGamepad() {
    try {
      const newState = !builtinGamepadDisabled;
      const result = await invoke<{
        success: boolean;
        message?: string;
        error?: string;
      }>("toggle_builtin_gamepad", { enable: !newState });
      if (result.success) {
        builtinGamepadDisabled = newState;
        // 同时启用/禁用索引重映射，让外接手柄自动提升为索引0
        await invoke("set_gamepad_remap", { enabled: newState });
        showToast(
          result.message ||
            (newState
              ? t("toast_builtin_gamepad_disabled")
              : t("toast_builtin_gamepad_enabled")),
          "success",
        );
        // 刷新手柄列表（使用 safeTimeout 确保组件卸载时清理）
        safeTimeout(() => refreshConnectedGamepads(), 500);
      } else {
        showToast(result.error || t("toast_operation_failed_admin"), "error");
      }
    } catch (e: any) {
      console.error("切换掌机手柄状态失败:", e);
      showToast(t("toast_need_admin"), "error");
    }
  }

