  async function updateTrainerDatabase() {
    if (isUpdatingDatabase) return;
    isUpdatingDatabase = true;
    try {
      const result = await invoke<string>("update_trainer_database");
      showToast(result, "success");
      // 更新后自动刷新已安装列表
      await loadInstalledTrainers();
    } catch (e: any) {
      showToast(e.toString(), "error");
    } finally {
      isUpdatingDatabase = false;
    }
  }

  async function downloadTrainer(trainer: any) {
    if (isDownloadingTrainer) return;
    isDownloadingTrainer = true;
    downloadProgress = 0;

    // 监听下载进度
    const unlisten = await listen<number>(
      "trainer-download-progress",
      (event) => {
        downloadProgress = event.payload;
      },
    );

    try {
      await invoke<string>("download_trainer", { trainer });
      showToast(
        t("toast_download_success").replace(
          "{name}",
          trainer.trainer_name || trainer.game_name,
        ),
        "success",
      );
      // 刷新已安装列表
      await loadInstalledTrainers();
      // 刷新搜索结果
      if (trainerSearchKeyword) {
        await searchTrainers();
      }
    } catch (e: any) {
      showToast(
        t("toast_download_failed").replace("{error}", e.toString()),
        "error",
      );
    } finally {
      unlisten();
      isDownloadingTrainer = false;
      downloadProgress = 0;
    }
  }

  async function launchTrainer(exePath: string) {
    try {
      await invoke("launch_trainer", { exePath });
      showToast(t("toast_trainer_started"), "success");
    } catch (e: any) {
      showToast(
        t("toast_launch_failed").replace("{error}", e.toString()),
        "error",
      );
    }
