  async function searchTrainers() {
    if (!trainerSearchKeyword.trim()) {
      trainers = [];
      return;
    }
    if (isSearchingTrainers) return;

    isSearchingTrainers = true;
    try {
      const results = await invoke<any[]>("search_trainers", {
        keyword: trainerSearchKeyword,
      });
      trainers = results;
    } catch (e: any) {
      const errorMsg = e.toString();
      // 如果数据库不存在，自动尝试获取一次
      if (errorMsg.includes("数据库不存在")) {
        showToast(t("toast_fetching_db"), "info");
        try {
          await invoke<string>("update_trainer_database");
          // 获取成功后重新搜索
          const results = await invoke<any[]>("search_trainers", {
            keyword: trainerSearchKeyword,
          });
          trainers = results;
          showToast(t("toast_db_updated"), "success");
        } catch (updateError: any) {
          showToast(
            t("toast_fetch_db_failed").replace(
              "{error}",
              updateError.toString(),
            ),
            "error",
          );
          trainers = [];
        }
      } else {
        showToast(errorMsg, "error");
        trainers = [];
      }
    } finally {
      isSearchingTrainers = false;
    }
  }

