  function isTextEntryElement(
    target: EventTarget | Element | null,
  ): target is HTMLElement {
    if (!(target instanceof HTMLElement)) return false;
    if (target.isContentEditable) return true;
    return (
      target.tagName === "INPUT" ||
      target.tagName === "TEXTAREA" ||
      target.tagName === "SELECT"
    );
  }

  function getActiveTextEntryElement(): HTMLElement | null {
    if (typeof document === "undefined") return null;
    const activeElement = document.activeElement;
    return isTextEntryElement(activeElement) ? activeElement : null;
  }

  function hasFocusedTextEntry(target: EventTarget | null = null): boolean {
    return isTextEntryElement(target) || getActiveTextEntryElement() !== null;
  }

  function blurActiveTextEntry() {
    getActiveTextEntryElement()?.blur();
  }

  // ====== 陀螺仪功能 ======
  const GYRO_DEVICE_TYPES: GyroType[] = [
    "None",
    "BuiltIn",
    "DualSense",
    "DualShock4",
    "UsbImu",
    "XInputGamepad",
  ];
  // 设备名称映射（使用函数而非 const，确保切换语言后翻译更新）
  function getGyroDeviceName(type: GyroType): string {
    switch (type) {
      case "None": return t("off");
      case "BuiltIn": return t("gyro_builtin");
      case "DualSense": return "DualSense";
      case "DualShock4": return "DualShock 4";
      case "UsbImu": return "USB IMU";
      case "XInputGamepad": return t("xinput_gamepad");
      default: return String(type);
    }
  }

  const GYRO_MAPPING_MODES: GyroMappingMode[] = [
    "Disabled",
    "Mouse",
    "RightStick",
  ];

  const VIGEMBUS_DOWNLOAD_URL = "https://github.com/ViGEm/ViGEmBus/releases";

  function getAvailableGyroDeviceIndices(): number[] {
    return gyroAvailableDevices
      .map((d) => GYRO_DEVICE_TYPES.indexOf(d.device_type))
      .filter((idx) => idx >= 0);
  }

  /**
   * 左右切换陀螺仪设备：
   * - 未启用时：立即切换
   * - 启用时：仅设置 pending，需要按 A 确认（避免误触导致重启）
   */
  function stepGyroDevice(direction: number) {
    const available = getAvailableGyroDeviceIndices();
    if (available.length === 0) return;

    const baseIdx = gyroPendingDeviceIndex ?? gyroDeviceIndex;
    let pos = available.indexOf(baseIdx);
    if (pos === -1) pos = 0;

    const nextPos = (pos + direction + available.length) % available.length;
    const nextIdx = available[nextPos];

    if (gyroEnabled) {
      gyroPendingDeviceIndex = nextIdx === gyroDeviceIndex ? null : nextIdx;
      return;
    }

    gyroDeviceIndex = nextIdx;
    gyroDeviceType = GYRO_DEVICE_TYPES[nextIdx];
    gyroPendingDeviceIndex = null;
  }

  async function startGyro() {
    try {
      const config: GyroConfig = {
        enabled: true,
        device_type: gyroDeviceType,
        sensitivity: gyroSensitivity,
        deadzone: gyroDeadzone,
        mapping_mode: gyroMappingMode,
        invert_x: gyroInvertX,
        invert_y: gyroInvertY,
        use_filtering: gyroUseFiltering,
      };

      // 如果是右摇杆模式，先确保 ViGEm 驱动可用并初始化虚拟手柄
      if (gyroMappingMode === "RightStick") {
        // 重新检测驱动，避免状态过期
        try {
          vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
        } catch (e) {
          console.error("[ViGEm] 驱动检测失败:", e);
        }

        // 如果未安装，弹出安装界面（玩家反馈：否则不知道去哪装）
        if (!vigemDriverInstalled) {
          showToast(t("toast_vigem_required"), "warning");
          await installVigemDriver();

          // 安装后再检测一次
          try {
            vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
          } catch (_) {}

          if (!vigemDriverInstalled) {
            return; // 仍未安装，不启动陀螺仪
          }
        }

        try {
          await invoke("vigem_init");
          console.log("[ViGEm] 虚拟手柄已初始化（陀螺仪启动，右摇杆模式）");
        } catch (e) {
          console.error("[ViGEm] 虚拟手柄初始化失败:", e);
          showToast(
            t("toast_vigem_init_failed").replace("{error}", String(e)),
            "error",
          );
          return; // 初始化失败，不启动陀螺仪
        }
      }

      await invoke("gyro_start", { config });
      gyroEnabled = true;

      // 启动数据轮询
      if (!gyroPollInterval) {
        pollGyroData();
      }

      // 设置测试模式标志
      await invoke("gyro_set_test_mode", { enabled: isGyroTestMode });

      showToast(t("toast_gyro_started"), "success");
      console.log("陀螺仪启动成功:", config);
    } catch (e) {
      console.error("启动陀螺仪失败:", e);
      showToast(
        t("toast_launch_failed").replace("{error}", String(e)),
        "error",
      );
      gyroEnabled = false;

      // 如果启动失败且是右摇杆模式，也要关闭 ViGEm（可能已初始化）
      if (gyroMappingMode === "RightStick") {
        try {
          await invoke("vigem_shutdown");
        } catch (_) {}
      }
    }
  }

  async function stopGyro() {
    try {
      await invoke("gyro_stop");
      gyroEnabled = false;
      gyroData = null;

      // 停止轮询
      if (gyroPollInterval) {
        clearTimeout(gyroPollInterval);
        gyroPollInterval = null;
      }

      // 如果当前是右摇杆模式，关闭 ViGEm 虚拟手柄
      if (gyroMappingMode === "RightStick") {
        try {
          await invoke("vigem_shutdown");
          console.log("[ViGEm] 虚拟手柄已关闭（陀螺仪停止）");
        } catch (e) {
          console.error("[ViGEm] 虚拟手柄关闭失败:", e);
        }
      }

      await invoke("gyro_set_test_mode", { enabled: false });

      showToast(t("toast_gyro_stopped"), "info");
      console.log("陀螺仪已停止");
    } catch (e) {
      console.error("停止陀螺仪失败:", e);
    }
  }

  async function updateGyroConfig() {
    if (!gyroEnabled) return;

    try {
      const config: GyroConfig = {
        enabled: true,
        device_type: gyroDeviceType,
        sensitivity: gyroSensitivity,
        deadzone: gyroDeadzone,
        mapping_mode: gyroMappingMode,
        invert_x: gyroInvertX,
        invert_y: gyroInvertY,
        use_filtering: gyroUseFiltering,
      };

      await invoke("gyro_set_config", { config });
      console.log("陀螺仪配置已更新:", config);
    } catch (e) {
      console.error("更新陀螺仪配置失败:", e);
    }
  }

  let gyroPollInProgress = false; // 防止陀螺仪轮询堆积

  async function pollGyroData() {
    if (!gyroEnabled) {
      gyroPollInterval = null;
      return;
    }

    // 防止堆积：如果上一次还没完成，跳过本次
    if (gyroPollInProgress) {
      gyroPollInterval = window.setTimeout(pollGyroData, 100);
      return;
    }
    gyroPollInProgress = true;

    try {
      // 注意：实际的输入处理由后端高频轮询线程完成
      // 这里只是获取数据用于 UI 显示
      const data = await invoke<GyroData>("gyro_get_data");
      gyroData = data;
    } catch (e) {
      console.error("获取陀螺仪数据失败:", e);
    } finally {
      gyroPollInProgress = false;
    }

    // 继续轮询 (10Hz，仅用于 UI 显示)
    gyroPollInterval = window.setTimeout(pollGyroData, 100);
  }

  // 鼠标模拟开关
  async function toggleMouseSim() {
    mouseSimEnabled = !mouseSimEnabled;
    try {
      await invoke("set_mouse_simulation", { enabled: mouseSimEnabled });
      await invoke("save_settings", { settings: { mouse_sim_enabled: mouseSimEnabled } });
      showToast(
        mouseSimEnabled
          ? t("toast_mouse_sim_enabled")
          : t("toast_mouse_sim_disabled"),
        "success",
      );
    } catch (e) {
      console.error("设置鼠标模拟失败:", e);
      mouseSimEnabled = !mouseSimEnabled; // 回滚状态
      showToast(t("toast_mouse_sim_failed"), "error");
    }
  }

  // 桌面模式：回到桌面 + 开启模拟鼠标
  async function activateDesktopMode() {
    try {
      await invoke("show_desktop");
      await invoke("set_mouse_simulation", { enabled: true });
      mouseSimEnabled = true;
      showToast(t("toast_desktop_mode_on"), "success");
    } catch (e) {
      console.error("进入桌面模式失败:", e);
      showToast(t("toast_desktop_mode_failed"), "error");
    }
  }

  // 大屏幕模式：开启大屏幕 + 关闭模拟鼠标
  async function activateBigscreenMode() {
    try {
      await invoke("set_mouse_simulation", { enabled: false });
      mouseSimEnabled = false;
      await invoke("open_bigscreen_window");
      bigscreenWindowOpen = true;
      showToast(t("toast_bigscreen_mode_on"), "success");
    } catch (e) {
      console.error("进入大屏幕模式失败:", e);
      showToast(t("toast_bigscreen_mode_failed"), "error");
    }
  }

  // 切换大屏幕模式
  async function toggleBigscreenMode() {
    try {
      if (bigscreenWindowOpen) {
        await invoke("close_bigscreen_window");
        bigscreenWindowOpen = false;
        showToast(t("toast_bigscreen_mode_off"), "success");
      } else {
        await invoke("set_mouse_simulation", { enabled: false });
        mouseSimEnabled = false;
        await invoke("open_bigscreen_window");
        bigscreenWindowOpen = true;
        showToast(t("toast_bigscreen_mode_on"), "success");
      }
    } catch (e) {
      console.error("切换大屏幕模式失败:", e);
      showToast(t("toast_operation_failed"), "error");
    }
  }

  async function toggleGyro() {
    if (gyroEnabled) {
      await stopGyro();
    } else {
      // 检测可用设备
      if (gyroAvailableDevices.length === 0) {
        showToast(t("toast_no_gyro_device"), "warning");
        return;
      }
      // 若当前选择无效（未选择/设备不可用），则回退到第一个可用设备
      const availableIndices = getAvailableGyroDeviceIndices();
      if (
        gyroDeviceType === "None" ||
        availableIndices.length === 0 ||
        !availableIndices.includes(gyroDeviceIndex)
      ) {
        const nextIndex = availableIndices[0];
        if (nextIndex !== undefined) {
          gyroDeviceIndex = nextIndex;
          gyroDeviceType = GYRO_DEVICE_TYPES[nextIndex];
        }
      }
      // 如果映射模式是禁用，自动设置为鼠标模式
      if (gyroMappingMode === "Disabled") {
        gyroMappingIndex = 1; // Mouse
        gyroMappingMode = "Mouse";
      }
      await startGyro();
    }
  }

  // 应用待确认的陀螺仪设备
  async function applyPendingGyroDevice() {
    if (
      gyroPendingDeviceIndex === null ||
      gyroPendingDeviceIndex === gyroDeviceIndex
    )
      return;

    gyroDeviceIndex = gyroPendingDeviceIndex;
    gyroDeviceType = GYRO_DEVICE_TYPES[gyroPendingDeviceIndex];
    gyroPendingDeviceIndex = null;

    // 如果陀螺仪正在运行，重启以应用新设备
    if (gyroEnabled) {
      await stopGyro();
      if (gyroDeviceType !== "None") {
        await startGyro();
      }
    }
    showToast(
      t("toast_gyro_device_switched").replace(
        "{device}",
        getGyroDeviceName(gyroDeviceType),
      ),
      "success",
    );
  }

  // 检测可用的陀螺仪设备
  async function detectGyroDevices() {
    try {
      const devices = await invoke<GyroDeviceInfo[]>("gyro_detect_devices");
      // 过滤出可用的设备
      gyroAvailableDevices = devices.filter((d) => d.available);
      console.log(
        "[Gyro] 检测到可用设备:",
        gyroAvailableDevices.length,
        gyroAvailableDevices,
      );

      // 启用前允许选择：如果当前选择无效，则默认选中第一个可用设备
      if (!gyroEnabled) {
        const availableIndices = getAvailableGyroDeviceIndices();
        if (
          availableIndices.length > 0 &&
          (gyroDeviceType === "None" || !availableIndices.includes(gyroDeviceIndex))
        ) {
          const nextIndex = availableIndices[0];
          if (nextIndex !== undefined) {
            gyroDeviceIndex = nextIndex;
            gyroDeviceType = GYRO_DEVICE_TYPES[nextIndex];
          }
        }
      }
    } catch (e) {
      console.error("检测陀螺仪设备失败:", e);
      gyroAvailableDevices = [];
    }
  }

  async function toggleGyroTestMode() {
    isGyroTestMode = !isGyroTestMode;

    if (gyroEnabled) {
      try {
        await invoke("gyro_set_test_mode", { enabled: isGyroTestMode });
      } catch (e) {
        console.error("设置陀螺仪测试模式失败:", e);
      }
    }
  }

  async function handleGyroMappingChange(newIndex: number) {
    const oldMode = gyroMappingMode;
    const newMode = GYRO_MAPPING_MODES[newIndex];

    // 右摇杆模式需要 ViGEmBus 驱动。
    // 允许在未启用陀螺仪时预先选择（用于“启用前选择模式”的 UX），
    // 但在运行中切换到 RightStick 时必须先确保驱动可用。
    if (newMode === "RightStick") {
      try {
        vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
      } catch (e) {
        console.error("[ViGEm] 驱动检测失败:", e);
      }

      if (!vigemDriverInstalled && gyroEnabled) {
        showToast(t("toast_vigem_required"), "warning");
        await installVigemDriver();

        try {
          vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
        } catch (_) {}

        if (!vigemDriverInstalled) {
          return; // 驱动仍不可用，不切换模式
        }
      }
    }

    // 只有在陀螺仪运行时才需要初始化/关闭虚拟手柄
    if (gyroEnabled) {
      // 切换到右摇杆模式时，初始化 ViGEm 虚拟手柄
      if (newMode === "RightStick" && oldMode !== "RightStick") {
        try {
          await invoke("vigem_init");
          console.log("[ViGEm] 虚拟手柄已初始化（切换到右摇杆模式）");
        } catch (e) {
          console.error("[ViGEm] 虚拟手柄初始化失败:", e);
          showToast(
            t("toast_vigem_init_failed").replace("{error}", String(e)),
            "error",
          );
          return; // 初始化失败，不切换模式
        }
      }

      // 从右摇杆模式切换到其他模式时，关闭 ViGEm 虚拟手柄
      if (oldMode === "RightStick" && newMode !== "RightStick") {
        try {
          await invoke("vigem_shutdown");
          console.log("[ViGEm] 虚拟手柄已关闭（切换离开右摇杆模式）");
        } catch (e) {
          console.error("[ViGEm] 虚拟手柄关闭失败:", e);
          // 关闭失败不阻止模式切换
        }
      }
    }

    gyroMappingIndex = newIndex;
    gyroMappingMode = newMode;
    await updateGyroConfig();
  }

  // 检测 ViGEm 驱动状态
  async function checkVigemDriver() {
    try {
      vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
    } catch (e) {
      console.error("[ViGEm] 驱动检测失败:", e);
      vigemDriverInstalled = false;
    }
  }

  // 安装 ViGEm 驱动
  async function installVigemDriver() {
    if (vigemInstalling) return;

    vigemInstalling = true;
    showToast(t("toast_vigem_installing"), "info");

    try {
      await invoke("vigem_install_driver");

      // 安装结束后再检测一次，避免误判（安装器可能被取消/失败）
      try {
        vigemDriverInstalled = await invoke<boolean>("vigem_check_driver");
      } catch (_) {
        // 忽略检测失败
      }

      if (vigemDriverInstalled) {
        showToast(t("toast_vigem_success"), "success");
      } else {
        showToast(t("toast_vigem_required"), "warning");
      }
    } catch (e) {
      console.error("[ViGEm] 驱动安装失败:", e);

      const errStr = String(e);
      // 如果没有内置安装器，打开下载页面作为兜底
      if (
        errStr.includes("找不到 ViGEmBus 安装程序") ||
        errStr.includes("ViGEmBus_Setup.exe")
      ) {
        try {
          await invoke("open_external_url", { url: VIGEMBUS_DOWNLOAD_URL });
        } catch (_) {
          showToast(t("toast_download_url_unavailable"), "error");
        }
      }

      showToast(
        t("toast_driver_install_failed").replace("{error}", errStr),
        "error",
      );
    } finally {
      vigemInstalling = false;
    }
  }

  // ====== 后端输入事件（替代前端轮询）======
  type UiKeyPayload = {
    kind: "down" | "up";
    key: string;
  };

  type UiTabPayload = {
    delta: number;
  };

  type UiGamepadBindingPayload = {
    button: number;
  };

  type UiGamepadStatePayload = {
    connected: boolean;
    buttons: boolean[];
    axes: number[];
    left_trigger: number;
    right_trigger: number;
  };

  // ====== v0.9.112：大屏幕窗口手柄导航（前端轮询）======
  // 说明：后端 ui-key 路由在部分机器/场景下会导致大屏幕窗口收不到事件；
  // 这里对大屏幕窗口回退到 0.9.112 的轮询 + 模拟键盘事件逻辑。
  let bigscreenGamepadPollTimer: number | null = null;
  let bigscreenGamepadPollInProgress = false;
  let bigscreenPrevButtons: Record<string, boolean> = {};

  async function pollBigscreenGamepad() {
    // 只在独立大屏幕窗口启用
    if (!isBigscreenWindow) return;

    // 大屏幕窗口模式下，窗口没有焦点时不发送键盘事件（防止游戏中误触发）
    if (!document.hasFocus()) {
      bigscreenGamepadPollTimer = window.setTimeout(pollBigscreenGamepad, 100);
      return;
    }

    // 防止轮询堆积：如果上一次还没完成，跳过本次
    if (bigscreenGamepadPollInProgress) {
      bigscreenGamepadPollTimer = window.setTimeout(pollBigscreenGamepad, 32);
      return;
    }
    bigscreenGamepadPollInProgress = true;

    try {
      const gp: BackendGamepadState = await invoke("get_gamepad_state");

      if (!gp.connected) {
        bigscreenGamepadPollTimer = window.setTimeout(pollBigscreenGamepad, 100);
        return;
      }

      // 正常模式 - 合并 D-Pad 和摇杆的方向输入（防止同时触发导致跳选）
      const axisX = gp.axes[0] || 0;
      const axisY = gp.axes[1] || 0;
      const threshold = 0.5;

      // 合并 D-Pad 按钮和摇杆方向：任意一个触发即为该方向激活
      const dirUp = gp.buttons[12] || axisY < -threshold;
      const dirDown = gp.buttons[13] || axisY > threshold;
      const dirLeft = gp.buttons[14] || axisX < -threshold;
      const dirRight = gp.buttons[15] || axisX > threshold;

      // 方向导航（边缘检测）
      const dispatchDirection = (key: string, current: boolean, prevKey: string) => {
        const prev = bigscreenPrevButtons[prevKey];
        if (current && !prev) {
          window.dispatchEvent(new KeyboardEvent("keydown", { key }));
        } else if (!current && prev) {
          window.dispatchEvent(new KeyboardEvent("keyup", { key }));
        }
        bigscreenPrevButtons[prevKey] = current;
      };

      dispatchDirection("ArrowUp", dirUp, "dir_up");
      dispatchDirection("ArrowDown", dirDown, "dir_down");
      dispatchDirection("ArrowLeft", dirLeft, "dir_left");
      dispatchDirection("ArrowRight", dirRight, "dir_right");

      // A/B/X/Y 按钮独立映射（不与方向冲突）
      const mapActionButton = (index: number, key: string) => {
        const pressed = gp.buttons[index];
        const prev = bigscreenPrevButtons[`btn_${index}`];
        if (pressed && !prev) {
          window.dispatchEvent(new KeyboardEvent("keydown", { key }));
        } else if (!pressed && prev) {
          window.dispatchEvent(new KeyboardEvent("keyup", { key }));
        }
        bigscreenPrevButtons[`btn_${index}`] = pressed || false;
      };

      mapActionButton(0, "a");
      mapActionButton(1, "b");
      mapActionButton(2, "x");
      mapActionButton(3, "y");
    } catch {
      // 忽略错误，继续轮询
    } finally {
      bigscreenGamepadPollInProgress = false;
    }

    bigscreenGamepadPollTimer = window.setTimeout(pollBigscreenGamepad, 32);
  }

  function startBigscreenGamepadPolling() {
    if (!isBigscreenWindow) return;
    if (bigscreenGamepadPollTimer) return;
    bigscreenPrevButtons = {};
    bigscreenGamepadPollTimer = window.setTimeout(pollBigscreenGamepad, 16);
  }

  function dispatchUiKey(payload: UiKeyPayload) {
    const type = payload.kind === "down" ? "keydown" : "keyup";
    window.dispatchEvent(
      new KeyboardEvent(type, {
        key: payload.key,
        bubbles: true,
        cancelable: true,
      }),
    );
  }

  let tabSwitchTimer: number | null = null;
  let pendingTab: number | null = null;

  function handleUiTab(delta: number) {
    if (isBigscreenWindow) return;
    if (!visibleTabs.length) return;
    // 基于最新的 pendingTab（未渲染）或 activeTab（已渲染）计算下一个分页
    const base = pendingTab ?? activeTab;
    const next = (base + delta + visibleTabs.length) % visibleTabs.length;
    pendingTab = next;

    // 快速连按时只渲染最终停留的分页，避免经过重分页（如游戏库）时卡顿
    if (tabSwitchTimer) clearTimeout(tabSwitchTimer);
    tabSwitchTimer = window.setTimeout(() => {
      tabSwitchTimer = null;
      if (pendingTab !== null) {
        const target = pendingTab;
        pendingTab = null;
        switchTab(target);
      }
    }, 60);
  }

  function handleUiGamepadBinding(button: number) {
    // 按键映射（复用 KBM 引擎）- chord 捕获优先
    if (buttonMappingDialog && buttonMappingGamepadCaptureCountdown > 0) {
      const btn = kbmButtonFromUiIndex(button);
      if (!btn) return;
      // 收集 chord（去重 + 按后端索引顺序排序）
      buttonMappingDialog.source_buttons = sortKbmButtons([
        ...buttonMappingDialog.source_buttons,
        btn,
      ]);
      // 有新输入则重置倒计时，方便连续按多个键
      buttonMappingGamepadCaptureCountdown = BUTTON_MAPPING_GAMEPAD_CAPTURE_DURATION;
      return;
    }

    if (!(isListeningSummon || isListeningSummon2 || listeningHotkeyType))
      return;
    if (triggerButtonIndex !== null && button === triggerButtonIndex) return;

    const btnKey = `btn_${button}`;
    const now = Date.now();
    if (now - (lastBindingKeyTime[btnKey] || 0) < BINDING_DEBOUNCE_MS) return;
    lastBindingKeyTime[btnKey] = now;

    gamepadButtons.add(button);
    // XInput 优先：有 XInput 按钮时清除 HID custom_keys（同时触发说明是同一物理按键）
    tempBinding = {
      type: "gamepadButton",
      buttons: Array.from(gamepadButtons).sort((a, b) => a - b),
    };
  }

  function handleUiGamepadState(gp: UiGamepadStatePayload) {
    if (!isGamepadTestMode) return;

    const newButtons: Record<number, boolean> = {};
    gp.buttons.forEach((pressed, idx) => {
      newButtons[idx] = pressed;
    });

    gamepadTestState = {
      buttons: newButtons,
      axes: gp.axes,
      triggers: { left: gp.left_trigger, right: gp.right_trigger },
    };

    // A键长按退出
    const aPressed = gp.buttons[0];
    if (aPressed) {
      if (!aButtonHoldStartTime[0]) aButtonHoldStartTime[0] = Date.now();
      const holdDuration = Date.now() - (aButtonHoldStartTime[0] || 0);
      aButtonHoldProgress = Math.min(100, (holdDuration / 3000) * 100);
      if (holdDuration >= 3000) {
        isGamepadTestMode = false;
        aButtonHoldProgress = 0;
        aButtonHoldStartTime[0] = null;
      }
    } else {
      if (aButtonHoldStartTime[0]) {
        aButtonHoldStartTime[0] = null;
        aButtonHoldProgress = 0;
      }
    }
  }

  // ====== 键盘事件处理 ======
  function handleKeydown(e: KeyboardEvent) {
    // 禁用浏览器默认的 Ctrl+F 搜索（避免用户使用 Ctrl+Alt+F 呼出面板时意外触发）
    if (e.ctrlKey && e.key.toLowerCase() === "f") {
      e.preventDefault();
      return;
    }

    // 禁用 F3 搜索（浏览器默认行为）
    if (e.key === "F3") {
      e.preventDefault();
      return;
    }

    // 输入框/文本域聚焦时，不处理全局按键（避免影响文字输入）
    if (hasFocusedTextEntry(e.target)) {
      if (
        e.key === "Escape" ||
        (e.key === "b" && !isTextEntryElement(e.target))
      ) {
        blurActiveTextEntry();
        e.preventDefault();
      }
      return;
    }

    // 独立大屏幕窗口，由 BigScreen 组件处理所有按键
    if (isBigscreenWindow) return;

    // 隐藏模式下，忽略所有按键（呼出键由后端处理）
    if (!isOpen) return;

    // 监听模式（呼出键或其他快捷键）
    if (isListeningSummon || isListeningSummon2 || listeningHotkeyType) {
      e.preventDefault();
      if (!e.isTrusted) return;
      if (triggerKey && e.key === triggerKey) {
        triggerKey = null;
        return;
      }

      // HID 优先：如果已经捕获了 HID 特殊按键（gamepadButton），
      // 忽略同时到达的键盘事件（它们只是 HID 映射后的键，如 M1→F13）
      if (tempBinding?.type === "gamepadButton" && tempBinding.custom_keys) {
        return;
      }

      const keyMap: Record<string, string> = {
        " ": "Space",
        ArrowUp: "Up",
        ArrowDown: "Down",
        ArrowLeft: "Left",
        ArrowRight: "Right",
        Control: "Ctrl",
        Meta: "Super",
      };
      let key =
        keyMap[e.key] || (e.key.length === 1 ? e.key.toUpperCase() : e.key);

      // 防抖：500ms内重复的按键忽略
      const now = Date.now();
      if (now - (lastBindingKeyTime[key] || 0) < BINDING_DEBOUNCE_MS) return;
      lastBindingKeyTime[key] = now;

      heldKeys.add(key);
      maxKeys.add(key);

      const modifiers = ["Ctrl", "Shift", "Alt", "Super"];
      const sorted = Array.from(maxKeys).sort((a, b) => {
        const aIsMod = modifiers.includes(a);
        const bIsMod = modifiers.includes(b);
        if (aIsMod && !bIsMod) return -1;
        if (!aIsMod && bIsMod) return 1;
        return modifiers.indexOf(a) - modifiers.indexOf(b);
      });
      pressedKeys = sorted;
      tempBinding = { type: "keyboard", accelerator: sorted.join("+") };
      return;
    }

    // 测试模式下屏蔽
    if (isGamepadTestMode) return;

    // 游戏信息编辑面板打开时，拦截导航
    if (editingGameInfo) {
      e.preventDefault();
      switch (e.key) {
        case "Enter":
        case "a":
          saveGameInfo();
          playSound("click", soundEnabled);
          break;
        case "Escape":
        case "b":
          editingGameInfo = null;
          playSound("navigate", soundEnabled);
          break;
      }
      return;
    }

    // 游戏库下拉菜单打开时，拦截导航
    if (gameMenuOpen) {
      e.preventDefault();
      const currentItem = GAME_MENU_ITEMS[gameMenuIndex];
      switch (e.key) {
        case "ArrowUp":
          gameMenuIndex = Math.max(0, gameMenuIndex - 1);
          playSound("navigate", soundEnabled);
          break;
        case "ArrowDown":
          gameMenuIndex = Math.min(
            GAME_MENU_ITEMS.length - 1,
            gameMenuIndex + 1,
          );
          playSound("navigate", soundEnabled);
          break;
        case "ArrowLeft":
        case "ArrowRight":
          // 场景选择器左右切换
          if (currentItem?.type === "stepper" && gameMenuTarget) {
            const direction = e.key === "ArrowLeft" ? -1 : 1;
            handleGameProfileChange(currentItem.id, direction);
            playSound("navigate", soundEnabled);
          }
          break;
        case "Enter":
        case "a":
          if (gameMenuIndex >= 0 && gameMenuIndex < GAME_MENU_ITEMS.length) {
            // 如果是场景选择器，不需要特殊处理，左右键已处理
            if (currentItem?.type !== "stepper") {
              executeGameMenuItem(GAME_MENU_ITEMS[gameMenuIndex].id);
            }
            playSound("click", soundEnabled);
          }
          break;
        case "Escape":
        case "b":
          closeGameMenu();
          playSound("navigate", soundEnabled);
          break;
      }
      return;
    }

    // 快捷分页交换模式：A、X、Enter等操作键退出交换模式（Y键用于交换、B键用于取消、方向键用于导航）
    const swapExitKeys = ["a", "x", "Enter"];
    if (isInSwapMode && swapExitKeys.includes(e.key)) {
      exitSwapMode();
      showToast(t("toast_swap_cancelled"), "info");
      // 不return，继续处理按键的原有功能
    }

    switch (e.key) {
      case "Enter":
      case "a":
        handleAction();
        break;
      case "x":
        if (currentTabId === "library" && focusIndex < games.length) {
          // 游戏库删除需要长按1秒
          if (!xButtonHoldStartTime) {
            xButtonHoldStartTime = Date.now();
            xButtonHoldProgress = 0;
            // 捕获当前焦点索引，避免在回调中使用可能已变化的 focusIndex
            const targetGameIndex = focusIndex;
            const targetGameId = displayGames[targetGameIndex]?.id;
            if (!targetGameId) return; // 边界检查
            // 启动轮询检测长按进度
            if (xButtonHoldInterval) clearInterval(xButtonHoldInterval);
            xButtonHoldInterval = window.setInterval(() => {
              if (xButtonHoldStartTime) {
                const elapsed = Date.now() - xButtonHoldStartTime;
                xButtonHoldProgress = Math.min(100, (elapsed / 1000) * 100);
                if (elapsed >= 1000) {
                  // 长按1秒后执行删除（使用捕获的游戏ID）
                  deleteGame(targetGameId);
                  clearXButtonHold();
                }
              }
            }, 50);
          }
        } else if (
          currentTabId === "display" &&
          focusIndex >= DISPLAY_PROCESS_BASE_INDEX &&
          windowProcesses.length > 0
        ) {
          // 结束进程（从 DISPLAY_PROCESS_BASE_INDEX 开始的索引是进程列表）- 需要长按1秒
          const procIdx = focusIndex - DISPLAY_PROCESS_BASE_INDEX;
          if (procIdx < windowProcesses.length) {
            if (!xProcessKillStartTime) {
              xProcessKillStartTime = Date.now();
              xProcessKillProgress = 0;
              // 捕获当前进程PID，避免在回调中使用可能已变化的进程列表
              const targetPid = windowProcesses[procIdx].pid;
              // 启动轮询检测长按进度
              if (xProcessKillInterval) clearInterval(xProcessKillInterval);
              xProcessKillInterval = window.setInterval(() => {
                if (xProcessKillStartTime) {
                  const elapsed = Date.now() - xProcessKillStartTime;
                  xProcessKillProgress = Math.min(100, (elapsed / 1000) * 100);
                  if (elapsed >= 1000) {
                    // 长按1秒后执行结束进程（使用捕获的PID）
                    killProcess(targetPid);
                    clearXButtonHold();
                  }
                }
              }, 50);
            }
          }
        } else if (currentTabId === "quick" && quickItems.length > 0) {
          // 快捷分页删除需要长按1秒
          if (!xButtonHoldStartTime) {
            xButtonHoldStartTime = Date.now();
            xButtonHoldProgress = 0;
            // 捕获当前焦点索引，避免在回调中使用可能已变化的 focusIndex
            const targetQuickIndex = focusIndex;
            if (targetQuickIndex < 0 || targetQuickIndex >= quickItems.length) return; // 边界检查
            if (xButtonHoldInterval) clearInterval(xButtonHoldInterval);
            xButtonHoldInterval = window.setInterval(() => {
              if (xButtonHoldStartTime) {
                const elapsed = Date.now() - xButtonHoldStartTime;
                xButtonHoldProgress = Math.min(100, (elapsed / 1000) * 100);
                if (elapsed >= 1000) {
                  removeFromQuickItems(targetQuickIndex);
                  clearXButtonHold();
                }
              }
            }, 50);
          }
        } else if (
          currentTabId === "settings" &&
          isFocused("preset_select") &&
          customTdpPresets.length > 0
        ) {
          // 删除选中的自定义预设
          deleteCustomTdpPreset(selectedCustomPresetIndex);
        } else if (currentTabId === "trainers" && focusIndex >= 2) {
          // 修改器删除需要长按1秒（索引0=更新数据库，1=搜索框，2+是修改器列表）
          const trainerIdx = focusIndex - 2;
          const trainerList = showInstalledOnly ? installedTrainers : trainers;
          if (
            trainerIdx < trainerList.length &&
            trainerList[trainerIdx].installed
          ) {
            if (!xButtonHoldStartTime) {
              xButtonHoldStartTime = Date.now();
              xButtonHoldProgress = 0;
              // 捕获当前修改器名称，避免在回调中使用可能已变化的索引
              const targetTrainerName = trainerList[trainerIdx].game_name;
              // 启动轮询检测长按进度
              if (xButtonHoldInterval) clearInterval(xButtonHoldInterval);
              xButtonHoldInterval = window.setInterval(() => {
                if (xButtonHoldStartTime) {
                  const elapsed = Date.now() - xButtonHoldStartTime;
                  xButtonHoldProgress = Math.min(100, (elapsed / 1000) * 100);
                  if (elapsed >= 1000) {
                    // 长按1秒后执行删除（使用捕获的修改器名称）
                    deleteTrainer(targetTrainerName);
                    clearXButtonHold();
                  }
                }
              }, 50);
            }
          }
        } else if (currentTabId === "hotkey") {
          // X 键长按：清除当前聚焦的快捷键绑定
          const type = getFocusedHotkeyType();
          const binding = type ? getHotkeyBinding(type) : null;

          // 只有已绑定的热键才允许长按清除
          if (type && binding && binding.type !== "none") {
            if (!xHotkeyHoldStartTime) {
              xHotkeyHoldType = type;
              xHotkeyHoldStartTime = Date.now();
              xHotkeyHoldProgress = 0;

              if (xHotkeyHoldInterval) clearInterval(xHotkeyHoldInterval);
              xHotkeyHoldInterval = window.setInterval(() => {
                // 聚焦项变化时取消（避免误清除）
                if (!xHotkeyHoldStartTime || !xHotkeyHoldType) {
                  clearXButtonHold();
                  return;
                }
                if (getFocusedHotkeyType() !== xHotkeyHoldType) {
                  clearXButtonHold();
                  return;
                }

                const elapsed = Date.now() - xHotkeyHoldStartTime;
                xHotkeyHoldProgress = Math.min(
                  100,
                  (elapsed / X_HOTKEY_HOLD_DURATION) * 100,
                );

                if (elapsed >= X_HOTKEY_HOLD_DURATION) {
                  clearHotkeyBinding(xHotkeyHoldType).catch((e) => console.warn("clearHotkeyBinding failed:", e));
                  clearXButtonHold();
                }
              }, 50);
            }
          }
        }
        break;
      case "y":
        // Y 键功能：
        // - 快捷分页：短按Y交换选项位置
        // - 其他分页：长按 3 秒添加到快捷分页（短按功能在 keyup 时触发）
        if (currentTabId === "quick") {
          if (quickItems.length > 0) {
            handleQuickItemSwap();
          }
        } else if (!e.repeat) {
          startYButtonHold();
        }
        break;
      case "b":
        // B 键功能：隐藏面板（独立大屏幕窗口下禁用）
        // 完整检查所有监听状态，防止任何监听模式卡住时 B 键失效
        if (!isListeningSummon && !isListeningSummon2 && !listeningHotkeyType && !isGamepadTestMode && !isBigscreenWindow) {
          // 交换模式下，B键退出交换模式而不是隐藏面板
          if (isInSwapMode) {
            exitSwapMode();
            showToast(t("toast_swap_cancelled"), "info");
          } else {
            invoke("hide_panel").catch(console.error);
          }
        }
        break;
      case "ArrowUp":
        e.preventDefault();
        if (!e.repeat) {
          navigateUp();
          // 所有分页支持上键连发
          startNavigationRepeat(navigateUp);
        }
        break;
      case "ArrowDown":
        e.preventDefault();
        if (!e.repeat) {
          navigateDown();
          startNavigationRepeat(navigateDown);
        }
        break;
      case "ArrowLeft":
        e.preventDefault();
        if (!e.repeat) {
          handleLeft(e);
          // 多列页面支持左键连发（游戏库）
          if (currentTabId === "library") {
            startNavigationRepeat(() => handleLeft(e));
          }
        }
        break;
      case "ArrowRight":
        e.preventDefault();
        if (!e.repeat) {
          handleRight(e);
          // 多列页面支持右键连发（游戏库）
          if (currentTabId === "library") {
            startNavigationRepeat(() => handleRight(e));
          }
        }
        break;
    }
  }

  // 清除X键长按状态
  function clearXButtonHold() {
    // 清除游戏库删除的长按状态
    if (xButtonHoldInterval) {
      clearInterval(xButtonHoldInterval);
      xButtonHoldInterval = null;
    }
    xButtonHoldStartTime = null;
    xButtonHoldProgress = 0;

    // 清除进程结束的长按状态
    if (xProcessKillInterval) {
      clearInterval(xProcessKillInterval);
      xProcessKillInterval = null;
    }
    xProcessKillStartTime = null;
    xProcessKillProgress = 0;

    // 清除快捷键清除的长按状态
    if (xHotkeyHoldInterval) {
      clearInterval(xHotkeyHoldInterval);
      xHotkeyHoldInterval = null;
    }
    xHotkeyHoldStartTime = null;
    xHotkeyHoldType = null;
    xHotkeyHoldProgress = 0;
  }

  // ====== Y键长按：添加到快捷分页（3秒）======
  function startYButtonHold() {
    // 只在非快捷分页中生效
    if (currentTabId === "quick") return;
    if (yButtonHoldStartTime) return;

    yButtonHoldStartTime = Date.now();
    yButtonHoldTriggered = false;
    yButtonPressTabId = currentTabId;
    yButtonPressFocusIndex = focusIndex;
    yButtonHoldProgress = 0;

    if (yButtonHoldInterval) clearInterval(yButtonHoldInterval);
    yButtonHoldInterval = window.setInterval(() => {
      if (yButtonHoldStartTime) {
        const elapsed = Date.now() - yButtonHoldStartTime;
        yButtonHoldProgress = Math.min(
          100,
          (elapsed / Y_BUTTON_HOLD_DURATION) * 100,
        );
        if (elapsed >= Y_BUTTON_HOLD_DURATION) {
          // 触发长按功能
          yButtonHoldTriggered = true;
          handleYButtonHold();
          // 停止计时器（保留 triggered 状态，避免 keyup 触发短按）
          stopYButtonHoldTimer();
        }
      }
    }, 50);
  }

  function stopYButtonHoldTimer() {
    if (yButtonHoldInterval) {
      clearInterval(yButtonHoldInterval);
      yButtonHoldInterval = null;
    }
    yButtonHoldStartTime = null;
    yButtonHoldProgress = 0;
  }

  function clearYButtonHold() {
    stopYButtonHoldTimer();
    yButtonHoldTriggered = false;
    yButtonPressTabId = null;
    yButtonPressFocusIndex = null;
  }

  // 清除A键长按状态（进入/退出测试模式等）
  function clearAButtonHold() {
    if (aButtonHoldInterval) {
      clearInterval(aButtonHoldInterval);
      aButtonHoldInterval = null;
    }
    aButtonHoldStartTime = {};
    aButtonHoldProgress = 0;
  }

  function handleKeyup(e: KeyboardEvent) {
    // 输入框/文本域聚焦时，不处理全局按键（避免影响文字输入）
    if (hasFocusedTextEntry(e.target)) {
      return;
    }

    // A键释放时取消危险操作确认
    if (e.key === "a" || e.key === "Enter") {
      handleActionRelease();
    }
    // X键释放时清除长按状态
    if (e.key === "x") {
      clearXButtonHold();
    }
    // Y键释放：区分长按添加快捷项与短按功能
    if (e.key === "y") {
      const didTrigger = yButtonHoldTriggered;
      const tabAtPress = yButtonPressTabId;
      const focusAtPress = yButtonPressFocusIndex;

      clearYButtonHold();

      // 长按已触发：不执行短按功能
      if (!didTrigger) {
        if (tabAtPress === "display") {
          // 屏幕页刷新进程列表
          loadWindowProcesses();
        } else if (
          tabAtPress === "library" &&
          focusAtPress !== null &&
          focusAtPress < games.length
        ) {
          // 游戏库打开下拉菜单
          const game = displayGames[focusAtPress];
          if (game) {
            openGameMenu(game);
          }
        } else if (tabAtPress === "hotkey") {
          // 热键页：Y 键短按切换热键长按模式
          const hotkeyType = getFocusedHotkeyType();
          if (hotkeyType) {
            toggleHotkeyLongPress(hotkeyType);
          }
        }
      }
    }
    // 清除导航连发
    if (
      e.key === "ArrowUp" ||
      e.key === "ArrowDown" ||
      e.key === "ArrowLeft" ||
      e.key === "ArrowRight"
    ) {
      clearNavigationRepeat();
    }
    if (e.key === "ArrowLeft" || e.key === "ArrowRight") clearKeyRepeat();

    if ((isListeningSummon || isListeningSummon2 || listeningHotkeyType) && e.isTrusted) {
      const keyMap: Record<string, string> = {
        " ": "Space",
        ArrowUp: "Up",
        ArrowDown: "Down",
        ArrowLeft: "Left",
        ArrowRight: "Right",
        Control: "Ctrl",
        Meta: "Super",
      };
      const key =
        keyMap[e.key] || (e.key.length === 1 ? e.key.toUpperCase() : e.key);

      heldKeys.delete(key);
    }
  }

  function handleAction() {
    // 播放点击音效
    playSound("click", soundEnabled);

    const item = getCurrentItem();

    if (!item) return;

    // A 键长按进入手柄测试模式（3秒）
    if (item.id === "gamepad_test") {
      if (!aButtonHoldStartTime[1]) {
        aButtonHoldStartTime[1] = Date.now();
        aButtonHoldProgress = 0;
        if (aButtonHoldInterval) clearInterval(aButtonHoldInterval);
        aButtonHoldInterval = window.setInterval(() => {
          if (aButtonHoldStartTime[1]) {
            const elapsed = Date.now() - aButtonHoldStartTime[1];
            aButtonHoldProgress = Math.min(100, (elapsed / 3000) * 100);
            if (elapsed >= 3000) {
              isGamepadTestMode = true;
              clearAButtonHold();
            }
          }
        }, 50);
      }
      return;
    }

    // 根据项目 id 处理动作
    const handlers: Record<string, () => void> = {
      // 性能页
      tdp_slider: () => applyTdp(tdpWatts),
      tdp_preset: () => applyTdp(tdpPresetLevels[tdpIndex]),
      tdp_boost: () => applyTdpBoost(tdpBoostWatts),
      tdp_fppt: () => applyTdpFppt(tdpFpptWatts),
      rtss_toggle: () => {
        if (!rtssLoading) toggleRtss();
      },
      osd_compact_toggle: () => {
        cycleRtssOsdMode();
      },
      rtss_osd_mode: () => {
        cycleRtssOsdMode();
      },
      rtss_osd_transparent: () => {
        toggleRtssOsdTransparentBg();
      },
      osd_desktop_mode: () => {
        // 内置 OSD：常驻桌面模式开关（A 键触发）
        void toggleOsdDesktopMode();
      },
      osd_visual_style: () => {
        cycleOsdVisualStyle();
      },
      rtss_fps_limit_toggle: () => {
        if (!rtssLoading) toggleRtssFpsLimit();
      },
      rtss_fps_limit_value: () => {}, // stepper，值通过左右键修改
      fps_settings_toggle: () => {
        fpsSettingsExpanded = !fpsSettingsExpanded;
      },
      fan_mode: () => {
        if (fanControlAvailable) applyFanMode();
      },
      fan_custom_toggle: () => {
        fanCustomMode = !fanCustomMode;
        if (fanCustomMode) loadFanCurves();
      },
      fan_curve_mode: () => {}, // stepper，无需 action
      fan_curve_0: () => {},
      fan_curve_1: () => {},
      fan_curve_2: () => {},
      fan_curve_3: () => {},
      fan_curve_4: () => {},
      fan_curve_5: () => {},
      fan_curve_save: () => saveFanCurves(),
      fan_curve_reset: () => resetFanCurve(),
      turbo_boost: () => toggleTurboBoost(),
      epp: () => applyEpp(),
      active_cores: () => applyActiveCores(),
      core_mode: () => applyCoreMode(),
      core_scheduling: () => setCoreSchedulingMode(coreSchedulingMode),
      prefer_perf_cores: () => togglePreferPerfCores(),
      cpu_freq_toggle: () => {
        cpuFreqLimitEnabled = !cpuFreqLimitEnabled;
        applyCpuMaxFreq();
      },
      cpu_freq: () => {
        applyCpuMaxFreq();
      },
      intel_gpu_power: () => applyIntelGpuPowerShare(),
      power_plan: () => applyPowerPlan(),
      import_power_plan: () => importPowerPlan(),
      export_power_plan: () => exportPowerPlan(),
      reset_color_settings: () => resetCustomColorSettings(),
      game_profile_switch: () => toggleGameProfileSwitch(),
      // 性能场景配置
      profile_toggle: () => {
        profileExpanded = !profileExpanded;
      },
      profile_select: () => {
        // 按 A 键应用选中的场景
        if (performanceProfiles.length > 0 && selectedProfileIndex < performanceProfiles.length) {
          applyPerformanceProfile(performanceProfiles[selectedProfileIndex].id);
        }
      },
      profile_create: () => createPerformanceProfile(),
      profile_delete: () => {
        if (performanceProfiles.length > 0 && selectedProfileIndex < performanceProfiles.length) {
          deletePerformanceProfile(performanceProfiles[selectedProfileIndex].id);
        }
      },
      profile_rename: () => {
        if (performanceProfiles.length > 0 && selectedProfileIndex < performanceProfiles.length) {
          openProfileRename(performanceProfiles[selectedProfileIndex]);
        }
      },
      // 插电场景绑定（按 A 键确认绑定）
      ac_profile: () => {
        if (performanceProfiles.length > 0 && selectedAcProfileIndex < performanceProfiles.length) {
          const newProfileId = performanceProfiles[selectedAcProfileIndex].id;
          if (acProfileId !== newProfileId) {
            acProfileId = newProfileId;
            updatePowerProfileBinding();
            showToast(t("ac_profile_bound"), "success");
          }
        }
      },
      // 离电场景绑定（按 A 键确认绑定）
      battery_profile: () => {
        if (performanceProfiles.length > 0 && selectedBatteryProfileIndex < performanceProfiles.length) {
          const newProfileId = performanceProfiles[selectedBatteryProfileIndex].id;
          if (batteryProfileId !== newProfileId) {
            batteryProfileId = newProfileId;
            updatePowerProfileBinding();
            showToast(t("battery_profile_bound"), "success");
          }
        }
      },
      // 进阶设置
      advanced_settings_toggle: () => {
        advancedSettingsExpanded = !advancedSettingsExpanded;
      },
      // AMD 显卡设置
      amd_settings_toggle: () => {
        if (adlxAvailable) amdSettingsExpanded = !amdSettingsExpanded;
      },
      // 设置页 - TDP 自定义
      tdp_custom_toggle: () => {
        tdpCustomExpanded = !tdpCustomExpanded;
      },
      // 设置页 - 连接设置
      connection_toggle: () => {
        connectionExpanded = !connectionExpanded;
      },
      // 设置页 - 窗口行为
      window_behavior_toggle: () => {
        windowBehaviorExpanded = !windowBehaviorExpanded;
      },
      // 设置页 - 配色主题
      theme_toggle: () => {
        themeExpanded = !themeExpanded;
        if (themeExpanded) loadCustomThemes();
      },
      // 设置页 - 系统优化
      optimize_toggle: () => {
        optimizeExpanded = !optimizeExpanded;
      },
      // 输入页 - 系统快捷键
      shortcut_toggle: () => {
        shortcutExpanded = !shortcutExpanded;
      },
      // 输入页 - 屏幕键盘类型
      osk_type_toggle: () => {
        useOskKeyboard = !useOskKeyboard;
        invoke("save_settings", {
          settings: { use_osk_keyboard: useOskKeyboard },
        });
        // 同步到后端键盘重定向模块
        invoke("set_osk_keyboard_mode", { useOsk: useOskKeyboard });
      },
      // Auto-TDP / Auto-Fan / Float GPU
      auto_tdp_toggle: () => toggleAutoTdp(),
      float_gpu_toggle: () => toggleFloatGpu(),
