    // 检查是否有预定义的处理器
    if (handlers[item.id]) {
      handlers[item.id]();
      return;
    }

    // 处理动态生成的项目
    if (item.id.startsWith("process_")) {
      const idx = parseInt(item.id.split("_")[1]);
      if (!isNaN(idx) && idx >= 0 && idx < windowProcesses.length) {
        toggleProcessSuspend(windowProcesses[idx].pid);
      }
    } else if (item.id.startsWith("media_")) {
      const idx = parseInt(item.id.split("_")[1]);
      if (!isNaN(idx) && idx >= 0 && MEDIA_ACTIONS[idx]) mediaControl(MEDIA_ACTIONS[idx].command);
    } else if (item.id.startsWith("shortcut_")) {
      const idx = parseInt(item.id.split("_")[1]);
      if (!isNaN(idx) && idx >= 0 && SHORTCUTS[idx]) simulateShortcut(SHORTCUTS[idx].command);
    } else if (item.id.startsWith("game_")) {
      const idx = parseInt(item.id.split("_")[1]);
      if (idx < games.length) {
        launchGame(displayGames[idx]);
      } else if (idx === games.length) {
        importSteamGames();
      } else if (idx === games.length + 1) {
        importEpicGames();
      } else if (idx === games.length + 2) {
        importEAGames();
      } else if (idx === games.length + 3) {
        importUbisoftGames();
      } else if (idx === games.length + 4) {
        importXboxGames();
      } else if (idx === games.length + 5) {
        importGOGGames();
      } else if (idx === games.length + 6) {
        addGameManually();
      } else if (idx === games.length + 7) {
        clearAllGames();
      } else if (idx === games.length + 8) {
        clearIgnoredGames();
      }
    } else if (item.id.startsWith("quick_")) {
      // 快捷分页项目
      const idx = parseInt(item.id.split("_")[1]);
      if (!isNaN(idx) && idx >= 0) {
        handleQuickItemAction(idx);
      }
    } else if (item.id.startsWith("opt_")) {
      // 优化选项
      const optId = item.id.substring(4);
      if (optimizationRunning) return;
      const revOpt = REVERSIBLE_OPTIMIZATIONS.find((o) => o.id === optId);
      if (revOpt) {
        toggleOptimizationState(optId);
      } else {
        const irrevOpt = IRREVERSIBLE_OPTIMIZATIONS.find((o) => o.id === optId);
        if (irrevOpt && !optimizationResults[optId]) {
          // 不可还原操作需要按住5秒确认
          startDangerConfirm(optId);
        }
      }
    } else if (item.id.startsWith("trainer_")) {
      // 修改器列表项
      const idx = parseInt(item.id.split("_")[1]);
      const trainerList = showInstalledOnly ? installedTrainers : trainers;
      if (!isNaN(idx) && idx >= 0 && idx < trainerList.length) {
        const trainer = trainerList[idx];
        if (trainer.installed && trainer.local_path) {
          launchTrainer(trainer.local_path);
        } else if (!trainer.installed) {
          downloadTrainer(trainer);
        }
      }
    } else if (item.id.startsWith("osd_custom_")) {
      // 自定义 OSD 项目开关
      const itemKey = item.id.substring(11) as OsdItemKey;
      toggleCustomOsdItem(itemKey);
    }
  }

  // 处理 A 键释放（用于取消危险操作确认 + 中断手柄测试长按）
  function handleActionRelease() {
    if (dangerConfirmId) {
      cancelDangerConfirm();
    }
    // 中断手柄测试模式的 A 键长按
    if (aButtonHoldStartTime[1]) {
      clearAButtonHold();
    }
  }

  // ====== 纯逻辑导航（硬编码布局）======
  // ⚠️ 重要：这里的导航规则与页面 HTML/CSS 布局强绑定。
  // 如果以后调整了某个页面的结构（例如：把 2 列改 3 列、插入/移动卡片、改变网格分组），
  // 请务必同时更新下面的导航规则，否则方向键/手柄导航会出现“跳错/跳不到”的问题。
  //
  // 注意：目前默认使用 DOM-based 导航（避免硬编码布局错位）。
  // 这里的纯逻辑导航仅作为兜底/历史实现（例如 contentBody 不可用时）。

  type NavDir = "up" | "down" | "left" | "right";
  type NavResult = { newIndex: number; moved: boolean };

  function noMove(currentIndex: number): NavResult {
    return { newIndex: currentIndex, moved: false };
  }

  function navList(
    currentIndex: number,
    total: number,
    dir: NavDir,
  ): NavResult {
    if (total <= 0) return noMove(currentIndex);

    if (dir === "up") {
      return currentIndex > 0
        ? { newIndex: currentIndex - 1, moved: true }
        : noMove(currentIndex);
    }

    if (dir === "down") {
      return currentIndex < total - 1
        ? { newIndex: currentIndex + 1, moved: true }
        : noMove(currentIndex);
    }

    // 单列列表默认不处理左右移动（交给 slider/stepper 的值调整逻辑）
    return noMove(currentIndex);
  }

  function navGridIndex(
    currentIndex: number,
    total: number,
    cols: number,
    dir: NavDir,
  ): NavResult {
    if (total <= 0 || cols <= 0) return noMove(currentIndex);

    const row = Math.floor(currentIndex / cols);
    const col = currentIndex % cols;

    if (dir === "left") {
      return col > 0
        ? { newIndex: currentIndex - 1, moved: true }
        : noMove(currentIndex);
    }

    if (dir === "right") {
      const candidate = currentIndex + 1;
      // 需要保证仍在同一行 & 没越界（最后一行可能不满 cols）
      if (
        col < cols - 1 &&
        candidate < total &&
        Math.floor(candidate / cols) === row
      ) {
        return { newIndex: candidate, moved: true };
      }
      return noMove(currentIndex);
    }

    if (dir === "up") {
      const candidate = currentIndex - cols;
      return candidate >= 0
        ? { newIndex: candidate, moved: true }
        : noMove(currentIndex);
    }

    if (dir === "down") {
      const candidate = currentIndex + cols;
      return candidate < total
        ? { newIndex: candidate, moved: true }
        : noMove(currentIndex);
    }

    return noMove(currentIndex);
  }

  function navGridRange(
    currentIndex: number,
    start: number,
    count: number,
    cols: number,
    dir: NavDir,
    upOut?: number,
    downOut?: number,
  ): NavResult {
    const end = start + count;
    if (currentIndex < start || currentIndex >= end)
      return noMove(currentIndex);

    const localIndex = currentIndex - start;
    const local = navGridIndex(localIndex, count, cols, dir);

    if (local.moved) return { newIndex: start + local.newIndex, moved: true };

    // up/down 越界时允许跳到外部指定项（例如回到折叠 header）
    if (dir === "up" && upOut !== undefined)
      return { newIndex: upOut, moved: true };
    if (dir === "down" && downOut !== undefined)
      return { newIndex: downOut, moved: true };

    return noMove(currentIndex);
  }

  function navListByOrder(
    currentIndex: number,
    order: number[],
    dir: NavDir,
    upOut?: number,
    downOut?: number,
  ): NavResult {
    const pos = order.indexOf(currentIndex);
    if (pos === -1) return noMove(currentIndex);

    if (dir === "up") {
      if (pos > 0) return { newIndex: order[pos - 1], moved: true };
      return upOut !== undefined
        ? { newIndex: upOut, moved: true }
        : noMove(currentIndex);
    }

    if (dir === "down") {
      if (pos < order.length - 1)
        return { newIndex: order[pos + 1], moved: true };
      return downOut !== undefined
        ? { newIndex: downOut, moved: true }
        : noMove(currentIndex);
    }

    return noMove(currentIndex);
  }

  function navExplicitGrid(
    currentIndex: number,
    indices: number[],
    cols: number,
    dir: NavDir,
    upOut?: number,
    downOut?: number,
  ): NavResult {
    const pos = indices.indexOf(currentIndex);
    if (pos === -1 || cols <= 0) return noMove(currentIndex);

    const row = Math.floor(pos / cols);
    const col = pos % cols;

    if (dir === "left") {
      if (col === 0) return noMove(currentIndex);
      return { newIndex: indices[pos - 1], moved: true };
    }

    if (dir === "right") {
      const candidate = pos + 1;
      // 同一行内才允许右移（最后一行可能不满 cols）
      if (candidate < indices.length && Math.floor(candidate / cols) === row) {
        return { newIndex: indices[candidate], moved: true };
      }
      return noMove(currentIndex);
    }

    if (dir === "up") {
      const candidate = pos - cols;
      if (candidate >= 0) return { newIndex: indices[candidate], moved: true };
      return upOut !== undefined
        ? { newIndex: upOut, moved: true }
        : noMove(currentIndex);
    }

    if (dir === "down") {
      const candidate = pos + cols;
      if (candidate < indices.length)
        return { newIndex: indices[candidate], moved: true };
      return downOut !== undefined
        ? { newIndex: downOut, moved: true }
        : noMove(currentIndex);
    }

    return noMove(currentIndex);
  }

  function navigateByLayout(dir: NavDir, currentIndex: number): NavResult {
    const total = currentTabItems.length;
    if (total <= 0) return noMove(currentIndex);

    // 游戏库：三个分类区域，每个区域内部是 3 列网格
    if (currentTabId === "library") {
      // 最近游戏区域: index 0 ~ recentGames.length - 1
      // 其他游戏区域: index recentGames.length ~ games.length - 1
      // 导入按钮区域: index games.length ~ games.length + 8
      const recentStart = 0;
      const recentEnd = recentGames.length;
      const otherStart = recentEnd;
      const otherEnd = games.length;
      const actionStart = games.length;
      const actionEnd = games.length + 9; // 9个操作按钮

      // 在最近游戏区域
      if (currentIndex >= recentStart && currentIndex < recentEnd) {
        const downOut = otherGames.length > 0 ? otherStart : actionStart;
        return navGridRange(
          currentIndex,
          recentStart,
          recentEnd - recentStart,
          3,
          dir,
          undefined,
          downOut,
        );
      }

      // 在其他游戏区域
      if (currentIndex >= otherStart && currentIndex < otherEnd) {
        const upOut = recentGames.length > 0 ? recentEnd - 1 : undefined;
        return navGridRange(
          currentIndex,
          otherStart,
          otherEnd - otherStart,
          3,
          dir,
          upOut,
          actionStart,
        );
      }

      // 在导入按钮区域
      if (currentIndex >= actionStart && currentIndex < actionEnd) {
        const upOut =
          otherGames.length > 0
            ? otherEnd - 1
            : recentGames.length > 0
              ? recentEnd - 1
              : undefined;
        return navGridRange(
          currentIndex,
          actionStart,
          actionEnd - actionStart,
          3,
          dir,
          upOut,
          undefined,
        );
      }

      return navGridIndex(currentIndex, total, 3, dir);
    }

    if (currentTabId === "display") {
      // 视听页：上方两条 slider + 中间两列媒体控制网格 + 下方列表 + 进程列表
      const idxBrightness = getItemIndex("brightness");
      const idxVolume = getItemIndex("volume");

      const idxMic = getItemIndex("media_mic");
      const idxMute = getItemIndex("media_mute");
      const idxPlay = getItemIndex("media_play");
      const idxPrev = getItemIndex("media_prev");
      const idxNext = getItemIndex("media_next");

      const grid = [idxMic, idxMute, idxPlay, idxPrev, idxNext].filter(
        (i) => i >= 0,
      );

      const idxRefresh = getItemIndex("refresh_rate");
      const idxResolution = getItemIndex("resolution");
      const idxKill = getItemIndex("kill_top_process");
      const idxSuspend = getItemIndex("suspend_top_process");
      const afterGrid = [idxRefresh, idxResolution, idxKill, idxSuspend].filter(
        (i) => i >= 0,
      );

      const idxProcess0 = getItemIndex("process_0");

      // 上方 slider 列表
      const beforeGrid = [idxBrightness, idxVolume].filter((i) => i >= 0);

      if (beforeGrid.includes(currentIndex)) {
        // down：volume -> grid 入口
        const downOut = grid.length > 0 ? grid[0] : undefined;
        return navListByOrder(
          currentIndex,
          beforeGrid,
          dir,
          undefined,
          downOut,
        );
      }

      if (grid.includes(currentIndex)) {
        const upOut =
          beforeGrid.length > 0 ? beforeGrid[beforeGrid.length - 1] : undefined;
        const downOut = afterGrid.length > 0 ? afterGrid[0] : undefined;
        return navExplicitGrid(currentIndex, grid, 2, dir, upOut, downOut);
      }

      if (afterGrid.includes(currentIndex)) {
        const upOut = grid.length > 0 ? grid[grid.length - 1] : undefined;
        const downOut = idxProcess0 >= 0 ? idxProcess0 : undefined;
        return navListByOrder(currentIndex, afterGrid, dir, upOut, downOut);
      }

      // 进程列表（单列）
      if (idxProcess0 >= 0 && currentIndex >= idxProcess0) {
        const upOut = idxSuspend >= 0 ? idxSuspend : undefined;
        // 进程列表本身按 index 连续排列，直接用 list 导航即可
        if (
          dir === "up" &&
          currentIndex === idxProcess0 &&
          upOut !== undefined
        ) {
          return { newIndex: upOut, moved: true };
        }
        return navList(currentIndex, total, dir);
      }

      return navList(currentIndex, total, dir);
    }

    if (currentTabId === "gamepad") {
      // 输入页：大部分是单列；系统快捷键区域是两列网格（`.shortcuts-grid-compact`）
      const shortcutIndices = SHORTCUTS.map((_, i) =>
        getItemIndex(`shortcut_${i}`),
      ).filter((i) => i >= 0);
      if (shortcutIndices.includes(currentIndex)) {
        const upOut = getItemIndex("shortcut_toggle");
        return navExplicitGrid(
          currentIndex,
          shortcutIndices,
          2,
          dir,
          upOut,
          undefined,
        );
      }

      return navList(currentIndex, total, dir);
    }

    if (currentTabId === "performance") {
      // 性能页：AMD 设置展开时，开关区是两列网格
      const amdToggleIndex = getItemIndex("amd_settings_toggle");
      if (amdToggleIndex >= 0 && amdSettingsExpanded && adlxAvailable) {
        let amdToggleCount = 5;
        if (adlxDisplaySettings.integer_scaling_supported) amdToggleCount++;
        if (adlxDisplaySettings.gpu_scaling_supported) amdToggleCount++;
        if (adlxDisplaySettings.freesync_supported) amdToggleCount++;
        if (afmfSupported) amdToggleCount++;
        if (imageSharpeningSupported) amdToggleCount++;

        const start = amdToggleIndex + 1;
        const end = start + amdToggleCount;
        if (currentIndex >= start && currentIndex < end) {
          const downOut = end < total ? end : undefined;
          return navGridRange(
            currentIndex,
            start,
            amdToggleCount,
            2,
            dir,
            amdToggleIndex,
            downOut,
          );
        }
      }
      return navList(currentIndex, total, dir);
    }

    if (currentTabId === "settings") {
      // 设置页：大部分是单列；分页可见性是两列网格，系统优化是三列网格
      const tabGridIds = [
        "guide_tab_toggle",
        "display_tab_toggle",
        "performance_tab_toggle",
        "monitor_tab_toggle",
        "library_tab_toggle",
        "trainer_tab_toggle",
        "gamepad_tab_toggle",
        "hotkey_tab_toggle",
        "quick_tab_toggle",
      ];
      const tabGrid = tabGridIds
        .map((id) => getItemIndex(id))
        .filter((i) => i >= 0);
      if (tabGrid.includes(currentIndex)) {
        const upOut = getItemIndex("tab_visibility_toggle");
        const downOut = getItemIndex("optimize_toggle");
        return navExplicitGrid(currentIndex, tabGrid, 2, dir, upOut, downOut);
      }

      if (optimizeExpanded) {
        const optGrid = ALL_OPTIMIZATIONS.map((opt) =>
          getItemIndex(`opt_${opt.id}`),
        ).filter((i) => i >= 0);
        if (optGrid.includes(currentIndex)) {
          const upOut = getItemIndex("optimize_toggle");
          const downOut = getItemIndex("about_info");
          return navExplicitGrid(currentIndex, optGrid, 3, dir, upOut, downOut);
        }
      }

      return navList(currentIndex, total, dir);
    }

    // Quick/Guide/Monitor/Trainers/Hotkey 等：单列列表
    return navList(currentIndex, total, dir);
  }

  function shouldUseDomNavigation(): boolean {
    // 全局启用 DOM-based 导航：从实际 DOM 位置推断上下左右，避免硬编码布局错位
    return true;
  }

  function navigateByDom(dir: NavDir, currentIndex: number): NavResult {
    // DOM 导航默认启用（shouldUseDomNavigation 预留开关）
    if (!shouldUseDomNavigation()) return navigateByLayout(dir, currentIndex);

    switch (dir) {
      case "up":
        return domNavigateUp(currentIndex, contentBody);
      case "down":
        return domNavigateDown(currentIndex, contentBody);
      case "left":
        return domNavigateLeft(currentIndex, contentBody);
      case "right":
        return domNavigateRight(currentIndex, contentBody);
      default:
        return noMove(currentIndex);
    }
  }

  function navigateUp() {
    // 防抖检查
    const now = Date.now();
    if (now - (lastNavTime.up || 0) < NAV_DEBOUNCE_MS) return;
    lastNavTime.up = now;

    const result = navigateByDom("up", focusIndex);
    if (result.moved) {
      playSound("navigate", soundEnabled);
      focusIndex = result.newIndex;
    }
  }

  function navigateDown() {
    // 防抖检查
    const now = Date.now();
    if (now - (lastNavTime.down || 0) < NAV_DEBOUNCE_MS) return;
    lastNavTime.down = now;

    const result = navigateByDom("down", focusIndex);
    if (result.moved) {
      playSound("navigate", soundEnabled);
      focusIndex = result.newIndex;
    }
  }

  function handleLeft(e: KeyboardEvent) {
    // 防抖检查
    const now = Date.now();
    if (now - (lastNavTime.left || 0) < NAV_DEBOUNCE_MS) return;
    lastNavTime.left = now;

    const result = navigateByDom("left", focusIndex);

    if (result.moved) {
      // 网格区域内移动
      playSound("navigate", soundEnabled);
      focusIndex = result.newIndex;
    } else {
      // 单列区域：调节滑条/选择器
      const item = getCurrentItem();
      if (item?.type === "slider" && !e.repeat) {
        handleValueChange(currentTabId, focusIndex, -1);
        startKeyRepeat(-1);
      } else if (item?.type === "stepper") {
        handleValueChange(currentTabId, focusIndex, -1);
      }
    }
  }

  function handleRight(e: KeyboardEvent) {
    // 防抖检查
    const now = Date.now();
    if (now - (lastNavTime.right || 0) < NAV_DEBOUNCE_MS) return;
    lastNavTime.right = now;

    const result = navigateByDom("right", focusIndex);

    if (result.moved) {
      // 网格区域内移动
      playSound("navigate", soundEnabled);
      focusIndex = result.newIndex;
    } else {
      // 单列区域：调节滑条/选择器
      const item = getCurrentItem();
      if (item?.type === "slider" && !e.repeat) {
        handleValueChange(currentTabId, focusIndex, 1);
        startKeyRepeat(1);
      } else if (item?.type === "stepper") {
        handleValueChange(currentTabId, focusIndex, 1);
      }
    }
  }

  // ====== 生命周期 ======
  type BackendToastPayload = {
    message: string;
    type?: Toast["type"];
    duration?: number;
  };

  let unlistenOpen: (() => void) | null = null;
  let unlistenWatchdog: (() => void) | null = null;
  let unlistenUpdateProgress: (() => void) | null = null;
  let unlistenBackendToast: (() => void) | null = null;

  // 后端 UI 输入事件（手柄推送）
  let unlistenUiKey: (() => void) | null = null;
  let unlistenUiTab: (() => void) | null = null;
  let unlistenUiGamepadBinding: (() => void) | null = null;
  let unlistenUiGamepadState: (() => void) | null = null;

  // 修复内存泄漏：所有事件监听器的 unlisten 函数
  let unlistenOsdReady: (() => void) | null = null;
  let unlistenOsdRequestRefresh: (() => void) | null = null;
  let unlistenHotkeyOsdToggle: (() => void) | null = null;
  let unlistenHotkeyOsdModeNext: (() => void) | null = null;
  let unlistenHotkeyTdpUp: (() => void) | null = null;
  let unlistenHotkeyTdpDown: (() => void) | null = null;
  let unlistenHotkeyMouseSimToggle: (() => void) | null = null;
  let unlistenHotkeyScreenshot: (() => void) | null = null;
  let unlistenHotkeyRecordToggle: (() => void) | null = null;
  let unlistenHotkeyGyroToggle: (() => void) | null = null;
  let unlistenHotkeyGyroHold: (() => void) | null = null;
  let unlistenHotkeyGyroRelease: (() => void) | null = null;
  let unlistenMouseSimChanged: (() => void) | null = null;
  let unlistenWidgetTdpChanged: (() => void) | null = null;
  let unlistenWidgetFanModeChanged: (() => void) | null = null;
  let unlistenWidgetOsdToggle: (() => void) | null = null;
  let unlistenWidgetOsdMode: (() => void) | null = null;
  let unlistenWidgetOsdStyle: (() => void) | null = null;
  let unlistenWidgetFpsLimitChanged: (() => void) | null = null;
  let unlistenAutoTdpUpdate: (() => void) | null = null;
  let unlistenCustomKeyPressed: (() => void) | null = null;
  let unlistenProfileApplied: (() => void) | null = null;
  let unlistenDeviceDetected: (() => void) | null = null;
  let unlistenWidgetLanguageChanged: (() => void) | null = null;
  let unlistenRtssStatusChanged: (() => void) | null = null;
  let unlistenSystemResumed: (() => void) | null = null;

  let lastWatchdogToastAt = 0;

  onMount(() => {
    // 初始化多语言
    initLocale();
    currentLanguage = getLocale();

    // 获取当前版本
    invoke<string>("get_current_version")
      .then((v) => {
        currentVersion = v;
      })
      .catch((e) => console.warn("get_version failed:", e));

    // 检测 ViGEm 驱动状态
    checkVigemDriver();

    // 监听更新下载进度事件
    listen<{ downloaded: number; total: number; percent: number }>(
      "update-download-progress",
      (event) => {
        updateDownloadProgress = event.payload.percent;
      },
    )
      .then((unlisten) => {
        unlistenUpdateProgress = unlisten;
      })
      .catch((e) => console.warn("listen update-progress failed:", e));

    // 后端看门狗提示：后台服务被迫中断（心跳异常等），提示用户重新应用设置
    listen<{ service: string }>("watchdog-service-interrupted", (_event) => {
      const now = Date.now();
      if (lastWatchdogToastAt > 0 && now - lastWatchdogToastAt < 2000) return;
      lastWatchdogToastAt = now;

      showToast(t("toast_unknown_error"), "error", 6000);
    })
      .then((unlisten) => {
        unlistenWatchdog = unlisten;
      })
      .catch((e) => console.warn("listen watchdog failed:", e));

    // 后端通用 Toast 事件（用于提示诸如 LhmHelper 数据源缺失等原因）
    listen<BackendToastPayload>("backend-toast", (event) => {
      const payload = event.payload;
      if (!payload?.message) return;
      showToast(
        payload.message,
        payload.type ?? "warning",
        payload.duration ?? 8000,
      );
    })
      .then((unlisten) => {
        unlistenBackendToast = unlisten;
      })
      .catch((e) => console.warn("listen backend-toast failed:", e));

    // 系统唤醒事件：重置 OSD 轮询状态，防止 in-flight 标志/熔断器卡死导致 FPS 始终为 0
    // 同时重新同步后端状态，确保 UI 与后端一致（休眠时后端服务会被停止）
    listen("system-resumed", async () => {
      console.log("[PowerEvents] 系统唤醒，重置前端状态并同步后端");
      // 1. 重置 OSD 轮询状态
      rtssOsdInProgress = false;
      osdUpdateErrorCount = 0;
      osdUpdatePaused = false;
      osdUpdatePauseUntil = 0;
      lastOsdTickTime = 0;
      rtssOsdErrorCount = 0;

      // 2. 重新同步后端设置（休眠时 TDP/风扇服务被 on_system_suspend() 停止，
      //    后端 on_system_resume() 会重新启动它们，但前端 UI 变量可能与后端不同步）
      try {
        const settings = await invoke<any>("load_settings");
        if (settings) {
          if (settings.tdp != null) {
            tdpWatts = settings.tdp;
            finalTdp = settings.tdp;
          }
          // 同步 SPPT/FPPT 显示（休眠唤醒后后端可能已重新应用）
          if (settings.tdp_boost != null) tdpBoostWatts = settings.tdp_boost;
          if (settings.tdp_fppt != null) tdpFpptWatts = settings.tdp_fppt;
          if (settings.fan_mode != null) {
            fanModeIndex = settings.fan_mode;
            appliedFanModeIndex = settings.fan_mode;
          }
          if (settings.brightness != null) {
            brightness = settings.brightness;
          }
          if (settings.volume != null) {
            volume = settings.volume;
          }
        }
      } catch (e) {
        console.warn("[PowerEvents] 唤醒后同步设置失败:", e);
      }
    })
      .then((unlisten) => {
        unlistenSystemResumed = unlisten;
      })
      .catch((e) => console.warn("listen system-resumed failed:", e));

    // OSD WebView 就绪事件：立即刷新数据（避免等待轮询周期）
    listen("osd-ready", () => {
      if (rtssOsdEnabled) {
        updateRtssOsd();
      }
    })
      .then((unlisten) => {
        unlistenOsdReady = unlisten;
      })
      .catch((e) => console.warn("listen osd-ready failed:", e));

    // OSD 请求刷新事件：OSD 窗口启用后主动请求数据（解决时序问题）
    listen("osd-request-refresh", () => {
      console.log("[OSD] 收到刷新请求");
      if (rtssOsdEnabled) {
        updateRtssOsd();
      }
    })
      .then((unlisten) => {
        unlistenOsdRequestRefresh = unlisten;
      })
      .catch((e) => console.warn("listen osd-request-refresh failed:", e));

    // 快捷键事件监听
    listen("hotkey-osd-toggle", () => {
      toggleRtss(); // toggleRtss 已支持 builtin 和 rtss 两种模式
    })
      .then((unlisten) => {
        unlistenHotkeyOsdToggle = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-osd-toggle failed:", e));

    listen("hotkey-osd-mode-next", () => {
      // 12个模式循环：实体详细/灵动/极简、透明详细/灵动/极简、横条详细/灵动/极简、透明横条详细/灵动/极简
      const styles: Array<"solid" | "transparent" | "bar" | "bar-trans"> = [
        "solid",
        "transparent",
        "bar",
        "bar-trans",
      ];
      const displayModes: Array<"detailed" | "compact" | "minimal"> = [
        "detailed",
        "compact",
        "minimal",
      ];
      const modes: Array<{
        style: "solid" | "transparent" | "bar" | "bar-trans";
        mode: "detailed" | "compact" | "minimal";
      }> = [];
      for (const style of styles) {
        for (const mode of displayModes) {
          modes.push({ style, mode });
        }
      }
      // 找到当前模式索引
      const currentIdx = modes.findIndex(
        (m) => m.style === osdVisualStyle && m.mode === osdDisplayMode,
      );
      const nextIdx = (currentIdx + 1) % modes.length;
      const next = modes[nextIdx];
      osdVisualStyle = next.style;
      osdDisplayMode = next.mode;
      invoke("save_settings", {
        settings: {
          osd_visual_style: osdVisualStyle,
          osd_display_mode: osdDisplayMode,
        },
      });
      if (osdType === "builtin") {
        invoke("set_osd_visual_style", { style: osdVisualStyle });
        invoke("set_osd_mode", { mode: osdDisplayMode });
      }
      const styleNames: Record<string, string> = {
        solid: t("osd_style_solid"),
        transparent: t("osd_style_transparent"),
        bar: t("osd_style_bar"),
        "bar-trans": t("osd_style_bar_trans"),
      };
      const modeNames: Record<string, string> = {
        detailed: t("osd_display_detailed"),
        compact: t("osd_display_compact"),
        minimal: t("osd_display_minimal"),
      };
      showToast(
        `OSD: ${styleNames[next.style]} ${modeNames[next.mode]}`,
        "success",
        1500,
      );
    })
      .then((unlisten) => {
        unlistenHotkeyOsdModeNext = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-osd-mode-next failed:", e));

    // TDP 热键防抖：避免快速连续按下导致竞态条件
    let tdpHotkeyLastTrigger = 0;
    const TDP_HOTKEY_DEBOUNCE_MS = 200; // 200ms 防抖

    listen("hotkey-tdp-up", async () => {
      const now = Date.now();
      if (now - tdpHotkeyLastTrigger < TDP_HOTKEY_DEBOUNCE_MS) {
        return; // 忽略过快触发
      }
      tdpHotkeyLastTrigger = now;

      const newTdp = Math.min(tdpWatts + 1, tdpMax);
      if (newTdp !== tdpWatts) {
        tdpWatts = newTdp;
        await applyTdp(newTdp);
        showToast(
          t("toast_tdp_value").replace("{value}", String(newTdp)),
          "success",
          1500,
        );
      }
    })
      .then((unlisten) => {
        unlistenHotkeyTdpUp = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-tdp-up failed:", e));

    listen("hotkey-tdp-down", async () => {
      const now = Date.now();
      if (now - tdpHotkeyLastTrigger < TDP_HOTKEY_DEBOUNCE_MS) {
        return; // 忽略过快触发
      }
      tdpHotkeyLastTrigger = now;

      const newTdp = Math.max(tdpWatts - 1, tdpMin);
      if (newTdp !== tdpWatts) {
        tdpWatts = newTdp;
        await applyTdp(newTdp);
        showToast(
          t("toast_tdp_value").replace("{value}", String(newTdp)),
          "success",
          1500,
        );
      }
    })
      .then((unlisten) => {
        unlistenHotkeyTdpDown = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-tdp-down failed:", e));

    // 模拟鼠标开关快捷键
    listen("hotkey-mouse-sim-toggle", async () => {
      await toggleMouseSim();
      showToast(
        t("toast_mouse_sim").replace(
          "{status}",
          mouseSimEnabled ? t("on") : t("off"),
        ),
        "success",
        1500,
      );
    })
      .then((unlisten) => {
        unlistenHotkeyMouseSimToggle = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-mouse-sim-toggle failed:", e));

    // 截屏快捷键 - 模拟 Win+PrintScreen
    listen("hotkey-screenshot", async () => {
      // 防误触：只有在用户设置了截图热键时才响应
      if (!screenshotBinding || screenshotBinding.type === "none") return;
      try {
        await invoke("simulate_screenshot");
        showToast(t("toast_screenshot_saved"), "success", 1500);
      } catch (e) {
        console.error("截屏失败:", e);
      }
    })
      .then((unlisten) => {
        unlistenHotkeyScreenshot = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-screenshot failed:", e));

    // 录制开关快捷键 - 模拟 Win+Alt+R
    listen("hotkey-record-toggle", async () => {
      // 防误触：只有在用户设置了录制热键时才响应
      if (!recordToggleBinding || recordToggleBinding.type === "none") return;
      try {
        await invoke("simulate_record_toggle");
        showToast(t("toast_record_toggled"), "success", 1500);
      } catch (e) {
        console.error("录制切换失败:", e);
      }
    })
      .then((unlisten) => {
        unlistenHotkeyRecordToggle = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-record-toggle failed:", e));

    // 陀螺仪开关快捷键
    listen("hotkey-gyro-toggle", async () => {
      if (!gyroEnabled) {
        await startGyro();
      } else {
        await stopGyro();
      }
    })
      .then((unlisten) => {
        unlistenHotkeyGyroToggle = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-gyro-toggle failed:", e));

    // 按住开启陀螺仪快捷键
    listen("hotkey-gyro-hold-press", async () => {
      if (!gyroEnabled) {
        await startGyro();
      }
    })
      .then((unlisten) => {
        unlistenHotkeyGyroHold = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-gyro-hold-press failed:", e));

    // 松开关闭陀螺仪快捷键
    listen("hotkey-gyro-hold-release", async () => {
      if (gyroEnabled) {
        await stopGyro();
      }
    })
      .then((unlisten) => {
        unlistenHotkeyGyroRelease = unlisten;
      })
      .catch((e) => console.warn("listen hotkey-gyro-hold-release failed:", e));

    // 监听模拟鼠标状态变化（由快捷键触发）
    listen<boolean>("mouse-simulation-changed", (event) => {
      mouseSimEnabled = event.payload;
    })
      .then((unlisten) => {
        unlistenMouseSimChanged = unlisten;
      })
      .catch((e) => console.warn("listen mouse-sim-changed failed:", e));

    // 监听 Widget 同步 TDP 变化（Widget 修改 TDP 时通知主程序 UI）
    listen<number>("widget_tdp_changed", (event) => {
      const newTdp = event.payload;
      console.log("[Widget] TDP 同步:", newTdp);
      tdpWatts = newTdp;
      finalTdp = newTdp;
      // 更新 TDP 预设索引（如果匹配）
      const presetIdx = tdpPresetLevels.findIndex((p) => p === newTdp);
      if (presetIdx >= 0) {
        tdpIndex = presetIdx;
      }
    })
      .then((unlisten) => {
        unlistenWidgetTdpChanged = unlisten;
      })
      .catch((e) => console.warn("listen widget-tdp-changed failed:", e));

    // 监听 Widget 同步风扇模式变化（Widget 修改风扇模式时通知主程序 UI）
    listen<number>("widget_fan_mode_changed", (event) => {
      const newMode = event.payload;
      console.log("[Widget] 风扇模式同步:", newMode);
      fanModeIndex = newMode;
      appliedFanModeIndex = newMode;
    })
      .then((unlisten) => {
        unlistenWidgetFanModeChanged = unlisten;
      })
      .catch((e) => console.warn("listen widget-fan-mode-changed failed:", e));

    // 监听场景应用事件（游戏启动/电源切换等自动应用场景后，同步 UI）
    listen<string>("profile-applied", async (event) => {
      const profileId = event.payload;
      console.log("[Profile] 场景已应用:", profileId);
      // 刷新设置以获取最新状态
      try {
        const settings = await invoke<any>("load_settings");
        if (settings.tdp != null) {
          finalTdp = settings.tdp;
          tdpWatts = settings.tdp;
          // 更新 TDP 预设索引（如果匹配）
          const presetIdx = tdpPresetLevels.findIndex((p) => p === settings.tdp);
          if (presetIdx >= 0) {
            tdpIndex = presetIdx;
          }
        }
        if (settings.fan_mode != null) {
          fanModeIndex = settings.fan_mode;
          appliedFanModeIndex = settings.fan_mode;
        }
        // 同步 SPPT/FPPT 显示
        if (settings.tdp_boost != null) tdpBoostWatts = settings.tdp_boost;
        if (settings.tdp_fppt != null) tdpFpptWatts = settings.tdp_fppt;
        if (settings.turbo_boost != null) turboBoostEnabled = settings.turbo_boost;
        if (settings.auto_tdp_enabled != null) autoTdpEnabled = settings.auto_tdp_enabled;
        if (settings.auto_tdp_target_fps != null) autoTdpTargetFps = settings.auto_tdp_target_fps;
        if (settings.auto_fan_enabled != null) autoFanEnabled = settings.auto_fan_enabled;
        if (settings.auto_fan_temp_min != null) autoFanTempMin = settings.auto_fan_temp_min;
        if (settings.auto_fan_temp_max != null) autoFanTempMax = settings.auto_fan_temp_max;
        // 更新帧率限制状态
        if (settings.rtss_fps_limit_enabled != null) rtssFpsLimitEnabled = settings.rtss_fps_limit_enabled;
        if (settings.rtss_fps_limit_value != null) rtssFpsLimitValue = settings.rtss_fps_limit_value;
        // 更新活跃核心数
        if (settings.active_cores != null) activeCores = settings.active_cores;
        // 更新 CPU 最大频率
        if (settings.cpu_max_freq != null) {
          cpuFreqLimitEnabled = settings.cpu_max_freq > 0;
          cpuFreqSlider = settings.cpu_max_freq > 0 ? settings.cpu_max_freq : 2500;
        }
      } catch (e) {
        console.warn("[Profile] 场景应用后同步设置失败:", e);
      }
    })
      .then((unlisten) => {
        unlistenProfileApplied = unlisten;
      })
      .catch((e) => console.warn("listen profile-applied failed:", e));

    // 监听设备检测延迟成功事件（开机自启时 WMI 可能未就绪，后端会延迟重试）
    listen<{
      fanControlAvailable: boolean;
      detectedDevice: string;
      fanControlType: string | null;
      deviceTdpMin: number | null;
      deviceTdpMax: number | null;
    }>("device_detected", (event) => {
      const payload = event.payload;
      console.log("[Device] 延迟检测成功:", payload);
      
      // 更新设备信息
      if (payload.fanControlAvailable !== undefined) {
        fanControlAvailable = payload.fanControlAvailable;
      }
      if (payload.detectedDevice) {
        detectedDevice = payload.detectedDevice;
      }
      if (payload.fanControlType) {
        fanControlType = payload.fanControlType;
      }
      if (payload.deviceTdpMin !== null) {
        deviceTdpMin = payload.deviceTdpMin;
      }
      if (payload.deviceTdpMax !== null) {
        deviceTdpMax = payload.deviceTdpMax;
      }
      
      // 提示用户设备已识别
      if (fanControlAvailable) {
        showToast(
          t("detected_device").replace("{device}", detectedDevice || ""),
          "success"
        );
      }
    }).then((unlisten) => {
        unlistenDeviceDetected = unlisten;
      })
      .catch((e) => console.warn("listen device_detected failed:", e));

    // 监听 Widget OSD 开关
    listen<boolean>("widget_osd_toggle", async (event) => {
      const enabled = event.payload;
      console.log("[Widget] OSD 开关:", enabled);
      // 只有当状态不同时才切换
      if (enabled !== rtssOsdEnabled) {
        await toggleRtss();
      }
    })
      .then((unlisten) => {
        unlistenWidgetOsdToggle = unlisten;
      })
      .catch((e) => console.warn("listen widget-osd-toggle failed:", e));

    // 监听 Widget OSD 模式变化
    listen<string>("widget_osd_mode", async (event) => {
      const mode = event.payload as "minimal" | "compact" | "detailed";
      console.log("[Widget] OSD 模式:", mode);
      if (mode !== osdDisplayMode) {
        osdDisplayMode = mode;
        if (osdType === "builtin") {
          invoke("set_osd_mode", { mode });
        }
        invoke("save_settings", { settings: { osd_display_mode: mode } });
      }
    })
      .then((unlisten) => {
        unlistenWidgetOsdMode = unlisten;
      })
      .catch((e) => console.warn("listen widget-osd-mode failed:", e));

    // 监听 Widget OSD 样式变化
    listen<string>("widget_osd_style", async (event) => {
      const style = event.payload as "solid" | "transparent" | "bar" | "bar-trans";
      console.log("[Widget] OSD 样式:", style);
      if (style !== osdVisualStyle) {
        osdVisualStyle = style;
        if (osdType === "builtin") {
          invoke("set_osd_visual_style", { style });
        }
        invoke("save_settings", { settings: { osd_visual_style: style } });
      }
    })
      .then((unlisten) => {
        unlistenWidgetOsdStyle = unlisten;
      })
      .catch((e) => console.warn("listen widget-osd-style failed:", e));

    // 监听 Widget FPS 限制变化（Widget 修改 FPS 限制时通知主程序 UI）
    listen<{ enabled: boolean; value: number }>("widget_fps_limit_changed", (event) => {
      const { enabled, value } = event.payload;
      console.log("[Widget] FPS 限制同步:", enabled, value);
      rtssFpsLimitEnabled = enabled;
      rtssFpsLimitValue = value;
    })
      .then((unlisten) => {
        unlistenWidgetFpsLimitChanged = unlisten;
      })
      .catch((e) => console.warn("listen widget-fps-limit-changed failed:", e));

    // 监听 Widget 语言变化（Widget 修改语言时通知主程序 UI）
    listen<string>("widget_language_changed", (event) => {
      const lang = event.payload as Locale;
      console.log("[Widget] 语言同步:", lang);
      if (lang !== currentLanguage) {
        currentLanguage = lang;
        setLocale(lang);
        // OSD 同步
        if (osdType === "builtin") {
          invoke("set_osd_language", { language: lang });
        }
      }
    }).then((unlisten) => {
        unlistenWidgetLanguageChanged = unlisten;
      })
      .catch((e) => console.warn("listen widget-language-changed failed:", e));

    // 监听 RTSS 状态变化事件（由后端检测流程完成后发送）
    listen<RtssDetectionResult>("rtss-status-changed", (event) => {
      const result = event.payload;
      console.log("[RTSS] 状态变化:", result);
      // 更新 rtssStatus 以反映检测结果
      rtssStatus = {
        ...rtssStatus,
        installed: result.path != null,
        running: result.running,
        install_path: result.path,
      };
      // 如果不再需要用户操作，关闭安装对话框
      if (!result.need_user_action) {
        showRtssInstallDialog = false;
      }
    })
      .then((unlisten) => {
        unlistenRtssStatusChanged = unlisten;
      })
      .catch((e) => console.warn("listen rtss-status-changed failed:", e));

    // 监听 Auto-TDP 状态更新
    listen<{
      running: boolean;
      target_fps: number;
      current_tdp: number;
      current_fps: number;
      tdp_min: number;
      tdp_max: number;
    }>("auto-tdp-update", (event) => {
      const status = event.payload;
      autoTdpEnabled = status.running;
      autoTdpTargetFps = status.target_fps;
    })
      .then((unlisten) => {
        unlistenAutoTdpUpdate = unlisten;
      })
      .catch((e) => console.warn("listen auto-tdp-update failed:", e));

    // 监听掌机特殊按键（用于快捷键录制）
    listen<number>("custom-key-pressed", (event) => {
      if (isListeningSummon || isListeningSummon2 || listeningHotkeyType) {
        const customKeys = event.payload;
        // 注意：0x80000000 在 JavaScript 中会被视为负数，使用 !== 0 而不是 > 0
        if (customKeys && customKeys !== 0) {
          // HID 优先：如果之前已经捕获了键盘按键（type="keyboard"），
          // 说明那些键盘键是 HID 映射后的（如 M1→F13），需要丢弃它们，
          // 用原始 HID 按键覆盖
          if (!tempBinding || tempBinding.type !== "gamepadButton") {
            // 清除键盘录制的内容（它们是映射键，不是用户真正想绑定的）
            pressedKeys = [];
            heldKeys.clear();
            maxKeys.clear();
            tempBinding = {
              type: "gamepadButton",
              buttons: [],
              custom_keys: customKeys,
            };
            console.log("[CustomKeys] HID 优先：覆盖键盘绑定，使用 HID 按键:", customKeys);
          } else if (tempBinding.buttons && tempBinding.buttons.length > 0) {
            // 已有 XInput 按钮，说明同一物理按键同时触发了 XInput 和 HID，
            // XInput 优先，忽略 HID 事件
            console.log("[CustomKeys] XInput 已捕获，忽略同时到达的 HID 按键:", customKeys);
          } else {
            // 纯 HID（无 XInput），更新 custom key 状态
            // 注意：payload 是后端发送的完整按键状态（所有当前按下的键），
            // 不能用 JS 的 | 运算符（会截断 bit >= 32 的 u64 值，如 AYANEO/GPD Menu 按键）
            tempBinding.custom_keys = customKeys;
            console.log("[CustomKeys] 更新 HID 按键:", customKeys);
          }
        }
      }
    })
      .then((unlisten) => {
        unlistenCustomKeyPressed = unlisten;
      })
      .catch((e) => console.warn("listen custom-key-pressed failed:", e));

    // 后端推送的 UI 输入事件（替代前端轮询）
    // 大屏幕窗口回退到 0.9.112：前端轮询 + 模拟键盘事件，避免双重输入
    listen<UiKeyPayload>("ui-key", (event) => {
      if (isBigscreenWindow) return;
      dispatchUiKey(event.payload);
    })
      .then((unlisten) => {
        unlistenUiKey = unlisten;
      })
      .catch((e) => console.warn("listen ui-key failed:", e));

    listen<UiTabPayload>("ui-tab", (event) => {
      handleUiTab(event.payload.delta);
    })
      .then((unlisten) => {
        unlistenUiTab = unlisten;
      })
      .catch((e) => console.warn("listen ui-tab failed:", e));

    listen<UiGamepadBindingPayload>("ui-gamepad-binding", (event) => {
      handleUiGamepadBinding(event.payload.button);
    })
      .then((unlisten) => {
        unlistenUiGamepadBinding = unlisten;
      })
      .catch((e) => console.warn("listen ui-gamepad-binding failed:", e));

    listen<UiGamepadStatePayload>("ui-gamepad-state", (event) => {
      handleUiGamepadState(event.payload);
    })
      .then((unlisten) => {
        unlistenUiGamepadState = unlisten;
      })
      .catch((e) => console.warn("listen ui-gamepad-state failed:", e));

    // exit-bigscreen 事件不再需要，大屏幕窗口关闭时会自动销毁

    // 更新检查将在面板首次打开时触发

    // 超时保护：防止 get_initial_settings 卡住导致永远显示骨架屏
    const uiReadyTimeout = setTimeout(() => {
      if (!uiReady) {
        console.warn("[Init] UI 设置加载超时，强制显示界面");
        uiReady = true;
      }
    }, 3000);

    // 异步初始化（并行优化版本）
    (async () => {
      const initStart = performance.now();
      console.log("[Init] ========== 开始初始化 ==========");

      // ===== 阶段1：关键设置（必须优先，影响 UI） =====
      // 只调用一次 get_initial_settings，同时包含 UI 所需的设置，避免重复读取 settings.json
      console.log("[Init] 调用 get_initial_settings...");
      const settingsResult = await invokeWithTimeout<{
        tdp: number | null;
        brightness: number;
        volume: number;
        fanMode: number;
        fanControlAvailable: boolean;
        detectedDevice: string | null;
        fanControlType: string | null;
        summonBinding: SummonBinding | null;
        summonBinding2: SummonBinding | null;
        tdp_min?: number;
        tdp_max?: number;
        deviceTdpMin?: number | null;
        deviceTdpMax?: number | null;
        // 以下字段在 Settings 中本来就存在，这里一并带出，减少一次 load_settings
        theme?: string;
        language?: Locale;
        sound_enabled?: boolean;
        tdp_presets?: number[];
        panel_width?: number;
        font_size?: number;
        gesture_enabled?: boolean;
        blur_hide_enabled?: boolean;
        no_focus_mode?: boolean;
        focus_return_enabled?: boolean;
        fullscreen_mode?: boolean;
        safe_mode?: boolean;
        suspend_on_sleep?: boolean;
        input_isolation_enabled?: boolean;
        xinput_isolation_enabled?: boolean;
        gilrs_detection_enabled?: boolean;
        vibration_intensity?: number;
        trigger_deadzone_lt?: number;
        trigger_deadzone_rt?: number;
        left_stick_mode?: import("./lib/api").KbmStickMode;
        right_stick_mode?: import("./lib/api").KbmStickMode;
        gamepad_vibration_intensity?: number[];
        touchscreen_disabled?: boolean;
        optical_mouse_disabled?: boolean;
        autostart?: boolean;
        start_minimized?: boolean;
        power_switch_tdp_enabled?: boolean;
        hide_tab_bar?: boolean;
        hide_status_bar?: boolean;
        use_osk_keyboard?: boolean;
        quick_items?: QuickItem[];
        active_cores?: number;
        core_mode?: string;
        core_scheduling?: string;
      } | null>("get_initial_settings", undefined, 8000, null);

      // 应用初始设置
      console.log("[Init] get_initial_settings 返回:", settingsResult);
      if (settingsResult) {
        const settings = settingsResult;
        if (settings.brightness !== undefined) brightness = settings.brightness;
        if (settings.volume !== undefined) volume = settings.volume;
        if (settings.fanMode !== undefined) {
          fanModeIndex = settings.fanMode;
          appliedFanModeIndex = settings.fanMode;
        }
        if (settings.fanControlAvailable !== undefined)
          fanControlAvailable = settings.fanControlAvailable;
        if (settings.detectedDevice) detectedDevice = settings.detectedDevice;
        if (settings.fanControlType) fanControlType = settings.fanControlType;
        if (settings.summonBinding && settings.summonBinding.type !== "none")
          summonBinding = settings.summonBinding;
        if (settings.summonBinding2 && settings.summonBinding2.type !== "none")
          summonBinding2 = settings.summonBinding2;
        // 直接用 initial settings 初始化 UI，避免二次读取和竞态
        applyUiSettingsFromInitial(settings);
        // 保存设备推荐的 TDP 范围
        if (settings.deviceTdpMin !== undefined)
          deviceTdpMin = settings.deviceTdpMin;
        if (settings.deviceTdpMax !== undefined)
          deviceTdpMax = settings.deviceTdpMax;
        // 检测 Intel 设备
        if (settings.detectedDevice?.toLowerCase().includes("intel")) {
          isIntelDevice = true;
        }

        // UI 设置加载完成
        clearTimeout(uiReadyTimeout);
        uiReady = true;

        console.log(
          `[Init] 阶段1完成: ${(performance.now() - initStart).toFixed(0)}ms`,
        );

        // 输出设备检测结果
        if (settings.detectedDevice) {
          console.log(
            `检测到设备: ${settings.detectedDevice}, 风扇控制: ${settings.fanControlAvailable ? "可用" : "不可用"}, 类型: ${fanControlType || "N/A"}`,
          );
        } else {
          console.log("未识别到支持的设备，风扇控制已禁用");
        }
      } else {
        // 超时回退：确保 UI 可用
        clearTimeout(uiReadyTimeout);
        uiReady = true;
        console.warn("[Init] get_initial_settings 超时，使用默认设置");
      }

      // ===== 阶段2：并行加载所有独立数据 =====
      const phase2Start = performance.now();

      // 启动所有独立的初始化任务（不等待）
      const parallelTasks = [
        // 游戏库和修改器
        loadGames(),
        loadInstalledTrainers(),
        // 读取分页可见性设置
        invoke<string | null>("load_setting", { key: "tab_visibility" })
          .then((v) => {
            if (v) {
              try {
                const parsed = JSON.parse(v);
                // 合并保存的值到 tabVisibility
                Object.assign(tabVisibility, parsed);
              } catch (e) {
                console.warn("解析分页可见性设置失败", e);
              }
            } else {
              // 回退到旧的 show_trainer_tab 设置（兼容旧版本）
              invoke<string | null>("load_setting", { key: "show_trainer_tab" })
                .then((oldV) => {
                  if (oldV === "true") {
                    tabVisibility.trainers = true;
                  }
                })
                .catch((e) => console.warn("update_trainer_database failed:", e));
            }
          })
          .catch((e) => console.warn("load_settings failed:", e)),
        // 读取分页排序设置
        invoke<string | null>("load_setting", { key: "tab_order" })
          .then((v) => {
            if (v) {
              try {
                const parsed = JSON.parse(v);
                if (Array.isArray(parsed)) {
                  // 确保所有可配置的分页都在列表中
                  const configurableTabs = [
                    "guide",
                    "display",
                    "performance",
                    "monitor",
                    "library",
                    "trainers",
                    "gamepad",
                    "hotkey",
                  ];
                  const validOrder = parsed.filter((id: string) =>
                    configurableTabs.includes(id),
                  );
                  // 添加缺失的分页到末尾
                  for (const tabId of configurableTabs) {
                    if (!validOrder.includes(tabId)) {
                      validOrder.push(tabId);
                    }
                  }
                  tabOrder.splice(0, tabOrder.length, ...validOrder);
                }
              } catch (e) {
                console.warn("解析分页排序设置失败", e);
              }
            }
          })
          .catch((e) => console.warn("get_kv_store tab_order failed:", e)),

        // 系统状态
        invoke<number>("get_volume")
          .then((v) => {
            if (v >= 0) volume = v;
          })
          .catch((e) => console.warn("get_volume failed:", e)),
        // 开机自启状态从持久化设置读取，不从系统查询（太慢）
        invoke<{
          current: boolean;
          ac: boolean;
          dc: boolean;
          is_on_battery: boolean;
        }>("get_turbo_boost")
          .then((status) => {
            turboBoostEnabled = status.current;
          })
          .catch((e) => console.warn("get_turbo_boost failed:", e)),
        invoke<number>("get_cpu_max_freq")
          .then((v) => {
            cpuFreqLimitEnabled = v > 0;
            cpuFreqSlider = v > 0 ? v : 2500;
          })
          .catch((e) => console.warn("get_cpu_max_freq failed:", e)),

        // 硬件状态
        loadWindowProcesses(),
        loadDisplayInfo(),
        detectGyroDevices(),
        // ROG Ally 控制器检测
        invoke<boolean>("rog_ally_is_controller_available")
          .then((available) => {
            rogAllyControllerAvailable = available;
            console.log("[Init] ROG Ally 控制器:", available ? "可用" : "不可用");
          })
          .catch((e) => console.warn("rog_ally_is_controller_available failed:", e)),
        // Legion Go 控制器检测
        invoke<boolean>("legion_is_controller_available")
          .then((available) => {
            legionControllerAvailable = available;
            console.log("[Init] Legion Go 控制器:", available ? "可用" : "不可用");
          })
          .catch((e) => console.warn("legion_is_controller_available failed:", e)),
        loadRadioStatus(),
        loadHotspotStatus(),
        loadMicMuted(),
        loadBatteryStatus(),
        loadEpp(),
        // 活跃核心数：仅用于 UI 显示当前系统状态；启动时应用配置由 init_global_config 负责。
        // 避免 settings.json 与 global_performance.json 双来源导致互相覆盖。
        (async () => {
          await loadCpuCoreCount();
          await loadActiveCores();
        })(),
        loadCoreTopology(),

        // 驱动和高级功能（loadOptimizationStates 不涉及 GPU 驱动，可并行）
        loadOptimizationStates(),

        // 获取 CPU 名称（只显示型号）
        invoke<{ cpu_type: string; cpu_name: string }>("get_cpu_info")
          .then((info) => {
            if (info.cpu_name) {
              // 提取 CPU 型号：AMD 提取如 6800H, Intel 提取如 i7-12700K
              const name = info.cpu_name.trim();
              // AMD: 匹配 Ryzen X XXXX 或纯数字型号
              const amdMatch = name.match(/(\d{4}[A-Z]?[A-Z]?\d?)/i);
              // Intel: 匹配 iX-XXXXX 格式
              const intelMatch = name.match(/(i\d-\d{4,5}[A-Z]*)/i);
              if (intelMatch) cpuName = intelMatch[1];
              else if (amdMatch) cpuName = amdMatch[1];
              else cpuName = name.length > 12 ? name.substring(0, 12) : name;
            }
          })
          .catch((e) => console.warn("get_system_info (cpu_name) failed:", e)),

        // 获取 GPU 名称（只显示型号）
        invoke<string>("get_gpu_name")
          .then((name) => {
            if (name) {
              // 提取 GPU 型号：
              // AMD: RX 6800 XT → 6800XT, Radeon 780M → 780M
              // NVIDIA: RTX 4090 → 4090, GTX 1080 → 1080
              // Intel: Arc A770 → A770
              const rxMatch = name.match(/(?:RX\s*)?(\d{3,4})\s*(XT|XTX)?/i);
              const rtxMatch = name.match(
                /(?:RTX|GTX)\s*(\d{3,4})\s*(Ti|SUPER)?/i,
              );
              const arcMatch = name.match(/Arc\s*(A\d{3,4})/i);
              const mMatch = name.match(/(\d{3,4}M)/i); // 集显如 780M

              if (arcMatch) gpuName = arcMatch[1];
              else if (mMatch) gpuName = mMatch[1];
              else if (rxMatch) gpuName = rxMatch[1] + (rxMatch[2] || "");
              else if (rtxMatch) gpuName = rtxMatch[1] + (rtxMatch[2] || "");
              else gpuName = name.length > 12 ? name.substring(0, 12) : name;
            }
          })
          .catch((e) => console.warn("get_gpu_name failed:", e)),

        // Intel CPU/GPU 偏好（仅 Intel 设备）
        isIntelDevice ? loadIntelGpuPowerShare() : Promise.resolve(),

        // 电源计划
        loadPowerPlans(),

        // 光学鼠标（使用 chcp 437 + pnputil 读取状态，参考 MotionAssistant 项目）
        invoke<boolean>("check_optical_mouse_available")
          .then(async (available) => {
            opticalMouseAvailable = available;
            if (available) {
              opticalMouseEnabled = await invoke<boolean>(
                "check_optical_mouse_enabled",
              );
            }
          })
          .catch((e) => console.warn("check_optical_mouse_available failed:", e)),

        // 触摸屏：检测可用性；若用户设置为“禁用触摸屏”，启动时 best-effort 再禁用一次。
        // 一些设备可能在重启后触摸屏重新枚举/被系统重新启用，仅靠持久化设置无法保证硬件状态。
        invoke<boolean>("check_touchscreen_available")
          .then((available) => {
            touchscreenAvailable = available;

            // 如果用户希望禁用触摸屏，则在后台尝试应用一次（不阻塞初始化）
            if (available && touchscreenEnabled === false) {
              (async () => {
                try {
                  const isEnabled = await invoke<boolean>(
                    "check_touchscreen_enabled",
                  ).catch(() => true);
                  if (!isEnabled) return;

                  await invoke("set_touchscreen_enabled", { enabled: false });
                  console.log("[Init] 已根据设置禁用触摸屏");
                } catch (e) {
                  console.error("[Init] 启动时禁用触摸屏失败:", e);
                  // 不回滚 UI：持久化设置仍然是“禁用”
                  showToast(t("toast_set_failed"), "error");
                }
              })();
            }
          })
          .catch((e) => console.warn("check_touchscreen_available failed:", e)),

      ];

      // 等待所有无硬件冲突的任务完成
      await Promise.allSettled(parallelTasks);

      // ===== 阶段 2b：驱动相关初始化（串行，避免 ADLX / LHM GPU 并发 TDR）=====
      // 顺序：ADLX 初始化 → LHM 启动（loadRtssStatus 内触发）
      // ADLX 初始化期间后端会阻止 LHM 启动（ADLX_INIT_IN_PROGRESS 标志），
      // 这里在前端也做串行保证双重安全。每个步骤有独立超时保护。
      try { await Promise.race([checkAdlxAvailable(), new Promise((_, rej) => setTimeout(() => rej("timeout"), 10000))]); }
      catch (e) { console.warn("[Init] checkAdlxAvailable 超时或失败:", e); }

      // RTSS 启动检测：按优先级检测 RTSS（持久化路径 → 注册表 → 进程 → 安装引导）
      try {
        const detectResult = await Promise.race([
          invoke<RtssDetectionResult>("rtss_startup_detect"),
          new Promise<RtssDetectionResult>((_, rej) => setTimeout(() => rej("timeout"), 15000)),
        ]);
        console.log("[RTSS] 启动检测结果:", detectResult);
        // 更新 rtssStatus
        rtssStatus = {
          ...rtssStatus,
          installed: detectResult.path != null,
          running: detectResult.running,
          install_path: detectResult.path,
        };
        // 需要用户操作时显示安装引导对话框
        if (detectResult.need_user_action) {
          showRtssInstallDialog = true;
        }
      } catch (e) {
        console.warn("[Init] rtss_startup_detect 超时或失败:", e);
      }

      try { await Promise.race([loadRtssStatus(), new Promise((_, rej) => setTimeout(() => rej("timeout"), 10000))]); }
      catch (e) { console.warn("[Init] loadRtssStatus 超时或失败:", e); }

      // Auto-TDP 可用性检查（在 loadRtssStatus 完成后执行，确保 RTSS 已启动）
      // 后端会先等待系统就绪（开机自启时最多 30s），再检查 RTSS 共享内存（重试最多 12s）
      try { await Promise.race([checkAutoTdpAvailable(), new Promise((_, rej) => setTimeout(() => rej("timeout"), 45000))]); }
      catch (e) { console.warn("[Init] checkAutoTdpAvailable 超时或失败:", e); }

      // 浮动 GPU 可用性检查
      try { await Promise.race([checkFloatGpuAvailable(), new Promise((_, rej) => setTimeout(() => rej("timeout"), 10000))]); }
      catch (e) { console.warn("[Init] checkFloatGpuAvailable 超时或失败:", e); }

      // 恢复 Auto-TDP 和 Auto-Fan 设置（合并为单次 load_settings 调用）
      try {
        const savedSettings = await invoke<any>("load_settings");

        // Auto-TDP
        if (autoTdpAvailable) {
          if (savedSettings?.auto_tdp_target_fps) {
            autoTdpTargetFps = savedSettings.auto_tdp_target_fps;
          }
          if (savedSettings?.auto_tdp_enabled === true) {
            await invoke("start_auto_tdp", {
              config: {
                enabled: true,
                target_fps: autoTdpTargetFps,
                tdp_min: tdpMin,
                tdp_max: tdpMax,
              },
            });
            autoTdpEnabled = true;
            console.log("[Init] 恢复 Auto-TDP 状态: 已启用");
          }
        }

        // Auto-Fan（仅在支持风扇控制的设备上恢复）
        if (fanControlAvailable) {
          if (savedSettings?.auto_fan_temp_min != null) {
            autoFanTempMin = savedSettings.auto_fan_temp_min;
          }
          if (savedSettings?.auto_fan_temp_max != null) {
            autoFanTempMax = savedSettings.auto_fan_temp_max;
          }
          if (savedSettings?.auto_fan_enabled === true) {
            await invoke("start_auto_fan", {
              config: {
                enabled: true,
                temp_min: autoFanTempMin,
                temp_max: autoFanTempMax,
              },
            });
            autoFanEnabled = true;
            console.log("[Init] 恢复 Auto-Fan 状态: 已启用");
          }
        }

        // 浮动 GPU（仅在 AMD CPU 上恢复）
        if (floatGpuAvailable && savedSettings?.float_gpu_enabled === true) {
          try {
            const result = await invoke<{ success: boolean }>(
              "set_float_gpu_enabled",
              { enabled: true, gpuType: floatGpuType }
            );
            if (result.success) {
              floatGpuEnabled = true;
              await updateFloatGpuStatus();
              console.log("[Init] 恢复浮动 GPU 状态: 已启用");
            }
          } catch (e) {
            console.error("[Init] 恢复浮动 GPU 状态失败:", e);
          }
        }

        // 性能场景配置
        if (savedSettings?.game_profile_switch_enabled != null) {
          gameProfileSwitchEnabled = savedSettings.game_profile_switch_enabled;
        }
        if (savedSettings?.ac_profile_id != null) {
          acProfileId = savedSettings.ac_profile_id;
        }
        if (savedSettings?.battery_profile_id != null) {
          batteryProfileId = savedSettings.battery_profile_id;
        }
        if (savedSettings?.performance_profiles && Array.isArray(savedSettings.performance_profiles)) {
          performanceProfiles = savedSettings.performance_profiles;
          
          // 初始化临时选中索引为当前绑定的场景
          if (acProfileId) {
            const acIdx = performanceProfiles.findIndex(p => p.id === acProfileId);
            selectedAcProfileIndex = acIdx >= 0 ? acIdx : 0;
          }
          if (batteryProfileId) {
            const batIdx = performanceProfiles.findIndex(p => p.id === batteryProfileId);
            selectedBatteryProfileIndex = batIdx >= 0 ? batIdx : 0;
          }
        }
        // 鼠标模拟
        if (savedSettings?.mouse_sim_enabled === true) {
          try {
            await invoke("set_mouse_simulation", { enabled: true });
            mouseSimEnabled = true;
            console.log("[Init] 恢复鼠标模拟状态: 已启用");
          } catch (e) {
            console.error("[Init] 恢复鼠标模拟失败:", e);
          }
        }

        console.log("[Init] 恢复场景化设置完成");
      } catch (e) {
        console.error("[Init] 恢复 Auto-TDP/Auto-Fan 设置失败:", e);
      }

      console.log(
        `[Init] 阶2完成: ${(performance.now() - phase2Start).toFixed(0)}ms`,
      );
      console.log(
        `[Init] 总初始化时间: ${(performance.now() - initStart).toFixed(0)}ms`,
      );

      // 启动电池状态轮询（每 2 秒更新一次）
      batteryPollInterval = window.setInterval(loadBatteryStatus, 2000);

      // 启动时间更新（每秒更新）
      timeUpdateInterval = window.setInterval(() => {
        currentTime = new Date().toLocaleTimeString("zh-CN", {
          hour: "2-digit",
          minute: "2-digit",
        });
      }, 1000);

      // 监听后端状态变化事件（后端已操作窗口，只同步前端状态）
      unlistenOpen = await listen<boolean>(
        "panel-state-changed",
        async (event) => {
          isExternalStateChange = true;
          isOpen = event.payload;

          // 面板隐藏时立即中断所有按键操作
          if (!event.payload) {
            // 清除所有长按/连发定时器和状态
            clearXButtonHold();
            clearYButtonHold();
            clearAButtonHold();
            clearNavigationRepeat();
            clearKeyRepeat();

            // 强制清除所有快捷键监听状态（防止卡住导致 B 键失效）
            isListeningSummon = false;
            isListeningSummon2 = false;
            if (listeningHotkeyType) {
              listeningHotkeyType = null;
            }

            // 中断按键映射（复用 KBM 引擎）录制弹窗/捕获
            cancelButtonMappingDialog();

            // 清理所有可能残留的弹窗/浮层状态
            gameMenuOpen = false;
            gameMenuTarget = null;
            editingGameInfo = null;
            profileRenameOpen = false;
            hotspotConfigMode = false;

            // 等待 DOM 更新后通知后端动画已开始
            await tick();
            requestAnimationFrame(() => {
              // 再等一帧确保动画开始
              requestAnimationFrame(() => {
                invoke("panel_hide_animation_started").catch((e) => console.warn("panel_hide_animation_started failed:", e));
              });
            });
          } else {
            // 面板显示时也重置状态
            clearYButtonHold();
            clearAButtonHold();

            // 强制清除监听状态（防止上次隐藏时未清除导致 B 键失效）
            isListeningSummon = false;
            isListeningSummon2 = false;
            if (listeningHotkeyType) {
              listeningHotkeyType = null;
            }

            try {
              const realVolume = await invoke<number>("get_volume");
              if (realVolume >= 0) {
                volume = realVolume;
              }
            } catch (e) {
              // 静默失败
            }

            // 面板首次打开时检查更新（本次会话只检查一次）
            if (!hasCheckedUpdateThisSession) {
              hasCheckedUpdateThisSession = true;
              // 延迟 1 秒后检查，避免阻塞面板显示（使用 safeTimeout 确保组件卸载时清理）
              safeTimeout(() => {
                silentCheckUpdate();
              }, 1000);
            }
          }
        },
      );

      // 同步初始面板状态（从后端获取，支持最小化启动）
      invoke<boolean>("get_panel_state")
        .then((initialState) => {
          isOpen = initialState;
          isInitializing = false; // 初始化完成，允许 effect 同步状态
          console.log("[Startup] 初始面板状态:", initialState);
        })
        .catch((e) => {
          console.error("[Startup] 获取面板状态失败:", e);
          isInitializing = false;
        });
    })();

    // 大屏幕窗口：回退到 0.9.112 的前端手柄轮询（避免后端 ui-key 路由导致大屏无输入）
    if (isBigscreenWindow) {
      startBigscreenGamepadPolling();
    }

    // 手柄输入已改为后端推送事件（ui-key/ui-tab/ui-gamepad-*），无需前端轮询（大屏幕窗口除外）

    // 倒计时
    const countdownInterval = setInterval(() => {
      if (isListeningSummon && listeningCountdown > 0) {
        listeningCountdown--;
        if (listeningCountdown === 0) confirmBinding();
      }
      // 第二个呼出键监听倒计时（使用 else if 防止同一 tick 多次递减）
      else if (isListeningSummon2 && listeningCountdown > 0) {
        listeningCountdown--;
        if (listeningCountdown === 0) confirmBinding();
      }
      // 新快捷键监听倒计时
      else if (listeningHotkeyType && listeningCountdown > 0) {
        listeningCountdown--;
        if (listeningCountdown === 0) confirmHotkeyBinding();
      }

      // 按键映射（复用 KBM 引擎）手柄 chord 捕获倒计时
      if (buttonMappingDialog && buttonMappingGamepadCaptureCountdown > 0) {
        buttonMappingGamepadCaptureCountdown--;
        if (buttonMappingGamepadCaptureCountdown === 0) {
          stopButtonMappingGamepadCapture();
        }
      }
    }, 1000);

    // 窗口获得焦点时清除手柄按钮状态，防止虚假触发
    const handleFocus = () => {
      // 清除可能残留的按键/长按状态，避免从游戏切回面板时产生虚假触发
      clearXButtonHold();
      clearYButtonHold();
      clearAButtonHold();
      cancelHotkeyHold();
    };
    window.addEventListener("focus", handleFocus);

    // 窗口失焦时的处理
    const handleBlur = () => {
      // 独立大屏幕窗口不处理失焦
      if (isBigscreenWindow) return;

      // 普通模式下，失焦自动隐藏面板
      if (blurHideEnabled) {
        invoke("hide_panel").catch(console.error);
      }
    };
    const blurTimer = setTimeout(() => {
      window.addEventListener("blur", handleBlur);
    }, 1500);

    return () => {
      clearInterval(countdownInterval);
      clearTimeout(blurTimer);
      stopMediaInfoPolling();
      if (batteryPollInterval) clearInterval(batteryPollInterval);
      if (timeUpdateInterval) clearInterval(timeUpdateInterval);
      // 使用 typeof 检查确保 unlisten 是函数，防止 listen() Promise 失败时调用 undefined
      if (typeof unlistenOpen === "function") unlistenOpen();
      if (typeof unlistenWatchdog === "function") unlistenWatchdog();
      if (typeof unlistenUpdateProgress === "function") unlistenUpdateProgress();
      if (typeof unlistenBackendToast === "function") unlistenBackendToast();
      if (typeof unlistenUiKey === "function") unlistenUiKey();
      if (typeof unlistenUiTab === "function") unlistenUiTab();
      if (typeof unlistenUiGamepadBinding === "function") unlistenUiGamepadBinding();
      if (typeof unlistenUiGamepadState === "function") unlistenUiGamepadState();
      // 清理新增的事件监听器（修复内存泄漏）
      if (typeof unlistenOsdReady === "function") unlistenOsdReady();
      if (typeof unlistenOsdRequestRefresh === "function") unlistenOsdRequestRefresh();
      if (typeof unlistenHotkeyOsdToggle === "function") unlistenHotkeyOsdToggle();
      if (typeof unlistenHotkeyOsdModeNext === "function") unlistenHotkeyOsdModeNext();
      if (typeof unlistenHotkeyTdpUp === "function") unlistenHotkeyTdpUp();
      if (typeof unlistenHotkeyTdpDown === "function") unlistenHotkeyTdpDown();
      if (typeof unlistenHotkeyMouseSimToggle === "function") unlistenHotkeyMouseSimToggle();
      if (typeof unlistenHotkeyScreenshot === "function") unlistenHotkeyScreenshot();
      if (typeof unlistenHotkeyRecordToggle === "function") unlistenHotkeyRecordToggle();
      if (typeof unlistenHotkeyGyroToggle === "function") unlistenHotkeyGyroToggle();
      if (typeof unlistenHotkeyGyroHold === "function") unlistenHotkeyGyroHold();
      if (typeof unlistenHotkeyGyroRelease === "function") unlistenHotkeyGyroRelease();
      if (typeof unlistenMouseSimChanged === "function") unlistenMouseSimChanged();
      if (typeof unlistenWidgetTdpChanged === "function") unlistenWidgetTdpChanged();
      if (typeof unlistenWidgetFanModeChanged === "function") unlistenWidgetFanModeChanged();
      if (typeof unlistenWidgetOsdToggle === "function") unlistenWidgetOsdToggle();
      if (typeof unlistenWidgetOsdMode === "function") unlistenWidgetOsdMode();
      if (typeof unlistenWidgetOsdStyle === "function") unlistenWidgetOsdStyle();
      if (typeof unlistenWidgetFpsLimitChanged === "function") unlistenWidgetFpsLimitChanged();
      if (typeof unlistenAutoTdpUpdate === "function") unlistenAutoTdpUpdate();
      if (typeof unlistenCustomKeyPressed === "function") unlistenCustomKeyPressed();
      if (typeof unlistenProfileApplied === "function") unlistenProfileApplied();
      if (typeof unlistenDeviceDetected === "function") unlistenDeviceDetected();
      if (typeof unlistenWidgetLanguageChanged === "function") unlistenWidgetLanguageChanged();
      if (typeof unlistenRtssStatusChanged === "function") unlistenRtssStatusChanged();
      if (typeof unlistenSystemResumed === "function") unlistenSystemResumed();
      if (bigscreenGamepadPollTimer) {
        clearTimeout(bigscreenGamepadPollTimer);
        bigscreenGamepadPollTimer = null;
      }
      // 清理陀螺仪轮询定时器
      if (gyroPollInterval) {
        clearTimeout(gyroPollInterval);
        gyroPollInterval = null;
      }
      // 清理快捷键长按定时器
      if (hotkeyHoldTimer) {
        clearTimeout(hotkeyHoldTimer);
        hotkeyHoldTimer = null;
      }
      // 清理危险操作确认定时器
      if (dangerConfirmTimer) {
        clearInterval(dangerConfirmTimer);
        dangerConfirmTimer = null;
      }
      // 清理核心模式确认定时器
      if (coreModeConfirmTimer) {
        clearTimeout(coreModeConfirmTimer);
        coreModeConfirmTimer = null;
      }
      // 清理性能监控定时器（由 $effect 创建，但组件卸载时需要显式清理）
      if (perfMetricsInterval) {
        clearInterval(perfMetricsInterval);
        perfMetricsInterval = null;
      }
      // 清理 RTSS OSD 轮询定时器
      if (rtssPollingInterval) {
        clearInterval(rtssPollingInterval);
        rtssPollingInterval = null;
      }
      // 清理按键连发/长按定时器
      clearKeyRepeat();
      clearNavigationRepeat();
      clearXButtonHold();
      clearAButtonHold();
      // 清理分页切换防抖定时器
      if (tabSwitchTimer) {
        clearTimeout(tabSwitchTimer);
        tabSwitchTimer = null;
      }
      stopYButtonHoldTimer();
      // 清理防抖保存定时器
      if (saveSettingsTimer !== null) {
        clearTimeout(saveSettingsTimer);
        saveSettingsTimer = null;
      }
      // 清理所有通过 safeTimeout 创建的一次性定时器
      clearAllPendingTimeouts();
      window.removeEventListener("focus", handleFocus);
      window.removeEventListener("blur", handleBlur);
    };
  });

  // 管理媒体信息轮询（仅在视听Tab且面板打开时）
  $effect(() => {
    if (currentTabId === "display" && isOpen) {
      startMediaInfoPolling();
    } else {
      stopMediaInfoPolling();
    }
  });

  // 切换到手柄页时刷新手柄列表
  $effect(() => {
    if (currentTabId === "gamepad" && isOpen) {
      refreshConnectedGamepads();
    }
  });

  // 性能监控数据轮询（性能页激活时）
  $effect(() => {
    // 当性能页打开 或 OSD 启用 或 快捷页有性能监控项时，都需要监控数据
    const hasQuickPerfMonitor = quickItems.some(
      (item) => item.item_id === "perf_monitor",
    );
    const needsMetrics =
      (currentTabId === "performance" && isOpen) ||
      (currentTabId === "quick" && hasQuickPerfMonitor && isOpen) ||
      rtssOsdEnabled;
    if (needsMetrics) {
      // 立即获取一次
      updatePerformanceMetrics();
      // 每秒更新一次（统一更新，供性能页和 OSD 共用）
      const id = window.setInterval(updatePerformanceMetrics, 1000);
      perfMetricsInterval = id;
      // $effect 清理函数：在依赖变化或组件卸载时自动清理
      return () => {
        clearInterval(id);
        perfMetricsInterval = null;
      };
    } else {
      perfMetricsInterval = null;
    }
  });

  let perfMetricsInProgress = false; // 防止性能监控轮询堆积

  async function updatePerformanceMetrics() {
    // 防止堆积：如果上一次还没完成，跳过本次
    if (perfMetricsInProgress) return;
    perfMetricsInProgress = true;

    try {
      performanceMetrics = await invoke<SystemMetrics>("get_system_metrics");


      // Auto-TDP 活跃状态检查（仅当 Auto-TDP 功能功能开启时）
      if (autoTdpEnabled) {
        try {
          autoTdpActive = await invoke<boolean>("is_auto_tdp_active");
        } catch {
          autoTdpActive = false;
        }
      } else {
        autoTdpActive = false;
      }
    } catch (e) {
      /* 静默失败 */
    } finally {
      perfMetricsInProgress = false;
    }
  }

  // 面板状态同步到后端（仅当前端触发时，如按 M 键）
  $effect(() => {
    const open = isOpen;
    // 初始化期间不同步，等待从后端获取初始状态
    if (isInitializing) {
      return;
    }
    // 使用 untrack 读取标志，避免将其作为响应式依赖
    // 否则 isExternalStateChange = false 会触发 effect 重跑，导致仍调用 invoke
    if (untrack(() => isExternalStateChange)) {
      isExternalStateChange = false;
      return;
    }
    invoke(open ? "show_panel" : "hide_panel").catch(console.error);
  });

  // 手柄测试模式同步到后端
  $effect(() => {
    invoke("set_gamepad_test_mode", { isTestMode: isGamepadTestMode }).catch(
      console.error,
    );
  });

  // 绑定监听模式同步到后端
  $effect(() => {
    invoke("set_binding_listening_mode", {
      isListening:
        isListeningSummon ||
        isListeningSummon2 ||
        !!listeningHotkeyType ||
        buttonMappingGamepadCaptureCountdown > 0,
    }).catch(console.error);
  });

  // 焦点变化时滚动到可见区域
  $effect(() => {
    focusIndex;
    activeTab;
    // 如果是分页设置变化导致的更新，跳过滚动
    if (suppressScrollOnTabUpdate) {
      suppressScrollOnTabUpdate = false;
      return;
    }
    scrollToFocused();
  });
</script>

<svelte:window onkeydown={handleKeydown} onkeyup={handleKeyup} />

{#if isBigscreenWindow}
  <!-- 独立大屏幕窗口 -->
  <BigScreen
    games={games.map((g) => ({ ...g, cover: g.cover || gameCovers[g.id] }))}
    onExit={async () => {
      await invoke("close_bigscreen_window");
    }}
    onLaunchGame={(game) => {
      launchGame(game);
    }}
    onAddGame={() => {
      addGameManually();
    }}
    onTogglePin={async (game) => {
      await invoke('toggle_game_pinned', { gameId: game.id });
      games = games.map(g => g.id === game.id ? { ...g, pinned: !g.pinned } : g);
    }}
    {tdpWatts}
    {tdpMin}
    {tdpMax}
    onTdpChange={(v) => {
      tdpWatts = v;
      applyTdp(v);
    }}
    {fanModeIndex}
    fanModes={[t("fan_silent"), t("fan_balanced"), t("fan_performance")]}
    onFanModeChange={(i) => {
      fanModeIndex = i;
      applyFanMode();
    }}
    {brightness}
    onBrightnessChange={(v) => {
      brightness = v;
      applyBrightness();
    }}
    {volume}
    onVolumeChange={(v) => {
      volume = v;
      applyVolume();
    }}
    {refreshRateIndex}
    refreshRates={availableRefreshRates.map((r) => r + "Hz")}
    onRefreshRateChange={(i) => {
      refreshRateIndex = i;
      applyDisplaySettings();
    }}
    {t}
  />
{:else}
  <div class="app-container" class:open={isOpen} class:ui-ready={uiReady}>
    <!-- 顶部 Tab 栏 -->
    <nav class="tab-bar" class:hidden={hideTabBar}>
      {#each visibleTabs as tab, i}
        <button
          class="tab-item"
          class:active={activeTab === i}
          onclick={() => {
            switchTab(i);
          }}
        >
          <div class="tab-icon-wrapper">
            {#if tab.id === "quick"}
              <!-- StarIcon (快捷) -->
              <Icon name="star-path" size={20} />
            {:else if tab.id === "library"}
              <!-- LibraryIcon (Grid) -->
              <Icon name="grid-rects" size={20} />
            {:else if tab.id === "performance"}
              <!-- ZapIcon -->
              <Icon name="zap" size={20} />
            {:else if tab.id === "display"}
              <!-- MonitorIcon + Volume -->
              <Icon name="monitor-lines" size={20} />
            {:else if tab.id === "gamepad"}
              <!-- GamepadIcon -->
              <Icon name="gamepad-lines" size={20} />
            {:else if tab.id === "monitor"}
              <!-- ActivityIcon (心电图) -->
              <Icon name="activity" size={20} />
            {:else if tab.id === "trainers"}
              <!-- TrainerIcon (Package) -->
              <Icon name="package" size={20} />
            {:else}
              <!-- SettingsIcon -->
              <Icon name="settings" size={20} />
            {/if}
          </div>
          <span class="tab-label">{t(tab.label as TranslationKey)}</span>
          {#if activeTab === i}<div class="active-indicator"></div>{/if}
        </button>
      {/each}
    </nav>

    <!-- 内容区 -->
    <div class="content-body custom-scrollbar" bind:this={contentBody}>
      {#if currentTabId === "quick"}
        <!-- 快捷分页 -->
        <div class="animate-fade-in">
          {#if quickItems.length === 0}
            <div
              class="empty-state"
              style="text-align: center; padding: 40px 20px; color: var(--text-secondary);"
            >
              <Icon name="star-path" size={48} style="margin-bottom: 16px; opacity: 0.5;" />
              <h3 style="margin: 0 0 8px 0; font-size: 16px; font-weight: 500;">
                {t("no_quick_items")}
              </h3>
              <p style="margin: 0; font-size: 13px; line-height: 1.5;">
                {@html t("quick_items_hint")}
              </p>
            </div>
          {:else}
            <h3
              class="section-title"
              style="display: flex; align-items: center; gap: 8px;"
            >
              <Icon name="star-path" size={16} />
              {t("my_quick_items")}
              <span
                style="font-size: 11px; color: var(--text-secondary); font-weight: normal;"
                >{isInSwapMode
                  ? t("swap_hint_confirm")
                  : t("swap_hint_normal")}</span
              >
            </h3>
            {#each quickItems as item, idx}
              {@const itemValue = getQuickItemValue(item.tab_id, item.item_id)}
              {@const isSwapSource = swapSourceIndex === idx}
              <div
                class="list-item"
                class:focused={focusIndex === idx}
                class:swap-source={isSwapSource}
                data-focus-index={idx}
                role="button"
                tabindex="0"
                style={isSwapSource
                  ? "opacity: 0.5; background: var(--bg-tertiary);"
                  : ""}
                onclick={() => {
                  focusIndex = idx;
                  // slider 类型由滑块的 pointerup 处理，避免重复触发
                  if (item.item_type !== "slider") {
                    handleQuickItemAction(idx);
                  }
                }}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
                    <svg
                      width="16"
                      height="16"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      stroke-width="2"
                      style="opacity: 0.6;"
                    >
                      {#if item.item_type === "slider"}
                        <line x1="4" y1="21" x2="4" y2="14" /><line
                          x1="4"
                          y1="10"
                          x2="4"
                          y2="3"
                        /><line x1="12" y1="21" x2="12" y2="12" /><line
                          x1="12"
                          y1="8"
                          x2="12"
                          y2="3"
                        /><line x1="20" y1="21" x2="20" y2="16" /><line
                          x1="20"
                          y1="12"
                          x2="20"
                          y2="3"
                        /><line x1="1" y1="14" x2="7" y2="14" /><line
                          x1="9"
                          y1="8"
                          x2="15"
                          y2="8"
                        /><line x1="17" y1="16" x2="23" y2="16" />
                      {:else if item.item_type === "toggle"}
                        <rect
                          x="1"
                          y="5"
                          width="22"
                          height="14"
                          rx="7"
                          ry="7"
                        /><circle cx="16" cy="12" r="3" />
                      {:else if item.item_type === "action"}
                        <circle cx="12" cy="12" r="10" /><line
                          x1="15"
                          y1="9"
                          x2="9"
                          y2="15"
                        /><line x1="9" y1="9" x2="15" y2="15" />
                      {:else if item.item_type === "display"}
                        <!-- 性能监控图标 -->
                        <rect
                          x="3"
                          y="3"
                          width="18"
                          height="18"
                          rx="2"
                          ry="2"
                        />
                        <line x1="7" y1="17" x2="7" y2="13" />
                        <line x1="11" y1="17" x2="11" y2="9" />
                        <line x1="15" y1="17" x2="15" y2="11" />
                      {:else}
                        <polyline points="9 18 15 12 9 6" />
                      {/if}
                    </svg>
                    {getItemLabel(item.tab_id, item.item_id)}
                  </div>
                  <!-- 根据类型渲染右侧控件 -->
                  {#if item.item_type === "toggle"}
                    <!-- 开关组件 -->
                    <ToggleSwitch checked={itemValue.value === true} />
                  {:else if item.item_type === "slider"}
                    <!-- 滑条值显示 -->
                    <span class="item-value"
                      >{itemValue.label || itemValue.value}</span
                    >
                  {:else if item.item_type === "stepper"}
                    <!-- 步进器：右侧显示 action-hint -->
                    {#if focusIndex === idx}<span class="action-hint"
                        >{isHorizontalListStepper(item.item_id)
                          ? t("click_to_select")
                          : t("left_right_adjust")}</span
                      >{/if}
                  {:else if item.item_type === "action"}
                    <!-- 动作按钮：右侧显示 action-hint -->
                    {#if focusIndex === idx}<span class="action-hint"
                        >{t("press_a_execute")}</span
                      >{/if}
                  {:else if item.item_type === "display"}
                    <!-- 性能监控：显示只读提示 -->
                    <span
                      class="item-value"
                      style="font-size: 12px; opacity: 0.7;"
                      >{t("perf_monitor")}</span
                    >
                  {/if}
                </div>
                <!-- 步进器组件 - 单独一行 -->
                {#if item.item_type === "stepper"}
                  {#if isHorizontalListStepper(item.item_id)}
                    <!-- 横向列表样式（TDP预设、风扇策略等） -->
                    {@const options = getStepperOptions(item.item_id)}
                    <div class="stepper-row">
                      {#each options as opt, i}
                        <div
                          class="stepper-item"
                          class:active={itemValue.value === opt.value ||
                            itemValue.value === i}
                          role="option"
                          tabindex="0"
                          aria-selected={itemValue.value === opt.value ||
                            itemValue.value === i}
                          onclick={(e) => {
                            e.stopPropagation();
                            handleQuickStepperSelect(
                              item.tab_id,
                              item.item_id,
                              opt.value,
                            );
                          }}
                          onkeydown={() => {}}
                        >
                          <div class="stepper-dot"></div>
                          <span class="stepper-label">{opt.label}</span>
                        </div>
                      {/each}
                    </div>
                  {:else}
                    <!-- 箭头选择器样式（刷新率、分辨率等） -->
                    <div class="arrow-stepper">
                      <button
                        class="arrow-stepper-btn"
                        aria-label={t("aria_decrease")}
                        onclick={(e) => {
                          e.stopPropagation();
                          handleQuickValueChange(item.tab_id, item.item_id, -1);
                        }}
                      >
<Icon name="chevron-left" size={18} />
                      </button>
                      <span class="arrow-stepper-value"
                        >{itemValue.label || itemValue.value}</span
                      >
                      <button
                        class="arrow-stepper-btn"
                        aria-label={t("aria_increase")}
                        onclick={(e) => {
                          e.stopPropagation();
                          handleQuickValueChange(item.tab_id, item.item_id, 1);
                        }}
                      >
<Icon name="chevron-right" size={18} />
                      </button>
                    </div>
                  {/if}
                {/if}
                <!-- 滑条组件 - 单独一行 -->
                {#if item.item_type === "slider" && typeof itemValue.value === "number" && itemValue.min !== undefined && itemValue.max !== undefined}
                  {@const percent =
                    ((itemValue.value - itemValue.min) /
                      (itemValue.max - itemValue.min)) *
                    100}
                  <div
                    class="slider-track"
                    onpointerdown={(e) => {
                      e.stopPropagation();
                      if (
                        itemValue.min !== undefined &&
                        itemValue.max !== undefined
                      ) {
                        handleQuickSliderPointerDown(
                          e,
                          item.tab_id,
                          item.item_id,
                          itemValue.min,
                          itemValue.max,
                        );
                      }
                    }}
                    onpointermove={(e) => {
                      e.stopPropagation();
                      handleQuickSliderPointerMove(e);
                    }}
                    onpointerup={(e) => {
                      e.stopPropagation();
                      handleQuickSliderPointerUp(e);
                    }}
                  >
                    <div class="slider-fill" style="width: {percent}%"></div>
                    <div
                      class="slider-thumb"
                      class:dragging={isDragging &&
                        quickSliderDragInfo?.itemId === item.item_id}
                      style="left: {percent}%"
                    ></div>
                  </div>
                {/if}
                <!-- 性能监控组件 - 单独一行 -->
                {#if item.item_type === "display" && item.item_id === "perf_monitor"}
                  <div class="perf-monitor-grid" style="margin-top: 8px;">
                    <!-- 第一行 -->
                    <div class="perf-item">
                      <span class="perf-label">TDP</span>
                      {#if autoTdpActive}
                        <span
                          class="perf-value auto-tdp"
                          title="Auto-TDP {t('auto_tdp_active')}"
                          >{t("auto_tdp_active")}</span
                        >
                      {:else}
                        <span class="perf-value accent"
                          >{finalTdp ? `${finalTdp}W` : "Max"}</span
                        >
                      {/if}
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_power")}</span>
                      <span class="perf-value power">{(() => {
                        // APU 功耗：优先 SoC 功耗，否则用 CPU 核心功耗
                        const apuPower = (performanceMetrics.soc_power || 0) > 0.5
                          ? (performanceMetrics.soc_power || 0)
                          : (performanceMetrics.cpu_power || 0);
                        return apuPower.toFixed(0);
                      })()}W</span>
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_discharge")}</span>
                      {#if batteryStatus.has_battery && performanceMetrics.battery_power && performanceMetrics.battery_power > 0.5}
                        <span class="perf-value power"
                          >-{performanceMetrics.battery_power.toFixed(1)}W</span
                        >
                      {:else if batteryStatus.has_battery && performanceMetrics.battery_power && performanceMetrics.battery_power < -0.5}
                        <span class="perf-value battery charging"
                          >+{(-performanceMetrics.battery_power).toFixed(
                            1,
                          )}W</span
                        >
                      {:else if !batteryStatus.has_battery || batteryStatus.is_ac_connected}
                        <span class="perf-value ac">AC</span>
                      {:else}
                        <span class="perf-value">0W</span>
                      {/if}
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">CPU</span>
                      <span class="perf-value cpu"
                        >{(performanceMetrics.cpu_usage || 0).toFixed(0)}%</span
                      >
                    </div>
                    <!-- 第二行 -->
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_temp")}</span>
                      <span
                        class="perf-value temp"
                        class:hot={performanceMetrics.cpu_temp > 80}
                        >{(performanceMetrics.cpu_temp || 0).toFixed(0)}°C</span
                      >
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_fan")}</span>
                      <span class="perf-value fan"
                        >{performanceMetrics.fan_speed || 0}</span
                      >
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_memory")}</span>
                      <span
                        class="perf-value"
                        class:low={performanceMetrics.ram_usage >= 90}
                        >{Math.round(performanceMetrics.ram_usage)}%</span
                      >
                    </div>
                    <div class="perf-item">
                      <span class="perf-label">{t("perf_battery_life")}</span>
                      {#if batteryStatus.has_battery && !batteryStatus.is_charging}
                        <span class="perf-value time"
                          >{batteryStatus.battery_life_time
                            ? `${Math.floor(batteryStatus.battery_life_time / 3600)}h${Math.floor((batteryStatus.battery_life_time % 3600) / 60)}m`
                            : "--"}</span
                        >
                      {:else if batteryStatus.is_charging}
                        <span class="perf-value battery charging">AC</span>
                      {:else}
                        <span class="perf-value ac">∞</span>
                      {/if}
                    </div>
                  </div>
                {/if}
                <!-- X 键长按删除进度条 -->
                {#if focusIndex === idx && xButtonHoldProgress > 0}
                  <div
                    class="progress-bar"
                    style="margin-top: 8px; height: 3px; background: var(--bg-tertiary); border-radius: 2px; overflow: hidden;"
                  >
                    <div
                      class="progress-fill"
                      style="width: {xButtonHoldProgress}%; height: 100%; background: #ef4444; transition: width 50ms linear;"
                    ></div>
                  </div>
                {/if}
              </div>
            {/each}
          {/if}
        </div>
      {:else if currentTabId === "guide"}
        <!-- 使用说明页 -->
        <div class="animate-fade-in guide-page">
          <div
            class="guide-section guide-highlight"
            class:focused={focusIndex === 0}
            data-focus-index="0"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(0)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_hotkey_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_hotkey_desc")}</p>
          </div>

          <div
            class="guide-section"
            class:focused={focusIndex === 1}
            data-focus-index="1"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(1)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_game_mode_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_game_mode_desc")}</p>
          </div>

          <div
            class="guide-section"
            class:focused={focusIndex === 2}
            data-focus-index="2"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(2)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_isolation_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_isolation_desc")}</p>
          </div>

          <div
            class="guide-section"
            class:focused={focusIndex === 3}
            data-focus-index="3"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(3)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_osd_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_osd_desc")}</p>
          </div>

          <div
            class="guide-section"
            class:focused={focusIndex === 4}
            data-focus-index="4"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(4)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_tdp_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_tdp_desc")}</p>
          </div>

          <div
            class="guide-section guide-warning"
            class:focused={focusIndex === 5}
            data-focus-index="5"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(5)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_anticheat_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_anticheat_desc")}</p>
          </div>

          <div
            class="guide-section guide-warning"
            class:focused={focusIndex === 6}
            data-focus-index="6"
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(6)}
            onkeydown={() => {}}
          >
            <h3 class="guide-section-title">{t("guide_emulator_title")}</h3>
            <p class="guide-section-desc">{@html t("guide_emulator_desc")}</p>
          </div>
        </div>
      {:else if currentTabId === "display"}
        {@const idxBrightness = getItemIndex("brightness")}
        {@const idxVolume = getItemIndex("volume")}
        {@const idxMic = getItemIndex("media_mic")}
        {@const idxMute = getItemIndex("media_mute")}
        {@const idxPlay = getItemIndex("media_play")}
        {@const idxPrev = getItemIndex("media_prev")}
        {@const idxNext = getItemIndex("media_next")}
        {@const idxHdr = getItemIndex("hdr")}
        {@const idxDynamicRefreshRate = getItemIndex("dynamic_refresh_rate")}
        {@const idxAdaptiveBrightness = getItemIndex("adaptive_brightness")}
        {@const idxRefresh = getItemIndex("refresh_rate")}
        {@const idxResolution = getItemIndex("resolution")}
        {@const idxKill = getItemIndex("kill_top_process")}
        {@const idxSuspend = getItemIndex("suspend_top_process")}

        <!-- 视听页 -->
        <div class="animate-fade-in">
          <!-- 亮度滑条 -->
          <div
            class="list-item"
            class:focused={isFocused("brightness")}
            data-focus-index={idxBrightness}
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(idxBrightness)}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
<Icon name="sun" />
                {t("screen_brightness")}
              </div>
              <span class="item-value">{brightness}%</span>
            </div>
            <Slider
              value={brightness}
              oninput={(v) => { brightness = v; applyBrightness(); }}
              onchange={(v) => { brightness = v; applyBrightness(); }}
            />
          </div>

          <!-- 音量滑条 -->
          <div
            class="list-item"
            class:focused={isFocused("volume")}
            data-focus-index={idxVolume}
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(idxVolume)}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="speaker" />
                {t("speaker_headphone")}
              </div>
              <span class="item-value">{volume}%</span>
            </div>
            <Slider
              value={volume}
              oninput={(v) => { volume = v; applyVolume(); }}
              onchange={(v) => { volume = v; applyVolume(); }}
            />
          </div>

          <!-- 正在播放 -->
          {#if mediaInfo.hasMedia}
            <div class="now-playing-card" style="margin-top: 10px;">
              <div
                class="now-playing-icon"
                class:playing={mediaInfo.status === "Playing"}
              >
                {#if mediaInfo.status === "Playing"}
                  <div class="sound-bars">
                    <div class="bar"></div>
                    <div class="bar"></div>
                    <div class="bar"></div>
                  </div>
                {:else}
                  <Icon name="play" size={20} />
                {/if}
              </div>
              <div class="now-playing-info">
                <div class="now-playing-title">
                  {mediaInfo.title || t("unknown_title")}
                </div>
                <div class="now-playing-artist">
                  {mediaInfo.artist || t("unknown_artist")}
                </div>
              </div>
              <div
                class="now-playing-status"
                class:playing={mediaInfo.status === "Playing"}
              >
                {mediaInfo.status === "Playing"
                  ? t("media_playing")
                  : t("media_paused")}
              </div>
            </div>
          {/if}

          <!-- 媒体控制两列布局 -->
          <div class="audio-control-grid">
            <!-- 麦克风静音 -->
            <div
              class="audio-control-card"
              class:active={micMuted}
              class:focused={isFocused("media_mic")}
              data-focus-index={idxMic}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxMic;
                toggleMicMute();
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="mic" size={16} />
                <span class="card-title">{t("mic_mute")}</span>
                <div class="toggle-switch small" class:active={micMuted}>
                  <div class="toggle-thumb"></div>
                </div>
              </div>
            </div>

            <!-- 静音 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("media_mute")}
              data-focus-index={idxMute}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxMute;
                mediaControl("volume_mute");
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="volume-x" size={16} />
                <span class="card-title">{t("mute_toggle")}</span>
              </div>
            </div>

            <!-- 播放暂停 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("media_play")}
              data-focus-index={idxPlay}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxPlay;
                mediaControl("media_play_pause");
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="play" size={16} />
                <span class="card-title">{t("play_pause")}</span>
              </div>
            </div>

            <!-- 上一首 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("media_prev")}
              data-focus-index={idxPrev}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxPrev;
                mediaControl("media_prev_track");
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="skip-back" size={16} />
                <span class="card-title">{t("prev_track")}</span>
              </div>
            </div>

            <!-- 下一首 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("media_next")}
              data-focus-index={idxNext}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxNext;
                mediaControl("media_next_track");
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="skip-forward" size={16} />
                <span class="card-title">{t("next_track")}</span>
              </div>
            </div>

            <!-- HDR -->
            <div
              class="audio-control-card"
              class:focused={isFocused("hdr")}
              class:disabled={!hdrKnown || !hdrSupported || hdrLoading}
              data-focus-index={idxHdr}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxHdr;
                void toggleHdr();
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="monitor-lines" size={16} />
                <span class="card-title">{t("hdr")}</span>
                <div class="toggle-switch small" class:active={hdrEnabled}>
                  <div class="toggle-thumb"></div>
                </div>
              </div>
            </div>

            <!-- 动态刷新率 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("dynamic_refresh_rate")}
              class:disabled={dynamicRefreshRateLoading}
              data-focus-index={idxDynamicRefreshRate}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxDynamicRefreshRate;
                void toggleDynamicRefreshRate();
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="monitor" size={16} />
                <span class="card-title">{t("dynamic_refresh_rate")}</span>
                <div class="toggle-switch small" class:active={dynamicRefreshRateEnabled}>
                  <div class="toggle-thumb"></div>
                </div>
              </div>
            </div>

            <!-- 自适应亮度 -->
            <div
              class="audio-control-card"
              class:focused={isFocused("adaptive_brightness")}
              class:disabled={adaptiveBrightnessLoading}
              data-focus-index={idxAdaptiveBrightness}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = idxAdaptiveBrightness;
                void toggleAdaptiveBrightness();
              }}
              onkeydown={() => {}}
            >
              <div class="card-header">
                <Icon name="brightness" size={16} />
                <span class="card-title">{t("adaptive_brightness")}</span>
                <div class="toggle-switch small" class:active={adaptiveBrightnessEnabled}>
                  <div class="toggle-thumb"></div>
                </div>
              </div>
            </div>

          </div>

          <div class="divider"></div>

          <!-- 刷新率 -->
          <div
            class="list-item"
            class:focused={isFocused("refresh_rate")}
            data-focus-index={idxRefresh}
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(idxRefresh)}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="monitor-lines" />
                {t("refresh_rate")}
              </div>
              <div class="item-right">
                {#if isFocused("refresh_rate")}<span class="action-hint"
                    >{t("press_a_apply")}</span
                  >{/if}
                {#if refreshRateIndex !== appliedSettings.refreshRateIndex}<span
                    class="unsaved-badge">{t("unsaved")}</span
                  >{:else}<span class="current-badge">{t("current")}</span>{/if}
              </div>
            </div>
            <div class="arrow-stepper">
              <button
                class="arrow-stepper-btn"
                aria-label={t("aria_lower_refresh")}
                onclick={(e) => {
                  e.stopPropagation();
                  handleValueChange("display", idxRefresh, -1);
                }}
              >
<Icon name="chevron-left" size={18} />
              </button>
              <span class="arrow-stepper-value"
                >{refreshRateOptions[refreshRateIndex] ?? 60} Hz</span
              >
              <button
                class="arrow-stepper-btn"
                aria-label={t("aria_raise_refresh")}
                onclick={(e) => {
                  e.stopPropagation();
                  handleValueChange("display", idxRefresh, 1);
                }}
              >
<Icon name="chevron-right" size={18} />
              </button>
            </div>
          </div>

          <!-- 分辨率 -->
          <div
            class="list-item"
            class:focused={isFocused("resolution")}
            data-focus-index={idxResolution}
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(idxResolution)}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="maximize" />
                {t("resolution")}
              </div>
              <div class="item-right">
                {#if isFocused("resolution")}<span class="action-hint"
                    >{t("press_a_apply")}</span
                  >{/if}
                {#if resolutionIndex !== appliedSettings.resolutionIndex}<span
                    class="unsaved-badge">{t("unsaved")}</span
                  >{:else}<span class="current-badge">{t("current")}</span>{/if}
              </div>
            </div>
            <div class="arrow-stepper">
              <button
                class="arrow-stepper-btn"
                aria-label={t("aria_lower_resolution")}
                onclick={(e) => {
                  e.stopPropagation();
                  handleValueChange("display", idxResolution, -1);
                }}
              >
<Icon name="chevron-left" size={18} />
              </button>
              <span class="arrow-stepper-value"
                >{resolutionOptions[resolutionIndex] ?? "1920x1080"}</span
              >
              <button
                class="arrow-stepper-btn"
                aria-label={t("aria_raise_resolution")}
                onclick={(e) => {
                  e.stopPropagation();
                  handleValueChange("display", idxResolution, 1);
                }}
              >
<Icon name="chevron-right" size={18} />
              </button>
            </div>
          </div>

          <!-- 一键关闭：内存占用最高的活跃游戏 -->
          <div
            class="list-item action-item"
            class:focused={isFocused("kill_top_process")}
            data-focus-index={idxKill}
            role="button"
            tabindex="0"
            onclick={() => {
              focusIndex = idxKill;
              killTopMemoryProcess();
            }}
            onkeydown={() => {}}
          >
            <div class="item-title" style="color: #ef4444;">
              {#if killingTopProcess}
                <div class="spinner small"></div>
              {:else}
                <Icon name="x" />
              {/if}
              {t("kill_game")}
            </div>
            <p class="item-description">{t("desc_kill_process")}</p>
          </div>

          <!-- 一键冻结：内存占用最高的活跃游戏 -->
          <div
            class="list-item action-item"
            class:focused={isFocused("suspend_top_process")}
            data-focus-index={idxSuspend}
            role="button"
            tabindex="0"
            onclick={() => {
              focusIndex = idxSuspend;
              suspendTopMemoryProcess();
            }}
            onkeydown={() => {}}
          >
            <div
              class="item-title"
              style="color: {topProcessSuspended ? '#22c55e' : '#f59e0b'};"
            >
              {#if suspendingTopProcess}
                <div class="spinner small"></div>
              {:else if topProcessSuspended}
                <!-- 已冻结时显示播放图标（点击恢复） -->
                <Icon name="play" />
              {:else}
                <!-- 未冻结时显示暂停图标（点击冻结） -->
                <Icon name="pause" />
              {/if}
              {t("suspend_game")}
            </div>
            <p class="item-description">{t("desc_suspend_process")}</p>
          </div>

          <div class="divider"></div>
          <h3 class="section-title">
            <span
              >{t("game_process")}
              <span class="hint-badge">{t("process_hint")}</span></span
            >
            <button
              class="refresh-btn"
              onclick={() => loadWindowProcesses()}
              disabled={processListLoading}
              aria-label="刷新进程列表"
            >
              <Icon name="refresh" size={14} class={processListLoading ? 'spinning' : ''} />
            </button>
          </h3>

          {#if processListLoading && windowProcesses.length === 0}
            <div class="empty-state">
              <div class="spinner"></div>
              <span>{t("loading_process_list")}</span>
            </div>
          {:else if windowProcesses.length === 0}
            <div class="empty-state">
              <Icon name="monitor-lines" size={32} style="opacity: 0.5" />
              <span>{t("no_game_process")}</span>
            </div>
          {:else}
            <!-- 进程列表：动态追加在 display 静态项之后（process_0...），起始索引为 DISPLAY_PROCESS_BASE_INDEX -->
            {#each windowProcesses as proc, idx}
              <div
                class="list-item process-item"
                class:focused={focusIndex === DISPLAY_PROCESS_BASE_INDEX + idx}
                class:suspended={proc.is_suspended}
                data-focus-index={DISPLAY_PROCESS_BASE_INDEX + idx}
                role="button"
                tabindex="0"
                onclick={() => {
                  focusIndex = DISPLAY_PROCESS_BASE_INDEX + idx;
                  toggleProcessSuspend(proc.pid);
                }}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
                    {#if processToggling === proc.pid}
                      <div class="spinner small"></div>
                    {:else if proc.is_suspended}
                      <Icon name="pause" stroke="#f59e0b" />
                    {:else}
                      <Icon name="play" stroke="#22c55e" />
                    {/if}
                    <span class="process-name">{proc.name}</span>
                  </div>
                  <div class="item-right">
                    {#if focusIndex === DISPLAY_PROCESS_BASE_INDEX + idx}
                      <span class="action-hint"
                        >{proc.is_suspended
                          ? t("press_a_resume")
                          : t("press_a_suspend")}</span
                      >
                    {/if}
                    <span
                      class="process-status"
                      class:suspended={proc.is_suspended}
                    >
                      {proc.is_suspended
                        ? t("process_suspended")
                        : t("process_running")}
                    </span>
                  </div>
                </div>
                <p class="item-description process-exe">
                  {proc.exe_name}.exe (PID: {proc.pid})
                </p>
                {#if focusIndex === DISPLAY_PROCESS_BASE_INDEX + idx && xProcessKillProgress > 0}
                  <div class="process-kill-progress-overlay">
                    <div class="process-kill-progress-text">
                      {t("hold_x_kill_process")}
                      {Math.round(xProcessKillProgress)}%
                    </div>
                    <div class="process-kill-progress-bar">
                      <div
                        class="process-kill-progress-fill"
                        style="width: {xProcessKillProgress}%"
                      ></div>
                    </div>
                  </div>
                {/if}
              </div>
            {/each}
          {/if}
        </div>
      {:else if currentTabId === "performance"}
        <!-- 性能页 -->
        <div class="animate-fade-in">
          <!-- 实时监控状态栏（两行四列）- 可聚焦、可添加到快捷页 -->
          <div
            class="perf-monitor-container"
            class:focused={isFocused("perf_monitor")}
            data-focus-index={getItemIndex("perf_monitor")}
            role="button"
            tabindex="0"
            onclick={() => handleListItemClick(getItemIndex("perf_monitor"))}
            onkeydown={() => {}}
          >
            <div class="perf-monitor-grid">
              <!-- 第一行：TDP、功耗（优先 SoC）、放电、CPU占用 -->
              <div class="perf-item">
                <span class="perf-label">TDP</span>
                {#if autoTdpActive}
                  <span
                    class="perf-value auto-tdp"
                    title="Auto-TDP {t('auto_tdp_active')}"
                    >{t("auto_tdp_active")}</span
                  >
                {:else}
                  <span class="perf-value accent"
                    >{finalTdp ? `${finalTdp}W` : "Max"}</span
                  >
                {/if}
              </div>
              <div class="perf-item">
                <span class="perf-label">{t("perf_power")}</span>
                <span class="perf-value power">{(() => {
                  // APU 功耗：优先 SoC 功耗，否则用 CPU 核心功耗
                  const apuPower = (performanceMetrics.soc_power || 0) > 0.5
                    ? (performanceMetrics.soc_power || 0)
                    : (performanceMetrics.cpu_power || 0);
                  return apuPower.toFixed(0);
                })()}W</span>
              </div>
              <div class="perf-item">
                <span class="perf-label">{t("perf_discharge")}</span>
                {#if batteryStatus.has_battery && performanceMetrics.battery_power && performanceMetrics.battery_power > 0.5}
                  <span class="perf-value power"
                    >-{performanceMetrics.battery_power.toFixed(1)}W</span
                  >
                {:else if batteryStatus.has_battery && performanceMetrics.battery_power && performanceMetrics.battery_power < -0.5}
                  <span class="perf-value battery charging"
                    >+{(-performanceMetrics.battery_power).toFixed(1)}W</span
                  >
                {:else if !batteryStatus.has_battery || batteryStatus.is_ac_connected}
                  <span class="perf-value ac">AC</span>
                {:else}
                  <span class="perf-value">0W</span>
                {/if}
              </div>
              <div class="perf-item">
                <span class="perf-label">CPU</span>
                <span class="perf-value cpu"
                  >{(performanceMetrics.cpu_usage || 0).toFixed(0)}%</span
                >
              </div>
              <!-- 第二行：温度、风扇、电池状态、续航 -->
              <div class="perf-item">
                <span class="perf-label">{t("perf_temp")}</span>
                <span
                  class="perf-value temp"
                  class:hot={performanceMetrics.cpu_temp > 80}
                  >{(performanceMetrics.cpu_temp || 0).toFixed(0)}°C</span
                >
              </div>
              <div class="perf-item">
                <span class="perf-label">{t("perf_fan")}</span>
                <span class="perf-value fan"
                  >{performanceMetrics.fan_speed || 0}</span
                >
              </div>
              <div class="perf-item">
                <span class="perf-label">{t("perf_memory")}</span>
                <span
                  class="perf-value"
                  class:low={performanceMetrics.ram_usage >= 90}
                  >{Math.round(performanceMetrics.ram_usage)}%</span
                >
              </div>
              <div class="perf-item">
                <span class="perf-label">{t("perf_battery_life")}</span>
                {#if batteryStatus.has_battery && !batteryStatus.is_charging}
                  <span class="perf-value time"
                    >{batteryStatus.battery_life_time
                      ? `${Math.floor(batteryStatus.battery_life_time / 3600)}h${Math.floor((batteryStatus.battery_life_time % 3600) / 60)}m`
                      : "--"}</span
                  >
                {:else if batteryStatus.is_charging}
                  <span class="perf-value battery charging">AC</span>
                {:else}
                  <span class="perf-value ac">∞</span>
                {/if}
              </div>
            </div>
          </div>
          <h3 class="section-title">{t("section_tdp")}</h3>
          <!-- TDP 调节组合框 -->
          <div class="tdp-combo-box">
            <!-- TDP 精细滑条 -->
            <div
              class="tdp-combo-item"
              class:focused={isFocused("tdp_slider")}
              data-focus-index={getItemIndex("tdp_slider")}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = getItemIndex("tdp_slider");
                handleAction();
              }}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-right">
                  {#if isFocused("tdp_slider")}<span class="action-hint"
                      >{t("press_a_apply")}</span
                    >{/if}
                  {#if tdpWatts !== finalTdp}<span class="unsaved-badge"
                      >{t("unsaved")}</span
                    >{:else}<span class="current-badge">{t("current")}</span
                    >{/if}
                  <span class="item-value">{tdpWatts}W</span>
                </div>
              </div>
              <Slider
                value={tdpWatts}
                min={tdpMin}
                max={tdpMax}
                percentMode={false}
                oninput={(v) => { tdpWatts = v; }}
                onchange={(v) => { tdpWatts = v; applyTdp(tdpWatts); }}
                showLabels={true}
                labelLeft="{tdpMin}W"
                labelRight="{tdpMax}W"
              />
            </div>

            <div class="tdp-combo-divider"></div>

            <!-- TDP 预设 -->
            <div
              class="tdp-combo-item"
              class:focused={isFocused("tdp_preset")}
              data-focus-index={getItemIndex("tdp_preset")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("tdp_preset"))}
              onkeydown={() => {}}
            >
              <div class="item-header" style="margin-bottom: 8px;">
                <div class="item-right">
                  {#if isFocused("tdp_preset")}<span class="action-hint"
                      >{t("press_a_apply")}</span
                    >{/if}
                  {#if typeof tdpPresetLevels[tdpIndex] === "number" ? tdpPresetLevels[tdpIndex] !== finalTdp : finalTdp !== null}<span
                      class="unsaved-badge">{t("unsaved")}</span
                    >{:else}<span class="current-badge">{t("current")}</span
                    >{/if}
                </div>
              </div>
              <div class="stepper-row">
                {#each tdpPresetLevels as level, i}
                  <div
                    class="stepper-item"
                    class:active={tdpIndex === i}
                    role="option"
                    tabindex="0"
                    aria-selected={tdpIndex === i}
                    onclick={(e) => {
                      e.stopPropagation();
                      tdpIndex = i;
                      applyTdp(tdpPresetLevels[i]);
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="stepper-dot"></div>
                    <span class="stepper-label"
                      >{typeof level === "number"
                        ? level + "W"
                        : t("unlimited")}</span
                    >
                  </div>
                {/each}
              </div>
            </div>
          </div>

          <!-- 短时功耗 (PL2/Fast PPT) -->
            <div
              class="list-item"
              class:focused={isFocused("tdp_boost")}
              data-focus-index={getItemIndex("tdp_boost")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("tdp_boost"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="zap" />
                  {t("tdp_boost")}
                </div>
                <div class="item-right">
                  {#if isFocused("tdp_boost")}<span class="action-hint"
                      >{t("press_a_apply")}</span
                    >{/if}
                  <span class="item-value">{tdpBoostWatts === 0 ? t("tdp_boost_auto") : `${tdpBoostWatts}W`}</span>
                </div>
              </div>
              <Slider
                value={tdpBoostWatts === 0 ? (finalTdp ?? tdpWatts) + 1 : tdpBoostWatts}
                min={tdpMin}
                max={tdpMax}
                percentMode={false}
                oninput={(v) => { tdpBoostWatts = v <= (finalTdp ?? tdpWatts) ? 0 : v; }}
                onchange={(v) => { const val = v <= (finalTdp ?? tdpWatts) ? 0 : v; applyTdpBoost(val); }}
                showLabels={true}
                labelLeft={t("tdp_boost_auto")}
                labelRight={`${tdpMax}W`}
              />
              <p class="item-description">
                {t("tdp_boost_hint")}
              </p>
            </div>

          <!-- 瞬时功耗 (FPPT) -->
            <div
              class="list-item"
              class:focused={isFocused("tdp_fppt")}
              data-focus-index={getItemIndex("tdp_fppt")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("tdp_fppt"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="zap" />
                  {t("tdp_fppt")}
                </div>
                <div class="item-right">
                  {#if isFocused("tdp_fppt")}<span class="action-hint"
                      >{t("press_a_apply")}</span
                    >{/if}
                  <span class="item-value">{tdpFpptWatts === 0 ? t("tdp_fppt_auto") : `${tdpFpptWatts}W`}</span>
                </div>
              </div>
              <Slider
                value={tdpFpptWatts === 0 ? (finalTdp ?? tdpWatts) + 1 : tdpFpptWatts}
                min={tdpMin}
                max={tdpMax}
                percentMode={false}
                oninput={(v) => { tdpFpptWatts = v <= (finalTdp ?? tdpWatts) ? 0 : v; }}
                onchange={(v) => { const val = v <= (finalTdp ?? tdpWatts) ? 0 : v; applyTdpFppt(val); }}
                showLabels={true}
                labelLeft={t("tdp_fppt_auto")}
                labelRight={`${tdpMax}W`}
              />
              <p class="item-description">
                {t("tdp_fppt_hint")}
              </p>
            </div>

          <!-- Intel Lunar Lake PL1/PL2 提示 -->
          {#if isIntelDevice}
            <div class="info-banner hint">
              <Icon name="info" size={16} />
              <span>{t("tdp_intel_pl_hint")}</span>
            </div>
          {/if}

          <!-- 风扇策略 - 仅在支持EC风扇控制的设备上显示 -->
          {#if fanControlAvailable}
            <!-- 设备识别状态提示 -->
            {#if detectedDevice}
              <div class="info-banner success">
                <Icon name="check" size={16} />
                <span
                  >{t("detected_device").replace(
                    "{device}",
                    detectedDevice,
                  )}</span
                >
              </div>
            {/if}

            <div
              class="list-item"
              class:focused={isFocused("fan_mode")}
              data-focus-index={getItemIndex("fan_mode")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("fan_mode"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="fan" />
                  {t("fan_mode")}
                </div>
                <div class="item-right">
                  {#if isFocused("fan_mode")}<span class="action-hint"
                      >{t("press_a_or_click")}</span
                    >{/if}
                  {#if fanModeIndex !== appliedFanModeIndex}<span
                      class="unsaved-badge">{t("unsaved")}</span
                    >{:else}<span class="current-badge">{t("current")}</span
                    >{/if}
                  <span class="item-value"
                    >{t(FAN_MODES[fanModeIndex] as TranslationKey)}</span
                  >
                </div>
              </div>
              <div class="mode-row">
                {#each FAN_MODES as mode, i}
                  <div
                    class="mode-item"
                    class:active={fanModeIndex === i}
                    role="option"
                    tabindex="0"
                    aria-selected={fanModeIndex === i}
                    onclick={(e) => {
                      e.stopPropagation();
                      fanModeIndex = i;
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="mode-bar"></div>
                    <span>{t(mode as TranslationKey)}</span>
                  </div>
                {/each}
              </div>
            </div>
          {/if}

          <!-- Auto-Fan 自动温控（仅支持风扇控制时显示） -->
          {#if fanControlAvailable}
            <div
              class="list-item toggle-item"
              class:focused={isFocused("auto_fan_toggle")}
              data-focus-index={getItemIndex("auto_fan_toggle")}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = getItemIndex("auto_fan_toggle");
                toggleAutoFan();
              }}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="thermometer" />
                  {t("auto_fan")}
                </div>
                <ToggleSwitch checked={autoFanEnabled} />
              </div>
              <p class="item-description">{t("desc_auto_fan")}</p>
            </div>

            {#if autoFanEnabled}
              <!-- 温度下限 -->
              <div
                class="list-item"
                class:focused={isFocused("auto_fan_temp_min")}
                data-focus-index={getItemIndex("auto_fan_temp_min")}
                role="button"
                tabindex="0"
                onclick={() => handleListItemClick(getItemIndex("auto_fan_temp_min"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
                    <Icon name="chevron-down" />
                    {t("auto_fan_temp_min")}
                  </div>
                  <span class="item-value">{autoFanTempMin}°C</span>
                </div>
                <Slider
                  value={autoFanTempMin}
                  min={40}
                  max={autoFanTempMax - 1}
                  percentMode={false}
                  oninput={(v) => { autoFanTempMin = Math.round(v); }}
