                    }}
                    onchange={(v) => {
                      fpsLimitMin = Math.round(v);
                      if (rtssFpsLimitValue < fpsLimitMin) setRtssFpsLimitValue(fpsLimitMin);
                      invoke("save_settings", { settings: { fps_limit_min: fpsLimitMin } });
                    }}
                    showLabels={true}
                    labelLeft={`${FPS_LIMIT_ABSOLUTE_MIN}`}
                    labelRight={`${FPS_LIMIT_ABSOLUTE_MAX}`}
