                <div class="game-info-bottom">
                  <div class="game-name">{game.name}</div>
                  <div class="game-last-played">
                    <Icon name="clock" size={9} />
                    {formatLastPlayed(game.lastPlayedAt)}
                  </div>
                </div>
                {#if focusIndex === idx}<div
                    class="game-focus-overlay"
                  ></div>{/if}
                {#if focusIndex === idx && xButtonHoldProgress > 0}
                  <div class="delete-progress-overlay">
                    <div class="delete-progress-text">
                      {t("hold_x_delete")}
                      {Math.round(xButtonHoldProgress)}%
                    </div>
                    <div class="delete-progress-bar">
                      <div
                        class="delete-progress-fill"
                        style="width: {xButtonHoldProgress}%"
                      ></div>
                    </div>
                  </div>
                {/if}
                {#if focusIndex === idx}
                  <div class="game-action-hints">
                    <span class="hint-item">A {t("hint_launch")}</span>
                    <span class="hint-item">Y {t("hint_menu")}</span>
                    <span class="hint-item">X {t("hint_delete")}</span>
                  </div>
                {/if}
              </div>
            {/each}

            <!-- 其他游戏分类标题 -->
            {#if otherGames.length > 0}
              <div class="grid-section-title">
                <Icon name="grid-rects" size={12} class="icon-muted" />
                <span
                  >{recentGames.length > 0
                    ? t("other_games")
                    : t("all_games")}</span
                >
              </div>
            {/if}

            <!-- 其他游戏 -->
            {#each otherGames as game, idx}
              {@const displayIdx = recentGames.length + idx}
              {@const coverUrl = getGameCoverUrl(game)}
              <div
                class="game-card"
                class:focused={focusIndex === displayIdx}
                data-game-index={displayIdx}
                role="button"
                tabindex="0"
                onclick={() => handleGameCardClick(displayIdx)}
                onkeydown={() => {}}
                oncontextmenu={(e) => {
                  e.preventDefault();
                }}
              >
                <div class="game-cover">
                  {#if coverUrl}
                    <img src={coverUrl} alt={game.name} />
                  {:else}
                    <div class="game-cover-placeholder">
                      <Icon name="gamepad-lines" size={28} />
                      <span class="placeholder-name">{game.name}</span>
                    </div>
                  {/if}
                </div>
                <div class="game-info-bottom">
                  <div class="game-name">{game.name}</div>
                  {#if game.source === "steam"}
                    <div class="game-source">
                      <svg
                        width="10"
                        height="10"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        ><path
                          d="M12 2C6.48 2 2 6.48 2 12c0 4.84 3.44 8.87 8 9.8V15H8v-3h2V9.5C10 7.57 11.57 6 13.5 6H16v3h-2c-.55 0-1 .45-1 1v2h3l-.5 3H13v6.95c5.05-.5 9-4.76 9-9.95 0-5.52-4.48-10-10-10z"
                        /></svg
                      >
                      Steam
                    </div>
                  {/if}
                </div>
                {#if focusIndex === displayIdx}<div
                    class="game-focus-overlay"
                  ></div>{/if}
                {#if focusIndex === displayIdx && xButtonHoldProgress > 0}
                  <div class="delete-progress-overlay">
                    <div class="delete-progress-text">
                      {t("hold_x_delete")}
                      {Math.round(xButtonHoldProgress)}%
                    </div>
                    <div class="delete-progress-bar">
                      <div
                        class="delete-progress-fill"
                        style="width: {xButtonHoldProgress}%"
                      ></div>
                    </div>
                  </div>
                {/if}
                {#if focusIndex === displayIdx}
                  <div class="game-action-hints">
                    <span class="hint-item">A {t("hint_launch")}</span>
                    <span class="hint-item">Y {t("hint_menu")}</span>
                    <span class="hint-item">X {t("hint_delete")}</span>
                  </div>
                {/if}
              </div>
            {/each}

            <!-- 操作按钮分类标题 -->
            <div class="grid-section-title">
              <Icon name="plus" size={12} class="icon-muted" />
              <span>{t("add_game")}</span>
            </div>

            <!-- Steam 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length}
              data-game-index={games.length}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length)}
              onkeydown={() => {}}
            >
              <svg
                width="28"
                height="28"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                class:icon-accent={focusIndex === games.length}
                ><path
                  d="M12 2a10 10 0 1 0 0 20 10 10 0 0 0 0-20zm4.5 14.5l-1.5-1.5 1.5-1.5-1-1-1.5 1.5-1.5-1.5-1 1 1.5 1.5-1.5 1.5 1 1 1.5-1.5 1.5 1.5 1-1zM8 12a2 2 0 1 1 0-4 2 2 0 0 1 0 4z"
                /></svg
              >
              <span>{isImportingSteam ? t("importing") : "Steam"}</span>
            </div>

            <!-- Epic 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 1}
              data-game-index={games.length + 1}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 1)}
              onkeydown={() => {}}
            >
              <svg
                width="28"
                height="28"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                class:icon-accent={focusIndex === games.length + 1}
                ><path
                  d="M3 3h18v18H3V3zm3 3v12h3V6H6zm5 0v12h3v-5h3V6h-6z"
                /></svg
              >
              <span>{isImportingEpic ? t("importing") : "Epic"}</span>
            </div>

            <!-- EA 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 2}
              data-game-index={games.length + 2}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 2)}
              onkeydown={() => {}}
            >
              <svg
                width="28"
                height="28"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                class:icon-accent={focusIndex === games.length + 2}
                ><path
                  d="M4 4h16v16H4V4zm3 3v10h4v-3h3v-4h-3V7H7zm7 0v4h3v-4h-3z"
                /></svg
              >
              <span>{isImportingEA ? t("importing") : "EA"}</span>
            </div>

            <!-- Ubisoft 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 3}
              data-game-index={games.length + 3}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 3)}
              onkeydown={() => {}}
            >
              <Icon name="clock" size={28} class={focusIndex === games.length + 3 ? "icon-accent" : ""} />
              <span>{isImportingUbisoft ? t("importing") : "Ubisoft"}</span>
            </div>

            <!-- Xbox 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 4}
              data-game-index={games.length + 4}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 4)}
              onkeydown={() => {}}
            >
              <Icon name="x" size={28} class={focusIndex === games.length + 4 ? "icon-accent" : ""} />
              <span>{isImportingXbox ? t("importing") : "Xbox"}</span>
            </div>

            <!-- GOG 导入按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 5}
              data-game-index={games.length + 5}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 5)}
              onkeydown={() => {}}
            >
              <Icon name="target" size={28} class={focusIndex === games.length + 5 ? "icon-accent" : ""} />
              <span>{isImportingGOG ? t("importing") : "GOG"}</span>
            </div>

            <!-- 手动添加按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 6}
              data-game-index={games.length + 6}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 6)}
              onkeydown={() => {}}
            >
              <Icon name="plus" size={28} class={focusIndex === games.length + 6 ? "icon-accent" : ""} />
              <span>{t("manual_add")}</span>
            </div>

            <!-- 清空游戏库按钮 -->
            <div
              class="game-card action-card danger"
              class:focused={focusIndex === games.length + 7}
              data-game-index={games.length + 7}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 7)}
              onkeydown={() => {}}
            >
              <Icon name="trash" size={28} class={focusIndex === games.length + 7 ? "icon-accent" : ""} />
              <span>{t("clear_library")}</span>
            </div>

            <!-- 忽略列表说明（全宽） -->
            <div
              style="grid-column: 1 / -1; font-size: 12px; opacity: 0.7; margin-top: 2px;"
            >
              {t("ignored_games_desc")}
            </div>

            <!-- 清空忽略列表按钮 -->
            <div
              class="game-card action-card"
              class:focused={focusIndex === games.length + 8}
              data-game-index={games.length + 8}
              role="button"
              tabindex="0"
              onclick={() => handleGameCardClick(games.length + 8)}
              onkeydown={() => {}}
            >
              <Icon name="trash" size={28} class={focusIndex === games.length + 8 ? "icon-accent" : ""} />
              <span>{t("clear_ignored_games")}</span>
            </div>
          </div>

          <!-- 空状态提示 -->
          {#if games.length === 0}
            <div class="empty-state">
              <Icon name="grid-rects" size={48} />
              <p class="empty-title">{t("library_empty")}</p>
              <p class="empty-hint">{t("library_empty_hint")}</p>
            </div>
          {/if}

          <!-- 游戏库下拉菜单 -->
          {#if gameMenuOpen && gameMenuTarget}
            <div
              class="game-menu-overlay"
              role="button"
              tabindex="-1"
              onclick={() => closeGameMenu()}
              onkeydown={(e) => e.key === "Escape" && closeGameMenu()}
            >
              <div
                class="game-menu-popup"
                role="menu"
                tabindex="-1"
                onclick={(e) => e.stopPropagation()}
                onkeydown={() => {}}
              >
                <div class="game-menu-header">
                  <span class="game-menu-title">{gameMenuTarget.name}</span>
                </div>
                <div class="game-menu-items">
                  {#each GAME_MENU_ITEMS as item, idx}
                    <div
                      class="game-menu-item"
                      class:focused={gameMenuIndex === idx}
                      class:stepper-item={item.type === "stepper"}
                      role="menuitem"
                      tabindex="0"
                      onclick={() => {
                        gameMenuIndex = idx;
                        if (item.type !== "stepper") {
                          executeGameMenuItem(item.id);
                        }
                      }}
                      onkeydown={() => {}}
                    >
                      {#if item.id === "edit_game_info"}
                        <Icon name="edit" size={16} />
                      {:else if item.id === "game_ac_profile"}
                        <Icon name="zap" size={16} />
                      {:else if item.id === "game_battery_profile"}
                        <Icon name="battery" size={16} />
                      {:else if item.id === "find_trainer"}
                        <Icon name="box" size={16} />
                      {:else if item.id === "optiscaler_toggle"}
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="5 3 19 12 5 21 5 3"/><line x1="19" y1="3" x2="19" y2="21" opacity="0.4"/></svg>
                      {:else if item.id === "ls_toggle"}
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="3" width="20" height="14" rx="2"/><polyline points="8 21 16 21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>
                      {/if}
                      <span class="menu-item-label">{t(item.labelKey as TranslationKey)}</span>
                      {#if item.id === "optiscaler_toggle"}
                        {#if optiScalerLoading}
                          <span class="spinner-small"></span>
                        {:else if optiScalerApplied}
                          <span style="color: #10b981; font-size: 12px; margin-left: auto;">✓ {t("optiscaler_applied")}</span>
                        {:else}
                          <span style="color: var(--text-secondary); font-size: 12px; margin-left: auto;">{t("optiscaler_not_applied")}</span>
                        {/if}
                      {/if}
                      {#if item.id === "ls_toggle"}
                        {#if lsLoading}
                          <span class="spinner-small"></span>
                        {:else if !lsInstalled}
                          <span style="color: #f59e0b; font-size: 12px; margin-left: auto;">{t("ls_not_installed")}</span>
                        {:else if lsEnabled}
                          <span style="color: #10b981; font-size: 12px; margin-left: auto;">✓ {t("ls_auto_on")}</span>
                        {:else}
                          <span style="color: var(--text-secondary); font-size: 12px; margin-left: auto;">{t("ls_auto_off")}</span>
                        {/if}
                      {/if}
                      {#if item.type === "stepper"}
                        <!-- 场景选择器 -->
                        <div class="game-profile-stepper">
                          <button
                            class="stepper-arrow"
                            onclick={(e) => {
                              e.stopPropagation();
                              gameMenuIndex = idx;
                              handleGameProfileChange(item.id, -1);
                            }}
                          >
                            <Icon name="chevron-left" size={14} />
                          </button>
                          <span class="stepper-value">
                            {#if item.id === "game_ac_profile"}
                              {gameMenuTarget?.acProfileId ? performanceProfiles.find(p => p.id === gameMenuTarget?.acProfileId)?.name : t("none")}
                            {:else}
                              {gameMenuTarget?.batteryProfileId ? performanceProfiles.find(p => p.id === gameMenuTarget?.batteryProfileId)?.name : t("none")}
                            {/if}
                          </span>
                          <button
                            class="stepper-arrow"
                            onclick={(e) => {
                              e.stopPropagation();
                              gameMenuIndex = idx;
                              handleGameProfileChange(item.id, 1);
                            }}
                          >
                            <Icon name="chevron-right" size={14} />
                          </button>
                        </div>
                      {:else if gameMenuIndex === idx}
                        <span class="menu-hint">{t("press_a_select")}</span>
                      {/if}
                    </div>
                  {/each}
                </div>
                <div class="game-menu-footer">
                  <span class="menu-hint-key">{t("nav_select")}</span>
                  <span class="menu-hint-key">{t("a_confirm")}</span>
                  <span class="menu-hint-key">{t("b_close")}</span>
                </div>
              </div>
            </div>
          {/if}

          <!-- 游戏信息编辑面板（仅游戏库） -->
          {#if editingGameInfo}
            <div
              class="game-profile-modal"
              role="button"
              tabindex="-1"
              onclick={() => (editingGameInfo = null)}
              onkeydown={(e) => e.key === "Escape" && (editingGameInfo = null)}
            >
              <div
                class="profile-modal-content"
                role="dialog"
                tabindex="-1"
                onclick={(e) => e.stopPropagation()}
                onkeydown={() => {}}
              >
                <div class="profile-modal-header">
                  <span>{t("edit_game_info")}</span>
                </div>

                <div class="profile-form">
                  <!-- 游戏名称 -->
                  <div class="profile-field">
                    <label for="game-name">{t("game_name")}</label>
                    <input
                      id="game-name"
                      type="text"
                      placeholder={t("enter_game_name")}
                      bind:value={editingGameInfo!.name}
                    />
                  </div>

                  <!-- 封面预览 -->
                  <div class="profile-field">
                    <label for="game-cover-btn">{t("cover_image")}</label>
                    <div class="cover-preview-container">
                      {#if editingGameInfo.cover}
                        <img
                          src={convertFileSrc(editingGameInfo.cover)}
                          alt={t("cover_preview")}
                          class="cover-preview-img"
                        />
                      {:else}
                        <div class="cover-preview-placeholder">
                          <Icon name="image" size={32} />
                          <span>{t("no_cover")}</span>
                        </div>
                      {/if}
                    </div>
                    <button
                      id="game-cover-btn"
                      type="button"
                      class="btn-select-cover"
                      onclick={() => selectGameCover()}
                    >
                      <Icon name="upload" size={14} />
                      {t("select_image_file")}
                    </button>
                  </div>
                </div>

                <div class="profile-actions">
                  <button
                    type="button"
                    class="btn-cancel"
                    onclick={() => (editingGameInfo = null)}
                    >{t("cancel")}</button
                  >
                  <button
                    type="button"
                    class="btn-save"
                    onclick={() => saveGameInfo()}>{t("save")}</button
                  >
                </div>
              </div>
            </div>
          {/if}
        </div>

      {#if currentTabId === "trainers"}
        <!-- 修改器管理页面 -->
        <div class="animate-fade-in">
          <!-- 更新数据库按钮 -->
          <div
            class="list-item action-item"
            class:focused={isFocused("update_database")}
            data-focus-index={getItemIndex("update_database")}
            role="button"
            tabindex="0"
            onclick={() => {
              focusIndex = getItemIndex("update_database");
              updateTrainerDatabase();
            }}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="refresh" />
                {t("update_trainer_db")}
              </div>
              {#if isUpdatingDatabase}
                <div
                  class="loading-spinner"
                  style="width: 20px; height: 20px;"
                ></div>
              {:else if isFocused("update_database")}
                <span class="action-hint">{t("press_a_update")}</span>
              {/if}
            </div>
            <p class="item-description">
              {t("desc_trainer_update")}
            </p>
          </div>

          <!-- 搜索框 -->
          <div
            class="list-item"
            class:focused={isFocused("search_input")}
            data-focus-index={getItemIndex("search_input")}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="search" />
                {t("search_trainers")}
              </div>
            </div>
            <div class="trainer-search-container">
              <input
                type="text"
                class="trainer-search-input"
                placeholder={t("search_game_placeholder")}
                bind:value={trainerSearchKeyword}
                bind:this={trainerSearchInputEl}
                oninput={() => searchTrainers()}
                onfocus={() => {
                  focusIndex = getItemIndex("search_input");
                }}
                onkeydown={(e) => e.stopPropagation()}
              />
              <div class="trainer-view-toggle">
                <button
                  class="toggle-btn"
                  class:active={!showInstalledOnly}
                  onclick={() => {
                    showInstalledOnly = false;
                    focusIndex = 2;
                  }}
                >
                  {t("search_results")} ({trainers.length})
                </button>
                <button
                  class="toggle-btn"
                  class:active={showInstalledOnly}
                  onclick={() => {
                    showInstalledOnly = true;
                    focusIndex = 2;
                  }}
                >
                  {t("installed")} ({installedTrainers.length})
                </button>
              </div>
            </div>
          </div>

          <!-- 修改器列表 -->
          <div class="trainer-list">
            {#if showInstalledOnly}
              <!-- 已安装列表 -->
              {#if installedTrainers.length === 0}
                <div class="empty-state">
                  <Icon name="box" size={48} />
                  <p class="empty-title">{t("no_installed_trainers")}</p>
                  <p class="empty-hint">{t("hint_search_download_trainer")}</p>
                </div>
              {:else}
                {#each installedTrainers as trainer, idx}
                  {@const focusIdx = 2 + idx}
                  <div
                    class="trainer-item"
                    class:focused={focusIndex === focusIdx}
                    data-focus-index={focusIdx}
                    role="button"
                    tabindex="0"
                    onclick={() => {
                      focusIndex = focusIdx;
                      if (trainer.local_path) launchTrainer(trainer.local_path);
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="trainer-icon">
                      <Icon name="box" size={20} />
                    </div>
                    <div class="trainer-info">
                      <div class="trainer-name">
                        {trainer.trainer_name || trainer.game_name}
                      </div>
                      <div class="trainer-meta">
                        <span class="trainer-source"
                          >{trainer.origin === "fling_archive" ||
                          trainer.origin === "fling_main"
                            ? t("trainer_fling")
                            : t("trainer_xiaoxing")}</span
                        >
                        {#if trainer.version}
                          <span class="trainer-version">{trainer.version}</span>
                        {/if}
                      </div>
                    </div>
                    {#if focusIndex === focusIdx}
                      <div class="trainer-action-hint">
<Icon name="play" size={16} />
                        {t("press_a_launch")}
                      </div>
                    {:else}
                      <div class="trainer-status installed">
                        <Icon name="check" size={16} />
                        {t("installed")}
                      </div>
                    {/if}
                    {#if focusIndex === focusIdx && xButtonHoldProgress > 0}
                      <div class="delete-progress-overlay">
                        <div class="delete-progress-text">
                          {t("hold_x_delete")}
                          {Math.round(xButtonHoldProgress)}%
                        </div>
                        <div class="delete-progress-bar">
                          <div
                            class="delete-progress-fill"
                            style="width: {xButtonHoldProgress}%"
                          ></div>
                        </div>
                      </div>
                    {/if}
                  </div>
                {/each}
              {/if}
            {:else}
              <!-- 搜索结果列表 -->
              {#if isSearchingTrainers}
                <div class="empty-state">
                  <div class="loading-spinner"></div>
                  <p class="empty-title">{t("searching")}</p>
                </div>
              {:else if !trainerSearchKeyword}
                <div class="empty-state">
                  <Icon name="search" size={48} />
                  <p class="empty-title">{t("enter_game_name_search")}</p>
                  <p class="empty-hint">
                    {t("search_hint")}
                  </p>
                </div>
              {:else if trainers.length === 0}
                <div class="empty-state">
                  <Icon name="x" size={48} />
                  <p class="empty-title">{t("no_trainers_found")}</p>
                  <p class="empty-hint">{t("try_different_keyword")}</p>
                </div>
              {:else}
                {#each trainers as trainer, idx}
                  {@const focusIdx = 2 + idx}
                  <div
                    class="trainer-item"
                    class:focused={focusIndex === focusIdx}
                    class:downloading={isDownloadingTrainer &&
                      focusIndex === focusIdx}
                    data-focus-index={focusIdx}
                    role="button"
                    tabindex="0"
                    onclick={() => {
                      focusIndex = focusIdx;
                      if (trainer.installed && trainer.local_path) {
                        launchTrainer(trainer.local_path);
                      } else if (!trainer.installed) {
                        downloadTrainer(trainer);
                      }
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="trainer-icon">
                      <Icon name="box" size={20} />
                    </div>
                    <div class="trainer-info">
                      <div class="trainer-name">
                        {trainer.trainer_name || trainer.game_name}
                      </div>
                      <div class="trainer-meta">
                        <span class="trainer-source"
                          >{trainer.origin === "fling_archive" ||
                          trainer.origin === "fling_main"
                            ? t("trainer_fling")
                            : t("trainer_xiaoxing")}</span
                        >
                        {#if trainer.version}
                          <span class="trainer-version">{trainer.version}</span>
                        {/if}
                      </div>
                    </div>
                    {#if focusIndex === focusIdx}
                      <div class="trainer-action-hint">
                        {#if trainer.installed}
<Icon name="play" size={16} />
                          {t("press_a_launch")}
                        {:else}
                          <Icon name="download" size={16} />
                          {t("press_a_download")}
                        {/if}
                      </div>
                    {:else if trainer.installed}
                      <div class="trainer-status installed">
                        <Icon name="check" size={16} />
                        {t("installed")}
                      </div>
                    {:else}
                      <div class="trainer-status not-installed">
                        <Icon name="download" size={16} />
                        {t("not_installed")}
                      </div>
                    {/if}
                    {#if isDownloadingTrainer && focusIndex === focusIdx}
                      <div class="trainer-download-progress">
                        <div class="download-progress-text">
                          {t("downloading")}
                          {downloadProgress}%
                        </div>
                        <div class="download-progress-bar">
                          <div
                            class="download-progress-fill"
                            style="width: {downloadProgress}%"
                          ></div>
                        </div>
                      </div>
                    {/if}
                    {#if focusIndex === focusIdx && xButtonHoldProgress > 0 && trainer.installed}
                      <div class="delete-progress-overlay">
                        <div class="delete-progress-text">
                          {t("hold_x_delete")}
                          {Math.round(xButtonHoldProgress)}%
                        </div>
                        <div class="delete-progress-bar">
                          <div
                            class="delete-progress-fill"
                            style="width: {xButtonHoldProgress}%"
                          ></div>
                        </div>
                      </div>
                    {/if}
                  </div>
                {/each}
              {/if}
            {/if}
          </div>
        </div>
      {:else if currentTabId === "gamepad"}
        <!-- 手柄测试页 -->
        {#if !isGamepadTestMode}
          <div class="animate-fade-in">
            <h3 class="section-title">
              {t("vibration_settings")}
              <button
                class="refresh-btn"
                onclick={() => refreshConnectedGamepads()}
                style="margin-left: 8px; padding: 2px 6px; font-size: 11px; cursor: pointer;"
                >{t("refresh")}</button
              >
            </h3>
            <!-- 测试震动强度 -->
            <div
              class="list-item"
              class:focused={isFocused("vibration")}
              data-focus-index={getItemIndex("vibration")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("vibration"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="power" />
                  {t("vibration_test_intensity")}
                </div>
                <span class="item-value">{vibrationIntensity}%</span>
              </div>
              <Slider
                value={vibrationIntensity}
                oninput={(v) => { vibrationIntensity = v; }}
                onchange={(v) => { 
                  vibrationIntensity = v; 
                  invoke("save_settings", { settings: { vibration_intensity: vibrationIntensity } });
                }}
              />
            </div>

            <!-- 动态显示每个手柄的震动强度控制 -->
