                  `gamepad_vibration_${gamepad.index}`,
                )}
                <div
                  class="list-item"
                  class:focused={focusIndex === gpFocusIndex}
                  data-focus-index={gpFocusIndex}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = gpFocusIndex;
                  }}
                  onkeydown={() => {}}
                >
