                    <div class="item-title">
                      {#if gamepad.index === 0}
                        <Icon name="smartphone" />
                      {:else}
                        <Icon name="gamepad-lines" />
                      {/if}
                      {gamepad.name === "builtin_gamepad"
                        ? t("builtin_gamepad")
                        : gamepad.name.startsWith("gamepad_")
                          ? t("gamepad_n").replace(
                              "{n}",
                              gamepad.name.split("_")[1] || "?",
                            )
                          : gamepad.name}
                      {#if gamepad.isActive}<span
                          style="color: var(--theme-color); margin-left: 6px; font-size: 11px;"
                          >{t("current")}</span
                        >{/if}
                    </div>
                    <span class="item-value"
                      >{gamepadVibrationIntensity[gamepad.index]}%</span
                    >
                  </div>
                  <div
                    class="slider-track"
                    onpointerdown={(e) =>
                      handleSliderPointerDown(
                        e,
                        `gamepad_vibration_${gamepad.index}` as
                          | "gamepad_vibration_0"
                          | "gamepad_vibration_1"
                          | "gamepad_vibration_2"
                          | "gamepad_vibration_3",
                      )}
                    onpointermove={handleSliderPointerMove}
                    onpointerup={handleSliderPointerUp}
                  >
                    <div
                      class="slider-fill"
                      style="width: {gamepadVibrationIntensity[gamepad.index]}%"
                    ></div>
                    <div
                      class="slider-thumb"
                      class:dragging={isDragging &&
                        dragTarget === `gamepad_vibration_${gamepad.index}`}
                      style="left: {gamepadVibrationIntensity[gamepad.index]}%"
                    ></div>
                  </div>
                  {#if gamepad.index === 0}
                    <p class="item-description">
                      {t("desc_vibration_external")}
                    </p>
                  {/if}
                </div>
              {/each}
            {:else}
              <div class="list-item" style="opacity: 0.6;">
                <div class="item-title">
<Icon name="gamepad-lines" />
                  {t("no_gamepad_detected")}
                </div>
              </div>
            {/if}

            <h3 class="section-title">{t("section_gamepad")}</h3>

            <!-- 禁用掌机手柄（让外接手柄成为索引0） -->
            <div
