              data-focus-index={getItemIndex("disable_builtin")}
              role="button"
              tabindex="0"
              onclick={() =>
                handleListItemClick(getItemIndex("disable_builtin"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
<Icon name="circle" />
                  {t("disable_builtin")}
                </div>
<ToggleSwitch checked={builtinGamepadDisabled} />
              </div>
              <p class="item-description">
                {t("disable_builtin_desc")}
              </p>
            </div>

            <h3 class="section-title">{t("section_trigger")}</h3>

            <!-- LT 扳机 deadzone -->
            <div
