                  <div class="progress-bar">
                    <div
                      class="progress-fill"
                      style="width: {aButtonHoldProgress}%"
                    ></div>
                  </div>
                </div>
              {/if}
            </div>

            <!-- 鼠标模拟 -->
            <div class="divider"></div>
            <div
              class="list-item"
              class:focused={isFocused("mouse_sim")}
              data-focus-index={getItemIndex("mouse_sim")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("mouse_sim"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
<Icon name="mouse" />
                  {t("mouse_sim")}
                </div>
                <ToggleSwitch checked={mouseSimEnabled} />
              </div>
              <p class="item-description">{t("desc_mouse_sim")}</p>
            </div>

            <!-- 桌面模式 -->
            <div
