                      style="margin-left: 0.5rem; font-size: 0.7rem; color: var(--warning-color);"
                      >{t("unavailable")}</span
                    >
                  {/if}
                </div>
<ToggleSwitch checked={xinputIsolationEnabled} />
              </div>
              <p class="item-description">{t("desc_input_isolation")}</p>
            </div>

            <!-- 兼容性输入隔离 (HidHide) -->
            <div
              class="list-item toggle-item"
