              data-focus-index={getItemIndex("input_isolation_toggle")}
              role="button"
              tabindex="0"
              onclick={() => {
                focusIndex = getItemIndex("input_isolation_toggle");
                handleAction();
              }}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <svg
                    width="18"
                    height="18"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="2"
                    stroke-linecap="round"
                    stroke-linejoin="round"
                  >
                    <rect x="2" y="6" width="20" height="12" rx="2" />
                    <line x1="6" y1="12" x2="10" y2="12" />
                    <line x1="8" y1="10" x2="8" y2="14" />
                    <circle cx="17" cy="12" r="1" />
                  </svg>
                  {t("input_isolation_compat")}
                  {#if !hidhideDriverInstalled}
                    <span
                      class="badge"
                      style="margin-left: 0.5rem; font-size: 0.7rem; color: var(--accent-color);"
                      >{t("need_install")}</span
                    >
                  {/if}
                </div>
                <ToggleSwitch checked={inputIsolationEnabled} />
              </div>
              <p class="item-description">{t("desc_compat_isolation")}</p>
            </div>

            <!-- 非 Xbox 手柄检测 (gilrs) -->
            <div
              class="list-item toggle-item"
              class:focused={isFocused("gilrs_detection_toggle")}
              data-focus-index={getItemIndex("gilrs_detection_toggle")}
