                  <Icon name="target" />
                  {t("kbm_left_stick")}
                </div>
                <span class="item-value"
                  >{t(KBM_STICK_MODE_LABEL_KEYS[sanitizeKbmStickMode(leftStickMode)] as TranslationKey)}</span
                >
              </div>
              <div class="stepper-row" style="flex-wrap: wrap; gap: 8px;">
                {#each KBM_STICK_MODES as mode}
                  <div
                    class="stepper-item"
                    class:active={sanitizeKbmStickMode(leftStickMode) === mode}
                    role="option"
                    tabindex="0"
                    aria-selected={sanitizeKbmStickMode(leftStickMode) === mode}
                    onclick={(e) => {
                      e.stopPropagation();
                      if (mode === sanitizeKbmStickMode(leftStickMode)) return;
                      leftStickMode = mode;
                      invoke("save_settings", {
                        settings: { left_stick_mode: mode },
                      }).catch((e) => console.warn("save left_stick_mode failed:", e));
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="stepper-dot"></div>
                    <span class="stepper-label"
                      >{t(KBM_STICK_MODE_LABEL_KEYS[mode] as TranslationKey)}</span
                    >
                  </div>
                {/each}
              </div>
            </div>

