                    onclick={(e) => {
                      e.stopPropagation();
                      if (mode === sanitizeKbmStickMode(rightStickMode)) return;
                      rightStickMode = mode;
                      invoke("save_settings", {
                        settings: { right_stick_mode: mode },
                      }).catch((e) => console.warn("save right_stick_mode failed:", e));
                    }}
                    onkeydown={() => {}}
                  >
                    <div class="stepper-dot"></div>
                    <span class="stepper-label"
                      >{t(KBM_STICK_MODE_LABEL_KEYS[mode] as TranslationKey)}</span
                    >
                  </div>
                {/each}
              </div>
            </div>

            <!-- 按键映射设置 -->
