                    ? 180
                    : 0}deg); transition: transform 0.2s;"
                >
                  <polyline points="6 9 12 15 18 9" />
                </svg>
              </div>
              <p class="item-description">{t("desc_button_mapping")}</p>
            </div>

            <!-- 按键映射详细选项（展开时显示） -->
