              <!-- 配置选择（复用 KBM Profiles） -->
              <div
                class="list-item"
                class:focused={isFocused("mapping_profile_select")}
                data-focus-index={getItemIndex("mapping_profile_select")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("mapping_profile_select"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="file" />
                    {t("mapping_profile")}
                  </div>
                  <span class="item-value">
                    {kbmProfiles.length > 0
                      ? kbmProfiles[selectedKbmProfileIndex]?.name
                      : t("mapping_no_profiles")}
                  </span>
                </div>
                {#if kbmProfiles.length > 0}
                  <div class="stepper-row">
                    {#each kbmProfiles as profile, idx}
                      <div
                        class="stepper-item"
                        class:active={selectedKbmProfileIndex === idx}
                        role="option"
                        tabindex="0"
                        aria-selected={selectedKbmProfileIndex === idx}
                        onclick={(e) => {
                          e.stopPropagation();
                          selectedKbmProfileIndex = idx;
                        }}
                        onkeydown={() => {}}
                      >
                        <div class="stepper-dot"></div>
                        <span class="stepper-label">{profile.name}</span>
                        {#if activeKbmProfile?.id === profile.id}
                          <span
                            style="color: var(--theme-color); margin-left: 4px; font-size: 10px;"
                            >●</span
                          >
                        {/if}
                      </div>
                    {/each}
                  </div>
                {/if}
              </div>

              {#if kbmProfiles.length > 0}
                {@const profile = kbmProfiles[
                  Math.max(0, Math.min(kbmProfiles.length - 1, selectedKbmProfileIndex))
                ]}
                {@const activeSelected =
                  kbmEnabled && activeKbmProfile?.id === profile?.id}

                <!-- 新增按键映射 -->
                <div
                  class="list-item action-item"
                  class:focused={isFocused("mapping_add_button")}
                  data-focus-index={getItemIndex("mapping_add_button")}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = getItemIndex("mapping_add_button");
                    handleAction();
                  }}
                  onkeydown={() => {}}
                >
                  <div class="item-title">
<Icon name="plus" />
                    {t("mapping_add_button")}
                  </div>
                  {#if isFocused("mapping_add_button")}<span class="action-hint"
                      >{t("press_a_or_click")}</span
                    >{/if}
                </div>

                <!-- 启用/停用按钮 -->
                <div
                  class="list-item action-item"
                  class:focused={isFocused("mapping_activate")}
                  data-focus-index={getItemIndex("mapping_activate")}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = getItemIndex("mapping_activate");
                    handleAction();
                  }}
                  onkeydown={() => {}}
                >
                  <div class="item-title">
                    <svg
                      width="18"
                      height="18"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      stroke-width="2"
                    >
                      {#if activeSelected}
                        <rect x="3" y="3" width="18" height="18" rx="2" />
                        <line x1="9" y1="9" x2="15" y2="15" />
                        <line x1="15" y1="9" x2="9" y2="15" />
                      {:else}
                        <polygon points="5 3 19 12 5 21 5 3" />
                      {/if}
                    </svg>
                    {activeSelected
                      ? t("mapping_deactivate")
                      : t("mapping_activate")}
                  </div>
                  {#if isFocused("mapping_activate")}<span class="action-hint"
                      >{t("press_a_or_click")}</span
                    >{/if}
                </div>

                <!-- 映射列表（当前配置） -->
                {#if !profile?.button_bindings || profile.button_bindings.length === 0}
                  <p class="item-description" style="margin-top: 8px;">
                    {t("mapping_no_mappings")}
                  </p>
                {:else}
                  {#each profile.button_bindings as binding, idx (idx)}
                    {@const action = binding.normal}
                    {@const enabled = binding.enabled ?? true}
                    <div class="list-item" style="padding: 10px 12px;">
                      <div
                        class="item-header"
                        style="align-items: center; justify-content: space-between;"
                      >
                        <div class="item-title" style="flex: 1; min-width: 0;">
                          <div
                            style="font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;"
                          >
                            {formatKbmButtonSource(binding.source)} →
                            {action.type === "macro" ? "[macro]" : (action as any).keys}
                          </div>
                          <p class="item-description" style="margin: 4px 0 0 0;">
                            {t(KBM_ACTION_LABEL_KEYS[action.type] as TranslationKey)}
                            {#if action.type === "turbo"}
                              ({(action as any).rate_hz}Hz)
                            {/if}
                          </p>
                        </div>
                        <div
                          style="display: flex; align-items: center; gap: 8px; margin-left: 10px;"
                        >
<ToggleSwitch 
                            checked={enabled} 
                            onchange={() => toggleButtonMappingBindingEnabled(profile, idx)} 
                          />
                          <button
                            type="button"
                            class="btn-cancel"
                            style="padding: 6px 8px;"
                            title={t("hint_delete")}
                            aria-label={t("hint_delete")}
                            onclick={() => deleteButtonMappingBinding(profile, idx)}
                          >
                            <Icon name="trash" size={16} />
                          </button>
                        </div>
                      </div>
                    </div>
                  {/each}
                {/if}

                <!-- 删除配置 -->
                <div
                  class="list-item action-item"
                  class:focused={isFocused("mapping_delete")}
                  data-focus-index={getItemIndex("mapping_delete")}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = getItemIndex("mapping_delete");
                    handleAction();
                  }}
                  onkeydown={() => {}}
                >
                  <div class="item-title">
<Icon name="trash" />
                    {t("mapping_delete_profile")}
                  </div>
                  {#if isFocused("mapping_delete")}<span class="action-hint"
                      >{t("press_a_or_click")}</span
                    >{/if}
                </div>
              {/if}

              <!-- 新建配置 -->
              <div
                class="list-item action-item"
                class:focused={isFocused("mapping_create")}
                data-focus-index={getItemIndex("mapping_create")}
                role="button"
                tabindex="0"
                onclick={() => {
                  focusIndex = getItemIndex("mapping_create");
                  handleAction();
                }}
                onkeydown={() => {}}
              >
                <div class="item-title">
                  <Icon name="plus" />
                  {t("mapping_create_profile")}
                </div>
                {#if isFocused("mapping_create")}<span class="action-hint"
                    >{t("press_a_or_click")}</span
                  >{/if}
              </div>
            {/if}

            <!-- 按键映射录制弹窗（复用 KBM 引擎） -->
            {#if buttonMappingDialog}
              <div
                class="game-profile-modal"
                role="button"
                tabindex="-1"
                onclick={() => cancelButtonMappingDialog()}
                onkeydown={(e) => e.key === "Escape" && cancelButtonMappingDialog()}
              >
                <div
                  class="profile-modal-content"
                  role="dialog"
                  tabindex="-1"
                  onclick={(e) => e.stopPropagation()}
                  onkeydown={() => {}}
                  style="max-width: 640px;"
                >
                  <div class="profile-modal-header">
                    <span>{t("mapping_add_button")}</span>
                  </div>

                  <div class="profile-form">
                    <div class="profile-field">
                      <label for="btnmap-source">{t("mapping_source_button")}</label>
                      <input
                        id="btnmap-source"
                        type="text"
                        readonly
                        value={
                          buttonMappingDialog.source_buttons.length > 0
                            ? buttonMappingDialog.source_buttons
                                .map((b) => getKbmButtonLabel(b))
                                .join(" + ")
                            : ""
                        }
                        placeholder={t("kbm_capture_gamepad_hint")}
                      />

                      <div
                        style="display: flex; gap: 8px; margin-top: 8px; flex-wrap: wrap; align-items: center;"
                      >
                        <button
                          type="button"
                          class="btn-cancel"
                          onclick={() => {
                            if (buttonMappingGamepadCaptureCountdown > 0)
                              stopButtonMappingGamepadCapture();
                            else startButtonMappingGamepadCapture();
                          }}
                        >
                          {buttonMappingGamepadCaptureCountdown > 0
                            ? t("kbm_capture_stop")
                            : t("kbm_capture_start")}
                        </button>
                        {#if buttonMappingGamepadCaptureCountdown > 0}
                          <span class="countdown">
                            {buttonMappingGamepadCaptureCountdown}s
                          </span>
                        {/if}
                      </div>
                    </div>

                    <div class="profile-field">
                      <label for="btnmap-keys">{t("kbm_keys")}</label>
                      <input
                        id="btnmap-keys"
                        type="text"
                        placeholder={t("kbm_keys_placeholder")}
                        bind:value={buttonMappingDialog.keys}
                        bind:this={buttonMappingKeysInputEl}
                        onkeydown={handleButtonMappingKeysInputKeydown}
                        onkeyup={handleButtonMappingKeysInputKeyup}
                      />

                      <div
                        style="display: flex; gap: 8px; margin-top: 8px; flex-wrap: wrap;"
                      >
                        <button
                          type="button"
                          class="btn-cancel"
                          onclick={() => {
                            if (buttonMappingKeysCaptureActive)
                              stopButtonMappingKeysCapture();
                            else startButtonMappingKeysCapture();
                          }}
                        >
                          {buttonMappingKeysCaptureActive
                            ? t("kbm_capture_stop")
                            : t("kbm_capture_start")}
                        </button>
                        {#if buttonMappingKeysCaptureActive}
                          <span
                            class="item-description"
                            style="margin: 0; align-self: center; opacity: 0.85;"
                          >
                            {t("kbm_capture_keys_hint")}
                          </span>
                        {/if}
                      </div>
                    </div>

                    <div class="profile-field">
                      <label for="btnmap-action-tap">{t("kbm_action_type")}</label>
                      <div style="display: flex; gap: 8px; flex-wrap: wrap;">
                        <button
                          id="btnmap-action-tap"
                          type="button"
                          class={
                            buttonMappingDialog.action_type === "tap"
                              ? "btn-save"
                              : "btn-cancel"
                          }
                          onclick={() => {
                            if (!buttonMappingDialog) return;
                            buttonMappingDialog.action_type = "tap";
                          }}
                        >
                          {t("kbm_action_tap")}
                        </button>
                        <button
                          type="button"
                          class={
                            buttonMappingDialog.action_type === "hold"
                              ? "btn-save"
                              : "btn-cancel"
                          }
                          onclick={() => {
                            if (!buttonMappingDialog) return;
                            buttonMappingDialog.action_type = "hold";
                          }}
                        >
                          {t("kbm_action_hold")}
                        </button>
                        <button
                          type="button"
                          class={
                            buttonMappingDialog.action_type === "turbo"
                              ? "btn-save"
                              : "btn-cancel"
                          }
                          onclick={() => {
                            if (!buttonMappingDialog) return;
                            buttonMappingDialog.action_type = "turbo";
                          }}
                        >
                          {t("kbm_action_turbo")}
                        </button>
                      </div>

                      {#if buttonMappingDialog.action_type === "turbo"}
                        <div style="margin-top: 10px;">
                          <label for="btnmap-turbo" style="display: block; margin-bottom: 6px;">
                            {t("mapping_turbo_rate")}
                          </label>
                          <input
                            id="btnmap-turbo"
                            type="number"
                            min="1"
                            max="60"
                            step="1"
                            bind:value={buttonMappingDialog.turbo_rate_hz}
                          />
                        </div>
                      {/if}
                    </div>

                    <div class="profile-field">
                      <div style="font-size: calc(12px * var(--font-scale, 1)); font-weight: 600;">
                        {t("enabled")}
                      </div>
                      <ToggleSwitch 
                        checked={buttonMappingDialog.enabled}
                        ariaLabel={t("enabled")}
                        onchange={() => {
                          if (!buttonMappingDialog) return;
                          buttonMappingDialog.enabled = !buttonMappingDialog.enabled;
                        }}
                      />
                    </div>
                  </div>

                  <div class="profile-actions">
                    <button
                      type="button"
                      class="btn-cancel"
                      onclick={() => cancelButtonMappingDialog()}
                      >{t("cancel")}</button
                    >
                    <button
                      type="button"
                      class="btn-save"
                      onclick={() => confirmButtonMappingDialog()}
                      >{t("save")}</button
                    >
                  </div>
                </div>
              </div>
            {/if}

            <!-- 陀螺仪设置 -->
            <div class="divider"></div>
            <h3 class="section-title">
<Icon name="circle" />
              {t("section_gyro")}
            </h3>

            <!-- 启用陀螺仪 -->
            <div
              class="list-item"
              class:focused={isFocused("gyro_enable")}
              data-focus-index={getItemIndex("gyro_enable")}
              role="button"
              tabindex="0"
              onclick={() => handleListItemClick(getItemIndex("gyro_enable"))}
              onkeydown={() => {}}
            >
              <div class="item-header">
                <div class="item-title">
                  <Icon name="target" />
                  {t("gyro_enable")}
                </div>
                {#if gyroAvailableDevices.length === 0}
                  <span class="item-value" style="color: var(--warning-color);"
                    >{t("no_device_detected")}</span
                  >
                {:else}
                  <ToggleSwitch checked={gyroEnabled} />
                {/if}
              </div>
              {#if !gyroEnabled && gyroAvailableDevices.length > 0}
                <p class="item-description">
                  {t("detected_devices").replace(
                    "{count}",
                    gyroAvailableDevices.length.toString(),
                  )}
                </p>
              {/if}
            </div>

            <!-- 陀螺仪详细选项（检测到设备后显示） -->
            {#if gyroAvailableDevices.length > 0}
              <!-- 设备类型 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_device")}
                data-focus-index={getItemIndex("gyro_device")}
                role="button"
                tabindex="0"
                onclick={() => handleListItemClick(getItemIndex("gyro_device"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="device" />
                    {t("device_type")}
                  </div>
                  <span class="item-value"
                    >{getGyroDeviceName(
                      gyroDeviceType
                    )}{gyroPendingDeviceIndex !== null &&
                    gyroPendingDeviceIndex !== gyroDeviceIndex
                      ? " → " +
                        getGyroDeviceName(
                          GYRO_DEVICE_TYPES[gyroPendingDeviceIndex]
                        )
                      : ""}</span
                  >
                </div>
                <div class="arrow-stepper">
                  <button
                    class="arrow-stepper-btn"
                    aria-label={t("aria_decrease")}
                    onclick={(e) => {
                      e.stopPropagation();
                      handleValueChange(
                        "gamepad",
                        getItemIndex("gyro_device"),
                        -1,
                      );
                    }}
                  >
<Icon name="chevron-left" size={18} />
                  </button>
                  <span class="arrow-stepper-value"
                    >{getGyroDeviceName(
                      gyroPendingDeviceIndex !== null
                        ? GYRO_DEVICE_TYPES[gyroPendingDeviceIndex]
                        : gyroDeviceType
                    )}</span
                  >
                  <button
                    class="arrow-stepper-btn"
                    aria-label={t("aria_increase")}
                    onclick={(e) => {
                      e.stopPropagation();
                      handleValueChange(
                        "gamepad",
                        getItemIndex("gyro_device"),
                        1,
                      );
                    }}
                  >
<Icon name="chevron-right" size={18} />
                  </button>
                </div>
                {#if gyroPendingDeviceIndex !== null && gyroPendingDeviceIndex !== gyroDeviceIndex}
                  <p
                    class="item-description"
                    style="color: var(--accent-color);"
                  >
                    {t("press_a_confirm_switch")}
                  </p>
                {/if}
              </div>

              {#if gyroEnabled}
                <!-- 灵敏度 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_sensitivity")}
                data-focus-index={getItemIndex("gyro_sensitivity")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_sensitivity"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="sensitivity" />
                    {t("sensitivity")}
                  </div>
                  <span class="item-value">{gyroSensitivity.toFixed(1)}x</span>
                </div>
                <div class="slider-track">
                  <div
                    class="slider-fill"
                    style="width: {((gyroSensitivity - 0.1) / 9.9) * 100}%"
                  ></div>
                  <div
                    class="slider-thumb"
                    style="left: {((gyroSensitivity - 0.1) / 9.9) * 100}%"
                  ></div>
                </div>
              </div>

              <!-- 死区 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_deadzone")}
                data-focus-index={getItemIndex("gyro_deadzone")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_deadzone"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="target" />
                    {t("deadzone")}
                  </div>
                  <span class="item-value"
                    >{(gyroDeadzone * 100).toFixed(0)}%</span
                  >
                </div>
                <div class="slider-track">
                  <div
                    class="slider-fill"
                    style="width: {gyroDeadzone * 100}%"
                  ></div>
                  <div
                    class="slider-thumb"
                    style="left: {gyroDeadzone * 100}%"
                  ></div>
                </div>
              </div>
              {/if}

              <!-- 映射模式 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_mapping")}
                data-focus-index={getItemIndex("gyro_mapping")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_mapping"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="home" />
                    {t("mapping_mode")}
                  </div>
                  <span class="item-value"
                    >{[t("disabled"), t("mouse"), t("right_stick")][
                      gyroMappingIndex
                    ]}</span
                  >
                </div>
                <div class="arrow-stepper">
                  <button
                    class="arrow-stepper-btn"
                    aria-label={t("aria_decrease")}
                    onclick={(e) => {
                      e.stopPropagation();
                      handleValueChange(
                        "gamepad",
                        getItemIndex("gyro_mapping"),
                        -1,
                      );
                    }}
                  >
<Icon name="chevron-left" size={18} />
                  </button>
                  <span class="arrow-stepper-value"
                    >{[t("disabled"), t("mouse"), t("right_stick")][
                      gyroMappingIndex
                    ]}</span
                  >
                  <button
                    class="arrow-stepper-btn"
                    aria-label={t("aria_increase")}
                    onclick={(e) => {
                      e.stopPropagation();
                      handleValueChange(
                        "gamepad",
                        getItemIndex("gyro_mapping"),
                        1,
                      );
                    }}
                  >
<Icon name="chevron-right" size={18} />
                  </button>
                </div>
                {#if gyroMappingMode === "RightStick" && !vigemDriverInstalled}
                  <p class="item-description" style="color: #f59e0b;">
                    {t("vigem_required")}
                  </p>
                {/if}
              </div>

              <!-- ViGEm 驱动安装（仅当需要右摇杆且未安装时显示） -->
              {#if gyroMappingMode === "RightStick" && !vigemDriverInstalled}
                <div
                  class="list-item action-item"
                  class:focused={isFocused("vigem_install")}
                  data-focus-index={getItemIndex("vigem_install")}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = getItemIndex("vigem_install");
                    installVigemDriver();
                  }}
                  onkeydown={() => {}}
                >
                  <div class="item-header">
                    <div class="item-title">
<Icon name="download" />
                      {t("install_vigem_driver")}
                    </div>
                    {#if vigemInstalling}
                      <span style="color: #3b82f6;">{t("installing")}</span>
                    {:else}
                      <span class="action-hint">{t("press_a_install")}</span>
                    {/if}
                  </div>
                  <p class="item-description">
                    {t("desc_vigem_driver")}
                  </p>
                </div>
              {/if}

              {#if gyroEnabled}
                <!-- X轴反转 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_invert_x")}
                data-focus-index={getItemIndex("gyro_invert_x")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_invert_x"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="move" />
                    {t("invert_x")}
                  </div>
                  <ToggleSwitch checked={gyroInvertX} />
                </div>
              </div>

              <!-- Y轴反转 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_invert_y")}
                data-focus-index={getItemIndex("gyro_invert_y")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_invert_y"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="move" />
                    {t("invert_y")}
                  </div>
                  <ToggleSwitch checked={gyroInvertY} />
                </div>
              </div>

              <!-- 启用滤波 -->
              <div
                class="list-item"
                class:focused={isFocused("gyro_filtering")}
                data-focus-index={getItemIndex("gyro_filtering")}
                role="button"
                tabindex="0"
                onclick={() =>
                  handleListItemClick(getItemIndex("gyro_filtering"))}
                onkeydown={() => {}}
              >
                <div class="item-header">
                  <div class="item-title">
<Icon name="sliders" />
                    {t("enable_filtering")}
                  </div>
                  <ToggleSwitch checked={gyroUseFiltering} />
                </div>
              </div>
              {/if}
            {/if}

            <!-- 陀螺仪数据可视化 -->
            {#if gyroEnabled && gyroData}
              <div
                class="gyro-test-panel"
                class:focused={isFocused("gyro_test")}
                data-focus-index={getItemIndex("gyro_test")}
                role="button"
                tabindex="0"
                onclick={() => handleListItemClick(getItemIndex("gyro_test"))}
                onkeydown={() => {}}
              >
                <div class="panel-header">
                  <span>{t("realtime_data")}</span>
                  {#if isGyroTestMode}
                    <span class="test-mode-badge">{t("test_mode")}</span>
                  {/if}
                </div>

                <div class="gyro-data-grid">
                  <div class="gyro-data-section">
                    <h4>{t("gyro_angular_velocity")}</h4>
                    <div class="data-row">
                      <span class="data-label">X:</span>
                      <span class="data-value"
                        >{gyroData.gyro[0].toFixed(2)}</span
                      >
                    </div>
                    <div class="data-row">
                      <span class="data-label">Y:</span>
                      <span class="data-value"
                        >{gyroData.gyro[1].toFixed(2)}</span
                      >
                    </div>
                    <div class="data-row">
                      <span class="data-label">Z:</span>
                      <span class="data-value"
                        >{gyroData.gyro[2].toFixed(2)}</span
                      >
                    </div>
                  </div>

                  <div class="gyro-data-section">
                    <h4>{t("accelerometer")}</h4>
                    <div class="data-row">
                      <span class="data-label">X:</span>
                      <span class="data-value"
                        >{gyroData.accel[0].toFixed(2)}</span
                      >
                    </div>
                    <div class="data-row">
                      <span class="data-label">Y:</span>
                      <span class="data-value"
                        >{gyroData.accel[1].toFixed(2)}</span
                      >
                    </div>
                    <div class="data-row">
                      <span class="data-label">Z:</span>
                      <span class="data-value"
                        >{gyroData.accel[2].toFixed(2)}</span
                      >
                    </div>
                  </div>
                </div>

                <div class="gyro-visualizer">
                  <svg viewBox="-100 -100 200 200" class="gyro-svg">
                    <circle
                      cx="0"
                      cy="0"
                      r="90"
                      fill="none"
                      stroke="var(--color-border)"
                      stroke-width="1"
                      opacity="0.3"
                    />
                    <circle
                      cx="0"
                      cy="0"
                      r="60"
                      fill="none"
                      stroke="var(--color-border)"
                      stroke-width="1"
                      opacity="0.2"
                    />
                    <circle
                      cx="0"
                      cy="0"
                      r="30"
                      fill="none"
                      stroke="var(--color-border)"
                      stroke-width="1"
                      opacity="0.1"
                    />
                    <line
                      x1="-90"
                      y1="0"
                      x2="90"
                      y2="0"
                      stroke="var(--color-border)"
                      stroke-width="1"
                      opacity="0.2"
                    />
                    <line
                      x1="0"
                      y1="-90"
                      x2="0"
                      y2="90"
