                  <linearGradient
                    id="bodyGrad"
                    x1="0%"
                    y1="0%"
                    x2="0%"
                    y2="100%"
                  >
                    <stop offset="0%" stop-color="#e6e6e6" />
                    <stop offset="100%" stop-color="#b3b3b3" />
                  </linearGradient>
                  <filter id="glow">
                    <feGaussianBlur stdDeviation="2" result="coloredBlur" />
                    <feMerge
                      ><feMergeNode in="coloredBlur" /><feMergeNode
                        in="SourceGraphic"
                      /></feMerge
                    >
                  </filter>
                </defs>

                <!-- LT / RT 扳机 -->
                <path
                  d="M 120 50 Q 120 15 160 25 L 185 35 L 120 70 Z"
                  fill={gamepadTestState.triggers.left > 0.1 ? "#ddd" : "#444"}
                  stroke="#333"
                  stroke-width="2"
                />
                <path
                  d="M 480 50 Q 480 15 440 25 L 415 35 L 480 70 Z"
                  fill={gamepadTestState.triggers.right > 0.1 ? "#ddd" : "#444"}
                  stroke="#333"
                  stroke-width="2"
                />

                <!-- LB / RB 肩键 -->
                <path
                  d="M 120 70 Q 120 55 185 55 L 205 68 L 120 90 Z"
                  fill={gamepadTestState.buttons[4] ? "#ddd" : "#444"}
                  stroke="#333"
                  stroke-width="2"
                />
                <path
                  d="M 480 70 Q 480 55 415 55 L 395 68 L 480 90 Z"
                  fill={gamepadTestState.buttons[5] ? "#ddd" : "#444"}
                  stroke="#333"
                  stroke-width="2"
                />

                <!-- 手柄机身 -->
                <path
                  d="M 200 60 C 145 60, 90 105, 80 195 C 75 250, 95 305, 140 315 C 168 320, 185 290, 205 262 L 395 262 C 415 290, 432 320, 460 315 C 505 305, 525 250, 520 195 C 510 105, 455 60, 400 60 Q 300 42 200 60 Z"
                  fill="url(#bodyGrad)"
                  stroke="#888"
                  stroke-width="2.5"
                />

                <!-- 左摇杆 -->
                <g transform="translate(145, 140)">
                  <circle cx="0" cy="0" r="32" fill="#ccc" />
                  <circle
                    cx={(gamepadTestState.axes[0] || 0) * 12}
                    cy={(gamepadTestState.axes[1] || 0) * 12}
                    r="20"
                    fill={gamepadTestState.buttons[10] ? "#666" : "#4a4a4a"}
                    stroke="#333"
                    stroke-width="2"
                  />
                </g>

                <!-- 右摇杆 -->
                <g transform="translate(385, 200)">
                  <circle cx="0" cy="0" r="32" fill="#ccc" />
                  <circle
                    cx={(gamepadTestState.axes[2] || 0) * 12}
                    cy={(gamepadTestState.axes[3] || 0) * 12}
                    r="20"
                    fill={gamepadTestState.buttons[11] ? "#666" : "#4a4a4a"}
                    stroke="#333"
                    stroke-width="2"
                  />
                </g>

                <!-- D-Pad -->
                <g transform="translate(205, 200)">
                  <circle cx="0" cy="0" r="38" fill="#ccc" />
                  <path
                    d="M -10 -32 L 10 -32 L 10 -10 L -10 -10 Z"
                    fill={gamepadTestState.buttons[12] ? "#ddd" : "#444"}
                    stroke="#333"
                  />
                  <path
                    d="M -10 32 L 10 32 L 10 10 L -10 10 Z"
                    fill={gamepadTestState.buttons[13] ? "#ddd" : "#444"}
                    stroke="#333"
                  />
                  <path
                    d="M -32 -10 L -32 10 L -10 10 L -10 -10 Z"
                    fill={gamepadTestState.buttons[14] ? "#ddd" : "#444"}
                    stroke="#333"
                  />
                  <path
                    d="M 32 -10 L 32 10 L 10 10 L 10 -10 Z"
                    fill={gamepadTestState.buttons[15] ? "#ddd" : "#444"}
                    stroke="#333"
                  />
                  <rect x="-10" y="-10" width="20" height="20" fill="#555" />
                </g>

                <!-- ABXY 按钮 -->
                <g transform="translate(455, 135)">
                  <circle
                    cx="32"
                    cy="0"
                    r="13"
                    fill={gamepadTestState.buttons[1] ? "#ef4444" : "#444"}
                    stroke="#333"
                    stroke-width="2"
                    filter={gamepadTestState.buttons[1] ? "url(#glow)" : "none"}
                  />
                  <text
                    x="32"
                    y="4"
                    text-anchor="middle"
                    fill={gamepadTestState.buttons[1] ? "#fff" : "#bc0000"}
                    font-size="11"
                    font-weight="bold">B</text
                  >

                  <circle
                    cx="0"
                    cy="32"
                    r="13"
                    fill={gamepadTestState.buttons[0] ? "#22c55e" : "#444"}
                    stroke="#333"
                    stroke-width="2"
                    filter={gamepadTestState.buttons[0] ? "url(#glow)" : "none"}
                  />
                  <text
                    x="0"
                    y="36"
                    text-anchor="middle"
                    fill={gamepadTestState.buttons[0] ? "#fff" : "#00bc00"}
                    font-size="11"
                    font-weight="bold">A</text
                  >

                  <circle
                    cx="-32"
                    cy="0"
                    r="13"
                    fill={gamepadTestState.buttons[2] ? "#3b82f6" : "#444"}
                    stroke="#333"
                    stroke-width="2"
                    filter={gamepadTestState.buttons[2] ? "url(#glow)" : "none"}
                  />
                  <text
                    x="-32"
                    y="4"
                    text-anchor="middle"
                    fill={gamepadTestState.buttons[2] ? "#fff" : "#0066bc"}
                    font-size="11"
                    font-weight="bold">X</text
                  >

                  <circle
                    cx="0"
                    cy="-32"
                    r="13"
                    fill={gamepadTestState.buttons[3] ? "#fbbf24" : "#444"}
                    stroke="#333"
                    stroke-width="2"
                    filter={gamepadTestState.buttons[3] ? "url(#glow)" : "none"}
                  />
                  <text
                    x="0"
                    y="-28"
                    text-anchor="middle"
                    fill={gamepadTestState.buttons[3] ? "#fff" : "#bcbc00"}
                    font-size="11"
                    font-weight="bold">Y</text
                  >
                </g>

                <!-- Guide / Back / Start -->
                <circle
                  cx="300"
                  cy="135"
                  r="18"
                  fill={gamepadTestState.buttons[16] ? "#22c55e" : "#eee"}
                  stroke="#999"
                  stroke-width="2"
                  filter={gamepadTestState.buttons[16] ? "url(#glow)" : "none"}
                />
                <text
                  x="300"
                  y="140"
                  text-anchor="middle"
                  fill="#444"
                  font-size="18"
                  font-weight="bold">X</text
                >

                <circle
                  cx="248"
                  cy="135"
                  r="7"
                  fill={gamepadTestState.buttons[8] ? "#ddd" : "#444"}
                  stroke="#333"
                />
                <circle
                  cx="352"
                  cy="135"
                  r="7"
                  fill={gamepadTestState.buttons[9] ? "#ddd" : "#444"}
                  stroke="#333"
                />
              </svg>
            </div>

            <!-- 数据面板 -->
            <div class="gamepad-data-grid">
              <div class="data-col">
                <div class="data-label">{t("gamepad_axes")}</div>
                <div class="data-rows">
                  <div class="data-row">
                    <span>Left X</span><span class="data-value"
                      >{(gamepadTestState.axes[0] || 0).toFixed(2)}</span
                    >
                  </div>
                  <div class="data-row">
                    <span>Left Y</span><span class="data-value"
