                    >
                  </div>
                  <div class="trigger-bar">
                    <div
                      class="trigger-fill"
                      style="width: {(gamepadTestState.triggers.left || 0) *
                        100}%"
                    ></div>
                  </div>
                  <div class="data-row">
                    <span>RT</span><span class="data-value trigger"
                      >{(gamepadTestState.triggers.right || 0).toFixed(2)}</span
                    >
                  </div>
                  <div class="trigger-bar">
                    <div
                      class="trigger-fill"
                      style="width: {(gamepadTestState.triggers.right || 0) *
                        100}%"
                    ></div>
                  </div>
                </div>
                <div class="pressed-buttons">
                  {#if Object.entries(gamepadTestState.buttons).filter(([, v]) => v).length > 0}
                    <span class="pressed-label">{t("pressed")}:</span>
                    {#each Object.entries(gamepadTestState.buttons).filter(([, v]) => v) as [idx]}
                      <span class="btn-tag"
                        >{getXboxButtonName(Number(idx))}</span
                      >
                    {/each}
                  {:else}
                    <span class="no-press">{t("press_button_to_test")}</span>
                  {/if}
                </div>
              </div>
            </div>
          </div>
        {/if}
      {:else if currentTabId === "hotkey"}
