            class:focused={isFocused("reset_settings")}
            data-focus-index={getItemIndex("reset_settings")}
            role="button"
            tabindex="0"
            onclick={() => {
              focusIndex = getItemIndex("reset_settings");
              handleAction();
            }}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                  stroke-linecap="round"
                  stroke-linejoin="round"
                >
                  <polyline points="1 4 1 10 7 10" />
                  <path d="M3.51 15a9 9 0 1 0 2.13-9.36L1 10" />
                </svg>
                {t("reset_settings")}
              </div>
              {#if dangerConfirmId === "reset_settings"}
                <div class="danger-progress-bar">
                  <div
                    class="danger-progress-fill"
                    style="width: {(dangerConfirmCountdown / 5) * 100}%"
                  ></div>
                  <span class="danger-progress-text"
                    >{dangerConfirmCountdown}s</span
                  >
                </div>
              {:else}
                <span class="item-value"
                  >{isFocused("reset_settings")
                    ? t("press_a_config")
                    : ""}</span
                >
              {/if}
            </div>
            <p class="item-description">
              {t("desc_reset_settings")}
            </p>
          </div>

          <!-- RTSS 状态展示 -->
          <div class="divider"></div>
          <h3 class="section-title">{t("rtss_status_title")}</h3>
          <div
            class="list-item"
            class:focused={isFocused("rtss_status")}
            data-focus-index={getItemIndex("rtss_status")}
            role="button"
            tabindex="0"
            onclick={() => { focusIndex = getItemIndex("rtss_status"); }}
            onkeydown={() => {}}
          >
            <div class="item-header">
              <div class="item-title">
                <Icon name="monitor-lines" />
                RTSS
              </div>
              <span class="item-value" style="color: {rtssStatus.installed ? (rtssStatus.running ? 'var(--accent-color, #66c0f4)' : '#f59e0b') : '#ef4444'}">
                {rtssStatus.installed
                  ? (rtssStatus.running ? t("rtss_status_running") : t("rtss_status_not_running"))
                  : t("rtss_status_not_installed")}
              </span>
            </div>
            {#if rtssStatus.install_path}
              <p class="item-description" style="word-break: break-all;">
                {t("rtss_status_path")}: {rtssStatus.install_path}
              </p>
            {/if}
            {#if rtssStatus.installed && !rtssStatus.running}
              <button
                class="rtss-action-btn"
                onclick={(e) => {
                  e.stopPropagation();
                  invoke<RtssResult>("rtss_manual_launch")
                    .then((result) => {
                      if (result.success) {
                        rtssStatus = { ...rtssStatus, running: true };
                        showToast("RTSS " + t("rtss_status_running"), "success");
                      } else {
                        showToast(result.message || t("rtss_dialog_error"), "error");
                      }
                    })
                    .catch((err) => showToast(String(err), "error"));
                }}
              >
                {t("rtss_status_launch")}
              </button>
            {:else if !rtssStatus.installed}
              <button
                class="rtss-action-btn"
                onclick={(e) => { e.stopPropagation(); showRtssInstallDialog = true; }}
              >
                {t("rtss_status_install_import")}
              </button>
            {/if}
          </div>

          <!-- 系统优化折叠栏 -->
          <div
            class="collapse-header"
            class:focused={isFocused("optimize_toggle")}
            class:expanded={optimizeExpanded}
            data-focus-index={getItemIndex("optimize_toggle")}
            role="button"
            tabindex="0"
            onclick={() => {
              focusIndex = getItemIndex("optimize_toggle");
              optimizeExpanded = !optimizeExpanded;
            }}
            onkeydown={() => {}}
          >
            <div class="collapse-title">
              <svg
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                ><path d="M12 20h9" /><path
                  d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"
                /></svg
              >
              {t("optimize")}
            </div>
            <Icon name="chevron-down" class="collapse-arrow" />
          </div>

          {#if optimizeExpanded}
            <!-- 可还原优化选项 - 三列布局 -->
            <div class="optimize-grid">
              {#each ALL_OPTIMIZATIONS as opt, idx}
                {@const optFocusIndex = getItemIndex("opt_" + opt.id)}
                <div
                  class="optimize-card"
                  class:active={optimizationStates[opt.id]}
                  class:running={optimizationRunning === opt.id}
                  class:danger={IRREVERSIBLE_OPTIMIZATIONS.some(
                    (o) => o.id === opt.id,
                  )}
                  class:success={optimizationResults[opt.id]?.success === true}
                  class:error={optimizationResults[opt.id]?.success === false}
                  class:confirming={dangerConfirmId === opt.id}
                  class:focused={focusIndex === optFocusIndex}
                  data-focus-index={optFocusIndex}
                  data-opt-index={idx}
                  role="button"
                  tabindex="0"
                  onclick={() => {
                    focusIndex = optFocusIndex;
                    const isIrreversible = IRREVERSIBLE_OPTIMIZATIONS.some(
                      (o) => o.id === opt.id,
                    );
                    if (isIrreversible) {
                      // 不可还原操作需要长按确认
                    } else {
                      toggleOptimizationState(opt.id);
                    }
                  }}
                  onpointerdown={() => {
                    focusIndex = optFocusIndex;
                    const isIrreversible = IRREVERSIBLE_OPTIMIZATIONS.some(
                      (o) => o.id === opt.id,
                    );
                    if (
                      isIrreversible &&
                      !optimizationRunning &&
                      !optimizationResults[opt.id]
                    ) {
                      startDangerConfirm(opt.id);
                    }
                  }}
                  onpointerup={() => cancelDangerConfirm()}
                  onpointerleave={() => cancelDangerConfirm()}
                  onkeydown={() => {}}
                >
                  <div class="card-header">
                    {#if optimizationRunning === opt.id}
                      <div class="spinner small"></div>
                    {:else if dangerConfirmId === opt.id}
                      <div class="countdown-circle small">
                        {dangerConfirmCountdown}
                      </div>
                    {:else if optimizationResults[opt.id]?.success === true}
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="#22c55e"
                        stroke-width="2"
                        ><path
                          d="M22 11.08V12a10 10 0 1 1-5.93-9.14"
                        /><polyline points="22 4 12 14.01 9 11.01" /></svg
                      >
                    {:else if optimizationResults[opt.id]?.success === false}
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="#ef4444"
                        stroke-width="2"
                        ><circle cx="12" cy="12" r="10" /><line
                          x1="15"
                          y1="9"
                          x2="9"
                          y2="15"
                        /><line x1="9" y1="9" x2="15" y2="15" /></svg
                      >
                    {:else if IRREVERSIBLE_OPTIMIZATIONS.some((o) => o.id === opt.id)}
                      <Icon name="zap" size={16} stroke="#ef4444" />
                    {:else}
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        ><circle cx="12" cy="12" r="3" /><path
                          d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"
                        /></svg
                      >
                    {/if}
                    <span class="card-title">{t(opt.label as TranslationKey)}</span>
                    {#if !IRREVERSIBLE_OPTIMIZATIONS.some((o) => o.id === opt.id)}
                      <div
                        class="toggle-switch small"
                        class:active={optimizationStates[opt.id]}
                      >
                        <div class="toggle-thumb"></div>
                      </div>
                    {/if}
                  </div>
                  {#if dangerConfirmId === opt.id}
                    <p class="card-desc danger-text">
                      ⚠️ {t("hold_seconds").replace(
                        "{seconds}",
                        String(dangerConfirmCountdown),
                      )}
                    </p>
                  {/if}
                </div>
              {/each}
