  /* ==================== Toast 通知样式（主题适配） ==================== */
  /* 基础样式已移至 Toast.svelte 组件 */

  /* Toast 暖色主题适配 */
  :global([data-theme="light"]) .toast,
  :global([data-theme="cream"]) .toast,
  :global([data-theme="lavender"]) .toast,
  :global([data-theme="mint"]) .toast,
  :global([data-theme="sky"]) .toast,
  :global([data-theme="rose"]) .toast {
    background: rgba(255, 255, 255, 0.95);
    border: 1px solid rgba(0, 0, 0, 0.1);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  }

  :global([data-theme="light"]) .toast-message,
  :global([data-theme="cream"]) .toast-message,
  :global([data-theme="lavender"]) .toast-message,
  :global([data-theme="mint"]) .toast-message,
  :global([data-theme="sky"]) .toast-message,
  :global([data-theme="rose"]) .toast-message {
