  :global([data-theme="cream"]) .toast-success,
  :global([data-theme="lavender"]) .toast-success,
  :global([data-theme="mint"]) .toast-success,
  :global([data-theme="sky"]) .toast-success,
  :global([data-theme="rose"]) .toast-success {
    border-color: rgba(34, 197, 94, 0.3);
    background: rgba(34, 197, 94, 0.05);
  }

  :global([data-theme="light"]) .toast-error,
  :global([data-theme="cream"]) .toast-error,
  :global([data-theme="lavender"]) .toast-error,
  :global([data-theme="mint"]) .toast-error,
  :global([data-theme="sky"]) .toast-error,
  :global([data-theme="rose"]) .toast-error {
    border-color: rgba(239, 68, 68, 0.3);
    background: rgba(239, 68, 68, 0.05);
  }

  :global([data-theme="light"]) .toast-warning,
  :global([data-theme="cream"]) .toast-warning,
  :global([data-theme="lavender"]) .toast-warning,
  :global([data-theme="mint"]) .toast-warning,
  :global([data-theme="sky"]) .toast-warning,
  :global([data-theme="rose"]) .toast-warning {
    border-color: rgba(251, 191, 36, 0.3);
    background: rgba(251, 191, 36, 0.05);
  }

  :global([data-theme="light"]) .toast-info,
  :global([data-theme="cream"]) .toast-info,
  :global([data-theme="lavender"]) .toast-info,
  :global([data-theme="mint"]) .toast-info,
  :global([data-theme="sky"]) .toast-info,
  :global([data-theme="rose"]) .toast-info {
