    background: rgba(var(--accent-rgb), 0.05);
  }

  .section-title :global(svg) {
    width: 18px;
    height: 18px;
    margin-right: 6px;
    opacity: 0.7;
  }

  /* ==================== 陀螺仪样式 ==================== */

  /* 陀螺仪测试面板 */
  .gyro-test-panel {
    background: var(--color-surface);
    border-radius: 12px;
    padding: 16px;
    margin-top: 12px;
    border: 2px solid transparent;
    transition: all 0.2s;
  }

  .gyro-test-panel.focused {
    border-color: var(--color-primary);
    box-shadow: 0 0 0 3px var(--color-primary-alpha);
  }

  .gyro-test-panel .panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
    font-weight: 600;
  }

  .test-mode-badge {
    background: var(--color-primary);
    color: white;
    padding: 2px 8px;
    border-radius: 4px;
    font-size: calc(12px * var(--font-scale, 1));
  }

  .gyro-data-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
    margin-bottom: 16px;
  }

  .gyro-data-section h4 {
    font-size: calc(13px * var(--font-scale, 1));
    margin-bottom: 8px;
    opacity: 0.7;
    font-weight: 500;
  }

  .data-row {
    display: flex;
    justify-content: space-between;
    padding: 4px 0;
    font-family: "Consolas", "Monaco", monospace;
  }

  .data-label {
    opacity: 0.6;
  }

  .data-value {
    font-weight: 600;
    color: var(--color-primary);
  }

  .gyro-visualizer {
    background: var(--color-bg);
    border-radius: 8px;
    padding: 16px;
    display: flex;
    justify-content: center;
    align-items: center;
    margin-bottom: 12px;
  }

  .gyro-svg {
    width: 180px;
    height: 180px;
  }

  .test-hint {
    text-align: center;
    font-size: calc(12px * var(--font-scale, 1));
    opacity: 0.6;
    font-style: italic;
  }

  /* 测试模式横幅 */
  .test-banner {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 12px 16px;
    background: rgba(var(--accent-color-rgb, 102, 192, 244), 0.1);
    border-radius: 8px;
    margin-bottom: 16px;
  }

  .pulse-dot {
    display: inline-block;
    width: 8px;
    height: 8px;
    background: var(--color-primary, #66c0f4);
    border-radius: 50%;
    animation: pulse 1.5s ease-in-out infinite;
  }

  @keyframes pulse {
    0%,
    100% {
      opacity: 1;
      transform: scale(1);
    }
    50% {
      opacity: 0.5;
      transform: scale(1.2);
    }
  }

  @keyframes blink-dot {
    0%,
    100% {
      opacity: 1;
    }
    50% {
      opacity: 0.5;
      transform: scale(1.2);
    }
  }

  /* ==================== ROG Ally 死区组样式 ==================== */

  .deadzone-group {
    background: var(--color-surface);
    border-radius: 12px;
    padding: 12px 16px;
    margin: 8px 0;
  }

  .deadzone-label {
    font-size: calc(13px * var(--font-scale, 1));
    font-weight: 600;
    margin-bottom: 8px;
    opacity: 0.9;
  }

  .deadzone-sliders {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
  }

  .slider-compact {
    padding: 8px 12px !important;
    min-height: auto !important;
  }

  .slider-compact .item-header {
    margin-bottom: 6px;
  }

  .slider-compact .mini-label {
    font-size: calc(11px * var(--font-scale, 1));
    opacity: 0.7;
  }

  .slider-compact .item-value {
    font-size: calc(12px * var(--font-scale, 1));
  }

  .slider-compact .slider-track {
    height: 4px;
  }

  .slider-compact .slider-thumb {
    width: 10px;
    height: 10px;
    top: -3px;
  }

  /* ===== 进程结束长按进度条样式 ===== */
  .process-kill-progress-overlay {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    background: linear-gradient(to top, rgba(239, 68, 68, 0.9), transparent);
    padding: 8px 12px;
    display: flex;
    flex-direction: column;
    gap: 4px;
    border-radius: 0 0 8px 8px;
    backdrop-filter: blur(4px);
  }

  .process-kill-progress-text {
    font-size: calc(11px * var(--font-scale, 1));
    font-weight: 600;
    color: white;
    text-align: center;
  }

  .process-kill-progress-bar {
    height: 4px;
    background: rgba(255, 255, 255, 0.3);
    border-radius: 2px;
    overflow: hidden;
  }

  .process-kill-progress-fill {
    height: 100%;
    background: white;
    transition: width 0.05s linear;
    box-shadow: 0 0 8px rgba(255, 255, 255, 0.8);
  }

  /* 暖色主题支持 */
  :global([data-theme="light"]) .process-kill-progress-text,
  :global([data-theme="cream"]) .process-kill-progress-text,
  :global([data-theme="lavender"]) .process-kill-progress-text,
  :global([data-theme="mint"]) .process-kill-progress-text,
  :global([data-theme="sky"]) .process-kill-progress-text,
  :global([data-theme="rose"]) .process-kill-progress-text {
    color: #dc2626;
  }

  :global([data-theme="light"]) .process-kill-progress-bar,
  :global([data-theme="cream"]) .process-kill-progress-bar,
  :global([data-theme="lavender"]) .process-kill-progress-bar,
  :global([data-theme="mint"]) .process-kill-progress-bar,
  :global([data-theme="sky"]) .process-kill-progress-bar,
  :global([data-theme="rose"]) .process-kill-progress-bar {
    background: rgba(0, 0, 0, 0.15);
  }

  :global([data-theme="light"]) .process-kill-progress-fill,
  :global([data-theme="cream"]) .process-kill-progress-fill,
  :global([data-theme="lavender"]) .process-kill-progress-fill,
  :global([data-theme="mint"]) .process-kill-progress-fill,
  :global([data-theme="sky"]) .process-kill-progress-fill,
  :global([data-theme="rose"]) .process-kill-progress-fill {
    background: #dc2626;
    box-shadow: 0 0 8px rgba(220, 38, 38, 0.5);
  }

  :global([data-theme="light"]) .process-kill-progress-overlay,
  :global([data-theme="cream"]) .process-kill-progress-overlay,
  :global([data-theme="lavender"]) .process-kill-progress-overlay,
  :global([data-theme="mint"]) .process-kill-progress-overlay,
  :global([data-theme="sky"]) .process-kill-progress-overlay,
  :global([data-theme="rose"]) .process-kill-progress-overlay {
    background: linear-gradient(to top, rgba(239, 68, 68, 0.15), transparent);
  }

  .loading-spinner {
    width: 32px;
    height: 32px;
    border: 3px solid rgba(255, 255, 255, 0.1);
    border-top-color: var(--accent-color);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
    margin: 0 auto 12px;
  }

  @keyframes spin {
    to {
      transform: rotate(360deg);
    }
  }

  /* ===== 修改器页面样式 ===== */
  .trainer-search-container {
    margin-top: 12px;
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  .trainer-search-input {
    width: 100%;
    padding: 10px 14px;
    background: rgba(255, 255, 255, 0.05);
    border: 1.5px solid rgba(255, 255, 255, 0.1);
    border-radius: 8px;
    color: #fff;
    font-size: 13px;
    outline: none;
    transition: all 0.2s;
  }

  .trainer-search-input:focus {
    background: rgba(255, 255, 255, 0.08);
    border-color: var(--accent-color);
  }

  .trainer-search-input::placeholder {
    color: rgba(255, 255, 255, 0.3);
  }

  .trainer-view-toggle {
    display: flex;
    gap: 8px;
    background: rgba(255, 255, 255, 0.03);
    padding: 4px;
    border-radius: 8px;
  }

  .trainer-view-toggle .toggle-btn {
    flex: 1;
    padding: 8px 12px;
    background: transparent;
    border: none;
    border-radius: 6px;
    color: rgba(255, 255, 255, 0.5);
    font-size: 12px;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s;
  }

  .trainer-view-toggle .toggle-btn:hover {
    background: rgba(255, 255, 255, 0.05);
    color: rgba(255, 255, 255, 0.7);
  }

  .trainer-view-toggle .toggle-btn.active {
    background: var(--accent-color);
    color: #fff;
  }

  .trainer-list {
    margin-top: 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
  }

  .trainer-item {
    position: relative;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 14px;
    background: rgba(255, 255, 255, 0.03);
    border: 2px solid transparent;
    border-radius: 10px;
    cursor: pointer;
    transition: all 0.2s;
  }

  .trainer-item:hover {
    background: rgba(255, 255, 255, 0.05);
  }

  .trainer-item.focused {
    background: rgba(255, 255, 255, 0.08);
    border-color: var(--accent-color);
    box-shadow: 0 0 0 3px rgba(var(--accent-rgb), 0.15);
  }

  .trainer-item.downloading {
    opacity: 0.6;
    pointer-events: none;
  }

  .trainer-icon {
    flex-shrink: 0;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 8px;
  }

  .trainer-icon :global(svg) {
    opacity: 0.7;
  }

  .trainer-item.focused .trainer-icon {
    background: var(--accent-color);
  }

  .trainer-item.focused .trainer-icon :global(svg) {
    opacity: 1;
  }

  .trainer-info {
    flex: 1;
    min-width: 0;
  }

  .trainer-name {
    font-size: 13.5px;
    font-weight: 500;
    color: #fff;
    margin-bottom: 4px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .trainer-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 11px;
    color: rgba(255, 255, 255, 0.4);
  }

  .trainer-source {
    padding: 2px 6px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 4px;
  }

  .trainer-version {
    padding: 2px 6px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 4px;
  }

  .trainer-status {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 6px 10px;
    border-radius: 6px;
    font-size: 11px;
    font-weight: 500;
    margin-left: auto;
  }

  .trainer-status.installed {
    background: rgba(34, 197, 94, 0.15);
    color: #22c55e;
  }

  .trainer-status.not-installed {
    background: rgba(251, 191, 36, 0.15);
    color: #fbbf24;
  }

  .trainer-action-hint {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 4px 8px;
    background: var(--accent-color);
    color: #fff;
    font-size: 11px;
    font-weight: 600;
    border-radius: 4px;
    white-space: nowrap;
    margin-left: auto;
  }

  .trainer-download-progress {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 8px 12px;
    background: linear-gradient(to top, rgba(59, 130, 246, 0.9), transparent);
    border-radius: 0 0 8px 8px;
    backdrop-filter: blur(4px);
  }

  .download-progress-text {
    font-size: 11px;
    font-weight: 600;
    color: white;
    text-align: center;
    margin-bottom: 4px;
  }

  .download-progress-bar {
    height: 4px;
    background: rgba(255, 255, 255, 0.3);
    border-radius: 2px;
    overflow: hidden;
  }

  .download-progress-fill {
    height: 100%;
    background: white;
    transition: width 0.3s ease;
    box-shadow: 0 0 8px rgba(255, 255, 255, 0.8);
  }

  /* 暖色主题适配 - 修改器页 */
  :global([data-theme="light"]) .trainer-search-input,
  :global([data-theme="cream"]) .trainer-search-input,
  :global([data-theme="lavender"]) .trainer-search-input,
  :global([data-theme="mint"]) .trainer-search-input,
  :global([data-theme="sky"]) .trainer-search-input,
  :global([data-theme="rose"]) .trainer-search-input {
    background: rgba(0, 0, 0, 0.03);
    border-color: rgba(0, 0, 0, 0.1);
    color: #1f2937;
  }

  :global([data-theme="light"]) .trainer-search-input:focus,
  :global([data-theme="cream"]) .trainer-search-input:focus,
  :global([data-theme="lavender"]) .trainer-search-input:focus,
  :global([data-theme="mint"]) .trainer-search-input:focus,
  :global([data-theme="sky"]) .trainer-search-input:focus,
  :global([data-theme="rose"]) .trainer-search-input:focus {
    background: rgba(0, 0, 0, 0.05);
  }

  :global([data-theme="light"]) .trainer-item,
  :global([data-theme="cream"]) .trainer-item,
  :global([data-theme="lavender"]) .trainer-item,
  :global([data-theme="mint"]) .trainer-item,
  :global([data-theme="sky"]) .trainer-item,
  :global([data-theme="rose"]) .trainer-item {
    background: rgba(0, 0, 0, 0.02);
  }

  :global([data-theme="light"]) .trainer-name,
  :global([data-theme="cream"]) .trainer-name,
  :global([data-theme="lavender"]) .trainer-name,
  :global([data-theme="mint"]) .trainer-name,
  :global([data-theme="sky"]) .trainer-name,
  :global([data-theme="rose"]) .trainer-name {
    color: #1f2937;
  }

  :global([data-theme="light"]) .trainer-meta,
  :global([data-theme="cream"]) .trainer-meta,
  :global([data-theme="lavender"]) .trainer-meta,
  :global([data-theme="mint"]) .trainer-meta,
  :global([data-theme="sky"]) .trainer-meta,
  :global([data-theme="rose"]) .trainer-meta {
    color: rgba(0, 0, 0, 0.4);
  }

  :global([data-theme="light"]) .trainer-icon,
  :global([data-theme="cream"]) .trainer-icon,
  :global([data-theme="lavender"]) .trainer-icon,
  :global([data-theme="mint"]) .trainer-icon,
  :global([data-theme="sky"]) .trainer-icon,
  :global([data-theme="rose"]) .trainer-icon {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-secondary);
  }

  /* ===== 媒体查询 - 掌机多分辨率适配 ===== */

  /* 720p 及以下高度（排除高DPI缩放用户） */
  @media screen and (max-height: 720px) and (-webkit-max-device-pixel-ratio: 1.25),
    screen and (max-height: 720px) and (max-resolution: 120dpi) {
    .tab-bar {
      padding: 16px 12px 12px;
      gap: 12px;
    }
    .footer {
      padding: 8px 12px;
      font-size: 10px;
    }
    .tab-icon-wrapper {
      padding: 6px;
    }
    .tab-icon-wrapper :global(svg) {
      width: 18px;
      height: 18px;
    }
    .tab-label {
      font-size: 9px;
    }

    .content-body {
      padding: 12px 14px;
    }

    .now-playing-card {
      padding: 10px;
      gap: 10px;
    }

    .battery-details-panel {
      padding: 12px;
    }
    .detail-row {
      padding: 6px 0;
    }

    .gamepad-visual {
      padding: 8px 0;
    }
    .gamepad-svg {
      max-width: 260px;
    }
    .gamepad-svg-full {
      max-width: 360px;
    }
    .gamepad-data-grid {
      padding: 10px;
      gap: 10px;
    }

    .gpu-metrics-overview {
      padding: 10px;
      gap: 12px;
    }
    .metric-item {
      min-width: 50px;
    }
    .metric-value {
      font-size: 16px;
    }
    .metric-label {
      font-size: 9px;
    }

    .optimize-grid {
      gap: 6px;
    }
    .optimize-card {
      padding: 8px 10px;
      min-height: 36px;
    }
